def _translation_failure_details(
    exc: Exception,
    target: str,
    unit: ProjectTranslationUnit,
    artifact_path: str | None,
) -> dict[str, Any]:
    del target
    return {
        **_crossgl_function_body_failure_details(exc, unit, artifact_path),
        **_opengl_template_failure_details(exc, unit, artifact_path),
        **_opengl_mapped_overload_failure_details(exc, unit, artifact_path),
        **_opengl_recursion_failure_details(exc, unit, artifact_path),
        **_opengl_aggregate_initializer_failure_details(exc, unit, artifact_path),
        **_opengl_scalar_conversion_failure_details(exc, unit, artifact_path),
        **_opengl_complex_arithmetic_failure_details(exc, unit, artifact_path),
        **_compile_time_global_failure_details(exc, unit, artifact_path),
        **_boolean_ordered_intrinsic_failure_details(exc, unit, artifact_path),
        **_math_intrinsic_failure_details(exc, unit, artifact_path),
        **_opengl_struct_construction_failure_details(exc, unit, artifact_path),
        **_opengl_fixed_array_resource_failure_details(exc, unit, artifact_path),
        **_opengl_resource_memory_qualifier_failure_details(exc, unit, artifact_path),
        **_directx_private_pointer_failure_details(exc, unit, artifact_path),
        **_directx_bfloat16_failure_details(exc, unit, artifact_path),
        **_directx_resource_pointer_array_failure_details(exc, unit, artifact_path),
        **_directx_trailing_zero_failure_details(exc, unit, artifact_path),
        **_opengl_private_pointer_failure_details(exc, unit, artifact_path),
        **_directx_workgroup_pointer_failure_details(exc, unit, artifact_path),
        **_opengl_index_type_failure_details(exc, unit, artifact_path),
        **_opengl_workgroup_pointer_failure_details(exc, unit, artifact_path),
        **_opengl_storage_pointer_failure_details(exc, unit, artifact_path),
        **_opengl_reference_parameter_failure_details(exc, unit, artifact_path),
        **_pointer_reinterpret_failure_details(exc, unit, artifact_path),
        **_generic_member_call_failure_details(exc, unit, artifact_path),
        **_metal_call_operator_failure_details(exc, unit, artifact_path),
        **_metal_struct_method_failure_details(exc, unit, artifact_path),
        **_metal_struct_method_call_failure_details(exc, unit, artifact_path),
        **_metal_constructor_failure_details(exc, unit, artifact_path),
        **_metal_stateless_global_failure_details(exc, unit, artifact_path),
        **_metal_static_assertion_failure_details(exc, unit, artifact_path),
        **_metal_static_constant_failure_details(exc, unit, artifact_path),
        **_metal_sizeof_failure_details(exc, unit, artifact_path),
        **_metal_template_argument_failure_details(exc, unit, artifact_path),
        **_metal_callable_failure_details(exc, unit, artifact_path),
        **_metal_callable_alias_failure_details(exc, unit, artifact_path),
        **_template_materialization_failure_details(exc),
        **_workgroup_size_failure_details(exc, unit, artifact_path),
        **_directx_entry_point_failure_details(exc, unit, artifact_path),
    }


def _translation_failure_project_diagnostics(
    exc: Exception,
    target: str,
    unit: ProjectTranslationUnit,
    variant: str | None,
    message: str,
    artifact_path: str | None = None,
) -> list[ProjectDiagnostic]:
    contracts = getattr(exc, "contracts", None)
    if contracts:
        diagnostics: list[ProjectDiagnostic] = []
        location = _translation_failure_location(exc, unit)
        for contract in contracts:
            code = getattr(contract, "code", None)
            if not _is_non_empty_string(code):
                code = _translation_failure_code(exc, target)
            format_message = getattr(contract, "format_project_message", None)
            if callable(format_message):
                diagnostic_message = format_message(target)
            else:
                diagnostic_message = str(contract)
            capabilities = getattr(contract, "missing_capabilities", None)
            if isinstance(capabilities, str):
                missing_capabilities = [capabilities]
            elif capabilities:
                missing_capabilities = [str(capability) for capability in capabilities]
            else:
                missing_capabilities = _translation_failure_missing_capabilities(
                    exc, target
                )
            diagnostics.append(
                ProjectDiagnostic(
                    severity="error",
                    code=code,
                    message=diagnostic_message,
                    location=location,
                    target=target,
                    source_backend=unit.source_backend,
                    variant=variant,
                    check_kind=getattr(exc, "check_kind", None),
                    missing_capabilities=missing_capabilities,
                    details=_translation_failure_details(
                        exc,
                        target,
                        unit,
                        artifact_path,
                    ),
                )
            )
        return diagnostics

    return [
        ProjectDiagnostic(
            severity="error",
            code=_translation_failure_code(exc, target),
            message=message,
            location=_translation_failure_location(exc, unit),
            target=target,
            source_backend=unit.source_backend,
            variant=variant,
            check_kind=getattr(exc, "check_kind", None),
            missing_capabilities=_translation_failure_missing_capabilities(exc, target),
            details=_translation_failure_details(exc, target, unit, artifact_path),
        )
    ]


def _opengl_template_enclosing_type_from_message(exc: Exception) -> str | None:
    match = re.search(r" from '([^']+)'", str(exc))
    return match.group(1) if match is not None else None


def _is_metal_template_failure(exc: Exception, unit: ProjectTranslationUnit) -> bool:
    return (
        unit.source_backend == "metal"
        and _translation_failure_diagnostic_code(exc)
        == "project.translate.opengl-template-type-unresolved"
    )


def _metal_template_missing_binding(exc: Exception) -> str | None:
    message = str(exc)
    match = re.search(r"unresolved template type '([^']+)'", message)
    if match is not None:
        return match.group(1)
    match = re.search(r"generic function '([^']+)'", message)
    if match is not None:
        return match.group(1)
    return None


def _metal_template_failure_function(exc: Exception) -> str | None:
    match = re.search(r"generic function '([^']+)'", str(exc))
    return match.group(1) if match is not None else None


def _split_template_parameters(text: str) -> list[str]:
    parts: list[str] = []
    current: list[str] = []
    depth = 0
    pairs = {"<": ">", "(": ")", "[": "]", "{": "}"}
    closers = set(pairs.values())
    for character in text:
        if character in pairs:
            depth += 1
        elif character in closers and depth > 0:
            depth -= 1
        if character == "," and depth == 0:
            part = "".join(current).strip()
            if part:
                parts.append(part)
            current = []
            continue
        current.append(character)
    part = "".join(current).strip()
    if part:
        parts.append(part)
    return parts


def _metal_template_parameter_name(parameter: str) -> str | None:
    parameter = parameter.split("=", 1)[0].strip()
    tokens = re.findall(r"[A-Za-z_][A-Za-z0-9_]*", parameter)
    if not tokens:
        return None
    if tokens[0] in {"typename", "class"} and len(tokens) >= 2:
        return tokens[-1]
    if len(tokens) >= 2:
        return tokens[-1]
    return None


def _source_location_at_offset(
    unit: ProjectTranslationUnit, text: str, offset: int, length: int
) -> SourceLocation:
    prefix = text[:offset]
    line = prefix.count("\n") + 1
    previous_newline = prefix.rfind("\n")
    column = offset + 1 if previous_newline == -1 else offset - previous_newline
    end_line, end_column = _advance_source_position(
        text[offset : offset + length],
        line,
        column,
    )
    return SourceLocation(
        file=unit.relative_path,
        line=line,
        column=column,
        offset=offset,
        length=length,
        end_line=end_line,
        end_column=end_column,
        end_offset=offset + length,
    )


def _metal_template_declaration_context(
    exc: Exception, unit: ProjectTranslationUnit
) -> dict[str, Any] | None:
    if not _is_metal_template_failure(exc, unit):
        return None
    try:
        text = unit.path.read_text(encoding="utf-8")
    except (OSError, UnicodeDecodeError):
        return None

    function_name = _metal_template_failure_function(exc)
    missing_binding = _metal_template_missing_binding(exc)
    pattern = re.compile(
        r"\btemplate\s*<(?P<params>.*?)>\s*"
        r"(?P<header>(?:(?!\btemplate\b).){0,1200}?)"
        r"\b(?P<name>[A-Za-z_][A-Za-z0-9_]*)\s*(?:<[^;{}()]*>)?\s*\(",
        re.DOTALL,
    )
    fallback = None
    for match in pattern.finditer(text):
        name = match.group("name")
        params = [
            name
            for name in (
                _metal_template_parameter_name(part)
                for part in _split_template_parameters(match.group("params"))
            )
            if name
        ]
        if function_name and name != function_name:
            continue
        if missing_binding and not function_name and missing_binding not in params:
            continue
        location = _source_location_at_offset(
            unit,
            text,
            match.start(),
            max(match.end() - match.start(), 0),
        )
        context = {
            "name": name,
            "parameters": params,
            "location": location,
        }
        if function_name or missing_binding in params:
            return context
        if fallback is None:
            fallback = context
    return fallback


def _metal_template_failure_message(
    exc: Exception,
    target: str,
    unit: ProjectTranslationUnit,
    artifact_path: str | None,
) -> str | None:
    context = _metal_template_declaration_context(exc, unit)
    if context is None and not _is_metal_template_failure(exc, unit):
        return None
    missing_binding = _metal_template_missing_binding(exc)
    if missing_binding is None and context is not None:
        missing_binding = ", ".join(context.get("parameters", ())) or None

    parts = [str(exc)]
    if missing_binding:
        parts.append(f"Missing template binding: {missing_binding}.")
    if context is not None:
        location = context["location"]
        declaration_name = context.get("name") or "<unknown>"
        parts.append(
            "Source declaration: "
            f"{declaration_name} at {location.file}:{location.line}:{location.column}."
        )
    else:
        parts.append(f"Source declaration: not found in {unit.relative_path}.")
    if artifact_path:
        parts.append(f"Target artifact: {artifact_path}.")
    parts.append(
        "Suggested action: add a concrete Metal template instantiation, supply "
        f"explicit template arguments, or specialize the source before {target} "
        "generation."
    )
    return " ".join(parts)


def _translation_source_location_value(location: Any, *names: str) -> Any:
    if isinstance(location, Mapping):
        for name in names:
            if name in location:
                return location[name]
        return None

    for name in names:
        if hasattr(location, name):
            return getattr(location, name)
    return None


def _translation_source_location_int(value: Any, default: int) -> int:
    if isinstance(value, bool):
        return default
    try:
        converted = int(value)
    except (TypeError, ValueError):
        return default
    return converted if converted >= 0 else default


def _translation_source_location_file(value: Any, unit: ProjectTranslationUnit) -> str:
    if not isinstance(value, str) or not value.strip():
        return unit.relative_path

    normalized = value.strip().replace("\\", "/")
    if PureWindowsPath(value).is_absolute() or PurePosixPath(normalized).is_absolute():
        return unit.relative_path
    if any(part in {"", ".", ".."} for part in PurePosixPath(normalized).parts):
        return unit.relative_path
    return normalized


def _metal_owner_alias_failure_location(
    exc: Exception, unit: ProjectTranslationUnit
) -> SourceLocation | None:
    owner_name = getattr(exc, "owner_struct_name", None)
    nested_name = getattr(exc, "nested_struct_name", None)
    aliases = getattr(exc, "owner_aliases", None)
    if (
        unit.source_backend != "metal"
        or not _is_non_empty_string(owner_name)
        or not _is_non_empty_string(nested_name)
        or not aliases
    ):
        return None
    alias_names = {str(alias) for alias in aliases if _is_non_empty_string(alias)}
    if not alias_names:
        return None
    try:
        text = unit.path.read_text(encoding="utf-8")
    except (OSError, UnicodeDecodeError):
        return None

    from crosstl.backend.Metal.preprocessor import MetalPreprocessor

    try:
        preprocessor = MetalPreprocessor()
        owner_spans = [
            template.span
            for template in preprocessor._find_template_structs(text)
            if template.name == owner_name
        ]
        owner_spans.extend(
            struct.span
            for struct in preprocessor._find_concrete_struct_definitions(text)
            if struct.name == owner_name
        )
    except Exception:  # noqa: BLE001
        return None
    search_spans = owner_spans or [(0, len(text))]
    nested_pattern = re.compile(rf"\b{re.escape(nested_name)}\s*<")
    for span_start, span_end in search_spans:
        for match in nested_pattern.finditer(text, span_start, span_end):
            angle_start = text.find("<", match.start(), match.end())
            angle_end = preprocessor._find_matching_angle(text, angle_start)
            if angle_end is None or angle_end >= span_end:
                continue
            argument_identifiers = set(
                re.findall(r"[A-Za-z_][A-Za-z0-9_]*", text[angle_start + 1 : angle_end])
            )
            if not (argument_identifiers & alias_names):
                continue
            return _source_location_at_offset(
                unit,
                text,
                match.start(),
                angle_end + 1 - match.start(),
            )
    return None


def _opengl_recursion_failure_location(
    exc: Exception,
    unit: ProjectTranslationUnit,
) -> SourceLocation | None:
    if _translation_failure_diagnostic_code(exc) != (
        "project.translate.opengl-recursion-unsupported"
    ):
        return None

    source_edge = getattr(exc, "source_edge", None)
    if not isinstance(source_edge, (list, tuple)) or len(source_edge) != 2:
        return None
    source_name, target_name = source_edge
    identifier_pattern = re.compile(r"[A-Za-z_][A-Za-z0-9_]*")
    if not all(
        isinstance(name, str) and identifier_pattern.fullmatch(name)
        for name in (source_name, target_name)
    ):
        return None

    try:
        text = unit.path.read_text(encoding="utf-8")
    except (OSError, UnicodeDecodeError):
        return None

    from crosstl.backend.Metal.preprocessor import MetalPreprocessor

    masked_text = _masked_metal_non_code_text(text)
    preprocessor = MetalPreprocessor()
    source_pattern = re.compile(rf"\b{re.escape(source_name)}\s*\(")
    target_pattern = re.compile(
        rf"\b{re.escape(target_name)}\s*(?:<[^;{{}}()]*>)?\s*\("
    )
    for source_match in source_pattern.finditer(masked_text):
        params_start = masked_text.find("(", source_match.start(), source_match.end())
        params_end = preprocessor._find_matching_delimiter(
            masked_text,
            params_start,
            "(",
            ")",
        )
        if params_end is None:
            continue
        body_start = masked_text.find("{", params_end + 1)
        declaration_end = masked_text.find(";", params_end + 1)
        if body_start == -1 or (declaration_end != -1 and declaration_end < body_start):
            continue
        body_end = preprocessor._find_matching_brace(masked_text, body_start)
        if body_end is None:
            continue
        call_match = target_pattern.search(masked_text, body_start + 1, body_end - 1)
        if call_match is None:
            continue
        call_start = call_match.start()
        call_paren = masked_text.find("(", call_start, call_match.end())
        call_end = preprocessor._find_matching_delimiter(
            masked_text,
            call_paren,
            "(",
            ")",
        )
        length = call_end + 1 - call_start if call_end is not None else len(target_name)
        return _source_location_at_offset(unit, text, call_start, length)
    return None


def _translation_failure_location(
    exc: Exception, unit: ProjectTranslationUnit
) -> SourceLocation:
    recursion_location = _opengl_recursion_failure_location(exc, unit)
    if recursion_location is not None:
        return recursion_location
    owner_alias_location = _metal_owner_alias_failure_location(exc, unit)
    if owner_alias_location is not None:
        return owner_alias_location
    source_location = getattr(exc, "source_location", None)
    if isinstance(source_location, SourceLocation):
        file_name = _translation_source_location_file(source_location.file, unit)
        if file_name == source_location.file:
            return source_location
        return replace(source_location, file=file_name)
    if source_location is None:
        index_location = _index_type_failure_location(exc, unit)
        if index_location is not None:
            return index_location
        context = _metal_template_declaration_context(exc, unit)
        if context is not None:
            return context["location"]
        return SourceLocation(file=unit.relative_path)

    file_name = _translation_source_location_file(
        _translation_source_location_value(source_location, "file"), unit
    )

    line = max(
        1,
        _translation_source_location_int(
            _translation_source_location_value(source_location, "line"), 1
        ),
    )
    column = max(
        1,
        _translation_source_location_int(
            _translation_source_location_value(source_location, "column"), 1
        ),
    )
    end_line = max(
        line,
        _translation_source_location_int(
            _translation_source_location_value(source_location, "end_line", "endLine"),
            line,
        ),
    )
    end_column = max(
        1,
        _translation_source_location_int(
            _translation_source_location_value(
                source_location, "end_column", "endColumn"
            ),
            column,
        ),
    )
    return SourceLocation(
        file=file_name,
        line=line,
        column=column,
        offset=_translation_source_location_int(
            _translation_source_location_value(source_location, "offset"), 0
        ),
        length=_translation_source_location_int(
            _translation_source_location_value(source_location, "length"), 0
        ),
        end_line=end_line,
        end_column=end_column,
        end_offset=_translation_source_location_int(
            _translation_source_location_value(
                source_location, "end_offset", "endOffset"
            ),
            0,
        ),
    )


def _index_type_failure_location(
    exc: Exception, unit: ProjectTranslationUnit
) -> SourceLocation | None:
    if _translation_failure_diagnostic_code(exc) not in {
        "project.translate.opengl-index-type-unsupported",
        "project.translate.webgl-index-type-unsupported",
    }:
        return None
    index_expression = getattr(exc, "index_expression", None)
    indexed_value = getattr(exc, "indexed_value", None)
    if not _is_non_empty_string(index_expression):
        return None
    try:
        source = unit.path.read_text(encoding="utf-8")
    except (OSError, UnicodeDecodeError):
        return None

    def source_pattern(value: str) -> str:
        return r"\s*".join(re.escape(part) for part in value.strip().split())

    index_pattern = source_pattern(index_expression)
    patterns = []
    if _is_non_empty_string(indexed_value):
        indexed_pattern = source_pattern(indexed_value)
        patterns.extend(
            (
                rf"{indexed_pattern}\s*\[\s*(?P<index>{index_pattern})",
                rf"\bbuffer_(?:load|store)\s*\(\s*{indexed_pattern}\s*,\s*"
                rf"(?P<index>{index_pattern})",
                rf"\btexelFetch\s*\(\s*{indexed_pattern}\s*,\s*"
                rf"(?P<index>{index_pattern})",
            )
        )
    patterns.append(rf"(?P<index>{index_pattern})")
    for pattern in patterns:
        match = re.search(pattern, source)
        if match is None:
            continue
        return _source_location_at_offset(
            unit,
            source,
            match.start("index"),
            match.end("index") - match.start("index"),
        )
    return None


_SPECIALIZATION_CONSTANT_ID_MAX = 0x7FFFFFFF
_METAL_FUNCTION_CONSTANT_ID_MAX = 0xFFFF


def _specialization_attribute_id_max(attribute: str) -> int:
    if attribute == "function_constant":
        return _METAL_FUNCTION_CONSTANT_ID_MAX
    return _SPECIALIZATION_CONSTANT_ID_MAX


@dataclass(frozen=True)
class _SpecializationIdValue:
    constant_id: int | None
    spelling: str | None
    reason: str | None = None
    parsed_value: int | None = None


@dataclass(frozen=True)
class _ProjectSpecializationAttribute:
    name: str
    constant_id: int | None
    spelling: str | None
    maximum_id: int
    reason: str | None = None
    parsed_value: int | None = None


@dataclass(frozen=True)
class _ProjectSpecializationSource:
    location: SourceLocation
    attributes: tuple[tuple[str, str], ...] = ()


@dataclass(frozen=True)
class _ProjectSpecializationDeclaration:
    name: str
    constant_id: int | None
    id_spelling: str | None
    source_type: str
    attribute: str
    has_default: bool
    default_value: Any
    location: SourceLocation


class ProjectSpecializationError(ValueError):
    """A project specialization contract blocked target generation."""

    def __init__(
        self,
        message: str,
        *,
        diagnostics: Sequence[ProjectDiagnostic],
    ) -> None:
        super().__init__(message)
        self.diagnostics = tuple(diagnostics)


def _specialization_id_value(
    value: Any,
    *,
    source_spelling: str | None = None,
    maximum_id: int = _SPECIALIZATION_CONSTANT_ID_MAX,
) -> _SpecializationIdValue:
    value = _runtime_host_interface_json_value(value)
    if isinstance(value, bool):
        spelling = (
            source_spelling.strip() if source_spelling is not None else str(value)
        )
        return _SpecializationIdValue(None, spelling, "invalid-literal")
    if isinstance(value, int):
        spelling = (
            source_spelling.strip() if source_spelling is not None else str(value)
        )
        if source_spelling is None:
            parsed_value = value
        else:
            try:
                parsed_value = parse_c_family_integral_literal(spelling)
            except CFamilyIntegralLiteralError as exc:
                signed_value = None
                if exc.reason == "negative":
                    try:
                        signed_value = -parse_c_family_integral_literal(spelling[1:])
                    except CFamilyIntegralLiteralError:
                        pass
                return _SpecializationIdValue(None, spelling, exc.reason, signed_value)
    elif isinstance(value, str) or source_spelling is not None:
        spelling = (
            source_spelling.strip()
            if source_spelling is not None
            else str(value).strip()
        )
        try:
            parsed_value = parse_c_family_integral_literal(spelling)
        except CFamilyIntegralLiteralError as exc:
            signed_value = None
            if exc.reason == "negative":
                try:
                    signed_value = -parse_c_family_integral_literal(spelling[1:])
                except CFamilyIntegralLiteralError:
                    pass
            return _SpecializationIdValue(None, spelling, exc.reason, signed_value)
    else:
        return _SpecializationIdValue(None, None, "invalid-literal")

    if parsed_value < 0:
        return _SpecializationIdValue(None, spelling, "negative", parsed_value)
    if parsed_value > maximum_id:
        return _SpecializationIdValue(None, spelling, "out-of-range", parsed_value)
    return _SpecializationIdValue(parsed_value, spelling, parsed_value=parsed_value)


def _specialization_int_value(value: Any) -> int | None:
    return _specialization_id_value(value).constant_id


def _specialization_scalar_literal(value: Any) -> Any:
    value = _runtime_host_interface_json_value(value)
    if not isinstance(value, str):
        return value
    text = value.strip()
    lowered = text.lower()
    if lowered in {"true", "false"}:
        return lowered == "true"
    numeric = text
    if numeric.lower().endswith(("u", "f", "h")):
        numeric = numeric[:-1]
    try:
        return int(numeric, 0)
    except ValueError:
        pass
    try:
        return float(numeric)
    except ValueError:
        return text


def _specialization_attribute_records(
    node: Any,
) -> list[_ProjectSpecializationAttribute]:
    values: list[_ProjectSpecializationAttribute] = []
    for attribute in getattr(node, "attributes", []) or []:
        name = str(getattr(attribute, "name", "")).strip().lower().replace("-", "_")
        if name not in {"function_constant", "constant_id"}:
            continue
        arguments = (
            getattr(attribute, "arguments", None)
            or getattr(attribute, "args", None)
            or []
        )
        maximum_id = _specialization_attribute_id_max(name)
        parsed = _specialization_id_value(
            arguments[0] if arguments else "", maximum_id=maximum_id
        )
        values.append(
            _ProjectSpecializationAttribute(
                name=name,
                constant_id=parsed.constant_id,
                spelling=parsed.spelling,
                maximum_id=maximum_id,
                reason=parsed.reason,
                parsed_value=parsed.parsed_value,
            )
        )
    for layout_name in ("layout", "interface_layout"):
        layout = getattr(node, layout_name, None)
        if not isinstance(layout, Mapping):
            continue
        for key, value in layout.items():
            if str(key).strip().lower() == "constant_id":
                maximum_id = _specialization_attribute_id_max("constant_id")
                parsed = _specialization_id_value(value, maximum_id=maximum_id)
                values.append(
                    _ProjectSpecializationAttribute(
                        name="constant_id",
                        constant_id=parsed.constant_id,
                        spelling=parsed.spelling,
                        maximum_id=maximum_id,
                        reason=parsed.reason,
                        parsed_value=parsed.parsed_value,
                    )
                )
    return values


def _specialization_attribute_values(node: Any) -> list[tuple[str, int | None]]:
    return [
        (attribute.name, attribute.constant_id)
        for attribute in _specialization_attribute_records(node)
    ]


def _specialization_ast_declaration_items(ast: Any) -> Iterator[tuple[Any, Any, bool]]:
    seen: set[int] = set()
    for group_name in ("global_variables", "global_vars", "constants", "constant"):
        for item in getattr(ast, group_name, []) or []:
            if id(item) in seen:
                continue
            seen.add(id(item))
            node = getattr(item, "left", None)
            if node is not None and _is_non_empty_string(getattr(node, "name", None)):
                yield node, getattr(item, "right", None), True
                continue
            if not _is_non_empty_string(getattr(item, "name", None)):
                continue
            if hasattr(item, "initial_value"):
                default_value = getattr(item, "initial_value")
                yield item, default_value, default_value is not None
            elif hasattr(item, "value"):
                default_value = getattr(item, "value")
                yield item, default_value, default_value is not None
            else:
                yield item, None, False


def _specialization_source_attributes(
    statement: str,
) -> list[tuple[int, int, str, str]]:
    attributes: list[tuple[int, int, str, str]] = []
    attribute_pattern = re.compile(
        r"\b(?P<name>function_constant|constant_id)\s*\(\s*"
        r"(?P<spelling>[^)]*?)\s*\)",
        re.IGNORECASE,
    )
    for match in attribute_pattern.finditer(statement):
        attributes.append(
            (
                match.start(),
                match.end(),
                match.group("name").lower(),
                match.group("spelling").strip(),
            )
        )

    layout_pattern = re.compile(r"\blayout\s*\((?P<body>[^)]*)\)", re.IGNORECASE)
    assignment_pattern = re.compile(
        r"\bconstant_id\s*=\s*(?P<spelling>[^,]*?)(?=\s*(?:,|$))",
        re.IGNORECASE,
    )
    for layout_match in layout_pattern.finditer(statement):
        body = layout_match.group("body")
        for assignment in assignment_pattern.finditer(body):
            start = layout_match.start("body") + assignment.start()
            end = layout_match.start("body") + assignment.end()
            attributes.append(
                (
                    start,
                    end,
                    "constant_id",
                    assignment.group("spelling").strip(),
                )
            )
    return sorted(attributes, key=lambda attribute: attribute[0])


def _specialization_statement_source(
    unit: ProjectTranslationUnit,
    source: str,
    *,
    name: str,
    used_offsets: set[int],
) -> _ProjectSpecializationSource:
    identifier = re.compile(rf"\b{re.escape(name)}\b")
    for statement in re.finditer(r"[^;{}]{0,4096};", source, re.DOTALL):
        if not identifier.search(statement.group(0)):
            continue
        source_attributes = _specialization_source_attributes(statement.group(0))
        if not source_attributes:
            continue
        first_start, first_end, _attribute, _spelling = source_attributes[0]
        offset = statement.start() + first_start
        if offset in used_offsets:
            continue
        used_offsets.add(offset)
        return _ProjectSpecializationSource(
            location=_source_location_at_offset(
                unit, source, offset, first_end - first_start
            ),
            attributes=tuple(
                (attribute, spelling)
                for _start, _end, attribute, spelling in source_attributes
            ),
        )
    return _ProjectSpecializationSource(SourceLocation(file=unit.relative_path))


def _specialization_attributes_with_source_spelling(
    attributes: Sequence[_ProjectSpecializationAttribute],
    source_attributes: Sequence[tuple[str, str]],
) -> list[_ProjectSpecializationAttribute]:
    if [attribute.name for attribute in attributes] != [
        attribute for attribute, _spelling in source_attributes
    ]:
        return list(attributes)

    values: list[_ProjectSpecializationAttribute] = []
    for attribute, (_source_attribute, source_spelling) in zip(
        attributes, source_attributes
    ):
        parsed = _specialization_id_value(
            (
                attribute.constant_id
                if attribute.constant_id is not None
                else attribute.spelling
            ),
            source_spelling=source_spelling,
            maximum_id=attribute.maximum_id,
        )
        values.append(
            _ProjectSpecializationAttribute(
                name=attribute.name,
                constant_id=parsed.constant_id,
                spelling=parsed.spelling,
                maximum_id=attribute.maximum_id,
                reason=parsed.reason,
                parsed_value=parsed.parsed_value,
            )
        )
    return values


def _specialization_invalid_id_message(
    name: str,
    *,
    reason: str,
    spelling: str | None,
    parsed_value: int | None,
    maximum_id: int,
) -> str:
    rendered = repr(spelling) if spelling is not None else "<missing>"
    if reason == "negative":
        return f"Specialization constant '{name}' id {rendered} must be non-negative."
    if reason == "out-of-range":
        return (
            f"Specialization constant '{name}' id {rendered} resolves to "
            f"{parsed_value}, exceeding the maximum supported id "
            f"{maximum_id}."
        )
    if reason == "invalid-octal-digit":
        return (
            f"Specialization constant '{name}' id {rendered} is not valid octal; "
            "a leading-zero id may contain only digits 0 through 7."
        )
    if reason == "invalid-digit-separator":
        return (
            f"Specialization constant '{name}' id {rendered} has an invalid digit "
            "separator; separators must appear between digits."
        )
    if reason == "invalid-suffix":
        return (
            f"Specialization constant '{name}' id {rendered} has an unsupported "
            "integer suffix."
        )
    if reason == "invalid-digit":
        return (
            f"Specialization constant '{name}' id {rendered} contains a digit that "
            "is invalid for its base."
        )
    if reason == "unsupported-expression":
        return (
            f"Specialization constant '{name}' id {rendered} must be one C-family "
            "integral literal; constant expressions are not supported."
        )
    if reason == "conflicting-ids":
        return f"Specialization constant '{name}' carries conflicting numeric ids."
    return (
        f"Specialization constant '{name}' requires one non-negative C-family "
        "integral literal id."
    )


def _project_specialization_declarations(
    unit: ProjectTranslationUnit,
    ast: Any,
    source: str,
) -> tuple[list[_ProjectSpecializationDeclaration], list[ProjectDiagnostic]]:
    declarations: list[_ProjectSpecializationDeclaration] = []
    diagnostics: list[ProjectDiagnostic] = []
    used_offsets: set[int] = set()
    for node, default_value, has_default in _specialization_ast_declaration_items(ast):
        attributes = _specialization_attribute_records(node)
        if not attributes:
            continue
        name = str(getattr(node, "name"))
        source_context = _specialization_statement_source(
            unit,
            source,
            name=name,
            used_offsets=used_offsets,
        )
        attributes = _specialization_attributes_with_source_spelling(
            attributes, source_context.attributes
        )
        canonical_ids = {
            attribute.constant_id
            for attribute in attributes
            if attribute.constant_id is not None
        }
        invalid_attribute = next(
            (attribute for attribute in attributes if attribute.reason is not None),
            None,
        )
        valid_id = invalid_attribute is None and len(canonical_ids) == 1
        constant_id = next(iter(canonical_ids)) if valid_id else None
        if not valid_id:
            reason = (
                invalid_attribute.reason
                if invalid_attribute is not None
                else "conflicting-ids"
            )
            spelling = (
                invalid_attribute.spelling
                if invalid_attribute is not None
                else attributes[0].spelling
            )
            parsed_value = (
                invalid_attribute.parsed_value
                if invalid_attribute is not None
                else None
            )
            maximum_id = (
                invalid_attribute.maximum_id
                if invalid_attribute is not None
                else min(attribute.maximum_id for attribute in attributes)
            )
            diagnostics.append(
                ProjectDiagnostic(
                    severity="error",
                    code="project.translate.specialization-constant-id-invalid",
                    message=_specialization_invalid_id_message(
                        name,
                        reason=reason,
                        spelling=spelling,
                        parsed_value=parsed_value,
                        maximum_id=maximum_id,
                    ),
                    location=source_context.location,
                    source_backend=unit.source_backend,
                    missing_capabilities=["specialization.constant.identity"],
                    details={
                        "name": name,
                        "reason": reason,
                        "id": parsed_value,
                        "idSpelling": spelling,
                        "idSpellings": [
                            attribute.spelling
                            for attribute in attributes
                            if attribute.spelling is not None
                        ],
                        "canonicalIds": sorted(canonical_ids),
                        "attributes": [attribute.name for attribute in attributes],
                        "minimumId": 0,
                        "maximumId": maximum_id,
                    },
                )
            )
        builtin_default = (
            GLSL_BUILTIN_INT_LIMITS.get(name)
            if unit.source_backend == "opengl"
            else None
        )
        source_type = (
            _runtime_host_interface_type_name(getattr(node, "var_type", None))
            or _runtime_host_interface_type_name(getattr(node, "vtype", None))
            or _runtime_host_interface_type_name(getattr(node, "const_type", None))
            or ("int" if builtin_default is not None else None)
            or "unknown"
        )
        if not has_default and builtin_default is not None:
            default_value = builtin_default
            has_default = True
        declarations.append(
            _ProjectSpecializationDeclaration(
                name=name,
                constant_id=constant_id,
                id_spelling=attributes[0].spelling,
                source_type=source_type,
                attribute=attributes[0].name,
                has_default=has_default,
                default_value=(
                    _specialization_scalar_literal(default_value)
                    if has_default
                    else None
                ),
                location=source_context.location,
            )
        )

    by_id: dict[int, _ProjectSpecializationDeclaration] = {}
    for declaration in declarations:
        if declaration.constant_id is None:
            continue
        previous = by_id.get(declaration.constant_id)
        if previous is None:
            by_id[declaration.constant_id] = declaration
            continue
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code="project.translate.specialization-constant-id-duplicate",
                message=(
                    f"Specialization constant id {declaration.constant_id} is used by "
                    f"both '{previous.name}' and '{declaration.name}'."
                ),
                location=declaration.location,
                source_backend=unit.source_backend,
                missing_capabilities=["specialization.constant.identity"],
                details={
                    "id": declaration.constant_id,
                    "idSpelling": declaration.id_spelling,
                    "name": declaration.name,
                    "previousName": previous.name,
                    "previousIdSpelling": previous.id_spelling,
                    "previousLocation": previous.location.to_json(),
                },
            )
        )
    return declarations, diagnostics


def _normalized_specialization_type(source_type: str) -> str:
    value = " ".join(source_type.strip().lower().replace("metal::", "").split())
    for qualifier in ("const ", "constant ", "constexpr "):
        if value.startswith(qualifier):
            value = value[len(qualifier) :]
    return value


def _specialization_value_for_type(
    value: Any, source_type: str
) -> tuple[bool, Any, str | None]:
    value = _specialization_scalar_literal(value)
    normalized_type = _normalized_specialization_type(source_type)
    if normalized_type in {"bool", "boolean"}:
        if isinstance(value, bool):
            return True, value, None
        return False, value, "expected a boolean"

    signed_types = {
        "char",
        "short",
        "int",
        "long",
        "long long",
        "int8_t",
        "int16_t",
        "int32_t",
        "int64_t",
        "i8",
        "i16",
        "i32",
        "i64",
    }
    unsigned_types = {
        "uchar",
        "ushort",
        "uint",
        "ulong",
        "ulong long",
        "unsigned char",
        "unsigned short",
        "unsigned int",
        "unsigned long",
        "unsigned long long",
        "uint8_t",
        "uint16_t",
        "uint32_t",
        "uint64_t",
        "u8",
        "u16",
        "u32",
        "u64",
        "size_t",
    }
    if normalized_type in signed_types | unsigned_types:
        if not isinstance(value, int) or isinstance(value, bool):
            return False, value, "expected an integer"
        if normalized_type in unsigned_types and value < 0:
            return False, value, "expected a non-negative integer"
        return True, value, None

    if normalized_type in {"half", "float", "double", "f16", "f32", "f64"}:
        if isinstance(value, bool) or not isinstance(value, (int, float)):
            return False, value, "expected a finite numeric value"
        converted = float(value)
        if not math.isfinite(converted):
            return False, value, "expected a finite numeric value"
        return True, converted, None
    return False, value, f"unsupported source type '{source_type}'"


def _specialization_diagnostic(
    declaration: _ProjectSpecializationDeclaration,
    unit: ProjectTranslationUnit,
    target: str,
    variant: str | None,
    *,
    code: str,
    message: str,
    details: Mapping[str, Any] = (),
) -> ProjectDiagnostic:
    return ProjectDiagnostic(
        severity="error",
        code=code,
        message=message,
        location=declaration.location,
        target=target,
        source_backend=unit.source_backend,
        variant=variant,
        missing_capabilities=["specialization.constant.materialization"],
        details=details if isinstance(details, Mapping) else {},
    )


def _resolved_project_specialization_constants(
    config: ProjectConfig,
    unit: ProjectTranslationUnit,
    declarations: Sequence[_ProjectSpecializationDeclaration],
    *,
    target: str,
    variant: str | None,
    configured_values: Mapping[str, tuple[Any, Mapping[str, Any]]] | None = None,
) -> tuple[list[dict[str, Any]], dict[str, Any], list[ProjectDiagnostic]]:
    configured = (
        dict(configured_values)
        if configured_values is not None
        else _variant_specialization_values(
            config,
            variant,
            relative_path=unit.relative_path,
        )
    )
    deferred = target in DEFERRED_SPECIALIZATION_TARGETS
    diagnostics: list[ProjectDiagnostic] = []
    records: list[dict[str, Any]] = []
    for declaration in declarations:
        selectors = [declaration.name]
        if declaration.constant_id is not None:
            selectors.append(str(declaration.constant_id))
        matches = [
            (selector, configured[selector])
            for selector in selectors
            if selector in configured
        ]
        resolved_matches: list[tuple[str, Any, dict[str, Any]]] = []
        for selector, (raw_value, provenance) in matches:
            valid, value, reason = _specialization_value_for_type(
                raw_value, declaration.source_type
            )
            if not valid:
                diagnostics.append(
                    _specialization_diagnostic(
                        declaration,
                        unit,
                        target,
                        variant,
                        code="project.translate.specialization-value-type-incompatible",
                        message=(
                            f"Configured value for specialization constant "
                            f"'{declaration.name}' is incompatible with source type "
                            f"{declaration.source_type}: {reason}."
                        ),
                        details={
                            "name": declaration.name,
                            "id": declaration.constant_id,
                            "sourceType": declaration.source_type,
                            "selector": selector,
                            "configuredValue": raw_value,
                            "provenance": provenance,
                        },
                    )
                )
                continue
            resolved_matches.append((selector, value, provenance))

        if len({value for _selector, value, _provenance in resolved_matches}) > 1:
            diagnostics.append(
                _specialization_diagnostic(
                    declaration,
                    unit,
                    target,
                    variant,
                    code="project.translate.specialization-value-conflict",
                    message=(
                        f"Specialization constant '{declaration.name}' has conflicting "
                        "configured values by name and numeric id."
                    ),
                    details={
                        "name": declaration.name,
                        "id": declaration.constant_id,
                        "matches": [
                            {
                                "selector": selector,
                                "value": value,
                                "provenance": provenance,
                            }
                            for selector, value, provenance in resolved_matches
                        ],
                    },
                )
            )
            resolved_matches = []

        selected_match = next(
            (match for match in resolved_matches if match[0] == declaration.name),
            resolved_matches[0] if resolved_matches else None,
        )
        record: dict[str, Any] = {
            "name": declaration.name,
            "id": declaration.constant_id,
            "kind": (
                "function-constant"
                if declaration.attribute == "function_constant"
                else "specialization-constant"
            ),
            "sourceType": declaration.source_type,
            "dtype": declaration.source_type,
            "required": not declaration.has_default,
            "overridden": selected_match is not None,
            "overrideStatus": (
                "overridden" if selected_match is not None else "not-overridden"
            ),
            "deferred": deferred,
            "source": f"{unit.source_backend}.{declaration.attribute}",
            "sourceLocation": declaration.location.to_json(),
        }
        if declaration.id_spelling is not None and (
            declaration.constant_id is None
            or declaration.id_spelling != str(declaration.constant_id)
        ):
            record["idSpelling"] = declaration.id_spelling
        if declaration.has_default:
            record["defaultValue"] = declaration.default_value
            record["default"] = declaration.default_value
        if selected_match is not None:
            _selector, concrete_value, provenance = selected_match
            record["concreteValue"] = concrete_value
            record["value"] = concrete_value
            record["status"] = "override"
            record["valueProvenance"] = dict(provenance)
        elif not deferred and declaration.has_default:
            valid, concrete_value, reason = _specialization_value_for_type(
                declaration.default_value, declaration.source_type
            )
            if valid:
                record["concreteValue"] = concrete_value
                record["value"] = concrete_value
                record["status"] = "materialized-default"
                record["valueProvenance"] = {
                    "kind": "source-default",
                    "path": f"{unit.relative_path}:{declaration.location.line}",
                }
            else:
                diagnostics.append(
                    _specialization_diagnostic(
                        declaration,
                        unit,
                        target,
                        variant,
                        code="project.translate.specialization-default-not-concrete",
                        message=(
                            f"Default for specialization constant "
                            f"'{declaration.name}' cannot be materialized for {target}: "
                            f"{reason}."
                        ),
                        details={
                            "name": declaration.name,
                            "id": declaration.constant_id,
                            "sourceType": declaration.source_type,
                            "defaultValue": declaration.default_value,
                        },
                    )
                )
                record["status"] = "invalid-default"
        elif not deferred:
            diagnostics.append(
                _specialization_diagnostic(
                    declaration,
                    unit,
                    target,
                    variant,
                    code="project.translate.specialization-value-required",
                    message=(
                        f"Target {target} cannot defer required specialization "
                        f"constant '{declaration.name}' (id {declaration.constant_id}); "
                        "configure a concrete value by source name or numeric id."
                    ),
                    details={
                        "name": declaration.name,
                        "id": declaration.constant_id,
                        "sourceType": declaration.source_type,
                    },
                )
            )
            record["status"] = "missing-required"
        elif declaration.has_default:
            record["status"] = "defaulted"
            record["valueProvenance"] = {
                "kind": "source-default",
                "path": f"{unit.relative_path}:{declaration.location.line}",
            }
        else:
            record["status"] = "required"
            record["valueProvenance"] = {"kind": "runtime-override-required"}
        records.append(record)

    status = "deferred" if deferred else "concrete"
    if any(diagnostic.severity == "error" for diagnostic in diagnostics):
        status = "failed"
    metadata = {
        "status": status,
        "mode": "deferred" if deferred else "concrete-crossgl-variant",
        "targetSupportsDeferredSpecialization": deferred,
        "constantCount": len(records),
        "requiredCount": sum(bool(record.get("required")) for record in records),
        "overriddenCount": sum(bool(record.get("overridden")) for record in records),
        "concreteCount": sum("concreteValue" in record for record in records),
        "source": "shared-crossgl-specialization",
    }
    return records, metadata, diagnostics


def _source_location_from_specialization_record(
    record: Mapping[str, Any], unit: ProjectTranslationUnit
) -> SourceLocation:
    location = record.get("sourceLocation")
    if not isinstance(location, Mapping):
        return SourceLocation(file=unit.relative_path)
    return SourceLocation(
        file=str(location.get("file") or unit.relative_path),
        line=max(1, int(location.get("line", 1))),
        column=max(1, int(location.get("column", 1))),
        offset=max(0, int(location.get("offset", 0))),
        length=max(0, int(location.get("length", 0))),
        end_line=max(1, int(location.get("endLine", location.get("line", 1)))),
        end_column=max(1, int(location.get("endColumn", location.get("column", 1)))),
        end_offset=max(0, int(location.get("endOffset", 0))),
    )


def _crossgl_specialization_literal(value: Any, source_type: str) -> str:
    normalized_type = _normalized_specialization_type(source_type)
    if isinstance(value, bool):
        return "true" if value else "false"
    if isinstance(value, int):
        return (
            f"{value}u" if normalized_type.startswith(("u", "unsigned")) else str(value)
        )
    if isinstance(value, float):
        text = repr(value)
        return text if "." in text or "e" in text.lower() else f"{text}.0"
    return str(value)


def _canonicalize_specialization_statement_ids(statement: str, constant_id: int) -> str:
    function_attribute = re.compile(
        r"(?P<prefix>\b(?:function_constant|constant_id)\s*\(\s*)"
        r"(?P<spelling>[^)]*?)(?P<suffix>\s*\))",
        re.IGNORECASE,
    )
    layout_attribute = re.compile(
        r"(?P<prefix>\bconstant_id\s*=\s*)"
        r"(?P<spelling>[^,)]*?)(?P<suffix>\s*(?=,|\)))",
        re.IGNORECASE,
    )

    def canonicalize(match: re.Match[str]) -> str:
        try:
            parsed = parse_c_family_integral_literal(match.group("spelling"))
        except CFamilyIntegralLiteralError:
            return match.group(0)
        if parsed != constant_id:
            return match.group(0)
        return f"{match.group('prefix')}{constant_id}{match.group('suffix')}"

    canonical = function_attribute.sub(canonicalize, statement)
    return layout_attribute.sub(canonicalize, canonical)


def _canonicalize_project_specialization_ids(
    source: str, records: Sequence[Mapping[str, Any]]
) -> str:
    statements = list(re.finditer(r"[^;{}]{0,4096};", source, re.DOTALL))
    used_statement_offsets: set[int] = set()
    replacements: list[tuple[int, int, str]] = []
    for record in records:
        name = record.get("name")
        constant_id = record.get("id")
        if not _is_non_empty_string(name) or not (
            isinstance(constant_id, int) and not isinstance(constant_id, bool)
        ):
            continue
        identifier = re.compile(rf"\b{re.escape(str(name))}\b")
        for statement in statements:
            if statement.start() in used_statement_offsets:
                continue
            text = statement.group(0)
            if not identifier.search(text) or not _specialization_source_attributes(
                text
            ):
                continue
            used_statement_offsets.add(statement.start())
            canonical = _canonicalize_specialization_statement_ids(text, constant_id)
            if canonical != text:
                replacements.append((statement.start(), statement.end(), canonical))
            break

    canonical_source = source
    for start, end, replacement in reversed(replacements):
        canonical_source = (
            canonical_source[:start] + replacement + canonical_source[end:]
        )
    return canonical_source


def _materialize_crossgl_specialization_constants(
    source: str,
    records: Sequence[Mapping[str, Any]],
    *,
    unit: ProjectTranslationUnit,
    target: str,
    variant: str | None,
) -> str:
    cgl_spec = SOURCE_REGISTRY.get("cgl")
    if cgl_spec is None:
        raise ProjectSpecializationError(
            "CrossGL parser is unavailable for specialization materialization.",
            diagnostics=(
                ProjectDiagnostic(
                    severity="error",
                    code="project.translate.specialization-intermediate-unavailable",
                    message=(
                        "CrossGL parser is unavailable for specialization "
                        "materialization."
                    ),
                    location=SourceLocation(file=unit.relative_path),
                    target=target,
                    source_backend=unit.source_backend,
                    variant=variant,
                    missing_capabilities=["specialization.constant.materialization"],
                ),
            ),
        )
    try:
        ast = cgl_spec.parse(source)
    except Exception as exc:
        raise ProjectSpecializationError(
            f"CrossGL specialization intermediate could not be parsed: {exc}",
            diagnostics=(
                ProjectDiagnostic(
                    severity="error",
                    code="project.translate.specialization-intermediate-invalid",
                    message=(
                        "CrossGL specialization intermediate could not be parsed: "
                        f"{exc}"
                    ),
                    location=SourceLocation(file=unit.relative_path),
                    target=target,
                    source_backend=unit.source_backend,
                    variant=variant,
                    missing_capabilities=["specialization.constant.materialization"],
                ),
            ),
        ) from exc
    shared_declarations, _diagnostics = _project_specialization_declarations(
        unit, ast, source
    )
    shared_by_id = {
        declaration.constant_id: declaration
        for declaration in shared_declarations
        if declaration.constant_id is not None
    }
    materialized = source
    for record in records:
        if "concreteValue" not in record:
            continue
        name = str(record.get("name") or "")
        constant_id = record.get("id")
        declaration = shared_by_id.get(constant_id)
        if declaration is None or declaration.name != name:
            diagnostic = ProjectDiagnostic(
                severity="error",
                code="project.translate.specialization-intermediate-mismatch",
                message=(
                    f"Shared CrossGL intermediate did not preserve specialization "
                    f"constant '{name}' with id {constant_id}."
                ),
                location=_source_location_from_specialization_record(record, unit),
                target=target,
                source_backend=unit.source_backend,
                variant=variant,
                missing_capabilities=["specialization.constant.identity"],
            )
            raise ProjectSpecializationError(
                diagnostic.message, diagnostics=(diagnostic,)
            )
        attribute_pattern = (
            r"@(?:function_constant|constant_id)\s*\(\s*"
            rf"{re.escape(declaration.id_spelling or str(constant_id))}\s*\)"
        )
        statement_pattern = re.compile(
            rf"^(?P<indent>[ \t]*)(?P<body>"
            rf"(?=[^;{{}}]*\b{re.escape(name)}\b)"
            rf"(?=[^;{{}}]*{attribute_pattern})[^;{{}}]*);",
            re.MULTILINE | re.DOTALL | re.IGNORECASE,
        )
        replacement = (
            rf"\g<indent>const {declaration.source_type} {name} = "
            + _crossgl_specialization_literal(
                record.get("concreteValue"), declaration.source_type
            )
            + ";"
        )
        materialized, replacement_count = statement_pattern.subn(
            replacement, materialized, count=1
        )
        if replacement_count != 1:
            diagnostic = ProjectDiagnostic(
                severity="error",
                code="project.translate.specialization-intermediate-mismatch",
                message=(
                    f"Shared CrossGL declaration for specialization constant "
                    f"'{name}' could not be materialized."
                ),
                location=_source_location_from_specialization_record(record, unit),
                target=target,
                source_backend=unit.source_backend,
                variant=variant,
                missing_capabilities=["specialization.constant.materialization"],
            )
            raise ProjectSpecializationError(
                diagnostic.message, diagnostics=(diagnostic,)
            )
    try:
        cgl_spec.parse(materialized)
    except Exception as exc:
        diagnostic = ProjectDiagnostic(
            severity="error",
            code="project.translate.specialization-materialization-invalid",
            message=f"Materialized CrossGL specialization variant is invalid: {exc}",
            location=SourceLocation(file=unit.relative_path),
            target=target,
            source_backend=unit.source_backend,
            variant=variant,
            missing_capabilities=["specialization.constant.materialization"],
        )
        raise ProjectSpecializationError(
            diagnostic.message, diagnostics=(diagnostic,)
        ) from exc
    return materialized


def _entry_scoped_specialization_names(
    unit: ProjectTranslationUnit,
    source_ast: Any,
    entry_point: str,
    target: str,
) -> set[str] | None:
    try:
        if unit.source_backend in {"cgl", "crossgl"}:
            crossgl_ast = source_ast
        else:
            source_spec = SOURCE_REGISTRY.get(unit.source_backend)
            cgl_spec = SOURCE_REGISTRY.get("cgl")
            if (
                source_spec is None
                or source_spec.reverse_codegen_factory is None
                or cgl_spec is None
            ):
                return None
            intermediate = source_spec.reverse_codegen_factory().generate(source_ast)
            crossgl_ast = cgl_spec.parse(
                intermediate,
                source_options={
                    "strict_function_bodies": unit.source_backend != "mojo"
                },
            )
        return _entry_scoped_specialization_names_from_crossgl_ast(
            crossgl_ast, entry_point, target
        )
    except Exception:  # noqa: BLE001
        return None


def _entry_scoped_specialization_names_from_crossgl_ast(
    crossgl_ast: Any,
    entry_point: str,
    target: str,
) -> set[str] | None:
    try:
        entry_scoped_ast = getattr(get_codegen(target), "entry_scoped_ast", None)
        if not callable(entry_scoped_ast):
            return None
        scoped_ast = entry_scoped_ast(crossgl_ast, entry_point)
        return {
            str(getattr(node, "name"))
            for node, _default_value, _has_default in (
                _specialization_ast_declaration_items(scoped_ast)
            )
            if _is_non_empty_string(getattr(node, "name", None))
        }
    except Exception:  # noqa: BLE001
        return None


def _specialization_reachability_diagnostic(
    unit: ProjectTranslationUnit,
    *,
    target: str,
    variant: str | None,
    entry_point: str,
) -> ProjectDiagnostic:
    return ProjectDiagnostic(
        severity="error",
        code="project.translate.specialization-reachability-unproven",
        message=(
            "Specialization-constant reachability could not be proven for "
            f"entry point '{entry_point}'; entry-scoped metadata was not emitted."
        ),
        location=SourceLocation(file=unit.relative_path),
        target=target,
        source_backend=unit.source_backend,
        variant=variant,
        missing_capabilities=["specialization.constant.reachability"],
        details={"entryPoint": entry_point},
    )


def _specialization_diagnostic_reaches_entry(
    diagnostic: ProjectDiagnostic, reachable_names: set[str]
) -> bool:
    name = diagnostic.details.get("name")
    if isinstance(name, str) and name not in reachable_names:
        return False
    previous_name = diagnostic.details.get("previousName")
    if isinstance(previous_name, str) and previous_name not in reachable_names:
        return False
    return True


def _project_specialization_metadata_for_input(
    config: ProjectConfig,
    unit: ProjectTranslationUnit,
    input_path: Path,
    *,
    target: str,
    variant: str | None,
    include_paths: Sequence[str],
    defines: Mapping[str, str],
    source_options: Mapping[str, Any],
    entry_point: str | None = None,
    configured_values: Mapping[str, tuple[Any, Mapping[str, Any]]] | None = None,
) -> tuple[list[dict[str, Any]], dict[str, Any] | None, list[ProjectDiagnostic]]:
    source = input_path.read_text(encoding="utf-8", errors="replace")
    if not re.search(r"\b(?:function_constant|constant_id)\b", source):
        return [], None, []
    source_spec = SOURCE_REGISTRY.get(unit.source_backend)
    if source_spec is None:
        return [], None, []
    ast = source_spec.parse(
        source,
        file_path=str(input_path),
        include_paths=include_paths,
        defines=defines,
        source_options=source_options,
    )
    try:
        diagnostic_source = unit.path.read_text(encoding="utf-8", errors="replace")
    except OSError:
        diagnostic_source = source
    declarations, declaration_diagnostics = _project_specialization_declarations(
        unit, ast, diagnostic_source
    )
    if entry_point is not None:
        reachable_names = _entry_scoped_specialization_names(
            unit, ast, entry_point, target
        )
        if reachable_names is None and declarations:
            declarations = []
            declaration_diagnostics.append(
                _specialization_reachability_diagnostic(
                    unit,
                    target=target,
                    variant=variant,
                    entry_point=entry_point,
                )
            )
        elif reachable_names is not None:
            declarations = [
                declaration
                for declaration in declarations
                if declaration.name in reachable_names
            ]
            declaration_diagnostics = [
                diagnostic
                for diagnostic in declaration_diagnostics
                if _specialization_diagnostic_reaches_entry(diagnostic, reachable_names)
            ]
    declaration_diagnostics = [
        replace(diagnostic, target=target, variant=variant)
        for diagnostic in declaration_diagnostics
    ]
    if not declarations:
        return [], None, declaration_diagnostics
    records, metadata, resolution_diagnostics = (
        _resolved_project_specialization_constants(
            config,
            unit,
            declarations,
            target=target,
            variant=variant,
            configured_values=configured_values,
        )
    )
    diagnostics = [*declaration_diagnostics, *resolution_diagnostics]
    if any(diagnostic.severity == "error" for diagnostic in diagnostics):
        metadata["status"] = "failed"
    return records, metadata, diagnostics


def _scope_artifact_specialization_metadata_for_entry(
    artifact: dict[str, Any],
    *,
    crossgl_ast: Any,
    entry_point: str,
    unit: ProjectTranslationUnit,
    target: str,
    variant: str | None,
) -> None:
    constants = artifact.get("specializationConstants")
    if not constants:
        artifact.pop("specializationConstants", None)
        artifact.pop("specializationMaterialization", None)
        return
    if not isinstance(constants, list) or any(
        not isinstance(constant, Mapping)
        or not _is_non_empty_string(constant.get("name"))
        for constant in constants
    ):
        reachable_names = None
    else:
        reachable_names = _entry_scoped_specialization_names_from_crossgl_ast(
            crossgl_ast,
            entry_point,
            target,
        )
    if reachable_names is None:
        diagnostic = _specialization_reachability_diagnostic(
            unit,
            target=target,
            variant=variant,
            entry_point=entry_point,
        )
        raise ProjectSpecializationError(
            diagnostic.message,
            diagnostics=(diagnostic,),
        )

    scoped_constants = [
        dict(constant)
        for constant in constants
        if constant.get("name") in reachable_names
    ]
    if not scoped_constants:
        artifact.pop("specializationConstants", None)
        artifact.pop("specializationMaterialization", None)
        return

    materialization = artifact.get("specializationMaterialization")
    if not isinstance(materialization, Mapping):
        diagnostic = _specialization_reachability_diagnostic(
            unit,
            target=target,
            variant=variant,
            entry_point=entry_point,
        )
        raise ProjectSpecializationError(
            diagnostic.message,
            diagnostics=(diagnostic,),
        )
    scoped_materialization = dict(materialization)
    scoped_materialization.update(
        {
            "constantCount": len(scoped_constants),
            "requiredCount": sum(
                bool(constant.get("required")) for constant in scoped_constants
            ),
            "overriddenCount": sum(
                bool(constant.get("overridden")) for constant in scoped_constants
            ),
            "concreteCount": sum(
                "concreteValue" in constant for constant in scoped_constants
            ),
        }
    )
    artifact["specializationConstants"] = scoped_constants
    artifact["specializationMaterialization"] = scoped_materialization


def _crossgl_parameter_has_semantic(parameter: Any, semantic: str) -> bool:
    parameter_semantic = getattr(parameter, "semantic", None)
    if _is_non_empty_string(parameter_semantic) and parameter_semantic == semantic:
        return True
    for attribute in getattr(parameter, "attributes", []) or []:
        name = getattr(attribute, "name", None)
        if _is_non_empty_string(name) and name == semantic:
            return True
    return False


def _crossgl_function_references_identifier(function: Any, name: str) -> bool:
    body = getattr(function, "body", None)
    if body is None or not callable(getattr(body, "walk", None)):
        return False
    return any(
        isinstance(node, IdentifierNode) and getattr(node, "name", None) == name
        for node in body.walk()
    )


def _crossgl_stage_name(stage: Any) -> str:
    value = getattr(stage, "value", stage)
    return str(value).strip().lower()


def _crossgl_compute_stages(ast: Any, entry_point: str | None) -> list[Any]:
    stages = getattr(ast, "stages", None)
    stage_items = stages.items() if hasattr(stages, "items") else []
    return [
        stage_node
        for stage_name, stage_node in stage_items
        if _crossgl_stage_name(stage_name) == "compute"
        and (
            entry_point is None
            or getattr(getattr(stage_node, "entry_point", None), "name", None)
            == entry_point
        )
    ]


def _literal_workgroup_size_component(value: Any) -> int | None:
    value = getattr(value, "value", value)
    if isinstance(value, int) and not isinstance(value, bool):
        return value if value > 0 else None
    if not isinstance(value, str) or not re.fullmatch(r"[1-9][0-9]*", value.strip()):
        return None
    parsed = int(value.strip())
    return parsed if parsed > 0 else None


def _crossgl_execution_workgroup_size(
    execution_config: Mapping[str, Any],
) -> tuple[tuple[int, int, int] | None, str | None, bool]:
    for field_name in ("numthreads", "workgroup_size", "local_size"):
        if field_name not in execution_config:
            continue
        raw = execution_config.get(field_name)
        if not isinstance(raw, Sequence) or isinstance(raw, (str, bytes, bytearray)):
            return None, field_name, True
        values = list(raw)
        if len(values) != 3:
            return None, field_name, True
        parsed = tuple(_literal_workgroup_size_component(value) for value in values)
        if any(value is None for value in parsed):
            return None, field_name, True
        return (int(parsed[0]), int(parsed[1]), int(parsed[2])), field_name, False

    fields = ("local_size_x", "local_size_y", "local_size_z")
    if not any(field_name in execution_config for field_name in fields):
        return None, None, False
    parsed = tuple(
        _literal_workgroup_size_component(execution_config.get(field_name, 1))
        for field_name in fields
    )
    if any(value is None for value in parsed):
        return None, "local_size", True
    return (int(parsed[0]), int(parsed[1]), int(parsed[2])), "local_size", False


def _set_crossgl_stage_workgroup_size(
    stage: Any,
    workgroup_size: Sequence[int],
) -> None:
    x, y, z = (str(value) for value in workgroup_size)
    execution_config = dict(getattr(stage, "execution_config", {}) or {})
    execution_config.update(
        {
            "local_size_x": x,
            "local_size_y": y,
            "local_size_z": z,
            "numthreads": (x, y, z),
        }
    )
    stage.execution_config = execution_config


def _crossgl_ast_for_project_target(
    *,
    input_path: Path,
    source_backend: str,
    original_source_backend: str,
    target: str,
    include_paths: Sequence[str],
    defines: Mapping[str, str],
    source_options: Mapping[str, Any],
    source_is_materialized: bool = False,
) -> Any:
    register_default_sources()
    source_spec = SOURCE_REGISTRY.get(source_backend)
    cgl_spec = SOURCE_REGISTRY.get("cgl")
    if source_spec is None or cgl_spec is None:
        raise ValueError("CrossGL source frontend is unavailable")

    if source_backend in {"cgl", "crossgl"}:
        intermediate = input_path.read_text(encoding="utf-8", errors="replace")
    else:
        source = input_path.read_text(encoding="utf-8", errors="replace")
        parser_defines = defines
        parser_options = source_options
        if source_backend == "metal" and not source_is_materialized:
            materialized = materialize_metal_source_for_target(
                source=source,
                file_path=input_path,
                target=target,
                include_paths=include_paths,
                defines=defines,
                source_options=source_options,
            )
            if materialized is not None:
                source = materialized.text
                parser_defines = materialized.defines
                parser_options = materialized.source_options
        source_ast = source_spec.parse(
            source,
            file_path=str(input_path),
            include_paths=include_paths,
            defines=parser_defines,
            source_options=parser_options,
        )
        lower_default_arguments(source_ast)
        if source_spec.reverse_codegen_factory is None:
            raise ValueError(
                f"Reverse translation not supported for source backend {source_backend}"
            )
        intermediate = source_spec.reverse_codegen_factory().generate(source_ast)

    return cgl_spec.parse(
        intermediate,
        source_options={
            "strict_function_bodies": original_source_backend != "mojo",
        },
    )


def _project_workgroup_execution_metadata(
    *,
    ast: Any,
    config: ProjectConfig,
    unit: ProjectTranslationUnit,
    target: str,
    variant: str | None,
    selected_entry_point: str | None,
    template_materialization: Mapping[str, Any] | None = None,
    configured_workgroup: tuple[tuple[int, int, int], Mapping[str, Any]] | None = None,
) -> dict[str, Any] | None:
    stages = _crossgl_compute_stages(ast, selected_entry_point)
    if not stages:
        return None

    configured_size, configured_provenance = (
        configured_workgroup
        if configured_workgroup is not None
        else _configured_workgroup_size(config, variant)
    )
    consumed_entries: list[str] = []
    source_sizes: dict[str, tuple[int, int, int]] = {}
    source_paths: dict[str, str] = {}
    source_location = None
    for stage in stages:
        function = getattr(stage, "entry_point", None)
        if function is None:
            continue
        entry_name = str(getattr(function, "name", "main"))
        if _crossgl_function_references_identifier(function, "gl_WorkGroupSize"):
            consumed_entries.append(entry_name)
        for parameter in (
            getattr(function, "parameters", getattr(function, "params", [])) or []
        ):
            if not _crossgl_parameter_has_semantic(parameter, "gl_WorkGroupSize"):
                continue
            if _crossgl_function_references_identifier(
                function, str(getattr(parameter, "name", ""))
            ):
                consumed_entries.append(entry_name)
                if source_location is None:
                    source_location = getattr(parameter, "source_location", None)

        execution_config = dict(getattr(stage, "execution_config", {}) or {})
        source_size, source_path, invalid = _crossgl_execution_workgroup_size(
            execution_config
        )
        if invalid:
            raise ProjectWorkgroupSizeError(
                f"Compute entry point '{entry_name}' has non-concrete workgroup-size "
                "metadata; configure a concrete project workgroup_size variant.",
                code="project.translate.workgroup-size-invalid",
                reason="source-metadata-not-concrete",
                source_entry_points=(entry_name,),
                workgroup_size=configured_size,
                source_location=source_location,
            )
        if source_size is not None and source_path is not None:
            source_sizes[entry_name] = source_size
            source_paths[entry_name] = source_path

    consumed_entries = sorted(set(consumed_entries))
    source_entry_points = sorted(
        {
            str(getattr(getattr(stage, "entry_point", None), "name", "main"))
            for stage in stages
        }
    )
    rule_execution = (
        None
        if configured_workgroup is not None
        else _project_workgroup_rule_execution_metadata(
            ast=ast,
            stages=stages,
            config=config,
            unit=unit,
            target=target,
            variant=variant,
            materialization=template_materialization,
            source_sizes=source_sizes,
            entry_scoped=selected_entry_point is not None,
        )
    )
    if rule_execution is not None:
        return rule_execution

    distinct_source_sizes = set(source_sizes.values())
    if len(distinct_source_sizes) > 1:
        raise ProjectWorkgroupSizeError(
            "Compute entry points in one artifact declare conflicting workgroup "
            "sizes; select one entry point or emit separate named variants.",
            code="project.translate.workgroup-size-conflict",
            reason="source-entry-point-conflict",
            source_entry_points=source_entry_points,
            workgroup_size=configured_size,
            source_location=source_location,
        )

    if (
        configured_size is not None
        and configured_provenance is not None
        and selected_entry_point is None
        and len(source_entry_points) > 1
    ):
        materialized_execution = _project_materialized_workgroup_execution_metadata(
            ast=ast,
            stages=stages,
            unit=unit,
            target=target,
            variant=variant,
            materialization=template_materialization,
            workgroup_size=configured_size,
            provenance=configured_provenance,
            source_sizes=source_sizes,
            entry_scoped=selected_entry_point is not None,
        )
        if materialized_execution is not None:
            return materialized_execution

    source_size = next(iter(distinct_source_sizes), None)
    source_proves_shared_size = bool(source_entry_points) and (
        set(source_sizes) == set(source_entry_points)
        and len(distinct_source_sizes) == 1
    )
    aggregate_size_is_unproven = (
        selected_entry_point is None
        and len(source_entry_points) > 1
        and not source_proves_shared_size
        and (configured_size is not None or len(consumed_entries) > 1)
    )
    if aggregate_size_is_unproven:
        raise ProjectWorkgroupSizeError(
            "A multi-entry compute artifact cannot apply one workgroup size when "
            "the emitted entry points do not declare a shared source size. Select "
            "one entry point or emit independently specialized artifacts.",
            code="project.translate.workgroup-size-entry-ambiguous",
            reason="aggregate-entry-size-unproven",
            source_entry_points=source_entry_points,
            workgroup_size=configured_size,
            source_location=source_location,
        )
    if configured_size is not None and source_size is not None:
        if tuple(configured_size) != tuple(source_size):
            raise ProjectWorkgroupSizeError(
                "Configured workgroup size conflicts with concrete source execution "
                "metadata.",
                code="project.translate.workgroup-size-conflict",
                reason="project-source-conflict",
                source_entry_points=source_entry_points,
                workgroup_size=configured_size,
                source_workgroup_size=source_size,
                source_location=source_location,
            )

    effective_size = configured_size or source_size
    if effective_size is None and consumed_entries:
        raise ProjectWorkgroupSizeError(
            "A consumed threads_per_threadgroup value requires a concrete project "
            "workgroup_size or source execution size for this target.",
            code="project.translate.workgroup-size-required",
            reason="consumed-source-value-unconfigured",
            source_entry_points=consumed_entries,
            source_location=source_location,
        )
    if effective_size is None:
        return None

    for stage in stages:
        _set_crossgl_stage_workgroup_size(stage, effective_size)

    if configured_provenance is not None:
        provenance = configured_provenance
    else:
        entry_name = source_entry_points[0]
        provenance = {
            "kind": "source",
            "path": (
                f"source.entryPoints.{entry_name}.executionConfig."
                f"{source_paths.get(entry_name, 'numthreads')}"
            ),
        }
    return {
        "workgroupSize": list(effective_size),
        "sourceEntryPoints": source_entry_points,
        "provenance": provenance,
        "identity": _workgroup_execution_identity(
            source=unit.relative_path,
            target=target,
            variant=variant,
            source_entry_points=source_entry_points,
            workgroup_size=effective_size,
        ),
    }


def _generate_project_target_from_crossgl_ast(
    *,
    ast: Any,
    target: str,
    output_path: Path,
    entry_point: str | None,
    format_output: bool,
    index_range_assertions: Sequence[IndexRangeAssertion] = (),
) -> str:
    codegen = get_codegen(target)
    if index_range_assertions:
        configure_index_ranges = getattr(codegen, "set_index_range_assertions", None)
        if not callable(configure_index_ranges):
            raise ValueError(
                f"Target '{target}' does not consume index range assertions"
            )
        configure_index_ranges(index_range_assertions)
    lower_default_arguments(ast)
    validate_pointer_reinterpretation_target(ast, target)
    if entry_point is None:
        generated = codegen.generate(ast)
    else:
        generate_entry = getattr(codegen, "generate_entry", None)
        if not callable(generate_entry):
            raise ValueError(
                "Entry-scoped artifact generation is not supported for the "
                "requested target backend"
            )
        generated = generate_entry(ast, entry_point)
    if format_output:
        try:
            from crosstl.formatter import format_shader_code
        except ImportError:
            pass
        else:
            generated = format_shader_code(generated, target, str(output_path))
    with output_path.open("w", encoding="utf-8", newline="") as output_file:
        output_file.write(generated)
    return generated


def _project_target_workgroup_entries(
    output_path: Path,
    target: str,
) -> list[tuple[str, tuple[Any, ...]]]:
    if target == "directx":
        source = output_path.read_text(encoding="utf-8", errors="replace")
        entries = []
        for match in DIRECTX_HLSL_FUNCTION_RE.finditer(source):
            dimensions = DIRECTX_HLSL_NUMTHREADS_VALUES_RE.search(
                match.group("attributes") or ""
            )
            if dimensions is None:
                continue
            try:
                size = tuple(
                    parse_c_family_integral_literal(dimensions.group(axis))
                    for axis in ("x", "y", "z")
                )
            except CFamilyIntegralLiteralError:
                continue
            entries.append((match.group("name"), size))
        return entries

    reflected = reflect_target_host_interface(output_path, target=target)
    entries = []
    for entry_point in _record_sequence(reflected.get("entryPoints")):
        if (
            not isinstance(entry_point, Mapping)
            or entry_point.get("stage") != "compute"
            or not _is_non_empty_string(entry_point.get("name"))
        ):
            continue
        execution_config = entry_point.get("executionConfig")
        if not isinstance(execution_config, Mapping):
            continue
        workgroup_size, _source = _runtime_manifest_execution_workgroup_size(
            execution_config
        )
        if workgroup_size is not None:
            entries.append((str(entry_point["name"]), tuple(workgroup_size)))
    return entries


def _validate_project_workgroup_target_output(
    output_path: Path,
    *,
    target: str,
    execution: Mapping[str, Any],
) -> None:
    execution_entries = [
        entry
        for entry in _record_sequence(execution.get("entryPoints"))
        if isinstance(entry, Mapping) and "workgroupSize" in entry
    ]
    if execution_entries:
        expected_by_target = {
            str(entry.get("targetEntryPoint")): tuple(entry.get("workgroupSize", ()))
            for entry in execution_entries
            if _is_non_empty_string(entry.get("targetEntryPoint"))
        }
        reflected_entries = _project_target_workgroup_entries(output_path, target)
        reflected_by_target = dict(reflected_entries)
        reflected_names = [name for name, _size in reflected_entries]
        if len(reflected_names) != len(set(reflected_names)) or set(
            reflected_by_target
        ) != set(expected_by_target):
            raise ProjectWorkgroupSizeError(
                "Generated target entries do not match the per-entry execution "
                "specialization contract.",
                code="project.translate.workgroup-size-materialization-invalid",
                reason="target-entry-identity-mismatch",
                source_entry_points=execution.get("sourceEntryPoints", ()),
                materialization_details={
                    "expectedTargetEntryPoints": sorted(expected_by_target),
                    "reflectedTargetEntryPoints": sorted(reflected_by_target),
                },
            )
        mismatches = [
            (name, expected_by_target[name], reflected_by_target[name])
            for name in sorted(expected_by_target)
            if expected_by_target[name] != reflected_by_target[name]
        ]
        if mismatches:
            name, expected_size, reflected_size = mismatches[0]
            raise ProjectWorkgroupSizeError(
                f"Generated target entry '{name}' has a workgroup size that does "
                "not match its execution specialization.",
                code="project.translate.workgroup-size-conflict",
                reason="target-output-mismatch",
                source_entry_points=execution.get("sourceEntryPoints", ()),
                workgroup_size=expected_size,
                source_workgroup_size=reflected_size,
                materialization_details={"targetEntryPoint": name},
            )
        return

    if "workgroupSize" not in execution:
        return
    expected = tuple(execution.get("workgroupSize", ()))
    reflected = reflect_target_host_interface(output_path, target=target)
    reflected_sizes = []
    for entry_point in _record_sequence(reflected.get("entryPoints")):
        if (
            not isinstance(entry_point, Mapping)
            or entry_point.get("stage") != "compute"
        ):
            continue
        execution_config = entry_point.get("executionConfig")
        if not isinstance(execution_config, Mapping):
            continue
        workgroup_size, _source = _runtime_manifest_execution_workgroup_size(
            execution_config
        )
        if workgroup_size is not None:
            reflected_sizes.append(tuple(workgroup_size))
    if not reflected_sizes:
        raise ProjectWorkgroupSizeError(
            "Generated target artifact does not expose reflected workgroup-size "
            "metadata.",
            code="project.translate.workgroup-size-invalid",
            reason="target-metadata-unavailable",
            source_entry_points=execution.get("sourceEntryPoints", ()),
            workgroup_size=expected,
        )
    mismatches = [size for size in reflected_sizes if size != expected]
    if mismatches:
        raise ProjectWorkgroupSizeError(
            "Generated target workgroup size does not match the project execution "
            "specialization.",
            code="project.translate.workgroup-size-conflict",
            reason="target-output-mismatch",
            source_entry_points=execution.get("sourceEntryPoints", ()),
            workgroup_size=expected,
            source_workgroup_size=mismatches[0],
        )


def _validate_project_subgroup_width_target_output(
    output_path: Path,
    *,
    execution: Mapping[str, Any],
) -> None:
    entries = [
        entry
        for entry in _record_sequence(execution.get("entryPoints"))
        if isinstance(entry, Mapping) and "subgroupWidth" in entry
    ]
    if not entries:
        return
    expected = {
        str(entry["targetEntryPoint"]): int(entry["subgroupWidth"]) for entry in entries
    }
    enforcement = execution.get("subgroupWidthEnforcement")
    profiles = (
        enforcement.get("entryProfiles") if isinstance(enforcement, Mapping) else None
    )
    profile_map = {
        str(item.get("entryPoint")): str(item.get("profile"))
        for item in _record_sequence(profiles)
        if isinstance(item, Mapping)
        and _is_non_empty_string(item.get("entryPoint"))
        and _is_non_empty_string(item.get("profile"))
    }
    if (
        not isinstance(enforcement, Mapping)
        or enforcement.get("mechanism") != "hlsl-wave-size-attribute"
        or enforcement.get("minimumShaderModel") != "6.6"
        or set(profile_map) != set(expected)
        or any(profile != "cs_6_6" for profile in profile_map.values())
    ):
        raise ProjectSubgroupWidthError(
            "DirectX subgroup-width enforcement requires WaveSize and cs_6_6.",
            code="project.translate.subgroup-width-invalid",
            reason="target-profile-contract-invalid",
            source_entry_points=execution.get("sourceEntryPoints", ()),
        )

    source = output_path.read_text(encoding="utf-8", errors="replace")
    reflected = {}
    for match in DIRECTX_HLSL_FUNCTION_RE.finditer(source):
        attributes = match.group("attributes") or ""
        if not DIRECTX_HLSL_NUMTHREADS_RE.search(attributes):
            continue
        matches = list(DIRECTX_HLSL_EXACT_WAVE_SIZE_RE.finditer(attributes))
        width = None
        if len(matches) == 1:
            try:
                width = parse_c_family_integral_literal(matches[0].group("width"))
            except CFamilyIntegralLiteralError:
                width = None
        reflected[match.group("name")] = width
    if set(reflected) != set(expected):
        raise ProjectSubgroupWidthError(
            "Generated DirectX entries do not match the subgroup-width contract.",
            code="project.translate.subgroup-width-invalid",
            reason="target-entry-identity-mismatch",
            source_entry_points=execution.get("sourceEntryPoints", ()),
        )
    mismatch = next(
        (
            (name, expected[name], reflected[name])
            for name in sorted(expected)
            if reflected[name] != expected[name]
        ),
        None,
    )
    if mismatch is not None:
        name, expected_width, reflected_width = mismatch
        raise ProjectSubgroupWidthError(
            f"Generated DirectX entry '{name}' does not enforce "
            f"WaveSize({expected_width}).",
            code="project.translate.subgroup-width-conflict",
            reason="target-output-mismatch",
            source_entry_points=execution.get("sourceEntryPoints", ()),
            subgroup_width=expected_width,
            source_subgroup_width=reflected_width,
        )
    generated_profiles = dict(_directx_dxc_entry_profiles_from_source(source) or ())
    if set(generated_profiles) != set(expected) or any(
        not profile.startswith("cs_") or _directx_dxc_profile_version(profile) < (6, 6)
        for profile in generated_profiles.values()
    ):
        raise ProjectSubgroupWidthError(
            "Generated DirectX entries do not require Shader Model 6.6 or newer.",
            code="project.translate.subgroup-width-invalid",
            reason="target-profile-too-low",
            source_entry_points=execution.get("sourceEntryPoints", ()),
        )


def _opengl_workgroup_split_specs(
    execution: Mapping[str, Any],
    *,
    unit: ProjectTranslationUnit,
    variant: str | None,
) -> list[tuple[str, str, dict[str, Any]]]:
    execution_entries = [
        dict(entry)
        for entry in _record_sequence(execution.get("entryPoints"))
        if isinstance(entry, Mapping)
    ]
    if execution_entries:
        specs = []
        for entry in execution_entries:
            source_entry = str(entry["sourceEntryPoint"])
            materialized_entry = str(entry["materializedEntryPoint"])
            split_entry = dict(entry)
            split_entry["targetEntryPoint"] = "main"
            split_entry["identity"] = _workgroup_rule_entry_identity(
                source=unit.relative_path,
                source_hash=unit.source_hash,
                target="opengl",
                variant=variant,
                entry=split_entry,
            )
            split_execution = {
                "sourceEntryPoints": [source_entry],
                "entryPoints": [split_entry],
                "provenance": dict(execution["provenance"]),
            }
            split_execution["identity"] = _workgroup_rule_execution_identity(
                source=unit.relative_path,
                source_hash=unit.source_hash,
                target="opengl",
                variant=variant,
                source_entry_points=[source_entry],
                entry_points=[split_entry],
                provenance=split_execution["provenance"],
            )
            specs.append((source_entry, materialized_entry, split_execution))
        return specs

    source_entries = [str(entry) for entry in execution.get("sourceEntryPoints", ())]
    if len(source_entries) <= 1:
        return []
    workgroup_size = list(execution["workgroupSize"])
    specs = []
    for source_entry in source_entries:
        provenance = dict(execution["provenance"])
        provenance_path = provenance.get("path")
        if provenance.get("kind") == "source" and isinstance(provenance_path, str):
            provenance["path"] = re.sub(
                r"^source\.entryPoints\.[^.]+\.",
                f"source.entryPoints.{source_entry}.",
                provenance_path,
            )
        split_execution = {
            "workgroupSize": workgroup_size,
            "sourceEntryPoints": [source_entry],
            "provenance": provenance,
            "identity": _workgroup_execution_identity(
                source=unit.relative_path,
                target="opengl",
                variant=variant,
                source_entry_points=[source_entry],
                workgroup_size=workgroup_size,
            ),
        }
        specs.append((source_entry, source_entry, split_execution))
    return specs


def _template_materialization_for_entry(
    materialization: Mapping[str, Any],
    *,
    source_entry_point: str,
    materialized_entry_point: str,
) -> dict[str, Any]:
    payload = dict(materialization)
    specializations = [
        dict(record)
        for record in _record_sequence(materialization.get("specializations"))
        if isinstance(record, Mapping)
    ]
    selected = [
        record
        for record in specializations
        if record.get("hostName") == source_entry_point
        and record.get("materializedName") == materialized_entry_point
    ]
    if len(selected) != 1:
        raise ValueError(
            "Entry-scoped artifact must select exactly one host-named template "
            "materialization"
        )
    payload["specializations"] = specializations
    payload["specializationCount"] = len(specializations)
    return payload


def _finalize_project_generated_artifact(
    *,
    config: ProjectConfig,
    unit: ProjectTranslationUnit,
    target: str,
    artifact: dict[str, Any],
    output_path: Path,
    generated_source: str,
    source_entry_point: str | None = None,
) -> tuple[list[dict[str, Any]], list[ProjectDiagnostic]]:
    mojo_diagnostics = _mojo_unresolved_target_construct_diagnostics(
        artifact, generated_source
    )
    metal_diagnostics: list[ProjectDiagnostic] = []
    if unit.source_backend == "metal":
        metal_diagnostics = _metal_unresolved_target_construct_diagnostics(
            artifact, generated_source
        )
    diagnostics = [*mojo_diagnostics, *metal_diagnostics]
    if diagnostics:
        artifact["status"] = "failed"
        artifact["error"] = diagnostics[0].message
        _remove_artifact_output_files(output_path)
        return [artifact], diagnostics

    if source_entry_point is not None:
        reflected = reflect_target_host_interface(output_path, target=target)
        reflected_entries = reflected.get("entryPoints", [])
        if len(reflected_entries) != 1:
            raise ValueError(
                "Entry-scoped target artifact must expose exactly one reflected "
                "entry point"
            )
        reflected_entry = reflected_entries[0]
        artifact["entryPoint"] = {
            "source": source_entry_point,
            "target": reflected_entry.get("name"),
            "stage": reflected_entry.get("stage"),
        }
    if target == "directx":
        uses_native_16bit_storage = hlsl_requires_native_16bit_types(generated_source)
        if "// CrossGL exact bfloat16 lowering:" in generated_source:
            artifact["bfloat16Lowering"] = {
                "status": "exact",
                "approximationUsed": False,
                "registerRepresentation": "uint-low-16-bits",
                "storageRepresentation": (
                    "native-uint16" if uses_native_16bit_storage else "not-required"
                ),
                "roundingMode": "round-to-nearest-ties-to-even",
            }
        if uses_native_16bit_storage:
            required_capabilities = set(artifact.get("requiredCapabilities", ()))
            required_capabilities.add("directx.native-16bit-types")
            artifact["requiredCapabilities"] = sorted(required_capabilities)
    artifact["generatedHash"] = _source_hash(output_path)
    artifact["generatedSizeBytes"] = output_path.stat().st_size
    artifact["sourceMap"] = _artifact_source_map(config, unit, target, output_path)
    split_artifacts = _webgl_split_stage_artifacts(config, unit, artifact, output_path)
    if split_artifacts is not None:
        records = split_artifacts
    else:
        _attach_artifact_source_remap(config, target, artifact, output_path)
        records = [artifact]
    diagnostics.extend(_generated_placeholder_diagnostics(records, config))
    return records, diagnostics


def translate_project(
    config_or_root: ProjectConfig | str | os.PathLike[str],
    *,
    targets: Sequence[str] | str | None = None,
    output_dir: str | os.PathLike[str] | None = None,
    variants: Sequence[str] | str | None = None,
    format_output: bool = False,
    validate: bool = False,
    run_toolchains: bool = False,
) -> ProjectPortabilityReport:
    """Translate all discovered project units to one or more target backends."""
    format_output = _bool_arg(format_output, field_name="format_output")
    validate = _bool_arg(validate, field_name="validate")
    run_toolchains = _bool_arg(run_toolchains, field_name="run_toolchains")
    config = (
        config_or_root
        if isinstance(config_or_root, ProjectConfig)
        else load_project_config(config_or_root)
    )
    if output_dir is not None:
        output_dir = _path_string_arg(output_dir, field_name="output_dir")
        if not output_dir.strip():
            raise ValueError("output_dir must be a non-empty string")
        config = ProjectConfig(
            root=config.root,
            config_path=config.config_path,
            source_roots=config.source_roots,
            include_patterns=config.include_patterns,
            exclude_patterns=config.exclude_patterns,
            targets=config.targets,
            output_dir=output_dir,
            source_overrides=config.source_overrides,
            entry_points=config.entry_points,
            include_dirs=config.include_dirs,
            defines=config.defines,
            source_options=config.source_options,
            variants=config.variants,
            specialization_constants=config.specialization_constants,
            source_specialization_constants=(config.source_specialization_constants),
            variant_specialization_constants=(config.variant_specialization_constants),
            workgroup_size=config.workgroup_size,
            variant_workgroup_sizes=config.variant_workgroup_sizes,
            workgroup_size_rules=config.workgroup_size_rules,
            subgroup_width_rules=config.subgroup_width_rules,
            selected_variants=config.selected_variants,
            dispatch_contracts=config.dispatch_contracts,
            external_corpus_manifest=config.external_corpus_manifest,
            index_range_assertions=config.index_range_assertions,
        )
    config = _config_with_selected_variants(config, variants)

    selected_targets = _normalized_targets(
        targets if targets is not None else config.targets
    )
    if not selected_targets:
        selected_targets = ["cgl"]

    scan = scan_project(config)
    config = scan.config
    diagnostics: list[ProjectDiagnostic] = list(scan.diagnostics)
    diagnostics.extend(_target_diagnostics(config, selected_targets))
    artifacts: list[dict[str, Any]] = []
    include_paths = _frontend_include_dirs(config)
    output_dir_blocked = _has_error_diagnostic(
        diagnostics, OUTPUT_DIR_OUTSIDE_PROJECT_CODE
    )

    variant_jobs = _variant_jobs(config)
    dispatch_artifacts = _dispatch_artifacts_by_source(scan.dispatch_artifact_plan)
    translation_variants = _project_translation_variants_by_source_target(
        config,
        scan.units,
        selected_targets,
        dispatch_artifacts,
    )
    max_define_count = max(
        (len(defines) for _variant, defines in variant_jobs), default=0
    )
    define_forwarding_diagnostics: set[str] = set()
    include_path_forwarding_diagnostics: set[str] = set()
    preserve_source_suffix = _artifact_source_suffix_pairs(scan.units, selected_targets)

    for unit in scan.units:
        required_capabilities = _required_capabilities_for_unit(unit)
        source_supports_defines = _source_frontend_supports_lexer_keyword(
            unit.source_backend, "defines"
        )
        source_supports_include_paths = _source_frontend_supports_lexer_keyword(
            unit.source_backend, "include_paths"
        )
        if (
            max_define_count > 0
            and not source_supports_defines
            and unit.source_backend not in define_forwarding_diagnostics
        ):
            diagnostics.append(
                _frontend_define_forwarding_diagnostic(unit, max_define_count)
            )
            define_forwarding_diagnostics.add(unit.source_backend)
        if (
            include_paths
            and not source_supports_include_paths
            and unit.source_backend not in include_path_forwarding_diagnostics
        ):
            diagnostics.append(
                _frontend_include_path_forwarding_diagnostic(
                    unit,
                    len(include_paths),
                )
            )
            include_path_forwarding_diagnostics.add(unit.source_backend)
        for target in selected_targets:
            translation_jobs = _project_translation_jobs_for_target(
                config,
                unit,
                target,
                dispatch_artifacts,
            )
            for translation_job in translation_jobs:
                variant = translation_job.variant
                defines = translation_job.defines
                selected_entry_point = translation_job.entry_point
                artifact_include_dependencies = _include_dependencies_for_artifact(
                    unit.include_dependencies,
                    variant,
                )
                output_path = _artifact_path(
                    config,
                    unit,
                    target,
                    variant,
                    preserve_source_suffix=(unit.relative_path, target)
                    in preserve_source_suffix,
                    entry_point=selected_entry_point,
                )
                artifact = {
                    "source": unit.relative_path,
                    "sourceBackend": unit.source_backend,
                    "target": target,
                    "path": _artifact_report_path(output_path, config),
                    "status": "translated",
                    "defines": dict(sorted(defines.items())),
                    "defineProcessing": _artifact_define_processing(
                        unit.source_backend,
                        defines,
                        supports_defines=source_supports_defines,
                    ),
                    "includePathProcessing": _artifact_include_path_processing(
                        unit.source_backend,
                        include_paths,
                        supports_include_paths=source_supports_include_paths,
                    ),
                    "includeDependencyProcessing": (
                        _artifact_include_dependency_processing(
                            unit.source_backend,
                            artifact_include_dependencies,
                            supports_include_paths=source_supports_include_paths,
                        )
                    ),
                    "sourceHash": dict(unit.source_hash),
                    "sourceSizeBytes": unit.source_size_bytes,
                    "provenance": {
                        "pipeline": (
                            "entry-scoped-translate"
                            if selected_entry_point is not None
                            else "single-file-translate"
                        ),
                        "intermediate": (
                            "crossgl"
                            if unit.source_backend not in {"cgl", "crossgl"}
                            and target not in {"cgl", "crossgl"}
                            else None
                        ),
                    },
                    "requiredCapabilities": list(required_capabilities),
                }
                if selected_entry_point is not None:
                    artifact["entryPoint"] = {
                        "source": selected_entry_point,
                        "target": (
                            "main" if target == "opengl" else selected_entry_point
                        ),
                    }
                if variant is not None:
                    artifact["variant"] = variant
                if translation_job.dispatch_artifact is not None:
                    artifact["dispatchArtifact"] = (
                        translation_job.dispatch_artifact.to_json()
                    )
                if output_dir_blocked:
                    artifact["status"] = "failed"
                    artifact["error"] = (
                        "Configured output directory resolves outside the repository; "
                        "artifact was not written."
                    )
                    artifacts.append(artifact)
                    continue
                source_options = _source_options_for_unit(
                    config,
                    unit.source_backend,
                    unit.relative_path,
                    target=target,
                )
                index_range_assertions = (
                    _index_range_assertions_for_unit(config, unit.relative_path)
                    if target in {"opengl", "webgl"}
                    else ()
                )
                try:
                    unsupported_rule_target = (
                        _unsupported_workgroup_size_rule_target_error(
                            config,
                            unit,
                            target,
                        )
                    )
                    if unsupported_rule_target is not None:
                        raise unsupported_rule_target
                    unsupported_subgroup_target = (
                        _unsupported_subgroup_width_rule_target_error(
                            config,
                            unit,
                            target,
                        )
                    )
                    if unsupported_subgroup_target is not None:
                        raise unsupported_subgroup_target
                    template_materialization = (
                        _project_template_materialization_for_artifact(
                            unit=unit,
                            target=target,
                            variant=variant,
                            defines=defines,
                            define_sources=_variant_define_sources(config, variant),
                            include_paths=include_paths,
                            source_options=source_options,
                            target_artifact=artifact.get("path"),
                            entry_point=selected_entry_point,
                        )
                    )
                except Exception as exc:  # noqa: BLE001
                    failure_message = _translation_failure_message(
                        exc,
                        target,
                        unit,
                        artifact.get("path"),
                    )
                    artifact["status"] = "failed"
                    artifact["error"] = failure_message
                    _remove_artifact_output_files(output_path)
                    diagnostics.extend(
                        _translation_failure_project_diagnostics(
                            exc,
                            target,
                            unit,
                            variant,
                            failure_message,
                            artifact.get("path"),
                        )
                    )
                    artifacts.append(artifact)
                    continue
                if template_materialization is not None:
                    if template_materialization.metadata:
                        artifact["templateMaterialization"] = dict(
                            template_materialization.metadata
                        )
                    diagnostics.extend(template_materialization.diagnostics)
                    if template_materialization.blocked:
                        artifact["status"] = "failed"
                        artifact["error"] = template_materialization.error or (
                            "Template materialization failed."
                        )
                        _remove_artifact_output_files(output_path)
                        artifacts.append(artifact)
                        continue
                artifact_records = [artifact]
                template_temp_dir: tempfile.TemporaryDirectory[str] | None = None
                split_output_paths: list[Path] = []
                generated_records_finalized = False
                try:
                    output_path.parent.mkdir(parents=True, exist_ok=True)
                    translation_input_path = unit.path
                    translation_source_backend = unit.source_backend
                    translation_defines: Mapping[str, str] = defines
                    translation_include_paths: Sequence[str] = include_paths
                    translation_source_options: Mapping[str, Any] = source_options
                    if template_materialization is not None:
                        template_temp_dir = tempfile.TemporaryDirectory(
                            prefix="crosstl-template-"
                        )
                        materialized_path = (
                            Path(template_temp_dir.name) / Path(unit.relative_path).name
                        )
                        with materialized_path.open(
                            "w", encoding="utf-8", newline=""
                        ) as file:
                            file.write(template_materialization.text)
                        translation_input_path = materialized_path
                        translation_defines = template_materialization.defines
                        translation_source_options = (
                            template_materialization.source_options
                        )
                    (
                        specialization_constants,
                        specialization_materialization,
                        specialization_diagnostics,
                    ) = _project_specialization_metadata_for_input(
                        config,
                        unit,
                        translation_input_path,
                        target=target,
                        variant=variant,
                        include_paths=include_paths,
                        defines=translation_defines,
                        source_options=translation_source_options,
                        entry_point=selected_entry_point,
                        configured_values=translation_job.specialization_values,
                    )
                    if specialization_constants:
                        artifact["specializationConstants"] = specialization_constants
                    if specialization_materialization is not None:
                        artifact["specializationMaterialization"] = (
                            specialization_materialization
                        )
                    if any(
                        diagnostic.severity == "error"
                        for diagnostic in specialization_diagnostics
                    ):
                        raise ProjectSpecializationError(
                            specialization_diagnostics[0].message,
                            diagnostics=specialization_diagnostics,
                        )
                    diagnostics.extend(specialization_diagnostics)
                    if specialization_constants:
                        specialization_source = translation_input_path.read_text(
                            encoding="utf-8", errors="replace"
                        )
                        canonical_specialization_source = (
                            _canonicalize_project_specialization_ids(
                                specialization_source, specialization_constants
                            )
                        )
                        if canonical_specialization_source != specialization_source:
                            source_parent = str(translation_input_path.parent)
                            if template_temp_dir is None:
                                template_temp_dir = tempfile.TemporaryDirectory(
                                    prefix="crosstl-specialization-"
                                )
                            canonical_path = (
                                Path(template_temp_dir.name)
                                / f"{translation_input_path.stem}.canonical"
                                f"{translation_input_path.suffix}"
                            )
                            canonical_path.write_text(
                                canonical_specialization_source, encoding="utf-8"
                            )
                            translation_input_path = canonical_path
                            translation_include_paths = tuple(
                                dict.fromkeys(
                                    (
                                        source_parent,
                                        str(unit.path.parent),
                                        *include_paths,
                                    )
                                )
                            )
                    if (
                        specialization_constants
                        and specialization_materialization is not None
                        and specialization_materialization.get("mode")
                        == "concrete-crossgl-variant"
                    ):
                        crossgl_kwargs: dict[str, Any] = {
                            "backend": "cgl",
                            "format_output": False,
                            "source_backend": unit.source_backend,
                            "include_paths": translation_include_paths,
                            "defines": translation_defines,
                        }
                        if translation_source_options:
                            crossgl_kwargs["source_options"] = (
                                translation_source_options
                            )
                        crossgl_source = translate(
                            str(translation_input_path), **crossgl_kwargs
                        )
                        materialized_crossgl = (
                            _materialize_crossgl_specialization_constants(
                                crossgl_source,
                                specialization_constants,
                                unit=unit,
                                target=target,
                                variant=variant,
                            )
                        )
                        if template_temp_dir is None:
                            template_temp_dir = tempfile.TemporaryDirectory(
                                prefix="crosstl-specialization-"
                            )
                        specialized_path = (
                            Path(template_temp_dir.name)
                            / f"{Path(unit.relative_path).stem}.specialized.cgl"
                        )
                        specialized_path.write_text(
                            materialized_crossgl, encoding="utf-8"
                        )
                        translation_input_path = specialized_path
                        translation_source_backend = "cgl"
                        translation_defines = (
                            defines if unit.source_backend in {"cgl", "crossgl"} else {}
                        )
                        translation_source_options = {
                            "strict_function_bodies": unit.source_backend != "mojo"
                        }
                    translate_kwargs: dict[str, Any] = {
                        "backend": target,
                        "save_shader": str(output_path),
                        "format_output": format_output,
                        "source_backend": translation_source_backend,
                        "include_paths": translation_include_paths,
                        "defines": translation_defines,
                    }
                    if selected_entry_point is not None:
                        translate_kwargs["entry_point"] = selected_entry_point
                    if translation_source_options:
                        translate_kwargs["source_options"] = translation_source_options
                    generated_source = None
                    crossgl_ast = None
                    requires_workgroup_specialization = (
                        target in WORKGROUP_SIZE_SPECIALIZATION_TARGETS
                        and (
                            unit.source_backend == "metal"
                            or translation_source_backend in {"cgl", "crossgl"}
                        )
                        and _project_input_requires_workgroup_specialization(
                            input_path=translation_input_path,
                            source_backend=translation_source_backend,
                            config=config,
                            variant=variant,
                            project_relative_path=unit.relative_path,
                            configured_workgroup=(translation_job.configured_workgroup),
                        )
                    )
                    configured_subgroup = translation_job.configured_subgroup
                    requires_subgroup_specialization = (
                        configured_subgroup is not None
                        or (
                            target == "directx"
                            and _configured_subgroup_width_rule(
                                config, unit.relative_path
                            )
                            is not None
                        )
                    )
                    if (
                        requires_workgroup_specialization
                        or requires_subgroup_specialization
                    ):
                        crossgl_ast = _crossgl_ast_for_project_target(
                            input_path=translation_input_path,
                            source_backend=translation_source_backend,
                            original_source_backend=unit.source_backend,
                            target=target,
                            include_paths=translation_include_paths,
                            defines=translation_defines,
                            source_options=translation_source_options,
                            source_is_materialized=(
                                template_materialization is not None
                            ),
                        )
                        workgroup_execution = _project_workgroup_execution_metadata(
                            ast=crossgl_ast,
                            config=config,
                            unit=unit,
                            target=target,
                            variant=variant,
                            selected_entry_point=selected_entry_point,
                            template_materialization=(
                                template_materialization.metadata
                                if template_materialization is not None
                                else None
                            ),
                            configured_workgroup=(translation_job.configured_workgroup),
                        )
                        if configured_subgroup is not None:
                            if translation_job.configured_workgroup is None:
                                raise DispatchArtifactPlanError(
                                    "dispatch-subgroup-workgroup-missing",
                                    "A dispatch subgroup contract requires a planned "
                                    "workgroup size.",
                                    details={"source": unit.relative_path},
                                )
                            subgroup_execution = (
                                _dispatch_subgroup_width_execution_metadata(
                                    ast=crossgl_ast,
                                    unit=unit,
                                    target=target,
                                    variant=variant,
                                    selected_entry_point=selected_entry_point,
                                    configured_workgroup=(
                                        translation_job.configured_workgroup[0]
                                    ),
                                    configured_subgroup=configured_subgroup,
                                )
                            )
                        elif requires_subgroup_specialization:
                            subgroup_execution = (
                                _project_subgroup_width_rule_execution_metadata(
                                    ast=crossgl_ast,
                                    stages=_crossgl_compute_stages(
                                        crossgl_ast, selected_entry_point
                                    ),
                                    config=config,
                                    unit=unit,
                                    target=target,
                                    variant=variant,
                                    materialization=(
                                        template_materialization.metadata
                                        if template_materialization is not None
                                        else None
                                    ),
                                    entry_scoped=selected_entry_point is not None,
                                )
                            )
                        else:
                            subgroup_execution = None
                        execution = workgroup_execution
                        if subgroup_execution is not None:
                            execution = (
                                subgroup_execution
                                if configured_subgroup is not None
                                else _merge_subgroup_rule_execution(
                                    workgroup=workgroup_execution,
                                    subgroup=subgroup_execution,
                                    unit=unit,
                                    target=target,
                                    variant=variant,
                                )
                            )
                        if execution is not None:
                            split_specs = (
                                _opengl_workgroup_split_specs(
                                    execution,
                                    unit=unit,
                                    variant=variant,
                                )
                                if target == "opengl" and selected_entry_point is None
                                else []
                            )
                            if split_specs:
                                artifact_records = []
                                generated_sources = []
                                for (
                                    source_entry,
                                    materialized_entry,
                                    split_execution,
                                ) in split_specs:
                                    split_output_path = _artifact_path(
                                        config,
                                        unit,
                                        target,
                                        variant,
                                        preserve_source_suffix=(
                                            unit.relative_path,
                                            target,
                                        )
                                        in preserve_source_suffix,
                                        entry_point=source_entry,
                                    )
                                    split_output_path.parent.mkdir(
                                        parents=True, exist_ok=True
                                    )
                                    split_output_paths.append(split_output_path)
                                    split_artifact = dict(artifact)
                                    split_artifact["path"] = _artifact_report_path(
                                        split_output_path, config
                                    )
                                    split_artifact["provenance"] = {
                                        **dict(artifact["provenance"]),
                                        "pipeline": "entry-scoped-translate",
                                    }
                                    if isinstance(
                                        artifact.get("templateMaterialization"),
                                        Mapping,
                                    ):
                                        split_artifact["templateMaterialization"] = (
                                            _template_materialization_for_entry(
                                                artifact["templateMaterialization"],
                                                source_entry_point=source_entry,
                                                materialized_entry_point=(
                                                    materialized_entry
                                                ),
                                            )
                                        )
                                    _scope_artifact_specialization_metadata_for_entry(
                                        split_artifact,
                                        crossgl_ast=crossgl_ast,
                                        entry_point=materialized_entry,
                                        unit=unit,
                                        target=target,
                                        variant=variant,
                                    )
                                    split_artifact["execution"] = split_execution
                                    try:
                                        split_source = (
                                            _generate_project_target_from_crossgl_ast(
                                                ast=crossgl_ast,
                                                target=target,
                                                output_path=split_output_path,
                                                entry_point=materialized_entry,
                                                format_output=format_output,
                                                index_range_assertions=(
                                                    index_range_assertions
                                                ),
                                            )
                                        )
                                    except Exception as exc:
                                        if getattr(
                                            exc, "project_diagnostic_code", None
                                        ) == "project.translate.workgroup-size-invalid" and not getattr(
                                            exc, "source_entry_points", ()
                                        ):
                                            exc.source_entry_points = (source_entry,)
                                        raise
                                    _validate_project_workgroup_target_output(
                                        split_output_path,
                                        target=target,
                                        execution=split_execution,
                                    )
                                    _validate_project_subgroup_width_target_output(
                                        split_output_path,
                                        execution=split_execution,
                                    )
                                    records, split_diagnostics = (
                                        _finalize_project_generated_artifact(
                                            config=config,
                                            unit=unit,
                                            target=target,
                                            artifact=split_artifact,
                                            output_path=split_output_path,
                                            generated_source=split_source,
                                            source_entry_point=source_entry,
                                        )
                                    )
                                    artifact_records.extend(records)
                                    diagnostics.extend(split_diagnostics)
                                    generated_sources.append(split_source)
                                generated_source = "\n".join(generated_sources)
                                generated_records_finalized = True
                            else:
                                artifact["execution"] = execution
                                try:
                                    generated_source = (
                                        _generate_project_target_from_crossgl_ast(
                                            ast=crossgl_ast,
                                            target=target,
                                            output_path=output_path,
                                            entry_point=selected_entry_point,
                                            format_output=format_output,
                                            index_range_assertions=(
                                                index_range_assertions
                                            ),
                                        )
                                    )
                                except Exception as exc:
                                    if getattr(
                                        exc, "project_diagnostic_code", None
                                    ) == "project.translate.workgroup-size-invalid" and not getattr(
                                        exc, "source_entry_points", ()
                                    ):
                                        exc.source_entry_points = tuple(
                                            execution.get("sourceEntryPoints", ())
                                        )
                                    raise
                                _validate_project_workgroup_target_output(
                                    output_path,
                                    target=target,
                                    execution=execution,
                                )
                                _validate_project_subgroup_width_target_output(
                                    output_path,
                                    execution=execution,
                                )
                    if generated_source is None and index_range_assertions:
                        crossgl_ast = crossgl_ast or _crossgl_ast_for_project_target(
                            input_path=translation_input_path,
                            source_backend=translation_source_backend,
                            original_source_backend=unit.source_backend,
                            target=target,
                            include_paths=translation_include_paths,
                            defines=translation_defines,
                            source_options=translation_source_options,
                            source_is_materialized=(
                                template_materialization is not None
                            ),
                        )
                        generated_source = _generate_project_target_from_crossgl_ast(
                            ast=crossgl_ast,
                            target=target,
                            output_path=output_path,
                            entry_point=selected_entry_point,
                            format_output=format_output,
                            index_range_assertions=index_range_assertions,
                        )
                    if generated_source is None:
                        generated_source = translate(
                            str(translation_input_path), **translate_kwargs
                        )
                    if not generated_records_finalized:
                        artifact_records, generated_diagnostics = (
                            _finalize_project_generated_artifact(
                                config=config,
                                unit=unit,
                                target=target,
                                artifact=artifact,
                                output_path=output_path,
                                generated_source=generated_source,
                                source_entry_point=selected_entry_point,
                            )
                        )
                        diagnostics.extend(generated_diagnostics)
                except ProjectSpecializationError as exc:
                    failure_message = str(exc)
                    artifact["status"] = "failed"
                    artifact["error"] = failure_message
                    artifact.pop("generatedHash", None)
                    artifact.pop("generatedSizeBytes", None)
                    artifact.pop("sourceMap", None)
                    artifact.pop("sourceRemap", None)
                    _remove_artifact_output_files(output_path)
                    for split_output_path in split_output_paths:
                        _remove_artifact_output_files(split_output_path)
                    artifact_records = [artifact]
                    diagnostics.extend(exc.diagnostics)
                except Exception as exc:  # noqa: BLE001
                    # Project translation reports per-artifact failures so one bad
                    # unit does not hide the rest of the repository's migration state.
                    failure_message = _translation_failure_message(
                        exc,
                        target,
                        unit,
                        artifact.get("path"),
                    )
                    artifact["status"] = "failed"
                    artifact["error"] = failure_message
                    artifact.pop("generatedHash", None)
                    artifact.pop("generatedSizeBytes", None)
                    artifact.pop("sourceMap", None)
                    artifact.pop("sourceRemap", None)
                    _remove_artifact_output_files(output_path)
                    for split_output_path in split_output_paths:
                        _remove_artifact_output_files(split_output_path)
                    artifact_records = [artifact]
                    diagnostics.extend(
                        _translation_failure_project_diagnostics(
                            exc,
                            target,
                            unit,
                            variant,
                            failure_message,
                            artifact.get("path"),
                        )
                    )
                finally:
                    if template_temp_dir is not None:
                        template_temp_dir.cleanup()
                artifacts.extend(artifact_records)

    validation = (
        _validate_artifacts(artifacts, selected_targets, config)
        if validate or run_toolchains
        else {"toolchains": [], "artifacts": []}
    )
    if run_toolchains:
        toolchain_runs = _run_toolchain_smoke(artifacts, config.root)
        validation["toolchainRuns"] = toolchain_runs
        validation["_diagnostics"].extend(_toolchain_run_diagnostics(toolchain_runs))
    diagnostics.extend(validation.pop("_diagnostics", []))
    return ProjectPortabilityReport(
        config=config,
        targets=selected_targets,
        units=scan.units,
        skipped=scan.skipped,
        native_directives=scan.native_directives,
        artifacts=artifacts,
        diagnostics=diagnostics,
        validation=validation,
        migration_actions=_project_migration_actions(
            config, scan.units, selected_targets, artifacts
        ),
        artifact_matrix=_artifact_matrix_report(
            config,
            scan.units,
            selected_targets,
            config.variants,
            artifacts,
            variants_by_source_target=translation_variants,
        ),
        dispatch_artifact_plan=scan.dispatch_artifact_plan,
    )


def _tool_status(target: str) -> dict[str, Any]:
    tools = TOOLCHAIN_BY_BACKEND.get(target, ())
    if not tools:
        return {
            "target": target,
            "status": "not-configured",
            "tools": [],
            "message": "No validation toolchain hook is configured for this target.",
        }
    resolved = []
    for tool in tools:
        path = shutil.which(tool)
        resolved.append({"name": tool, "path": path, "available": path is not None})
    available = all(tool["available"] for tool in resolved)
    return {
        "target": target,
        "status": "available" if available else "unavailable",
        "tools": resolved,
    }


def _status_counts(
    records: Sequence[Any], field_name: str, statuses: frozenset[str]
) -> dict[str, int]:
    counts = {status: 0 for status in sorted(statuses)}
    for record in records:
        if not isinstance(record, Mapping):
            continue
        status = record.get(field_name)
        if isinstance(status, str) and status in counts:
            counts[status] += 1
    return counts


def _validation_summary(artifact_checks: Sequence[Any]) -> dict[str, Any]:
    status_counts = _status_counts(
        artifact_checks, "status", VALIDATION_ARTIFACT_STATUSES
    )
    return {
        "artifactCount": len(artifact_checks),
        "okCount": status_counts["ok"],
        "failedCount": status_counts["failed"],
        "sourceHashStatusCounts": _status_counts(
            artifact_checks, "sourceHashStatus", SOURCE_HASH_VALIDATION_STATUSES
        ),
        "sourceSizeStatusCounts": _status_counts(
            artifact_checks, "sourceSizeStatus", SOURCE_SIZE_VALIDATION_STATUSES
        ),
        "generatedHashStatusCounts": _status_counts(
            artifact_checks,
            "generatedHashStatus",
            GENERATED_HASH_VALIDATION_STATUSES,
        ),
        "generatedSizeStatusCounts": _status_counts(
            artifact_checks,
            "generatedSizeStatus",
            GENERATED_SIZE_VALIDATION_STATUSES,
        ),
        "sourceMapStatusCounts": _status_counts(
            artifact_checks,
            "sourceMapStatus",
            SOURCE_MAP_VALIDATION_STATUSES,
        ),
        "sourceRemapStatusCounts": _status_counts(
            artifact_checks,
            "sourceRemapStatus",
            SOURCE_REMAP_VALIDATION_STATUSES,
        ),
    }


