    command = run.get("command")
    if (
        not isinstance(command, Sequence)
        or isinstance(command, (str, bytes, bytearray))
        or not command
    ):
        return None
    tool_name = command[0]
    if isinstance(tool_name, str) and tool_name.strip():
        return tool_name.strip()
    return None


