def _source_map_file_span_mismatch_reasons(
    prefix: str,
    span: Any,
    expected_span: Mapping[str, Any],
    expected_name: str,
) -> list[str]:
    if not isinstance(span, Mapping):
        return []
    reasons = []
    for field_name in SOURCE_MAP_SPAN_FIELDS:
        if span.get(field_name) != expected_span[field_name]:
            expected_field_name = "path" if field_name == "file" else field_name
            reasons.append(
                f"{prefix}.{field_name} must match "
                f"{expected_name} {expected_field_name} "
                f"({_value_mismatch_context(expected_span[field_name], span.get(field_name))})"
            )
    return reasons


def _source_map_line_preserving_mapping_reasons(
    prefix: str,
    source_map: Mapping[str, Any],
    source_path: Path,
    source_report_path: str,
    artifact_path: Path,
    artifact_report_path: str,
) -> list[str]:
    if source_map.get("mappingGranularity") != "line":
        return []
    mappings = source_map.get("mappings")
    if not isinstance(mappings, list):
        return []
    expected_mappings = _line_preserving_source_map_mappings(
        source_path,
        source_report_path,
        artifact_path,
        artifact_report_path,
    )
    if not expected_mappings:
        return []
    if mappings == expected_mappings:
        return []
    if len(mappings) != len(expected_mappings):
        return [
            f"{prefix}.mappings count must match current line-preserving line count "
            f"({_value_mismatch_context(len(expected_mappings), len(mappings))})"
        ]
    for mapping_index, expected_mapping in enumerate(expected_mappings):
        mapping = mappings[mapping_index]
        if not isinstance(mapping, Mapping) or dict(mapping) != expected_mapping:
            return [
                f"{prefix}.mappings[{mapping_index}] must match current "
                "line-preserving line span "
                f"({_value_mismatch_context(expected_mapping, mapping)})"
            ]
    return [
        f"{prefix}.mappings must match current line-preserving line spans "
        f"({_value_mismatch_context(expected_mappings, mappings)})"
    ]


def _source_map_derived_line_mapping_reasons(
    prefix: str,
    source_map: Mapping[str, Any],
    source_path: Path,
    source_report_path: str,
    artifact_path: Path,
    artifact_report_path: str,
) -> list[str]:
    if source_map.get("mappingGranularity") != "line":
        return []
    mappings = source_map.get("mappings")
    if not isinstance(mappings, list):
        return []
    if _line_preserving_source_map_mappings(
        source_path,
        source_report_path,
        artifact_path,
        artifact_report_path,
    ):
        return []
    expected_mappings = _derived_line_source_map_mappings(
        source_path,
        source_report_path,
        artifact_path,
        artifact_report_path,
    )
    if not expected_mappings:
        return []
    if mappings == expected_mappings:
        return []
    if len(mappings) != len(expected_mappings):
        return [
            f"{prefix}.mappings count must match current derived line count "
            f"({_value_mismatch_context(len(expected_mappings), len(mappings))})"
        ]
    for mapping_index, expected_mapping in enumerate(expected_mappings):
        mapping = mappings[mapping_index]
        if not isinstance(mapping, Mapping) or dict(mapping) != expected_mapping:
            return [
                f"{prefix}.mappings[{mapping_index}] must match current "
                "derived line span "
                f"({_value_mismatch_context(expected_mapping, mapping)})"
            ]
    return [
        f"{prefix}.mappings must match current derived line spans "
        f"({_value_mismatch_context(expected_mappings, mappings)})"
    ]


def _source_map_file_span_validation_diagnostics(
    artifact: Mapping[str, Any],
    config: ProjectConfig,
    artifact_path: Path,
    *,
    source_hash_status: str,
    generated_hash_status: str,
) -> list[ProjectDiagnostic]:
    if artifact.get("status") != "translated":
        return []

    source_map = artifact.get("sourceMap")
    if not isinstance(source_map, Mapping):
        return []

    reasons = []
    source_path: Path | None = None
    artifact_report_path = artifact.get("path")
    source = artifact.get("source")
    if source_hash_status in {"ok", "not-recorded"} and _is_non_empty_string(source):
        source_path = _resolve_report_path(config, source)
        if (
            _is_relative_to(source_path, config.root)
            and source_path.exists()
            and source_path.is_file()
        ):
            reasons.extend(
                _source_map_file_span_mismatch_reasons(
                    "sourceMap.source",
                    source_map.get("source"),
                    _file_span(source_path, source).to_json(),
                    "source file",
                )
            )

    if (
        generated_hash_status in {"ok", "not-recorded"}
        and _is_non_empty_string(artifact_report_path)
        and _is_relative_to(artifact_path, config.root)
        and artifact_path.exists()
        and artifact_path.is_file()
    ):
        reasons.extend(
            _source_map_file_span_mismatch_reasons(
                "sourceMap.generated",
                source_map.get("generated"),
                _file_span(artifact_path, artifact_report_path).to_json(),
                "generated artifact",
            )
        )

    if (
        source_path is not None
        and _is_non_empty_string(source)
        and _is_non_empty_string(artifact_report_path)
        and source_hash_status in {"ok", "not-recorded"}
        and generated_hash_status in {"ok", "not-recorded"}
        and _is_relative_to(source_path, config.root)
        and _is_relative_to(artifact_path, config.root)
        and source_path.exists()
        and source_path.is_file()
        and artifact_path.exists()
        and artifact_path.is_file()
    ):
        reasons.extend(
            _source_map_line_preserving_mapping_reasons(
                "sourceMap",
                source_map,
                source_path,
                source,
                artifact_path,
                artifact_report_path,
            )
        )
        reasons.extend(
            _source_map_derived_line_mapping_reasons(
                "sourceMap",
                source_map,
                source_path,
                source,
                artifact_path,
                artifact_report_path,
            )
        )

    if not reasons:
        return []
    return [
        ProjectDiagnostic(
            severity="error",
            code=(
                "project.validate.source-map-line-span-mismatch"
                if any(
                    "line-preserving line" in reason or "derived line" in reason
                    for reason in reasons
                )
                else "project.validate.source-map-file-span-mismatch"
            ),
            message=(
                "Source map spans do not match current files: "
                f"{artifact.get('path')}: {'; '.join(reasons)}"
            ),
            location=SourceLocation(file=str(artifact.get("source", ""))),
            **_artifact_diagnostic_context(artifact),
            missing_capabilities=["source.provenance"],
        )
    ]


def _source_remap_validation_diagnostics(
    artifact: Mapping[str, Any], config: ProjectConfig
) -> list[ProjectDiagnostic]:
    if artifact.get("status") != "translated":
        return []

    source_remap = artifact.get("sourceRemap")
    if not isinstance(source_remap, Mapping):
        return []

    remap_path = _resolve_report_path(config, source_remap["path"])
    if not _is_relative_to(remap_path, config.root):
        return [
            ProjectDiagnostic(
                severity="error",
                code="project.validate.source-remap-outside-project",
                message=(
                    "Source remap path resolves outside the repository: "
                    f"{source_remap['path']}"
                ),
                location=SourceLocation(file=str(artifact["source"])),
                **_artifact_diagnostic_context(artifact),
                missing_capabilities=["source.provenance"],
            )
        ]

    if not remap_path.exists():
        return [
            ProjectDiagnostic(
                severity="error",
                code="project.validate.missing-source-remap",
                message=(
                    "Expected source remap sidecar is missing: "
                    f"{source_remap['path']}"
                ),
                location=SourceLocation(file=str(artifact["source"])),
                **_artifact_diagnostic_context(artifact),
                missing_capabilities=["source.provenance"],
            )
        ]

    diagnostics = []
    expected_size = source_remap.get("sizeBytes")
    if not isinstance(expected_size, int) or isinstance(expected_size, bool):
        expected_size = None
    actual_remap_size = remap_path.stat().st_size
    if expected_size is not None and expected_size != actual_remap_size:
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code="project.validate.source-remap-size-mismatch",
                message=(
                    "Source remap sidecar size does not match report: "
                    f"{source_remap['path']} "
                    f"({_size_mismatch_context(expected_size, actual_remap_size)})"
                ),
                location=SourceLocation(file=str(artifact["source"])),
                **_artifact_diagnostic_context(artifact),
                missing_capabilities=["source.provenance"],
            )
        )

    actual_remap_hash = _source_hash(remap_path)
    source_remap_hash_matches = _hash_matches_report(
        actual_remap_hash, source_remap["hash"]
    )
    if not source_remap_hash_matches:
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code="project.validate.source-remap-hash-mismatch",
                message=(
                    "Source remap sidecar hash does not match report: "
                    f"{source_remap['path']} "
                    f"({_hash_mismatch_context(actual_remap_hash, source_remap['hash'])})"
                ),
                location=SourceLocation(file=str(artifact["source"])),
                **_artifact_diagnostic_context(artifact),
                missing_capabilities=["source.provenance"],
            )
        )

    try:
        remap_payload = json.loads(remap_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError) as exc:
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code="project.validate.source-remap-invalid",
                message=(
                    "Source remap sidecar is not valid JSON: "
                    f"{source_remap['path']}: {exc}"
                ),
                location=SourceLocation(file=str(artifact["source"])),
                **_artifact_diagnostic_context(artifact),
                missing_capabilities=["source.provenance"],
            )
        )
        return diagnostics

    semantic_reasons = _compiler_source_remap_payload_reasons(remap_payload)
    if semantic_reasons:
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code="project.validate.source-remap-invalid",
                message=(
                    "Source remap sidecar is not compiler-compatible: "
                    f"{source_remap['path']}: {'; '.join(semantic_reasons)}"
                ),
                location=SourceLocation(file=str(artifact["source"])),
                **_artifact_diagnostic_context(artifact),
                missing_capabilities=["source.provenance"],
            )
        )

    source_map = artifact.get("sourceMap")
    if isinstance(source_map, Mapping):
        expected_payload = _source_remap_payload(source_map)
        if remap_payload != expected_payload:
            diagnostics.append(
                ProjectDiagnostic(
                    severity="error",
                    code="project.validate.source-remap-mismatch",
                    message=(
                        "Source remap sidecar does not match artifact source map: "
                        f"{source_remap['path']}"
                    ),
                    location=SourceLocation(file=str(artifact["source"])),
                    **_artifact_diagnostic_context(artifact),
                    missing_capabilities=["source.provenance"],
                )
            )
    return diagnostics


def _source_map_validation_status(
    artifact: Mapping[str, Any],
    *,
    source_hash_status: str,
    generated_hash_status: str,
    source_map_diagnostics: Sequence[ProjectDiagnostic],
) -> str:
    if artifact.get("status") != "translated":
        return "not-applicable"
    if not isinstance(artifact.get("sourceMap"), Mapping):
        return "not-recorded"
    if source_map_diagnostics:
        return "mismatch"
    if source_hash_status not in {"ok", "not-recorded"}:
        return "not-checked"
    if generated_hash_status not in {"ok", "not-recorded"}:
        return "not-checked"
    return "ok"


def _source_remap_validation_status(
    artifact: Mapping[str, Any],
    diagnostics: Sequence[ProjectDiagnostic],
) -> str:
    if artifact.get("status") != "translated":
        return "not-applicable"
    if not isinstance(artifact.get("sourceRemap"), Mapping):
        return "not-recorded"
    if not diagnostics:
        return "ok"

    codes = {diagnostic.code for diagnostic in diagnostics}
    if "project.validate.source-remap-outside-project" in codes:
        return "outside-project"
    if "project.validate.missing-source-remap" in codes:
        return "missing"
    if "project.validate.source-remap-invalid" in codes:
        return "invalid"
    if "project.validate.source-remap-size-mismatch" in codes:
        return "mismatch"
    if "project.validate.source-remap-mismatch" in codes:
        return "mismatch"
    if "project.validate.source-remap-hash-mismatch" in codes:
        return "hash-mismatch"
    return "invalid"


def _artifact_diagnostic_context(artifact: Mapping[str, Any]) -> dict[str, Any]:
    context: dict[str, Any] = {"target": str(artifact.get("target", ""))}
    source_backend = artifact.get("sourceBackend")
    if _is_non_empty_string(source_backend):
        context["source_backend"] = source_backend
    variant = artifact.get("variant")
    if _is_non_empty_string(variant):
        context["variant"] = variant
    return context


def _mojo_target_construct_rule_applies(rule_id: str, target: str) -> bool:
    if target == "mojo":
        return False
    if rule_id == "mojo-host-main":
        return target != "opengl"
    if rule_id == "mojo-none":
        return target != "vulkan"
    if rule_id == "spirv-unresolved-warning":
        return target == "vulkan"
    return True


def _mojo_spirv_invalid_module_instruction(line_text: str) -> str | None:
    stripped = line_text.strip()
    if not stripped or stripped.startswith(";"):
        return None
    if "=" in stripped:
        _result_id, instruction = stripped.split("=", 1)
        opcode = instruction.strip().split(maxsplit=1)[0]
    else:
        opcode = stripped.split(maxsplit=1)[0]
    return opcode if opcode in MOJO_SPIRV_BLOCK_ONLY_OPS else None


def _mojo_unresolved_target_construct_findings(
    target: str, generated_source: str
) -> list[dict[str, Any]]:
    findings: list[dict[str, Any]] = []
    offset = 0
    in_spirv_function = False
    in_spirv_block = False

    for line_number, line in enumerate(
        generated_source.splitlines(keepends=True), start=1
    ):
        line_text = line.rstrip("\r\n")
        if target == "vulkan":
            stripped = line_text.strip()
            if stripped.startswith("OpFunctionEnd"):
                in_spirv_function = False
                in_spirv_block = False
            elif " OpFunction " in stripped or stripped.startswith("OpFunction "):
                in_spirv_function = True
                in_spirv_block = False
            elif in_spirv_function and (
                " OpLabel" in stripped or stripped.startswith("OpLabel")
            ):
                in_spirv_block = True
            elif not in_spirv_block:
                opcode = _mojo_spirv_invalid_module_instruction(line_text)
                if opcode:
                    findings.append(
                        {
                            "id": "spirv-block-only-instruction",
                            "label": (
                                f"SPIR-V block-only instruction outside a block "
                                f"({opcode})"
                            ),
                            "line": line_number,
                            "column": 1,
                            "offset": offset,
                            "length": max(len(line_text), 1),
                        }
                    )

        for rule_id, label, pattern in MOJO_UNRESOLVED_TARGET_CONSTRUCT_RULES:
            if not _mojo_target_construct_rule_applies(rule_id, target):
                continue
            match = pattern.search(line_text)
            if match is None:
                continue
            findings.append(
                {
                    "id": rule_id,
                    "label": label,
                    "line": line_number,
                    "column": match.start() + 1,
                    "offset": offset + match.start(),
                    "length": max(match.end() - match.start(), 1),
                }
            )
        offset += len(line)
    return findings


def _mojo_unresolved_target_construct_message(
    artifact: Mapping[str, Any], findings: Sequence[Mapping[str, Any]]
) -> str:
    labels = []
    seen = set()
    for finding in findings:
        label = finding.get("label")
        if not _is_non_empty_string(label) or label in seen:
            continue
        labels.append(label)
        seen.add(label)
    label_text = ", ".join(labels)
    return (
        f"Generated {artifact.get('target')} artifact contains unresolved Mojo "
        f"host/runtime constructs in {artifact.get('path')}: {label_text}. "
        "Separate GPU kernel code from Mojo host/runtime setup before target "
        "codegen, or mark the target artifact unsupported."
    )


def _mojo_unresolved_target_construct_diagnostics(
    artifact: Mapping[str, Any],
    generated_source: str,
) -> list[ProjectDiagnostic]:
    if artifact.get("sourceBackend") != "mojo":
        return []
    target = str(artifact.get("target", ""))
    if target == "mojo":
        return []
    findings = _mojo_unresolved_target_construct_findings(target, generated_source)
    if not findings:
        return []

    first_finding = findings[0]
    return [
        ProjectDiagnostic(
            severity="error",
            code=MOJO_UNRESOLVED_TARGET_CONSTRUCT_DIAGNOSTIC_CODE,
            message=_mojo_unresolved_target_construct_message(artifact, findings),
            location=SourceLocation(
                file=str(artifact.get("path", "")),
                line=int(first_finding["line"]),
                column=int(first_finding["column"]),
                offset=int(first_finding["offset"]),
                length=int(first_finding["length"]),
                end_line=int(first_finding["line"]),
                end_column=int(first_finding["column"]) + int(first_finding["length"]),
                end_offset=int(first_finding["offset"]) + int(first_finding["length"]),
            ),
            original_location=SourceLocation(file=str(artifact.get("source", ""))),
            **_artifact_diagnostic_context(artifact),
            check_kind="artifact",
            missing_capabilities=[MOJO_UNRESOLVED_TARGET_CONSTRUCT_CAPABILITY],
        )
    ]


def _metal_target_construct_rule_applies(rule_id: str, target: str) -> bool:
    # The Metal source backend is the origin of these tokens, so they are valid
    # in Metal output. CrossGL (target "cgl"/"crossgl") is the IR and keeps its
    # own intrinsics (e.g. buffer_load/buffer_store, metal::), so the CrossGL
    # source-to-source output is never scanned either.
    if target == "metal" or target in CROSSL_TARGETS:
        return False
    if rule_id == "glsl-builtin":
        # gl_* builtins (gl_Position, gl_FragCoord, ...) are valid in
        # OpenGL/Vulkan/GLSL output; only HLSL (DirectX) has no such namespace.
        return target == "directx"
    if rule_id in ("crossgl-buffer-load", "crossgl-buffer-store"):
        # The Rust and Mojo backends have no native indexed-buffer syntax, so
        # the CrossGL buffer_load/buffer_store intrinsics are part of their
        # *valid* generated output (they emit matching helper functions). Every
        # actual GPU shading target (directx, opengl, vulkan, wgsl, cuda, hip,
        # slang) lowers them away, so leaks there are real failures.
        return target not in ("rust", "mojo")
    return True


def _metal_locally_defined_simd_names(lines: Sequence[str]) -> set[str]:
    """Names of simd_* functions defined (not merely called) in the artifact.

    A definition is a declarator that starts with a return-type token, names a
    ``simd_*`` function, and opens a body (``{``) before any statement
    terminator. Pure call sites (``return simd_x(...)``) and assignments are
    excluded so a leaked, undefined intrinsic call is never mistaken for a
    locally provided helper.
    """
    names: set[str] = set()
    count = len(lines)
    for index, raw in enumerate(lines):
        line = raw.strip()
        if not line or line.startswith(("return", "//", "*", "/*")):
            continue
        match = METAL_SIMD_LOCAL_DEFINITION_PATTERN.match(line)
        if match is None:
            continue
        prefix = line[: match.start(1)].strip()
        if not prefix or "=" in prefix:
            continue
        # The declarator must open a brace before any terminator; scan ahead in
        # case the brace is on a following line.
        chunk = line[match.end(1) :]
        scan = index
        while "{" not in chunk and ";" not in chunk and scan + 1 < count:
            scan += 1
            chunk += " " + lines[scan].strip()
        brace = chunk.find("{")
        semicolon = chunk.find(";")
        if brace != -1 and (semicolon == -1 or brace < semicolon):
            names.add(match.group(1))
    return names


def _metal_unresolved_target_construct_findings(
    target: str, generated_source: str
) -> list[dict[str, Any]]:
    findings: list[dict[str, Any]] = []
    offset = 0
    lines_only = generated_source.splitlines()
    locally_defined_simd = _metal_locally_defined_simd_names(lines_only)
    for line_number, line in enumerate(
        generated_source.splitlines(keepends=True), start=1
    ):
        line_text = line.rstrip("\r\n")
        for rule_id, label, pattern in METAL_UNRESOLVED_TARGET_CONSTRUCT_RULES:
            if not _metal_target_construct_rule_applies(rule_id, target):
                continue
            match = pattern.search(line_text)
            if match is None:
                continue
            if (
                rule_id == "metal-simd-intrinsic"
                and match.group(0) in locally_defined_simd
            ):
                # A locally defined simd_* helper (e.g. an MLX utils.h shim) is
                # valid output, not a leaked Metal intrinsic. Skip it.
                continue
            findings.append(
                {
                    "id": rule_id,
                    "label": label,
                    "line": line_number,
                    "column": match.start() + 1,
                    "offset": offset + match.start(),
                    "length": max(match.end() - match.start(), 1),
                }
            )
        offset += len(line)
    return findings


def _metal_unresolved_target_construct_message(
    artifact: Mapping[str, Any], findings: Sequence[Mapping[str, Any]]
) -> str:
    labels = []
    seen = set()
    for finding in findings:
        label = finding.get("label")
        if not _is_non_empty_string(label) or label in seen:
            continue
        labels.append(label)
        seen.add(label)
    label_text = ", ".join(labels)
    return (
        f"Generated {artifact.get('target')} artifact contains unresolved Metal "
        f"source constructs in {artifact.get('path')}: {label_text}. "
        "Lower these Metal/CrossGL constructs to the target language before "
        "codegen, or mark the target artifact unsupported."
    )


def _metal_unresolved_target_construct_diagnostics(
    artifact: Mapping[str, Any],
    generated_source: str,
) -> list[ProjectDiagnostic]:
    if artifact.get("sourceBackend") != "metal":
        return []
    target = str(artifact.get("target", ""))
    if target == "metal" or target in CROSSL_TARGETS:
        return []
    findings = _metal_unresolved_target_construct_findings(target, generated_source)
    if not findings:
        return []

    first_finding = findings[0]
    return [
        ProjectDiagnostic(
            severity="error",
            code=METAL_UNRESOLVED_TARGET_CONSTRUCT_DIAGNOSTIC_CODE,
            message=_metal_unresolved_target_construct_message(artifact, findings),
            location=SourceLocation(
                file=str(artifact.get("path", "")),
                line=int(first_finding["line"]),
                column=int(first_finding["column"]),
                offset=int(first_finding["offset"]),
                length=int(first_finding["length"]),
                end_line=int(first_finding["line"]),
                end_column=int(first_finding["column"]) + int(first_finding["length"]),
                end_offset=int(first_finding["offset"]) + int(first_finding["length"]),
            ),
            original_location=SourceLocation(file=str(artifact.get("source", ""))),
            **_artifact_diagnostic_context(artifact),
            check_kind="artifact",
            missing_capabilities=[METAL_UNRESOLVED_TARGET_CONSTRUCT_CAPABILITY],
        )
    ]


def _generated_placeholder_diagnostic_message(
    target: str,
    artifact_path: str,
    label: str,
    action: str,
    provenance: str = "",
) -> str:
    return (
        f"Generated {target} artifact contains {label}: {artifact_path}{provenance}. "
        f"{action}"
    )


def _artifact_provenance_message_suffix(artifact: Mapping[str, Any]) -> str:
    provenance = artifact.get("provenance")
    if not isinstance(provenance, Mapping):
        return ""
    parts = []
    for field_name in ("pipeline", "intermediate"):
        value = provenance.get(field_name)
        if _is_non_empty_string(value):
            parts.append(f"{field_name}={value}")
    return f" ({', '.join(parts)})" if parts else ""


def _placeholder_marker_missing_capabilities(kind: str, target: str) -> list[str]:
    capabilities = [PLACEHOLDER_MISSING_CAPABILITY, kind]
    if target == "mojo" and kind == MOJO_RESOURCE_PLACEHOLDER_KIND:
        capabilities.append(MOJO_RESOURCE_PLACEHOLDER_CAPABILITY)
    return capabilities


def _placeholder_marker_action(kind: str, target: str, action: str) -> str:
    if target == "mojo" and kind == MOJO_RESOURCE_PLACEHOLDER_KIND:
        return (
            "Mojo resource placeholders are compile-only scaffolding for "
            "resource helpers. Replace them with Mojo-native resource "
            "bindings or host integration before relying on runtime behavior."
        )
    return action


def _generated_placeholder_diagnostics_for_artifact(
    artifact: Mapping[str, Any], config: ProjectConfig
) -> list[ProjectDiagnostic]:
    if artifact.get("status") != "translated":
        return []
    artifact_path_value = artifact.get("path")
    if not _is_non_empty_string(artifact_path_value):
        return []

    artifact_path = _resolve_report_path(config, artifact_path_value)
    if not _is_relative_to(artifact_path, config.root) or not artifact_path.is_file():
        return []

    try:
        source = artifact_path.read_text(encoding="utf-8", errors="replace")
    except OSError:
        return []

    diagnostics: list[ProjectDiagnostic] = []
    offset = 0
    for line_number, line in enumerate(source.splitlines(keepends=True), start=1):
        line_text = line.rstrip("\r\n")
        for kind, pattern, label, action in PLACEHOLDER_MARKER_RULES:
            match = pattern.search(line_text)
            if match is None:
                continue
            column = match.start() + 1
            length = max(match.end() - match.start(), 1)
            context = _artifact_diagnostic_context(artifact)
            target = str(artifact.get("target", ""))
            diagnostics.append(
                ProjectDiagnostic(
                    severity="warning",
                    code=GENERATED_PLACEHOLDER_DIAGNOSTIC_CODE,
                    message=_generated_placeholder_diagnostic_message(
                        target,
                        str(artifact_path_value),
                        label,
                        _placeholder_marker_action(kind, target, action),
                        _artifact_provenance_message_suffix(artifact),
                    ),
                    location=SourceLocation(
                        file=str(artifact_path_value),
                        line=line_number,
                        column=column,
                        offset=offset + match.start(),
                        length=length,
                        end_line=line_number,
                        end_column=column + length,
                        end_offset=offset + match.end(),
                    ),
                    original_location=SourceLocation(
                        file=str(artifact.get("source", ""))
                    ),
                    missing_capabilities=_placeholder_marker_missing_capabilities(
                        kind, target
                    ),
                    **context,
                )
            )
            break
        offset += len(line)
    return diagnostics


def _generated_placeholder_diagnostics(
    artifacts: Sequence[Mapping[str, Any]], config: ProjectConfig
) -> list[ProjectDiagnostic]:
    diagnostics: list[ProjectDiagnostic] = []
    for artifact in artifacts:
        diagnostics.extend(
            _generated_placeholder_diagnostics_for_artifact(artifact, config)
        )
    return diagnostics


def _diagnostic_location_field(diagnostic: Any, field_name: str) -> Any:
    if isinstance(diagnostic, ProjectDiagnostic):
        location = (
            diagnostic.original_location
            if field_name == "originalLocation"
            else getattr(diagnostic, field_name)
        )
        return location.to_json() if isinstance(location, SourceLocation) else None
    if isinstance(diagnostic, Mapping):
        location = diagnostic.get(field_name)
        return location if isinstance(location, Mapping) else None
    return None


def _diagnostic_field(diagnostic: Any, field_name: str) -> Any:
    if isinstance(diagnostic, ProjectDiagnostic):
        if field_name == "sourceBackend":
            return diagnostic.source_backend
        return getattr(diagnostic, field_name, None)
    if isinstance(diagnostic, Mapping):
        return diagnostic.get(field_name)
    return None


def _generated_placeholder_diagnostic_key(diagnostic: Any) -> tuple[Any, ...] | None:
    if _diagnostic_field(diagnostic, "code") != GENERATED_PLACEHOLDER_DIAGNOSTIC_CODE:
        return None
    location = _diagnostic_location_field(diagnostic, "location")
    if not isinstance(location, Mapping):
        return None
    return (
        _diagnostic_field(diagnostic, "target"),
        _diagnostic_field(diagnostic, "sourceBackend"),
        _diagnostic_field(diagnostic, "variant"),
        location.get("file"),
        location.get("line"),
        location.get("column"),
    )


def _placeholder_diagnostics_by_source(
    diagnostics: Sequence[Any],
) -> dict[str, int]:
    counts: dict[str, int] = {}
    for diagnostic in diagnostics:
        if _generated_placeholder_diagnostic_key(diagnostic) is None:
            continue
        original_location = _diagnostic_location_field(diagnostic, "originalLocation")
        source = (
            original_location.get("file")
            if isinstance(original_location, Mapping)
            else None
        )
        if not _is_non_empty_string(source):
            continue
        counts[source] = counts.get(source, 0) + 1
    return dict(sorted(counts.items()))


def _placeholder_diagnostics_by_target(
    diagnostics: Sequence[Any],
) -> dict[str, int]:
    counts: dict[str, int] = {}
    for diagnostic in diagnostics:
        if _generated_placeholder_diagnostic_key(diagnostic) is None:
            continue
        target = _diagnostic_field(diagnostic, "target")
        if not _is_non_empty_string(target):
            continue
        counts[target] = counts.get(target, 0) + 1
    return dict(sorted(counts.items()))


def _migration_placeholder_rollups(diagnostics: Sequence[Any]) -> dict[str, Any]:
    placeholder_count = sum(
        1
        for diagnostic in diagnostics
        if _generated_placeholder_diagnostic_key(diagnostic) is not None
    )
    return {
        "placeholderCount": placeholder_count,
        "placeholdersByTarget": _placeholder_diagnostics_by_target(diagnostics),
        "placeholdersBySource": _placeholder_diagnostics_by_source(diagnostics),
    }


def _missing_generated_placeholder_diagnostics(
    artifacts: Sequence[Mapping[str, Any]],
    config: ProjectConfig,
    source_diagnostics: Sequence[Mapping[str, Any]],
) -> list[ProjectDiagnostic]:
    reported = {
        key
        for diagnostic in source_diagnostics
        for key in (_generated_placeholder_diagnostic_key(diagnostic),)
        if key is not None
    }
    missing: list[ProjectDiagnostic] = []
    for diagnostic in _generated_placeholder_diagnostics(artifacts, config):
        key = _generated_placeholder_diagnostic_key(diagnostic)
        if key in reported:
            continue
        missing.append(
            ProjectDiagnostic(
                severity="error",
                code=PLACEHOLDER_DIAGNOSTIC_MISSING_CODE,
                message=(
                    "Generated artifact contains a known placeholder marker "
                    "without a matching project diagnostic: "
                    f"{diagnostic.location.file}:{diagnostic.location.line}:"
                    f"{diagnostic.location.column}"
                ),
                location=diagnostic.location,
                original_location=diagnostic.original_location,
                target=diagnostic.target,
                source_backend=diagnostic.source_backend,
                variant=diagnostic.variant,
                missing_capabilities=[
                    PLACEHOLDER_DIAGNOSTIC_CAPABILITY,
                    *diagnostic.missing_capabilities,
                ],
            )
        )
    return missing


def _subgroup_width_target_validation_diagnostics(
    artifact: Mapping[str, Any],
    artifact_path: Path,
) -> list[ProjectDiagnostic]:
    execution = artifact.get("execution")
    if artifact.get("target") != "directx" or not isinstance(execution, Mapping):
        return []
    entries = [
        entry
        for entry in _record_sequence(execution.get("entryPoints"))
        if isinstance(entry, Mapping) and "subgroupWidth" in entry
    ]
    if not entries:
        return []

    try:
        _validate_project_subgroup_width_target_output(
            artifact_path,
            execution=execution,
        )
    except ProjectSubgroupWidthError as exc:
        specialization = {
            "reason": exc.reason,
            "sourceEntryPoints": list(exc.source_entry_points),
        }
        if exc.subgroup_width is not None:
            specialization["subgroupWidth"] = exc.subgroup_width
        if exc.source_subgroup_width is not None:
            specialization["sourceSubgroupWidth"] = exc.source_subgroup_width
        return [
            ProjectDiagnostic(
                severity="error",
                code="project.validate.subgroup-width-contract-mismatch",
                message=(
                    "Generated artifact does not satisfy its recorded "
                    f"subgroup-width contract: {artifact['path']}: {exc}"
                ),
                location=SourceLocation(file=str(artifact["source"])),
                **_artifact_diagnostic_context(artifact),
                check_kind=exc.check_kind,
                missing_capabilities=list(exc.missing_capabilities),
                details={
                    "sourcePath": str(artifact["source"]),
                    "targetArtifact": str(artifact["path"]),
                    "executionSpecialization": specialization,
                },
            )
        ]
    return []


def _validate_artifacts(
    artifacts: Sequence[Mapping[str, Any]],
    targets: Sequence[str],
    config: ProjectConfig,
) -> dict[str, Any]:
    diagnostics: list[ProjectDiagnostic] = []
    toolchains = [_tool_status(target) for target in targets]
    artifact_checks = []

    for artifact in artifacts:
        artifact_path = _resolve_report_path(config, artifact["path"])
        artifact_inside_project = _is_relative_to(artifact_path, config.root)
        if not artifact_inside_project:
            diagnostics.append(
                ProjectDiagnostic(
                    severity="error",
                    code="project.validate.artifact-outside-project",
                    message=(
                        "Artifact path resolves outside the repository: "
                        f"{artifact['path']}"
                    ),
                    location=SourceLocation(file=str(artifact["source"])),
                    **_artifact_diagnostic_context(artifact),
                    missing_capabilities=["artifact.manifest"],
                )
            )
        exists = artifact_path.exists() if artifact_inside_project else False
        source_hash_status = "not-recorded"
        source_size_status = "not-recorded"
        source_hash = artifact.get("sourceHash")
        source_size = artifact.get("sourceSizeBytes")
        validate_source_hash = isinstance(source_hash, Mapping)
        validate_source_size = _is_non_negative_int(source_size)
        if validate_source_hash or validate_source_size:
            source_path = _resolve_report_path(config, artifact["source"])
            source_inside_project = _is_relative_to(source_path, config.root)
            if not source_inside_project:
                if validate_source_hash:
                    source_hash_status = "outside-project"
                if validate_source_size:
                    source_size_status = "outside-project"
                diagnostics.append(
                    ProjectDiagnostic(
                        severity="error",
                        code="project.validate.source-outside-project",
                        message=(
                            "Source path resolves outside the repository: "
                            f"{artifact['source']}"
                        ),
                        location=SourceLocation(file=str(artifact["source"])),
                        **_artifact_diagnostic_context(artifact),
                        missing_capabilities=["source.provenance"],
                    )
                )
            elif not source_path.exists():
                if validate_source_hash:
                    source_hash_status = "missing"
                if validate_source_size:
                    source_size_status = "missing"
                diagnostics.append(
                    ProjectDiagnostic(
                        severity="error",
                        code="project.validate.missing-source",
                        message=(
                            "Expected source artifact is missing: "
                            f"{artifact['source']}"
                        ),
                        location=SourceLocation(file=str(artifact["source"])),
                        **_artifact_diagnostic_context(artifact),
                        missing_capabilities=["source.provenance"],
                    )
                )
            else:
                if validate_source_hash:
                    actual_source_hash = _source_hash(source_path)
                    if not _hash_matches_report(actual_source_hash, source_hash):
                        source_hash_status = "mismatch"
                        diagnostics.append(
                            ProjectDiagnostic(
                                severity="error",
                                code="project.validate.source-hash-mismatch",
                                message=(
                                    "Source artifact hash does not match report: "
                                    f"{artifact['source']} "
                                    f"({_hash_mismatch_context(actual_source_hash, source_hash)})"
                                ),
                                location=SourceLocation(file=str(artifact["source"])),
                                **_artifact_diagnostic_context(artifact),
                                missing_capabilities=["source.provenance"],
                            )
                        )
                    else:
                        source_hash_status = "ok"
                if validate_source_size:
                    actual_source_size = source_path.stat().st_size
                    if source_size != actual_source_size:
                        source_size_status = "mismatch"
                        diagnostics.append(
                            ProjectDiagnostic(
                                severity="error",
                                code="project.validate.source-size-mismatch",
                                message=(
                                    "Source artifact size does not match report: "
                                    f"{artifact['source']} "
                                    f"({_size_mismatch_context(source_size, actual_source_size)})"
                                ),
                                location=SourceLocation(file=str(artifact["source"])),
                                **_artifact_diagnostic_context(artifact),
                                missing_capabilities=["source.provenance"],
                            )
                        )
                    else:
                        source_size_status = "ok"
        if (
            artifact_inside_project
            and not exists
            and artifact.get("status") == "translated"
        ):
            diagnostics.append(
                ProjectDiagnostic(
                    severity="error",
                    code="project.validate.missing-artifact",
                    message=f"Expected translated artifact is missing: {artifact['path']}",
                    location=SourceLocation(file=str(artifact["source"])),
                    **_artifact_diagnostic_context(artifact),
                    missing_capabilities=["artifact.manifest"],
                )
            )
        generated_hash_status = (
            "not-recorded"
            if artifact.get("status") == "translated"
            else "not-applicable"
        )
        generated_size_status = generated_hash_status
        generated_hash = artifact.get("generatedHash")
        generated_size = artifact.get("generatedSizeBytes")
        source_remap_diagnostics: list[ProjectDiagnostic] = []
        source_map_diagnostics: list[ProjectDiagnostic] = []
        subgroup_width_diagnostics: list[ProjectDiagnostic] = []
        if artifact.get("status") == "translated":
            if not artifact_inside_project:
                generated_hash_status = "outside-project"
                generated_size_status = "outside-project"
            elif not exists:
                generated_hash_status = "missing"
                generated_size_status = "missing"
            elif isinstance(generated_hash, Mapping):
                actual_hash = _source_hash(artifact_path)
                if not _hash_matches_report(actual_hash, generated_hash):
                    generated_hash_status = "mismatch"
                    diagnostics.append(
                        ProjectDiagnostic(
                            severity="error",
                            code="project.validate.generated-hash-mismatch",
                            message=(
                                "Generated artifact hash does not match report: "
                                f"{artifact['path']} "
                                f"({_hash_mismatch_context(actual_hash, generated_hash)})"
                            ),
                            location=SourceLocation(file=str(artifact["source"])),
                            **_artifact_diagnostic_context(artifact),
                            missing_capabilities=["artifact.manifest"],
                        )
                    )
                else:
                    generated_hash_status = "ok"
            if exists and _is_non_negative_int(generated_size):
                actual_size = artifact_path.stat().st_size
                if generated_size != actual_size:
                    generated_size_status = "mismatch"
                    diagnostics.append(
                        ProjectDiagnostic(
                            severity="error",
                            code="project.validate.generated-size-mismatch",
                            message=(
                                "Generated artifact size does not match report: "
                                f"{artifact['path']} "
                                f"({_size_mismatch_context(generated_size, actual_size)})"
                            ),
                            location=SourceLocation(file=str(artifact["source"])),
                            **_artifact_diagnostic_context(artifact),
                            missing_capabilities=["artifact.manifest"],
                        )
                    )
                else:
                    generated_size_status = "ok"
            source_remap_diagnostics = _source_remap_validation_diagnostics(
                artifact, config
            )
            diagnostics.extend(source_remap_diagnostics)
            source_map_diagnostics = _source_map_file_span_validation_diagnostics(
                artifact,
                config,
                artifact_path,
                source_hash_status=source_hash_status,
                generated_hash_status=generated_hash_status,
            )
            diagnostics.extend(source_map_diagnostics)
            if exists and generated_hash_status in {"ok", "not-recorded"}:
                subgroup_width_diagnostics = (
                    _subgroup_width_target_validation_diagnostics(
                        artifact,
                        artifact_path,
                    )
                )
                diagnostics.extend(subgroup_width_diagnostics)
        source_map_status = _source_map_validation_status(
            artifact,
            source_hash_status=source_hash_status,
            generated_hash_status=generated_hash_status,
            source_map_diagnostics=source_map_diagnostics,
        )
        source_remap_status = _source_remap_validation_status(
            artifact,
            source_remap_diagnostics,
        )
        if artifact.get("status") == "failed":
            error = str(artifact.get("error", "")).strip()
            message = (
                f"Artifact translation failed before validation: {artifact['path']}"
            )
            if error:
                message = f"{message}: {error}"
            diagnostics.append(
                ProjectDiagnostic(
                    severity="error",
                    code="project.validate.failed-artifact",
                    message=message,
                    location=SourceLocation(file=str(artifact["source"])),
                    **_artifact_diagnostic_context(artifact),
                    missing_capabilities=["batch.translation"],
                )
            )
        artifact_check = {
            "source": artifact["source"],
            "target": artifact["target"],
            "path": artifact["path"],
            "exists": exists,
            "status": (
                "ok"
                if artifact_inside_project
                and exists
                and artifact.get("status") == "translated"
                and source_hash_status in {"ok", "not-recorded"}
                and source_size_status in {"ok", "not-recorded"}
                and generated_hash_status in {"ok", "not-recorded"}
                and generated_size_status in {"ok", "not-recorded"}
                and not source_remap_diagnostics
                and not source_map_diagnostics
                and not subgroup_width_diagnostics
                else "failed"
            ),
            "sourceHashStatus": source_hash_status,
            "sourceSizeStatus": source_size_status,
            "generatedHashStatus": generated_hash_status,
            "generatedSizeStatus": generated_size_status,
            "sourceMapStatus": source_map_status,
            "sourceRemapStatus": source_remap_status,
        }
        if artifact.get("variant") is not None:
            artifact_check["variant"] = artifact["variant"]
        if artifact.get("sourceBackend") is not None:
            artifact_check["sourceBackend"] = artifact["sourceBackend"]
        if artifact.get("stage") is not None:
            artifact_check["stage"] = artifact["stage"]
        if isinstance(artifact.get("entryPoint"), Mapping):
            artifact_check["entryPoint"] = dict(artifact["entryPoint"])
        artifact_checks.append(artifact_check)

    for toolchain in toolchains:
        if toolchain["status"] == "unavailable":
            diagnostics.append(
                ProjectDiagnostic(
                    severity="warning",
                    code="project.validate.toolchain-unavailable",
                    message=f"No validation toolchain is available for target {toolchain['target']}",
                    location=_config_location(config),
                    target=toolchain["target"],
                    missing_capabilities=["toolchain.validation"],
                )
            )

    return {
        "toolchains": toolchains,
        "artifacts": artifact_checks,
        "summary": _validation_summary(artifact_checks),
        "_diagnostics": diagnostics,
    }


def validate_project_report(
    report_path: str | os.PathLike[str], *, run_toolchains: bool = False
) -> dict[str, Any]:
    """Validate artifact existence and optional toolchain availability for a report."""
    run_toolchains = _bool_arg(run_toolchains, field_name="run_toolchains")
    path = _filesystem_path_arg(report_path, field_name="Project report path")
    try:
        report = json.loads(path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError) as exc:
        diagnostic = _invalid_report_diagnostic(
            path, [f"could not read JSON report: {exc}"]
        )
        return _validation_report_payload(
            path,
            [diagnostic.to_json()],
            {"toolchains": [], "artifacts": []},
        )

    contract_diagnostics = _report_contract_diagnostics(path, report)
    if contract_diagnostics:
        diagnostics = [diagnostic.to_json() for diagnostic in contract_diagnostics]
        return _validation_report_payload(
            path,
            diagnostics,
            {"toolchains": [], "artifacts": []},
            project=report.get("project") if isinstance(report, Mapping) else None,
        )

    root = Path(report["project"]["root"])
    targets = report["project"].get("targets", [])
    config = ProjectConfig(
        root=root, output_dir=report["project"].get("outputDir", DEFAULT_OUTPUT_DIR)
    )
    validation = _validate_artifacts(report.get("artifacts", []), targets, config)
    if run_toolchains:
        toolchain_runs = _run_toolchain_smoke(report.get("artifacts", []), root)
        validation["toolchainRuns"] = toolchain_runs
        validation["_diagnostics"].extend(_toolchain_run_diagnostics(toolchain_runs))
    diagnostic_objects = validation.pop("_diagnostics", [])
    source_diagnostics = [
        dict(diagnostic)
        for diagnostic in report.get("diagnostics", [])
        if isinstance(diagnostic, Mapping)
    ]
    diagnostic_objects.extend(
        _missing_generated_placeholder_diagnostics(
            _record_sequence(report.get("artifacts", [])),
            config,
            source_diagnostics,
        )
    )
    diagnostics = _validation_diagnostics(
        source_diagnostics,
        [diagnostic.to_json() for diagnostic in diagnostic_objects],
    )
    return _validation_report_payload(
        path, diagnostics, validation, project=report.get("project")
    )


def _diagnostic_identity_value(value: Any) -> Any:
    if isinstance(value, Mapping):
        return tuple(
            (str(key), _diagnostic_identity_value(value[key]))
            for key in sorted(value, key=str)
        )
    if isinstance(value, Sequence) and not isinstance(value, (str, bytes, bytearray)):
        return tuple(_diagnostic_identity_value(item) for item in value)
    return value


def _diagnostic_identity(diagnostic: Mapping[str, Any]) -> tuple[Any, ...]:
    return tuple(
        (field_name, _diagnostic_identity_value(diagnostic.get(field_name)))
        for field_name in (
            "severity",
            "code",
            "message",
            "location",
            "target",
            "sourceBackend",
            "variant",
            "checkKind",
            "missingCapabilities",
            "details",
        )
    )


def _validation_diagnostics(
    source_diagnostics: Sequence[Mapping[str, Any]],
    generated_diagnostics: Sequence[Mapping[str, Any]],
) -> list[dict[str, Any]]:
    diagnostics = [dict(diagnostic) for diagnostic in source_diagnostics]
    seen_identities = {
        _diagnostic_identity(diagnostic) for diagnostic in source_diagnostics
    }
    for diagnostic in generated_diagnostics:
        identity = _diagnostic_identity(diagnostic)
        if identity in seen_identities:
            continue
        diagnostics.append(dict(diagnostic))
        seen_identities.add(identity)
    return diagnostics


def _inspection_external_corpus_entry(entry: Mapping[str, Any]) -> dict[str, Any]:
    payload: dict[str, Any] = {}
    for field_name in (
        "id",
        "path",
        "sourceBackend",
        "repository",
        "commit",
        "sourceUrl",
    ):
        value = entry.get(field_name)
        if isinstance(value, str):
            payload[field_name] = value
    targets = entry.get("targets")
    if isinstance(targets, list):
        payload["targets"] = [target for target in targets if isinstance(target, str)]
    return payload


def _inspection_external_corpus_sample(
    entries: Sequence[Any],
    *,
    present: bool,
    discovered: bool,
    limit: int = EXTERNAL_CORPUS_INSPECTION_SAMPLE_LIMIT,
) -> tuple[list[dict[str, Any]], int, int]:
    sampled_entries = [
        _inspection_external_corpus_entry(entry)
        for entry in entries
        if isinstance(entry, Mapping)
        and entry.get("present") is present
        and entry.get("discovered") is discovered
    ]
    return (
        sampled_entries[:limit],
        len(sampled_entries),
        max(0, len(sampled_entries) - limit),
    )


def _inspection_migration_action(action: Any) -> dict[str, Any] | None:
    if not isinstance(action, Mapping):
        return None

    payload: dict[str, Any] = {}
    for field_name in ("kind", "severity", "message"):
        value = action.get(field_name)
        if isinstance(value, str):
            payload[field_name] = value

    targets = action.get("targets")
    if isinstance(targets, list):
        payload["targets"] = [target for target in targets if isinstance(target, str)]
    runtime_references = action.get("runtimeReferences")
    if isinstance(runtime_references, list):
        payload["runtimeReferenceCount"] = len(runtime_references)
    return payload


def _empty_inspection_migration_summary() -> dict[str, Any]:
    return {
        "scope": None,
        "nonGoals": [],
        "actionCount": 0,
        "actionsByKind": {},
        "actionsBySeverity": {},
        "actionsByTarget": {},
        "runtimeReferenceCount": 0,
        "runtimeReferencesByBackend": {},
        "runtimeReferencesByKind": {},
        "runtimeReferencesByPath": {},
        "placeholderCount": 0,
        "placeholdersByTarget": {},
        "placeholdersBySource": {},
        "truncatedRuntimeReferenceCount": 0,
        "runtimeReferences": [],
        "truncatedActionCount": 0,
        "actions": [],
    }


def inspect_project_report(
    report_path: str | os.PathLike[str],
    *,
    run_toolchains: bool = False,
    max_diagnostics: int = 20,
    max_failed_artifacts: int = 20,
    max_source_map_artifacts: int = SOURCE_MAP_INSPECTION_SAMPLE_LIMIT,
    max_artifact_matrix_artifacts: int = ARTIFACT_MATRIX_INSPECTION_SAMPLE_LIMIT,
    max_artifact_provenance_artifacts: int = (
        ARTIFACT_PROVENANCE_INSPECTION_SAMPLE_LIMIT
    ),
    max_define_processing_artifacts: int = DEFINE_PROCESSING_INSPECTION_SAMPLE_LIMIT,
    max_skipped_sources: int = SKIPPED_SOURCE_INSPECTION_SAMPLE_LIMIT,
    max_include_path_processing_artifacts: int = (
        INCLUDE_PATH_PROCESSING_INSPECTION_SAMPLE_LIMIT
    ),
    max_include_dependencies: int = INCLUDE_DEPENDENCY_INSPECTION_SAMPLE_LIMIT,
    max_validation_artifacts: int = VALIDATION_INSPECTION_SAMPLE_LIMIT,
    max_toolchain_runs: int = VALIDATION_INSPECTION_SAMPLE_LIMIT,
    max_migration_actions: int = MIGRATION_ACTION_INSPECTION_SAMPLE_LIMIT,
    max_runtime_references: int = RUNTIME_REFERENCE_INSPECTION_SAMPLE_LIMIT,
    max_external_corpus_entries: int = EXTERNAL_CORPUS_INSPECTION_SAMPLE_LIMIT,
) -> dict[str, Any]:
    """Build a concise inspection summary for a project portability report."""
    run_toolchains = _bool_arg(run_toolchains, field_name="run_toolchains")
    path = _filesystem_path_arg(report_path, field_name="Project report path")
    validation_report = validate_project_report(path, run_toolchains=run_toolchains)
    diagnostic_limit = _inspection_limit_arg(
        max_diagnostics, field_name="max_diagnostics"
    )
    failed_artifact_limit = _inspection_limit_arg(
        max_failed_artifacts, field_name="max_failed_artifacts"
    )
    source_map_artifact_limit = _inspection_limit_arg(
        max_source_map_artifacts, field_name="max_source_map_artifacts"
    )
    artifact_matrix_artifact_limit = _inspection_limit_arg(
        max_artifact_matrix_artifacts, field_name="max_artifact_matrix_artifacts"
    )
    artifact_provenance_artifact_limit = _inspection_limit_arg(
        max_artifact_provenance_artifacts,
        field_name="max_artifact_provenance_artifacts",
    )
    define_processing_artifact_limit = _inspection_limit_arg(
        max_define_processing_artifacts,
        field_name="max_define_processing_artifacts",
    )
    skipped_source_limit = _inspection_limit_arg(
        max_skipped_sources, field_name="max_skipped_sources"
    )
    include_path_processing_artifact_limit = _inspection_limit_arg(
        max_include_path_processing_artifacts,
        field_name="max_include_path_processing_artifacts",
    )
    include_dependency_limit = _inspection_limit_arg(
        max_include_dependencies, field_name="max_include_dependencies"
    )
    validation_artifact_limit = _inspection_limit_arg(
        max_validation_artifacts, field_name="max_validation_artifacts"
    )
    toolchain_run_limit = _inspection_limit_arg(
        max_toolchain_runs, field_name="max_toolchain_runs"
    )
    migration_action_limit = _inspection_limit_arg(
        max_migration_actions, field_name="max_migration_actions"
    )
    runtime_reference_limit = _inspection_limit_arg(
        max_runtime_references, field_name="max_runtime_references"
    )
    external_corpus_entry_limit = _inspection_limit_arg(
        max_external_corpus_entries, field_name="max_external_corpus_entries"
    )
    diagnostics = list(validation_report.get("diagnostics", []))
    validation_result = validation_report.get("validation", {})
    validation_toolchains = (
        validation_result.get("toolchains")
        if isinstance(validation_result, Mapping)
        else []
    )
    validation_artifacts = (
        validation_result.get("artifacts")
        if isinstance(validation_result, Mapping)
        else []
    )
    validation_toolchain_runs = (
        validation_result.get("toolchainRuns")
        if isinstance(validation_result, Mapping)
        else []
    )
    artifact_status_by_target = validation_report.get("artifactStatusByTarget")
    artifact_status_by_source_backend = validation_report.get(
        "artifactStatusBySourceBackend"
    )
    artifact_status_by_variant = validation_report.get("artifactStatusByVariant")
    toolchain_status_counts = validation_report.get("toolchainStatusCounts")
    toolchain_run_status_counts = validation_report.get("toolchainRunStatusCounts")
    toolchain_run_status_by_target = validation_report.get("toolchainRunStatusByTarget")
    toolchain_run_status_by_source_backend = validation_report.get(
        "toolchainRunStatusBySourceBackend"
    )
    toolchain_run_status_by_check_kind = validation_report.get(
        "toolchainRunStatusByCheckKind"
    )
    toolchain_run_status_by_tool = validation_report.get("toolchainRunStatusByTool")
    toolchain_run_status_by_variant = validation_report.get(
        "toolchainRunStatusByVariant"
    )
    validation_artifact_samples = [
        sample
        for artifact in _record_sequence(validation_artifacts)
        for sample in (_inspection_validation_artifact(artifact),)
        if sample is not None
    ]
    validation_toolchain_run_samples = [
        sample
        for run in _record_sequence(validation_toolchain_runs)
        for sample in (_inspection_validation_toolchain_run(run),)
        if sample is not None
    ]
    payload: dict[str, Any] = {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": REPORT_INSPECTION_KIND,
        "sourceReport": str(path),
        "sourceReportHash": _optional_source_hash(path),
        "generatedAt": int(time.time()),
        "success": bool(validation_report.get("success")),
        "report": {"available": False, "valid": False},
        "sourceMaps": {"available": False},
        "artifactProvenance": {"available": False},
        "defineProcessing": {"available": False},
        "skippedSources": {"available": False},
        "includeDependencies": {"available": False},
        "includePathProcessing": {"available": False},
        "includeDependencyProcessing": {"available": False},
        "artifactMatrix": {"available": False},
        "migration": _empty_inspection_migration_summary(),
        "externalCorpus": {"available": False},
        "diagnosticCount": len(diagnostics),
        "truncatedDiagnosticCount": max(0, len(diagnostics) - diagnostic_limit),
        "failedArtifactCount": 0,
        "truncatedFailedArtifactCount": 0,
        "failedArtifacts": [],
        "diagnostics": diagnostics[:diagnostic_limit],
        "validation": {
            "success": bool(validation_report.get("success")),
            "diagnosticCounts": dict(validation_report.get("diagnosticCounts", {})),
            "diagnosticsByCode": dict(validation_report.get("diagnosticsByCode", {})),
            "diagnosticsByTarget": dict(
                validation_report.get("diagnosticsByTarget", {})
            ),
            "diagnosticsBySourceBackend": dict(
                validation_report.get("diagnosticsBySourceBackend", {})
            ),
            "diagnosticsByVariant": dict(
                validation_report.get("diagnosticsByVariant", {})
            ),
            "diagnosticsByCheckKind": dict(
                validation_report.get("diagnosticsByCheckKind", {})
            ),
            "missingCapabilityCounts": dict(
                validation_report.get("missingCapabilityCounts", {})
            ),
            "artifactStatusByTarget": (
                dict(artifact_status_by_target)
                if isinstance(artifact_status_by_target, Mapping)
                else _validation_artifact_status_by_target(
                    _record_sequence(validation_artifacts)
                )
            ),
            "artifactStatusBySourceBackend": (
                dict(artifact_status_by_source_backend)
                if isinstance(artifact_status_by_source_backend, Mapping)
                else _validation_artifact_status_by_source_backend(
                    _record_sequence(validation_artifacts)
                )
            ),
            "artifactStatusByVariant": (
                dict(artifact_status_by_variant)
                if isinstance(artifact_status_by_variant, Mapping)
                else _validation_artifact_status_by_variant(
                    _record_sequence(validation_artifacts)
                )
            ),
            "sourceHashStatusCounts": dict(
                validation_report.get("sourceHashStatusCounts", {})
            ),
            "sourceSizeStatusCounts": dict(
                validation_report.get("sourceSizeStatusCounts", {})
            ),
            "generatedHashStatusCounts": dict(
                validation_report.get("generatedHashStatusCounts", {})
            ),
            "generatedSizeStatusCounts": dict(
                validation_report.get("generatedSizeStatusCounts", {})
            ),
            "sourceMapStatusCounts": dict(
                validation_report.get("sourceMapStatusCounts", {})
            ),
            "sourceRemapStatusCounts": dict(
                validation_report.get("sourceRemapStatusCounts", {})
            ),
            "toolchainStatusCounts": (
                dict(toolchain_status_counts)
                if isinstance(toolchain_status_counts, Mapping)
                else _validation_toolchain_status_counts(
                    _record_sequence(validation_toolchains)
                )
            ),
            "toolchainRunStatusCounts": (
                dict(toolchain_run_status_counts)
                if isinstance(toolchain_run_status_counts, Mapping)
                else _validation_toolchain_run_status_counts(
                    _record_sequence(validation_toolchain_runs)
                )
            ),
            "toolchainRunStatusByTarget": (
                dict(toolchain_run_status_by_target)
                if isinstance(toolchain_run_status_by_target, Mapping)
                else _validation_toolchain_run_status_by_target(
                    _record_sequence(validation_toolchain_runs)
                )
            ),
            "toolchainRunStatusBySourceBackend": (
                dict(toolchain_run_status_by_source_backend)
                if isinstance(toolchain_run_status_by_source_backend, Mapping)
                else _validation_toolchain_run_status_by_source_backend(
                    _record_sequence(validation_toolchain_runs)
                )
            ),
            "toolchainRunStatusByCheckKind": (
                dict(toolchain_run_status_by_check_kind)
                if isinstance(toolchain_run_status_by_check_kind, Mapping)
                else _validation_toolchain_run_status_by_check_kind(
                    _record_sequence(validation_toolchain_runs)
                )
            ),
            "toolchainRunStatusByTool": (
                dict(toolchain_run_status_by_tool)
                if isinstance(toolchain_run_status_by_tool, Mapping)
                else _validation_toolchain_run_status_by_tool(
                    _record_sequence(validation_toolchain_runs)
                )
            ),
            "toolchainRunStatusByVariant": (
                dict(toolchain_run_status_by_variant)
                if isinstance(toolchain_run_status_by_variant, Mapping)
                else _validation_toolchain_run_status_by_variant(
                    _record_sequence(validation_toolchain_runs)
                )
            ),
            "artifactCount": len(validation_artifact_samples),
            "truncatedArtifactCount": max(
                0,
                len(validation_artifact_samples) - validation_artifact_limit,
            ),
            "artifacts": validation_artifact_samples[:validation_artifact_limit],
            "toolchainRunCount": len(validation_toolchain_run_samples),
            "truncatedToolchainRunCount": max(
                0,
                len(validation_toolchain_run_samples) - toolchain_run_limit,
            ),
            "toolchainRuns": validation_toolchain_run_samples[:toolchain_run_limit],
            "result": (
                dict(validation_result)
                if isinstance(validation_result, Mapping)
                else {}
            ),
        },
    }

    try:
        report = json.loads(path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return payload
    if not isinstance(report, Mapping):
        return payload

    summary = report.get("summary")
    project = report.get("project")
    generator = report.get("generator")
    validation_codes = validation_report.get("diagnosticsByCode", {})
    report_is_valid = not (
        isinstance(validation_codes, Mapping)
        and validation_codes.get("project.validate.invalid-report", 0)
    )
    payload["report"] = {
        "available": True,
        "valid": report_is_valid,
        "schemaVersion": report.get("schemaVersion"),
        "kind": report.get("kind"),
        "generatedAt": report.get("generatedAt"),
        "generator": dict(generator) if isinstance(generator, Mapping) else {},
        "project": _inspection_project_summary(project),
        "summary": dict(summary) if isinstance(summary, Mapping) else {},
    }
    payload["sourceMaps"] = _inspection_source_map_summary(
        summary,
        report.get("artifacts"),
        validation_artifacts=validation_artifacts,
        sample_limit=source_map_artifact_limit,
    )
    payload["artifactProvenance"] = _inspection_artifact_provenance_summary(
        summary,
        report.get("artifacts"),
        validation_artifacts=validation_artifacts,
        sample_limit=artifact_provenance_artifact_limit,
    )
    payload["defineProcessing"] = _inspection_define_processing_summary(
        summary,
        report.get("artifacts"),
        project=project,
        sample_limit=define_processing_artifact_limit,
    )
    payload["skippedSources"] = _inspection_skipped_source_summary(
        summary,
        report.get("skipped"),
        sample_limit=skipped_source_limit,
    )
    payload["includeDependencies"] = _inspection_include_dependency_summary(
        summary,
        report.get("units"),
        project=project,
        sample_limit=include_dependency_limit,
    )
    payload["includePathProcessing"] = _inspection_include_path_processing_summary(
        summary,
        report.get("artifacts"),
        project=project,
        sample_limit=include_path_processing_artifact_limit,
    )
    payload["includeDependencyProcessing"] = (
        _inspection_include_dependency_processing_summary(
            summary,
            report.get("artifacts"),
            sample_limit=include_path_processing_artifact_limit,
        )
    )
    payload["artifactMatrix"] = _inspection_artifact_matrix_summary(
        report.get("artifactMatrix"),
        report.get("artifacts"),
        project=project,
        units=report.get("units"),
        sample_limit=artifact_matrix_artifact_limit,
    )

    artifacts = report.get("artifacts", [])
    failed_artifacts_by_key: dict[tuple[Any, ...], dict[str, Any]] = {}
    if isinstance(artifacts, Sequence) and not isinstance(
        artifacts, (str, bytes, bytearray)
    ):
        for artifact in artifacts:
            if not isinstance(artifact, Mapping) or artifact.get("status") != "failed":
                continue
            failed = _inspection_failed_artifact(artifact)
            failed_artifacts_by_key[_inspection_failed_artifact_key(failed)] = failed

    validation_result = validation_report.get("validation", {})
    validation_artifacts = (
        validation_result.get("artifacts")
        if isinstance(validation_result, Mapping)
        else None
    )
    if isinstance(validation_artifacts, Sequence) and not isinstance(
        validation_artifacts, (str, bytes, bytearray)
    ):
        for artifact in validation_artifacts:
            if not isinstance(artifact, Mapping) or artifact.get("status") != "failed":
                continue
            failed = _inspection_failed_artifact(artifact)
            failed["validationStatus"] = "failed"
            key = _inspection_failed_artifact_key(failed)
            existing = failed_artifacts_by_key.get(key)
            if existing:
                existing.update(
                    {
                        field_name: failed[field_name]
                        for field_name in (
                            "exists",
                            "sourceBackend",
                            "sourceHashStatus",
                            "sourceSizeStatus",
                            "generatedHashStatus",
                            "generatedSizeStatus",
                            "sourceMapStatus",
                            "sourceRemapStatus",
                            "validationStatus",
                        )
                        if field_name in failed
                    }
                )
            else:
                failed_artifacts_by_key[key] = failed
    failed_artifacts = list(failed_artifacts_by_key.values())
    payload["failedArtifactCount"] = len(failed_artifacts)
    payload["truncatedFailedArtifactCount"] = max(
        0, len(failed_artifacts) - failed_artifact_limit
    )
    payload["failedArtifacts"] = failed_artifacts[:failed_artifact_limit]

    migration = report.get("migration")
    if isinstance(migration, Mapping):
        actions = (
            list(migration.get("actions", []))
            if isinstance(migration.get("actions"), list)
            else []
        )
        action_samples = [
            sample
            for action in actions
            if (sample := _inspection_migration_action(action)) is not None
        ]
        runtime_reference_rollups = _migration_runtime_reference_rollups(actions)
        runtime_references = [
            dict(reference) for reference in _migration_runtime_references(actions)
        ]
        placeholder_rollups = _migration_placeholder_rollups(
            _record_sequence(report.get("diagnostics", []))
        )
        payload["migration"] = {
            "scope": migration.get("scope"),
            "nonGoals": (
                list(migration.get("nonGoals", []))
                if isinstance(migration.get("nonGoals"), list)
                else []
            ),
            "actionCount": (
                migration.get("actionCount")
                if _is_non_negative_int(migration.get("actionCount"))
                else len(actions)
            ),
            "actionsByKind": (
                dict(migration.get("actionsByKind", {}))
                if isinstance(migration.get("actionsByKind"), Mapping)
                else _migration_action_counts_by_kind(actions)
            ),
            "actionsBySeverity": (
                dict(migration.get("actionsBySeverity", {}))
                if isinstance(migration.get("actionsBySeverity"), Mapping)
                else _migration_action_counts_by_severity(actions)
            ),
            "actionsByTarget": (
                dict(migration.get("actionsByTarget", {}))
                if isinstance(migration.get("actionsByTarget"), Mapping)
                else _migration_action_counts_by_target(actions)
            ),
            "runtimeReferenceCount": (
                migration.get("runtimeReferenceCount")
                if _is_non_negative_int(migration.get("runtimeReferenceCount"))
                else runtime_reference_rollups["runtimeReferenceCount"]
            ),
            "runtimeReferencesByBackend": (
                dict(migration.get("runtimeReferencesByBackend", {}))
                if isinstance(migration.get("runtimeReferencesByBackend"), Mapping)
                else runtime_reference_rollups["runtimeReferencesByBackend"]
            ),
            "runtimeReferencesByKind": (
                dict(migration.get("runtimeReferencesByKind", {}))
                if isinstance(migration.get("runtimeReferencesByKind"), Mapping)
                else runtime_reference_rollups["runtimeReferencesByKind"]
            ),
            "runtimeReferencesByPath": (
                dict(migration.get("runtimeReferencesByPath", {}))
                if isinstance(migration.get("runtimeReferencesByPath"), Mapping)
                else runtime_reference_rollups["runtimeReferencesByPath"]
            ),
            "placeholderCount": (
                migration.get("placeholderCount")
                if _is_non_negative_int(migration.get("placeholderCount"))
                else placeholder_rollups["placeholderCount"]
            ),
            "placeholdersByTarget": (
                dict(migration.get("placeholdersByTarget", {}))
                if isinstance(migration.get("placeholdersByTarget"), Mapping)
                else placeholder_rollups["placeholdersByTarget"]
            ),
            "placeholdersBySource": (
                dict(migration.get("placeholdersBySource", {}))
                if isinstance(migration.get("placeholdersBySource"), Mapping)
                else placeholder_rollups["placeholdersBySource"]
            ),
            "truncatedRuntimeReferenceCount": max(
                0,
                len(runtime_references) - runtime_reference_limit,
            ),
            "runtimeReferences": runtime_references[:runtime_reference_limit],
            "truncatedActionCount": max(
                0,
                len(action_samples) - migration_action_limit,
            ),
            "actions": action_samples[:migration_action_limit],
        }

    external_corpus = report.get("externalCorpus")
    if isinstance(external_corpus, Mapping):
        external_summary = external_corpus.get("summary")
        external_entries = _record_sequence(external_corpus.get("entries"))
        missing_entries, missing_entry_count, truncated_missing_entry_count = (
            _inspection_external_corpus_sample(
                external_entries,
                present=False,
                discovered=False,
                limit=external_corpus_entry_limit,
            )
        )
        undiscovered_entries, undiscovered_entry_count, truncated_undiscovered_count = (
            _inspection_external_corpus_sample(
                external_entries,
                present=True,
                discovered=False,
                limit=external_corpus_entry_limit,
            )
        )
        external_corpus_payload = {
            "available": True,
            "status": external_corpus.get("status"),
            "summary": (
                dict(external_summary) if isinstance(external_summary, Mapping) else {}
            ),
            "missingEntryCount": missing_entry_count,
            "truncatedMissingEntryCount": truncated_missing_entry_count,
            "missingEntries": missing_entries,
            "undiscoveredPresentEntryCount": undiscovered_entry_count,
            "truncatedUndiscoveredPresentEntryCount": truncated_undiscovered_count,
            "undiscoveredPresentEntries": undiscovered_entries,
        }
        for field_name in ("manifest", "name"):
            value = external_corpus.get(field_name)
            if isinstance(value, str):
                external_corpus_payload[field_name] = value
        payload["externalCorpus"] = external_corpus_payload
    return payload


def _runtime_plan_project(project: Any) -> dict[str, Any]:
    project = project if isinstance(project, Mapping) else {}
    targets = project.get("targets", [])
    payload = {
        "root": project.get("root"),
        "targets": (
            [target for target in targets if isinstance(target, str)]
            if isinstance(targets, list)
            else []
        ),
        "outputDir": project.get("outputDir"),
    }
    entry_point_selections = project.get("entryPointSelections")
    if isinstance(entry_point_selections, Mapping):
        payload["entryPointSelections"] = dict(entry_point_selections)
    if _is_non_negative_int(project.get("entryPointSelectionCount")):
        payload["entryPointSelectionCount"] = project["entryPointSelectionCount"]
    return payload


def _runtime_plan_artifact_counts(
    artifacts: Sequence[Any], target: str
) -> tuple[int, int, int]:
    artifact_count = 0
    translated_count = 0
    failed_count = 0
    for artifact in artifacts:
        if not isinstance(artifact, Mapping) or artifact.get("target") != target:
            continue
        artifact_count += 1
        if artifact.get("status") == "translated":
            translated_count += 1
        elif artifact.get("status") == "failed":
            failed_count += 1
    return artifact_count, translated_count, failed_count


def _runtime_plan_compiler_contract() -> dict[str, Any]:
    return {
        "name": RUNTIME_LOADER_PLAN_CONTRACT,
        "status": "requested",
        "issue": RUNTIME_LOADER_PLAN_CONTRACT_ISSUE,
        "metadataOnly": True,
        "deviceExecutionRequired": False,
        "compilerInvocationRequired": False,
        "translatorDependency": "external-json-contract",
    }


def _runtime_plan_compiler_request(target: str) -> dict[str, Any]:
    return {
        "target": target,
        "status": "blocked-until-contract-available",
        "contract": RUNTIME_LOADER_PLAN_CONTRACT,
        "metadataOnly": True,
        "deviceExecutionRequired": False,
        "packageMode": "auto",
        "command": [
            "cglc",
            "package",
            "plan-runtime",
            "<package.cglb>",
            "--target",
            target,
            "--package-mode",
            "auto",
            "--json",
        ],
    }


def _runtime_plan_target(
    target: str, artifacts: Sequence[Any], runtime_reference_count: int
) -> dict[str, Any]:
    artifact_count, translated_count, failed_count = _runtime_plan_artifact_counts(
        artifacts, target
    )
    return {
        "target": target,
        "artifactCount": artifact_count,
        "translatedArtifactCount": translated_count,
        "failedArtifactCount": failed_count,
        "runtimeReferenceCount": runtime_reference_count,
        "compilerRequestStatus": "blocked-until-contract-available",
        "compilerContract": RUNTIME_LOADER_PLAN_CONTRACT,
    }


def _runtime_plan_action_for_reference(
    reference: Mapping[str, Any], targets: Sequence[str]
) -> dict[str, Any]:
    backend = reference.get("backend")
    kind = reference.get("kind")
    symbol = reference.get("symbol")
    target_label = ", ".join(targets) if targets else "requested targets"
    message = (
        f"Review {backend or 'unknown'} {kind or 'runtime'} reference "
        f"{symbol or '<unknown>'} before consuming {target_label} runtime setup."
    )
    return {
        "kind": "review-runtime-reference",
        "severity": "note",
        "message": message,
        "targets": list(targets),
        "runtimeReference": {
            "path": reference.get("path"),
            "line": reference.get("line"),
            "column": reference.get("column"),
            "backend": backend,
            "kind": kind,
            "symbol": symbol,
        },
    }


def _runtime_plan_compiler_request_action(target: str) -> dict[str, Any]:
    return {
        "kind": "request-compiler-loader-plan",
        "severity": "note",
        "message": (
            "Generate or attach a metadata-only compiler runtime loader plan "
            f"for {target} once the stable compiler contract is available."
        ),
        "targets": [target],
    }


def plan_runtime_integration(
    report_path: str | os.PathLike[str],
    *,
    max_runtime_references: int = RUNTIME_REFERENCE_INSPECTION_SAMPLE_LIMIT,
) -> dict[str, Any]:
    """Build a metadata-only runtime integration plan from a project report."""

    runtime_reference_limit = _inspection_limit_arg(
        max_runtime_references, field_name="max_runtime_references"
    )
    path = _filesystem_path_arg(report_path, field_name="Project report path")
    validation_report = validate_project_report(path)
    validation_success = bool(validation_report.get("success"))
    try:
        report = json.loads(path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        report = {}

    report_mapping = (
        report if validation_success and isinstance(report, Mapping) else {}
    )
    project_payload = _runtime_plan_project(report_mapping.get("project"))
    targets = project_payload["targets"]
    artifacts = _record_sequence(report_mapping.get("artifacts"))
    migration = report_mapping.get("migration")
    actions = (
        _record_sequence(migration.get("actions"))
        if isinstance(migration, Mapping)
        else ()
    )
    runtime_reference_rollups = _migration_runtime_reference_rollups(actions)
    runtime_references = [
        dict(reference) for reference in _migration_runtime_references(actions)
    ]
    runtime_reference_count = runtime_reference_rollups["runtimeReferenceCount"]
    target_plans = [
        _runtime_plan_target(target, artifacts, runtime_reference_count)
        for target in targets
    ]
    compiler_requests = [_runtime_plan_compiler_request(target) for target in targets]
    plan_actions = [_runtime_plan_compiler_request_action(target) for target in targets]
    plan_actions.extend(
        _runtime_plan_action_for_reference(reference, targets)
        for reference in runtime_references
    )
    artifact_records = [
        artifact for artifact in artifacts if isinstance(artifact, Mapping)
    ]
    summary = {
        "targetCount": len(targets),
        "artifactCount": len(artifact_records),
        "translatedArtifactCount": sum(
            1 for artifact in artifact_records if artifact.get("status") == "translated"
        ),
        "failedArtifactCount": sum(
            1 for artifact in artifact_records if artifact.get("status") == "failed"
        ),
        "runtimeReferenceCount": runtime_reference_count,
        "actionCount": len(plan_actions),
        "compilerRequestCount": len(compiler_requests),
    }
    return {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": RUNTIME_INTEGRATION_PLAN_KIND,
        "sourceReport": str(path),
        "sourceReportHash": _optional_source_hash(path),
        "generatedAt": int(time.time()),
        "success": validation_success,
        "scope": RUNTIME_INTEGRATION_PLAN_SCOPE,
        "nonGoals": list(RUNTIME_INTEGRATION_PLAN_NON_GOALS),
        "compilerContract": _runtime_plan_compiler_contract(),
        "project": project_payload,
        "summary": summary,
        "runtimeReferencesByBackend": runtime_reference_rollups[
            "runtimeReferencesByBackend"
        ],
        "runtimeReferencesByKind": runtime_reference_rollups["runtimeReferencesByKind"],
        "runtimeReferencesByPath": runtime_reference_rollups["runtimeReferencesByPath"],
        "truncatedRuntimeReferenceCount": max(
            0, len(runtime_references) - runtime_reference_limit
        ),
        "runtimeReferences": runtime_references[:runtime_reference_limit],
        "targetPlans": target_plans,
        "compilerRequests": compiler_requests,
        "actions": plan_actions,
        "diagnosticCounts": validation_report.get("diagnosticCounts", {}),
        "diagnostics": validation_report.get("diagnostics", []),
    }


def _runtime_manifest_artifact_id(artifact: Mapping[str, Any]) -> str:
    variant = artifact.get("variant")
    variant_label = variant if isinstance(variant, str) and variant else "default"
    return "|".join(
        str(part)
        for part in (
            artifact.get("source", ""),
            artifact.get("target", ""),
            variant_label,
            artifact.get("path", ""),
        )
    )


def _runtime_manifest_source_host_interface(
    root_path: Path | None, artifact: Mapping[str, Any]
) -> dict[str, Any] | None:
    if root_path is None:
        return None
    source = artifact.get("source")
    source_backend = artifact.get("sourceBackend")
    if not (
        _is_non_empty_string(source)
        and _is_report_identity_path(source)
        and _is_non_empty_string(source_backend)
    ):
        return None

    try:
        register_default_sources()
        parser_name = SOURCE_REGISTRY.resolve_name(str(source_backend))
        source_spec = SOURCE_REGISTRY.get(parser_name)
    except Exception:
        return None

    source_path = (root_path / str(source)).resolve()
    if not _is_relative_to(source_path, root_path) or not source_path.is_file():
        return None

    try:
        ast = source_spec.parse(
            source_path.read_text(encoding="utf-8"),
            file_path=str(source_path),
        )
    except Exception:
        return None

    host_interface = _runtime_host_interface_from_ast(
        ast, parser=parser_name or "", source="source-artifact"
    )
    if (
        host_interface["entryPointCount"] == 0
        and host_interface["resourceCount"] == 0
        and host_interface.get("specializationConstantCount", 0) == 0
    ):
        return None
    target = artifact.get("target")
    if _is_non_empty_string(target) and _normalized_targets([str(target)])[0] == "wgsl":
        host_interface = _runtime_host_interface_for_wgsl_target(host_interface)
    return host_interface


def _runtime_manifest_reflected_host_interface(
    root_path: Path | None, artifact: Mapping[str, Any]
) -> dict[str, Any] | None:
    if root_path is None:
        return None
    target = artifact.get("target")
    path = artifact.get("path")
    if not (
        _is_non_empty_string(target)
        and _is_non_empty_string(path)
        and _is_report_identity_path(path)
    ):
        return None
    normalized_target = _normalized_targets([str(target)])[0]
    if normalized_target not in {"directx", "opengl", "webgl", "vulkan"}:
        return None
    artifact_path = (root_path / str(path)).resolve()
    if not _is_relative_to(artifact_path, root_path) or not artifact_path.is_file():
        return None
    catalog_entry = _runtime_adapter_catalog_entry(normalized_target)
    return reflect_target_host_interface(
        artifact_path,
        target=normalized_target,
        artifact_format=catalog_entry.get("artifactFormat"),
        stage=(
            str(artifact.get("stage"))
            if _is_non_empty_string(artifact.get("stage"))
            else None
        ),
    )


def _runtime_manifest_host_interface(
    root_path: Path | None, artifact: Mapping[str, Any]
) -> dict[str, Any] | None:
    reflected = _runtime_manifest_reflected_host_interface(root_path, artifact)
    source_interface = _runtime_manifest_source_host_interface(root_path, artifact)
    base = reflected if isinstance(reflected, Mapping) else source_interface
    if not isinstance(base, Mapping):
        return None
    return _runtime_manifest_merge_specialization_constants(
        base,
        source_interface=source_interface,
        artifact=artifact,
    )


def _runtime_specialization_constant_identity(
    constant: Mapping[str, Any],
) -> tuple[str, Any] | None:
    constant_id = constant.get("id", constant.get("constantId"))
    if constant_id is not None and not isinstance(constant_id, bool):
        return "id", constant_id
    name = constant.get("name")
    if _is_non_empty_string(name):
        return "name", name
    return None


def _runtime_merge_specialization_constant_records(
    *record_groups: Sequence[Mapping[str, Any]],
) -> list[dict[str, Any]]:
    records: list[dict[str, Any]] = []
    positions: dict[tuple[str, Any], int] = {}
    for group in record_groups:
        for constant in group:
            if not isinstance(constant, Mapping):
                continue
            payload = dict(constant)
            identity = _runtime_specialization_constant_identity(payload)
            if identity is None:
                continue
            position = positions.get(identity)
            if position is None:
                positions[identity] = len(records)
                records.append(payload)
                continue
            records[position] = {**records[position], **payload}
    return records


def _runtime_manifest_merge_specialization_constants(
    host_interface: Mapping[str, Any],
    *,
    source_interface: Mapping[str, Any] | None,
    artifact: Mapping[str, Any],
) -> dict[str, Any]:
    reflected_constants = [
        dict(constant)
        for constant in _record_sequence(host_interface.get("specializationConstants"))
        if isinstance(constant, Mapping)
    ]
    source_constants = [
        dict(constant)
        for constant in _record_sequence(
            source_interface.get("specializationConstants")
            if isinstance(source_interface, Mapping)
            else []
        )
        if isinstance(constant, Mapping)
    ]
    artifact_constants = [
        dict(constant)
        for constant in _record_sequence(artifact.get("specializationConstants"))
        if isinstance(constant, Mapping)
    ]
    specialization_constants = _runtime_merge_specialization_constant_records(
        reflected_constants,
        source_constants,
        artifact_constants,
    )
    if not specialization_constants:
        return dict(host_interface)
    source_contracts = {
        identity: constant
        for constant in _runtime_merge_specialization_constant_records(
            source_constants,
            artifact_constants,
        )
        if (identity := _runtime_specialization_constant_identity(constant)) is not None
    }
    for constant in specialization_constants:
        identity = _runtime_specialization_constant_identity(constant)
        contract = source_contracts.get(identity) if identity is not None else None
        if not isinstance(contract, Mapping) or contract.get("required") is not True:
            continue
        if "default" in contract or "defaultValue" in contract:
            continue
        constant.pop("default", None)
        constant.pop("defaultValue", None)

    specialization_names = {
        str(constant.get("name"))
        for constant in specialization_constants
        if _is_non_empty_string(constant.get("name"))
    }
    resources = [
        dict(resource)
        for resource in _record_sequence(host_interface.get("resources"))
        if isinstance(resource, Mapping)
        and resource.get("name") not in specialization_names
    ]
    constants = [
        dict(constant)
        for constant in _record_sequence(host_interface.get("constants"))
        if isinstance(constant, Mapping)
        and constant.get("name") not in specialization_names
    ]
    diagnostic_records = []
    for diagnostic in _record_sequence(host_interface.get("diagnosticRecords")):
        if not isinstance(diagnostic, Mapping):
            continue
        details = diagnostic.get("details")
        resource = details.get("resource") if isinstance(details, Mapping) else None
        conflicting = (
            details.get("conflictingResource") if isinstance(details, Mapping) else None
        )
        if resource in specialization_names or conflicting in specialization_names:
            continue
        diagnostic_records.append(dict(diagnostic))
    status = str(host_interface.get("status") or "ready")
    if status in {"ambiguous", "incomplete", "unavailable"} and not diagnostic_records:
        status = "ready"
    return host_interface_record(
        status=status,
        source=str(host_interface.get("source") or "compiled-artifact"),
        parser=(
            str(host_interface.get("parser"))
            if _is_non_empty_string(host_interface.get("parser"))
            else None
        ),
        artifact_format=(
            str(host_interface.get("artifactFormat"))
            if _is_non_empty_string(host_interface.get("artifactFormat"))
            else None
        ),
        entry_points=[
            dict(entry_point)
            for entry_point in _record_sequence(host_interface.get("entryPoints"))
            if isinstance(entry_point, Mapping)
        ],
        resources=resources,
        constants=constants,
        specialization_constants=specialization_constants,
        diagnostics=diagnostic_records,
    )


def _runtime_manifest_group_key(value: Any) -> str:
    if value is None:
        return "default"
    if isinstance(value, str):
        return value if value else "default"
    return str(value)


def _runtime_manifest_variant_count(
    artifacts: Sequence[Mapping[str, Any]],
) -> int:
    return len(
        {
            artifact.get("variant")
            for artifact in artifacts
            if _is_non_empty_string(artifact.get("variant"))
        }
    )


def _runtime_manifest_artifact_counter(
    artifacts: Sequence[Mapping[str, Any]],
    field_name: str,
) -> dict[str, int]:
    counts: Counter[str] = Counter()
    for artifact in artifacts:
        value = artifact.get(field_name)
        if _is_non_empty_string(value):
            counts[str(value)] += 1
    return dict(sorted(counts.items()))


def _runtime_manifest_status_counts(
    artifacts: Sequence[Mapping[str, Any]],
    field_name: str,
) -> dict[str, int]:
    counts: Counter[str] = Counter()
    for artifact in artifacts:
        record = artifact.get(field_name)
        if not isinstance(record, Mapping):
            counts["not-recorded"] += 1
            continue
        status = record.get("status")
        counts[str(status) if _is_non_empty_string(status) else "not-recorded"] += 1
    return dict(sorted(counts.items()))


def _runtime_manifest_data_status_counts(
    artifacts: Sequence[Mapping[str, Any]],
) -> dict[str, dict[str, int]]:
    counts: dict[str, Counter[str]] = {}
    for artifact in artifacts:
        status = artifact.get("runtimeDataStatus")
        if not isinstance(status, Mapping):
            continue
        for field_name, value in status.items():
            counts.setdefault(str(field_name), Counter())[str(value)] += 1
    return {
        field_name: dict(sorted(field_counts.items()))
        for field_name, field_counts in sorted(counts.items())
    }


def _runtime_manifest_artifact_groups(
    artifacts: Sequence[Mapping[str, Any]],
) -> dict[str, list[dict[str, Any]]]:
    grouped: dict[str, dict[str, list[Mapping[str, Any]]]] = {
        "source": {},
        "target": {},
        "variant": {},
    }
    for artifact in artifacts:
        for field_name in grouped:
            key = _runtime_manifest_group_key(artifact.get(field_name))
            grouped[field_name].setdefault(key, []).append(artifact)

    def group_payload(
        field_name: str, key: str, records: Sequence[Mapping[str, Any]]
    ) -> dict[str, Any]:
        payload = {
            field_name: None if field_name == "variant" and key == "default" else key,
            "artifactCount": len(records),
            "targets": sorted(
                {
                    str(record.get("target"))
                    for record in records
                    if _is_non_empty_string(record.get("target"))
                }
            ),
            "sources": sorted(
                {
                    str(record.get("source"))
                    for record in records
                    if _is_non_empty_string(record.get("source"))
                }
            ),
            "variants": sorted(
                {
                    str(record.get("variant"))
                    for record in records
                    if _is_non_empty_string(record.get("variant"))
                }
            ),
            "artifacts": [str(record.get("id", "")) for record in records],
        }
        if field_name == "variant":
            payload["variantLabel"] = key
        return payload

    return {
        "bySource": [
            group_payload("source", key, grouped["source"][key])
            for key in sorted(grouped["source"])
        ],
        "byTarget": [
            group_payload("target", key, grouped["target"][key])
            for key in sorted(grouped["target"])
        ],
        "byVariant": [
            group_payload("variant", key, grouped["variant"][key])
            for key in sorted(grouped["variant"])
        ],
    }


def _runtime_manifest_runtime_diagnostics(
    artifacts: Sequence[Mapping[str, Any]],
) -> list[dict[str, Any]]:
    diagnostics = []
    for artifact in artifacts:
        for diagnostic in _record_sequence(artifact.get("diagnostics")):
            if isinstance(diagnostic, Mapping):
                diagnostics.append(dict(diagnostic))
    return diagnostics


def _runtime_manifest_runtime_diagnostic_counts(
    diagnostics: Sequence[Mapping[str, Any]],
) -> dict[str, int]:
    return _diagnostic_payload_counts(diagnostics)


def _runtime_manifest_summary(
    *,
    targets: Sequence[str],
    artifacts: Sequence[Mapping[str, Any]],
    translated_artifacts: Sequence[Mapping[str, Any]],
    failed_artifact_count: int,
    source_map_rollups: Mapping[str, Any],
    runtime_reference_count: int,
    compiler_request_count: int,
    runtime_diagnostics: Sequence[Mapping[str, Any]],
) -> dict[str, Any]:
    return {
        "targetCount": len(targets),
        "sourceCount": len(
            {
                artifact.get("source")
                for artifact in artifacts
                if _is_non_empty_string(artifact.get("source"))
            }
        ),
        "variantCount": _runtime_manifest_variant_count(artifacts),
        "artifactCount": len(artifacts),
        "translatedArtifactCount": len(translated_artifacts),
        "failedArtifactCount": failed_artifact_count,
        "sourceMapCount": source_map_rollups["sourceMapCount"],
        "sourceRemapCount": source_map_rollups["sourceRemapCount"],
        "runtimeReferenceCount": runtime_reference_count,
        "compilerRequestCount": compiler_request_count,
        "entryPointCount": sum(
            len(_record_sequence(artifact.get("entryPoints"))) for artifact in artifacts
        ),
        "resourceBindingCount": sum(
            len(_record_sequence(artifact.get("resourceBindings")))
            for artifact in artifacts
        ),
        "specializationConstantCount": sum(
            len(_record_sequence(artifact.get("specializationConstants")))
            for artifact in artifacts
        ),
        "parameterBlockCount": sum(
            len(_record_sequence(artifact.get("parameterBlocks")))
            for artifact in artifacts
        ),
        "dispatchMetadataCount": sum(
            artifact.get("dispatch", {}).get("workgroupCount", 0)
            for artifact in artifacts
            if isinstance(artifact.get("dispatch"), Mapping)
        ),
        "artifactsBySource": _runtime_manifest_artifact_counter(artifacts, "source"),
        "artifactsByTarget": _runtime_manifest_artifact_counter(artifacts, "target"),
        "artifactsByVariant": _runtime_manifest_artifact_counter(artifacts, "variant"),
        "validationStatusCounts": _runtime_manifest_status_counts(
            artifacts, "validation"
        ),
        "toolchainStatusCounts": _runtime_manifest_status_counts(
            artifacts, "toolchain"
        ),
        "runtimeDataStatusCounts": _runtime_manifest_data_status_counts(artifacts),
        "runtimeDiagnosticCount": len(runtime_diagnostics),
    }


def _runtime_manifest_artifact_key(artifact: Mapping[str, Any]) -> tuple[Any, ...]:
    return (
        artifact.get("source"),
        artifact.get("target"),
        artifact.get("variant"),
        artifact.get("path"),
    )


def _runtime_manifest_validation_artifacts(
    validation_report: Mapping[str, Any],
) -> dict[tuple[Any, ...], dict[str, Any]]:
    validation = validation_report.get("validation")
    validation = validation if isinstance(validation, Mapping) else {}
    records: dict[tuple[Any, ...], dict[str, Any]] = {}
    for artifact in _record_sequence(validation.get("artifacts")):
        if isinstance(artifact, Mapping):
            records[_runtime_manifest_artifact_key(artifact)] = dict(artifact)
    return records


def _runtime_manifest_toolchains(
    validation_report: Mapping[str, Any],
) -> dict[str, dict[str, Any]]:
    validation = validation_report.get("validation")
    validation = validation if isinstance(validation, Mapping) else {}
    toolchains: dict[str, dict[str, Any]] = {}
    for toolchain in _record_sequence(validation.get("toolchains")):
        if not isinstance(toolchain, Mapping):
            continue
        target = toolchain.get("target")
        if isinstance(target, str) and target:
            toolchains[target] = dict(toolchain)
    return toolchains


def _runtime_manifest_toolchain_runs(
    validation_report: Mapping[str, Any],
) -> dict[tuple[Any, ...], list[dict[str, Any]]]:
    validation = validation_report.get("validation")
    validation = validation if isinstance(validation, Mapping) else {}
    runs: dict[tuple[Any, ...], list[dict[str, Any]]] = {}
    for run in _record_sequence(validation.get("toolchainRuns")):
        if not isinstance(run, Mapping):
            continue
        runs.setdefault(_runtime_manifest_artifact_key(run), []).append(dict(run))
    return runs


def _runtime_manifest_entry_points(
    host_interface: Mapping[str, Any] | None,
) -> list[dict[str, Any]]:
    if not isinstance(host_interface, Mapping):
        return []
    return [
        dict(entry_point)
        for entry_point in _record_sequence(host_interface.get("entryPoints"))
        if isinstance(entry_point, Mapping)
    ]


def _runtime_manifest_execution_host_interface(
    artifact: Mapping[str, Any],
    host_interface: Mapping[str, Any] | None,
) -> Mapping[str, Any] | None:
    if artifact.get("target") != "directx" or not isinstance(host_interface, Mapping):
        return host_interface
    execution = artifact.get("execution")
    execution_entries = (
        execution.get("entryPoints") if isinstance(execution, Mapping) else None
    )
    if not isinstance(execution_entries, list) or not execution_entries:
        return host_interface

    reflected_entries = _runtime_manifest_entry_points(host_interface)
    reflected_by_name = {
        str(entry.get("name")): entry
        for entry in reflected_entries
        if _is_non_empty_string(entry.get("name"))
    }
    entry_points = []
    expected_names = set()
    for execution_entry in execution_entries:
        if not isinstance(execution_entry, Mapping):
            continue
        name = execution_entry.get("targetEntryPoint")
        size = execution_entry.get("workgroupSize")
        subgroup_width = execution_entry.get("subgroupWidth")
        if not _is_non_empty_string(name) or (
            not isinstance(size, list) and subgroup_width is None
        ):
            continue
        expected_names.add(str(name))
        entry_point = dict(reflected_by_name.get(str(name), {}))
        execution_config = (
            dict(entry_point.get("executionConfig"))
            if isinstance(entry_point.get("executionConfig"), Mapping)
            else {}
        )
        if isinstance(size, list):
            execution_config["numthreads"] = list(size)
        if subgroup_width is not None:
            execution_config["subgroupWidth"] = subgroup_width
        entry_point.update(
            {
                "name": str(name),
                "stage": "compute",
                "executionConfig": execution_config,
            }
        )
        entry_points.append(entry_point)
    entry_points.extend(
        entry for entry in reflected_entries if entry.get("name") not in expected_names
    )
    if not entry_points:
        return host_interface

    payload = dict(host_interface)
    payload["entryPoints"] = entry_points
    payload["entryPointCount"] = len(entry_points)
    return payload


def _runtime_manifest_resources(
    host_interface: Mapping[str, Any] | None,
) -> list[dict[str, Any]]:
    if not isinstance(host_interface, Mapping):
        return []
    return [
        dict(resource)
        for resource in _record_sequence(host_interface.get("resources"))
        if isinstance(resource, Mapping)
    ]


def _runtime_manifest_specialization_constants(
    host_interface: Mapping[str, Any] | None,
) -> list[dict[str, Any]]:
    if not isinstance(host_interface, Mapping):
        return []
    return [
        dict(constant)
        for constant in _record_sequence(host_interface.get("specializationConstants"))
        if isinstance(constant, Mapping)
    ]


def _runtime_manifest_binding_status(resource: Mapping[str, Any]) -> str:
    has_set = resource.get("set") is not None
    has_binding = resource.get("binding") is not None
    if has_set and has_binding:
        return "bound"
    if has_set or has_binding:
        return "layout-partial"
    return "layout-missing"


def _runtime_manifest_resource_bindings(
    host_interface: Mapping[str, Any] | None,
) -> list[dict[str, Any]]:
    bindings = []
    for index, resource in enumerate(_runtime_manifest_resources(host_interface)):
        name = resource.get("name")
        kind = resource.get("kind")
        set_number = resource.get("set")
        binding_number = resource.get("binding")
        binding = {
            "id": "|".join(
                str(part)
                for part in (
                    _runtime_manifest_group_key(kind),
                    _runtime_manifest_group_key(set_number),
                    _runtime_manifest_group_key(binding_number),
                    _runtime_manifest_group_key(name),
                    index,
                )
            ),
            "name": name,
            "kind": kind,
            "type": resource.get("type"),
            "set": set_number,
            "binding": binding_number,
            "access": resource.get("access"),
            "status": _runtime_manifest_binding_status(resource),
            "source": "hostInterface.resources",
        }
        metadata = resource.get("metadata")
        if isinstance(metadata, Mapping) and metadata:
            binding["metadata"] = dict(metadata)
        bindings.append(binding)
    return bindings


def _runtime_manifest_parameter_blocks(
    resource_bindings: Sequence[Mapping[str, Any]],
) -> list[dict[str, Any]]:
    blocks = []
    for binding in resource_bindings:
        if binding.get("kind") not in {
            "constant-buffer",
            "uniform",
            "push-constant",
            "parameter-block",
        }:
            continue
        blocks.append(
            {
                "name": binding.get("name"),
                "kind": binding.get("kind"),
                "type": binding.get("type"),
                "set": binding.get("set"),
                "binding": binding.get("binding"),
                "access": binding.get("access"),
                "resourceBinding": binding.get("id"),
                "status": (
                    "layout-ready"
                    if binding.get("status") == "bound"
                    else "layout-incomplete"
                ),
                "fields": [],
                "fieldLayoutStatus": "unavailable",
            }
        )
    return blocks


def _runtime_manifest_json_scalar(value: Any) -> Any:
    if isinstance(value, str):
        stripped = value.strip()
        return int(stripped) if stripped.isdigit() else stripped
    return _runtime_host_interface_json_value(value)


def _runtime_manifest_sequence_workgroup_size(value: Any) -> list[Any] | None:
    if isinstance(value, Sequence) and not isinstance(value, (str, bytes, bytearray)):
        values = [_runtime_manifest_json_scalar(item) for item in value]
        return values if values else None
    return None


def _runtime_manifest_execution_workgroup_size(
    execution_config: Mapping[str, Any],
) -> tuple[list[Any] | None, str | None]:
    for field_name in ("numthreads", "workgroup_size", "workgroupSize", "local_size"):
        if field_name not in execution_config:
            continue
        values = _runtime_manifest_sequence_workgroup_size(
            execution_config.get(field_name)
        )
        if values is not None:
            return values, field_name
    local_size_fields = ("local_size_x", "local_size_y", "local_size_z")
    if any(field_name in execution_config for field_name in local_size_fields):
        return (
            [
                _runtime_manifest_json_scalar(execution_config.get(field_name, 1))
                for field_name in local_size_fields
            ],
            "local_size",
        )
    return None, None


def _runtime_manifest_dispatch(
    entry_points: Sequence[Mapping[str, Any]],
) -> dict[str, Any]:
    compute_entry_points = [
        entry_point
        for entry_point in entry_points
        if entry_point.get("stage") == "compute"
    ]
    workgroups = []
    for entry_point in compute_entry_points:
        execution_config = entry_point.get("executionConfig")
        execution_config = (
            dict(execution_config) if isinstance(execution_config, Mapping) else {}
        )
        workgroup_size, source = _runtime_manifest_execution_workgroup_size(
            execution_config
        )
        if workgroup_size is None:
            continue
        workgroups.append(
            {
                "entryPoint": entry_point.get("name"),
                "stage": entry_point.get("stage"),
                "workgroupSize": workgroup_size,
                "source": f"entryPoint.executionConfig.{source}",
                "executionConfig": execution_config,
            }
        )
    diagnostics = []
    if workgroups:
        status = "available"
    elif compute_entry_points:
        status = "unavailable"
        diagnostics.append("project.runtime-manifest.dispatch-metadata-unavailable")
    else:
        status = "not-applicable"
    return {
        "status": status,
        "workgroupCount": len(workgroups),
        "workgroups": workgroups,
        "diagnostics": diagnostics,
    }


def _runtime_manifest_diagnostic(
    *,
    artifact: Mapping[str, Any],
    code: str,
    message: str,
) -> dict[str, Any]:
    return ProjectDiagnostic(
        severity="note",
        code=code,
        message=message,
        location=SourceLocation(file=str(artifact.get("source", "<unknown>"))),
        target=(
            str(artifact.get("target"))
            if _is_non_empty_string(artifact.get("target"))
            else None
        ),
        source_backend=(
            str(artifact.get("sourceBackend"))
            if _is_non_empty_string(artifact.get("sourceBackend"))
            else None
        ),
        variant=(
            str(artifact.get("variant"))
            if _is_non_empty_string(artifact.get("variant"))
            else None
        ),
        check_kind="runtime-manifest",
        missing_capabilities=["runtime.integration.metadata"],
    ).to_json()


def _runtime_manifest_artifact_diagnostics(
    artifact: Mapping[str, Any],
    host_interface: Mapping[str, Any] | None,
    entry_points: Sequence[Mapping[str, Any]],
    resource_bindings: Sequence[Mapping[str, Any]],
    dispatch: Mapping[str, Any],
) -> list[dict[str, Any]]:
    diagnostics: list[dict[str, Any]] = []
    if not isinstance(host_interface, Mapping):
        diagnostics.append(
            _runtime_manifest_diagnostic(
                artifact=artifact,
                code="project.runtime-manifest.host-interface-unavailable",
                message=(
                    "Runtime host interface metadata could not be inferred for "
                    f"{artifact.get('path')}."
                ),
            )
        )
        return diagnostics
    if not entry_points:
        diagnostics.append(
            _runtime_manifest_diagnostic(
                artifact=artifact,
                code="project.runtime-manifest.entry-points-unavailable",
                message=(
                    "No runtime entry point metadata was inferred for "
                    f"{artifact.get('path')}."
                ),
            )
        )
    if any(binding.get("status") != "bound" for binding in resource_bindings):
        diagnostics.append(
            _runtime_manifest_diagnostic(
                artifact=artifact,
                code="project.runtime-manifest.resource-binding-layout-incomplete",
                message=(
                    "One or more reflected resources are missing complete "
                    f"set/binding metadata for {artifact.get('path')}."
                ),
            )
        )
    for diagnostic in _record_sequence(dispatch.get("diagnostics")):
        if not isinstance(diagnostic, str) or not diagnostic:
            continue
        diagnostics.append(
            _runtime_manifest_diagnostic(
                artifact=artifact,
                code=diagnostic,
                message=(
                    "Compute dispatch/workgroup metadata could not be inferred "
                    f"for {artifact.get('path')}."
                ),
            )
        )
    return diagnostics


def _runtime_manifest_status(
    *,
    host_interface: Mapping[str, Any] | None,
    entry_points: Sequence[Mapping[str, Any]],
    resource_bindings: Sequence[Mapping[str, Any]],
    specialization_constants: Sequence[Mapping[str, Any]],
    parameter_blocks: Sequence[Mapping[str, Any]],
    dispatch: Mapping[str, Any],
) -> dict[str, Any]:
    if not isinstance(host_interface, Mapping):
        return {
            "hostInterface": "unavailable",
            "entryPoints": "unavailable",
            "resourceBindings": "unavailable",
            "specializationConstants": "unavailable",
            "parameterBlocks": "unavailable",
            "dispatch": dispatch.get("status", "unavailable"),
        }
    resource_binding_status = "not-applicable"
    if resource_bindings:
        resource_binding_status = (
            "available"
            if all(binding.get("status") == "bound" for binding in resource_bindings)
            else "partial"
        )
    parameter_block_status = "not-applicable"
    if parameter_blocks:
        parameter_block_status = (
            "available"
            if all(block.get("status") == "layout-ready" for block in parameter_blocks)
            else "partial"
        )
    return {
        "hostInterface": host_interface.get("status", "unavailable"),
        "entryPoints": "available" if entry_points else "unavailable",
        "resourceBindings": resource_binding_status,
        "specializationConstants": (
            "available" if specialization_constants else "not-applicable"
        ),
        "parameterBlocks": parameter_block_status,
        "dispatch": dispatch.get("status", "unavailable"),
    }


def _runtime_manifest_artifact(
    artifact: Mapping[str, Any],
    *,
    root_path: Path | None = None,
    validation_artifacts: Mapping[tuple[Any, ...], Mapping[str, Any]] | None = None,
    toolchains: Mapping[str, Mapping[str, Any]] | None = None,
    toolchain_runs: Mapping[tuple[Any, ...], Sequence[Mapping[str, Any]]] | None = None,
) -> dict[str, Any]:
    host_interface = _runtime_manifest_host_interface(root_path, artifact)
    host_interface = _runtime_manifest_execution_host_interface(
        artifact, host_interface
    )
    entry_points = _runtime_manifest_entry_points(host_interface)
    resource_bindings = _runtime_manifest_resource_bindings(host_interface)
    specialization_constants = _runtime_manifest_specialization_constants(
        host_interface
    )
    parameter_blocks = _runtime_manifest_parameter_blocks(resource_bindings)
    dispatch = _runtime_manifest_dispatch(entry_points)
    diagnostics = _runtime_manifest_artifact_diagnostics(
        artifact, host_interface, entry_points, resource_bindings, dispatch
    )
    key = _runtime_manifest_artifact_key(artifact)
    validation = dict((validation_artifacts or {}).get(key, {}))
    target = artifact.get("target")
    toolchain = (
        dict((toolchains or {}).get(str(target), {}))
        if _is_non_empty_string(target)
        else {}
    )
    runs = [dict(run) for run in (toolchain_runs or {}).get(key, [])]
    payload = {
        "id": _runtime_manifest_artifact_id(artifact),
        "source": artifact.get("source"),
        "path": artifact.get("path"),
        "target": artifact.get("target"),
        "sourceBackend": artifact.get("sourceBackend"),
        "stage": artifact.get("stage"),
        "variant": artifact.get("variant"),
        "defines": (
            dict(artifact.get("defines"))
            if isinstance(artifact.get("defines"), Mapping)
            else {}
        ),
        "entryPoint": (
            dict(artifact.get("entryPoint"))
            if isinstance(artifact.get("entryPoint"), Mapping)
            else None
        ),
        "templateMaterialization": (
            dict(artifact.get("templateMaterialization"))
            if isinstance(artifact.get("templateMaterialization"), Mapping)
            else None
        ),
        "specializationMaterialization": (
            dict(artifact.get("specializationMaterialization"))
            if isinstance(artifact.get("specializationMaterialization"), Mapping)
            else None
        ),
        "execution": (
            dict(artifact.get("execution"))
            if isinstance(artifact.get("execution"), Mapping)
            else None
        ),
        "sourceHash": artifact.get("sourceHash"),
        "sourceSizeBytes": artifact.get("sourceSizeBytes"),
        "hash": artifact.get("generatedHash"),
        "sizeBytes": artifact.get("generatedSizeBytes"),
        "provenance": (
            dict(artifact.get("provenance"))
            if isinstance(artifact.get("provenance"), Mapping)
            else {}
        ),
        "sourceMap": (
            dict(artifact.get("sourceMap"))
            if isinstance(artifact.get("sourceMap"), Mapping)
            else None
        ),
        "sourceRemap": (
            dict(artifact.get("sourceRemap"))
            if isinstance(artifact.get("sourceRemap"), Mapping)
            else None
        ),
        "hostInterface": host_interface,
        "entryPoints": entry_points,
        "resourceBindings": resource_bindings,
        "specializationConstants": specialization_constants,
        "parameterBlocks": parameter_blocks,
        "dispatch": dispatch,
        "validation": validation,
        "toolchain": toolchain,
        "toolchainRuns": runs,
        "runtimeDataStatus": _runtime_manifest_status(
            host_interface=host_interface,
            entry_points=entry_points,
            resource_bindings=resource_bindings,
            specialization_constants=specialization_constants,
            parameter_blocks=parameter_blocks,
            dispatch=dispatch,
        ),
        "diagnostics": diagnostics,
    }
    return payload


def _runtime_manifest_target(
    target: str,
    artifacts: Sequence[Mapping[str, Any]],
    manifest_artifacts: Sequence[Mapping[str, Any]],
    runtime_reference_count: int,
) -> dict[str, Any]:
    target_artifacts = [
        artifact for artifact in artifacts if artifact.get("target") == target
    ]
    translated_artifacts = [
        artifact
        for artifact in target_artifacts
        if artifact.get("status") == "translated"
    ]
    failed_artifact_count = sum(
        1 for artifact in target_artifacts if artifact.get("status") == "failed"
    )
    target_manifest_artifacts = [
        artifact for artifact in manifest_artifacts if artifact.get("target") == target
    ]
    return {
        "target": target,
        "artifactCount": len(target_artifacts),
        "translatedArtifactCount": len(translated_artifacts),
        "failedArtifactCount": failed_artifact_count,
        "runtimeReferenceCount": runtime_reference_count,
        "sourceCount": len(
            {
                artifact.get("source")
                for artifact in target_manifest_artifacts
                if _is_non_empty_string(artifact.get("source"))
            }
        ),
        "variantCount": _runtime_manifest_variant_count(target_manifest_artifacts),
        "entryPointCount": sum(
            len(_record_sequence(artifact.get("entryPoints")))
            for artifact in target_manifest_artifacts
        ),
        "resourceBindingCount": sum(
            len(_record_sequence(artifact.get("resourceBindings")))
            for artifact in target_manifest_artifacts
        ),
        "specializationConstantCount": sum(
            len(_record_sequence(artifact.get("specializationConstants")))
            for artifact in target_manifest_artifacts
        ),
        "parameterBlockCount": sum(
            len(_record_sequence(artifact.get("parameterBlocks")))
            for artifact in target_manifest_artifacts
        ),
        "dispatchMetadataCount": sum(
            artifact.get("dispatch", {}).get("workgroupCount", 0)
            for artifact in target_manifest_artifacts
            if isinstance(artifact.get("dispatch"), Mapping)
        ),
        "artifacts": [
            str(artifact.get("id", "")) for artifact in target_manifest_artifacts
        ],
    }


def _runtime_manifest_runtime_plan(plan: Mapping[str, Any]) -> dict[str, Any]:
    compiler_contract = plan.get("compilerContract")
    contract = compiler_contract if isinstance(compiler_contract, Mapping) else {}
    return {
        "kind": plan.get("kind"),
        "contract": contract.get("name"),
        "contractStatus": contract.get("status"),
        "contractIssue": contract.get("issue"),
        "runtimeReferenceCount": (
            plan.get("summary", {}).get("runtimeReferenceCount")
            if isinstance(plan.get("summary"), Mapping)
            else 0
        ),
        "runtimeReferencesByBackend": (
            dict(plan.get("runtimeReferencesByBackend", {}))
            if isinstance(plan.get("runtimeReferencesByBackend"), Mapping)
            else {}
        ),
        "runtimeReferencesByKind": (
            dict(plan.get("runtimeReferencesByKind", {}))
            if isinstance(plan.get("runtimeReferencesByKind"), Mapping)
            else {}
        ),
        "runtimeReferencesByPath": (
            dict(plan.get("runtimeReferencesByPath", {}))
            if isinstance(plan.get("runtimeReferencesByPath"), Mapping)
            else {}
        ),
        "compilerRequests": (
            [dict(request) for request in plan.get("compilerRequests", [])]
            if isinstance(plan.get("compilerRequests"), list)
            else []
        ),
        "actionCount": (
            plan.get("summary", {}).get("actionCount")
            if isinstance(plan.get("summary"), Mapping)
            else 0
        ),
    }


def build_runtime_artifact_manifest(
    report_path: str | os.PathLike[str],
) -> dict[str, Any]:
    """Build a runtime artifact manifest from a validated project report."""

    path = _filesystem_path_arg(report_path, field_name="Project report path")
    validation_report = validate_project_report(path)
    validation_success = bool(validation_report.get("success"))
    try:
        report = json.loads(path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        report = {}

    report_mapping = (
        report if validation_success and isinstance(report, Mapping) else {}
    )
    project_payload = _runtime_plan_project(report_mapping.get("project"))
    targets = project_payload["targets"]
    artifacts = [
        artifact
        for artifact in _record_sequence(report_mapping.get("artifacts"))
        if isinstance(artifact, Mapping)
    ]
    translated_artifacts = [
        artifact for artifact in artifacts if artifact.get("status") == "translated"
    ]
    failed_artifact_count = sum(
        1 for artifact in artifacts if artifact.get("status") == "failed"
    )
    runtime_plan = plan_runtime_integration(path)
    runtime_plan_payload = _runtime_manifest_runtime_plan(runtime_plan)
    runtime_reference_count = runtime_plan_payload["runtimeReferenceCount"]
    source_map_rollups = _source_map_rollups(translated_artifacts)
    root_path = None
    if _is_non_empty_string(project_payload.get("root")):
        root_path = Path(str(project_payload["root"])).resolve()
    validation_artifacts = _runtime_manifest_validation_artifacts(validation_report)
    toolchains = _runtime_manifest_toolchains(validation_report)
    toolchain_runs = _runtime_manifest_toolchain_runs(validation_report)
    manifest_artifacts = [
        _runtime_manifest_artifact(
            artifact,
            root_path=root_path,
            validation_artifacts=validation_artifacts,
            toolchains=toolchains,
            toolchain_runs=toolchain_runs,
        )
        for artifact in translated_artifacts
    ]
    runtime_diagnostics = _runtime_manifest_runtime_diagnostics(manifest_artifacts)
    return {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": RUNTIME_ARTIFACT_MANIFEST_KIND,
        "sourceReport": str(path),
        "sourceReportHash": _optional_source_hash(path),
        "generatedAt": int(time.time()),
        "success": validation_success,
        "scope": RUNTIME_ARTIFACT_MANIFEST_SCOPE,
        "nonGoals": list(RUNTIME_ARTIFACT_MANIFEST_NON_GOALS),
        "project": project_payload,
        "summary": _runtime_manifest_summary(
            targets=targets,
            artifacts=manifest_artifacts,
            translated_artifacts=translated_artifacts,
            failed_artifact_count=failed_artifact_count,
            source_map_rollups=source_map_rollups,
            runtime_reference_count=runtime_reference_count,
            compiler_request_count=len(runtime_plan_payload["compilerRequests"]),
            runtime_diagnostics=runtime_diagnostics,
        ),
        "targets": [
            _runtime_manifest_target(
                target,
                artifacts,
                manifest_artifacts,
                runtime_reference_count,
            )
            for target in targets
        ],
        "artifactGroups": _runtime_manifest_artifact_groups(manifest_artifacts),
        "artifacts": manifest_artifacts,
        "runtimePlan": runtime_plan_payload,
        "diagnosticCounts": validation_report.get("diagnosticCounts", {}),
        "diagnostics": validation_report.get("diagnostics", []),
        "runtimeDiagnosticCounts": _runtime_manifest_runtime_diagnostic_counts(
            runtime_diagnostics
        ),
        "runtimeDiagnostics": runtime_diagnostics,
    }


def _runtime_binding_payload_hash(payload: Mapping[str, Any]) -> dict[str, str]:
    encoded = json.dumps(payload, sort_keys=True, separators=(",", ":")).encode("utf-8")
    return {
        "algorithm": "sha256",
        "value": hashlib.sha256(encoded).hexdigest(),
    }


def _runtime_binding_scalar_value(value: Any) -> Any:
    if not isinstance(value, str):
        converted = _runtime_host_interface_json_value(value)
        if isinstance(converted, str):
            return _runtime_binding_scalar_value(converted)
        return converted
    stripped = value.strip()
    lowered = stripped.lower()
    if lowered == "true":
        return True
    if lowered == "false":
        return False
    try:
        return int(stripped, 0)
    except ValueError:
        pass
    try:
        return float(stripped)
    except ValueError:
        return stripped


def _runtime_binding_scalar_dtype_from_value(value: Any) -> str:
    if isinstance(value, bool):
        return "bool"
    if isinstance(value, int):
        return "int"
    if isinstance(value, float):
        return "float"
    return "string"


_RUNTIME_BINDING_SCALAR_TYPES = frozenset(
    (
        "bool",
        "boolean",
        "int",
        "uint",
        "unsigned int",
        "short",
        "ushort",
        "long",
        "ulong",
        "float",
        "half",
        "double",
        "i32",
        "u32",
        "f16",
        "f32",
        "f64",
        "int32_t",
        "uint32_t",
        "size_t",
    )
)


def _runtime_binding_is_scalar_type(type_name: str | None) -> bool:
    if not isinstance(type_name, str):
        return False
    normalized = " ".join(type_name.strip().lower().split())
    return normalized in _RUNTIME_BINDING_SCALAR_TYPES


def _runtime_binding_define_constants(
    artifact: Mapping[str, Any],
) -> list[dict[str, Any]]:
    constants = []
    defines = artifact.get("defines")
    if not isinstance(defines, Mapping):
        return constants
    for name, raw_value in sorted(defines.items()):
        if not _is_non_empty_string(name):
            continue
        value = _runtime_binding_scalar_value(raw_value)
        constants.append(
            {
                "name": str(name),
                "kind": "project-define",
                "dtype": _runtime_binding_scalar_dtype_from_value(value),
                "value": value,
                "required": False,
                "source": "artifact.defines",
            }
        )
    return constants


def _runtime_binding_source_constant_payload(constant: Any) -> dict[str, Any] | None:
    if _specialization_attribute_values(constant):
        return None
    name = getattr(constant, "name", None)
    if not _is_non_empty_string(name):
        return None
    dtype = _runtime_host_interface_type_name(getattr(constant, "const_type", None))
    if not _runtime_binding_is_scalar_type(dtype):
        return None
    value = _runtime_binding_scalar_value(getattr(constant, "value", None))
    payload = {
        "name": str(name),
        "kind": "source-constant",
        "dtype": dtype,
        "value": value,
        "required": False,
        "source": "source.constants",
    }
    constant_id = _runtime_host_interface_attribute_value(
        constant, ("constant_id", "constantId", "id")
    )
    if constant_id is not None:
        payload["id"] = constant_id
    return payload


def _runtime_binding_source_scalar_constants(
    root_path: Path | None,
    artifact: Mapping[str, Any],
) -> list[dict[str, Any]]:
    source = artifact.get("source")
    source_backend = artifact.get("sourceBackend")
    if not (
        root_path is not None
        and _is_non_empty_string(source)
        and _is_report_identity_path(source)
        and _is_non_empty_string(source_backend)
    ):
        return []

    try:
        register_default_sources()
        parser_name = SOURCE_REGISTRY.resolve_name(str(source_backend))
        source_spec = SOURCE_REGISTRY.get(parser_name)
    except Exception:
        return []

    source_path = (root_path / str(source)).resolve()
    if not _is_relative_to(source_path, root_path) or not source_path.is_file():
        return []

    try:
        ast = source_spec.parse(
            source_path.read_text(encoding="utf-8"),
            file_path=str(source_path),
        )
    except Exception:
        return []

    constants = []
    for constant in getattr(ast, "constants", []) or []:
        payload = _runtime_binding_source_constant_payload(constant)
        if payload is not None:
            constants.append(payload)
    return constants


def _runtime_binding_scalar_constants(
    root_path: Path | None,
    artifact: Mapping[str, Any],
) -> list[dict[str, Any]]:
    constants = _runtime_binding_define_constants(artifact)
    constants.extend(_runtime_binding_source_scalar_constants(root_path, artifact))
    host_interface = artifact.get("hostInterface")
    if isinstance(host_interface, Mapping):
        for constant in _record_sequence(host_interface.get("constants")):
            if isinstance(constant, Mapping):
                constants.append(dict(constant))
    return constants


def _runtime_binding_specialization_constants(
    artifact: Mapping[str, Any],
) -> list[dict[str, Any]]:
    records = _record_sequence(artifact.get("specializationConstants"))
    if not records:
        host_interface = artifact.get("hostInterface")
        if isinstance(host_interface, Mapping):
            records = _record_sequence(host_interface.get("specializationConstants"))
    return [dict(record) for record in records if isinstance(record, Mapping)]


def _runtime_binding_resource_mutability(binding: Mapping[str, Any]) -> str:
    access = str(binding.get("access") or "").strip().lower().replace("-", "_")
    if access in {"read_write", "readwrite", "rw"}:
        return "read-write"
    if access in {"write", "write_only", "writeonly"}:
        return "write-only"
    if access in {"read", "read_only", "readonly"}:
        return "read-only"

    kind = str(binding.get("kind") or "").strip().lower()
    if kind in {"constant-buffer", "uniform", "texture", "sampler"}:
        return "read-only"
    type_name = str(binding.get("type") or "").strip().lower()
    if "rwstructuredbuffer" in type_name or type_name.startswith("rwbuffer"):
        return "read-write"
    if "structuredbuffer" in type_name or type_name.startswith("buffer"):
        return "read-only"
    return "unknown"


def _runtime_binding_resource_bindings(
    artifact: Mapping[str, Any],
) -> list[dict[str, Any]]:
    bindings = []
    for binding in _record_sequence(artifact.get("resourceBindings")):
        if not isinstance(binding, Mapping):
            continue
        payload = dict(binding)
        payload["mutability"] = _runtime_binding_resource_mutability(binding)
        bindings.append(payload)
    return bindings


def _runtime_binding_buffer_mutability(
    resource_bindings: Sequence[Mapping[str, Any]],
) -> dict[str, list[str]]:
    buckets = {
        "readOnly": [],
        "writeOnly": [],
        "readWrite": [],
        "unknown": [],
    }
    for index, binding in enumerate(resource_bindings):
        binding_id = binding.get("id")
        binding_label = (
            str(binding_id) if _is_non_empty_string(binding_id) else str(index)
        )
        mutability = binding.get("mutability")
        if mutability == "read-only":
            buckets["readOnly"].append(binding_label)
        elif mutability == "write-only":
            buckets["writeOnly"].append(binding_label)
        elif mutability == "read-write":
            buckets["readWrite"].append(binding_label)
        else:
            buckets["unknown"].append(binding_label)
    return buckets


def _runtime_binding_dispatch_dimensions(
    artifact: Mapping[str, Any],
    entry_point: Mapping[str, Any] | None,
) -> dict[str, Any]:
    dispatch = artifact.get("dispatch")
    dispatch = dispatch if isinstance(dispatch, Mapping) else {}
    entry_name = entry_point.get("name") if isinstance(entry_point, Mapping) else None
    workgroups = [
        workgroup
        for workgroup in _record_sequence(dispatch.get("workgroups"))
        if isinstance(workgroup, Mapping)
        and (
            entry_name is None
            or workgroup.get("entryPoint") == entry_name
            or workgroup.get("entryPoint") is None
        )
    ]
    workgroup = workgroups[0] if workgroups else {}
    status = "available" if workgroup else dispatch.get("status", "unavailable")
    return {
        "status": status,
        "entryPoint": entry_name,
        "workgroupSize": (
            list(workgroup.get("workgroupSize"))
            if isinstance(workgroup.get("workgroupSize"), list)
            else None
        ),
        "workgroupCount": None,
        "globalSize": None,
        "gridSize": None,
        "source": workgroup.get("source"),
        "executionConfig": (
            dict(workgroup.get("executionConfig"))
            if isinstance(workgroup.get("executionConfig"), Mapping)
            else (
                dict(entry_point.get("executionConfig"))
                if isinstance(entry_point, Mapping)
                and isinstance(entry_point.get("executionConfig"), Mapping)
                else {}
            )
        ),
    }


def _runtime_binding_source_provenance(artifact: Mapping[str, Any]) -> dict[str, Any]:
    return {
        "sourceHash": artifact.get("sourceHash"),
        "sourceSizeBytes": artifact.get("sourceSizeBytes"),
        "provenance": (
            dict(artifact.get("provenance"))
            if isinstance(artifact.get("provenance"), Mapping)
            else {}
        ),
        "sourceMap": (
            dict(artifact.get("sourceMap"))
            if isinstance(artifact.get("sourceMap"), Mapping)
            else None
        ),
        "sourceRemap": (
            dict(artifact.get("sourceRemap"))
            if isinstance(artifact.get("sourceRemap"), Mapping)
            else None
        ),
    }


def _runtime_binding_validation_payload(
    artifact: Mapping[str, Any],
) -> dict[str, Any]:
    return {
        "artifact": (
            dict(artifact.get("validation"))
            if isinstance(artifact.get("validation"), Mapping)
            else {}
        ),
        "toolchain": (
            dict(artifact.get("toolchain"))
            if isinstance(artifact.get("toolchain"), Mapping)
            else {}
        ),
        "runtimeDataStatus": (
            dict(artifact.get("runtimeDataStatus"))
            if isinstance(artifact.get("runtimeDataStatus"), Mapping)
            else {}
        ),
    }


def _runtime_binding_manifest_entry_id(
    artifact: Mapping[str, Any],
    entry_point: Mapping[str, Any] | None,
    index: int,
) -> str:
    artifact_id = artifact.get("id")
    entry_name = entry_point.get("name") if isinstance(entry_point, Mapping) else None
    return "|".join(
        str(part)
        for part in (
            artifact_id if _is_non_empty_string(artifact_id) else "artifact",
            "entry",
            entry_name if _is_non_empty_string(entry_name) else "default",
            index,
        )
    )


def _runtime_binding_manifest_entries(
    runtime_manifest: Mapping[str, Any],
) -> list[dict[str, Any]]:
    project = runtime_manifest.get("project")
    root_path = None
    if isinstance(project, Mapping) and _is_non_empty_string(project.get("root")):
        root_path = Path(str(project["root"])).resolve()

    entries = []
    for artifact in _record_sequence(runtime_manifest.get("artifacts")):
        if not isinstance(artifact, Mapping):
            continue
        entry_points = [
            entry_point
            for entry_point in _record_sequence(artifact.get("entryPoints"))
            if isinstance(entry_point, Mapping)
        ]
        if not entry_points:
            entry_points = [None]
        resource_bindings = _runtime_binding_resource_bindings(artifact)
        scalar_constants = _runtime_binding_scalar_constants(root_path, artifact)
        specialization_constants = _runtime_binding_specialization_constants(artifact)
        for index, entry_point in enumerate(entry_points):
            entries.append(
                {
                    "id": _runtime_binding_manifest_entry_id(
                        artifact, entry_point, index
                    ),
                    "sourceFile": artifact.get("source"),
                    "sourceBackend": artifact.get("sourceBackend"),
                    "targetBackend": artifact.get("target"),
                    "variant": artifact.get("variant"),
                    "defines": (
                        dict(artifact.get("defines"))
                        if isinstance(artifact.get("defines"), Mapping)
                        else {}
                    ),
                    "artifactId": artifact.get("id"),
                    "artifactPath": artifact.get("path"),
                    "artifactHash": artifact.get("hash"),
                    "artifactSizeBytes": artifact.get("sizeBytes"),
                    "sourceProvenance": _runtime_binding_source_provenance(artifact),
                    "entryPoint": (
                        dict(entry_point) if entry_point is not None else None
                    ),
                    "resourceBindings": [
                        dict(binding) for binding in resource_bindings
                    ],
                    "bufferMutability": _runtime_binding_buffer_mutability(
                        resource_bindings
                    ),
                    "scalarConstants": [
                        dict(constant) for constant in scalar_constants
                    ],
                    "specializationConstants": [
                        dict(constant) for constant in specialization_constants
                    ],
                    "dispatchDimensions": _runtime_binding_dispatch_dimensions(
                        artifact, entry_point
                    ),
                    "validation": _runtime_binding_validation_payload(artifact),
                    "diagnostics": [
                        dict(diagnostic)
                        for diagnostic in _record_sequence(artifact.get("diagnostics"))
                        if isinstance(diagnostic, Mapping)
                    ],
                }
            )
    return entries


def _runtime_binding_manifest_summary(
    runtime_manifest: Mapping[str, Any],
    entries: Sequence[Mapping[str, Any]],
) -> dict[str, Any]:
    targets = [
        target
        for target in _record_sequence(runtime_manifest.get("targets"))
        if isinstance(target, Mapping)
    ]
    artifacts = [
        artifact
        for artifact in _record_sequence(runtime_manifest.get("artifacts"))
        if isinstance(artifact, Mapping)
    ]
    return {
        "targetCount": len(targets),
        "artifactCount": len(artifacts),
        "entryCount": len(entries),
        "resourceBindingCount": sum(
            len(_record_sequence(entry.get("resourceBindings"))) for entry in entries
        ),
        "scalarConstantCount": sum(
            len(_record_sequence(entry.get("scalarConstants"))) for entry in entries
        ),
        "specializationConstantCount": sum(
            len(_record_sequence(entry.get("specializationConstants")))
            for entry in entries
        ),
        "dispatchDimensionCount": sum(
            1
            for entry in entries
            if isinstance(entry.get("dispatchDimensions"), Mapping)
            and entry["dispatchDimensions"].get("status") == "available"
        ),
        "entriesBySource": _runtime_manifest_artifact_counter(entries, "sourceFile"),
        "entriesByTarget": _runtime_manifest_artifact_counter(entries, "targetBackend"),
        "entriesByVariant": _runtime_manifest_artifact_counter(entries, "variant"),
    }


def _runtime_binding_manifest_target(
    target: Mapping[str, Any],
    entries: Sequence[Mapping[str, Any]],
) -> dict[str, Any]:
    target_name = target.get("target")
    target_entries = [
        entry for entry in entries if entry.get("targetBackend") == target_name
    ]
    return {
        "targetBackend": target_name,
        "artifactCount": target.get("artifactCount", 0),
        "entryCount": len(target_entries),
        "resourceBindingCount": sum(
            len(_record_sequence(entry.get("resourceBindings")))
            for entry in target_entries
        ),
        "scalarConstantCount": sum(
            len(_record_sequence(entry.get("scalarConstants")))
            for entry in target_entries
        ),
        "specializationConstantCount": sum(
            len(_record_sequence(entry.get("specializationConstants")))
            for entry in target_entries
        ),
        "dispatchDimensionCount": sum(
            1
            for entry in target_entries
            if isinstance(entry.get("dispatchDimensions"), Mapping)
            and entry["dispatchDimensions"].get("status") == "available"
        ),
        "artifacts": [
            artifact
            for artifact in _record_sequence(target.get("artifacts"))
            if _is_non_empty_string(artifact)
        ],
        "entries": [
            entry.get("id")
            for entry in target_entries
            if _is_non_empty_string(entry.get("id"))
        ],
    }


def build_runtime_binding_manifest(
    report_path: str | os.PathLike[str],
) -> dict[str, Any]:
    """Build a backend-neutral runtime binding manifest from a project report."""

    runtime_manifest = build_runtime_artifact_manifest(report_path)
    entries = _runtime_binding_manifest_entries(runtime_manifest)
    targets = [
        _runtime_binding_manifest_target(target, entries)
        for target in _record_sequence(runtime_manifest.get("targets"))
        if isinstance(target, Mapping)
    ]
    return {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": RUNTIME_BINDING_MANIFEST_KIND,
        "sourceReport": runtime_manifest.get("sourceReport"),
        "sourceReportHash": runtime_manifest.get("sourceReportHash"),
        "sourceRuntimeManifestHash": _runtime_binding_payload_hash(runtime_manifest),
        "generatedAt": int(time.time()),
        "success": bool(runtime_manifest.get("success")),
        "scope": RUNTIME_BINDING_MANIFEST_SCOPE,
        "nonGoals": list(RUNTIME_BINDING_MANIFEST_NON_GOALS),
        "project": (
            dict(runtime_manifest.get("project"))
            if isinstance(runtime_manifest.get("project"), Mapping)
            else {"targets": []}
        ),
        "summary": _runtime_binding_manifest_summary(runtime_manifest, entries),
        "targets": targets,
        "entries": entries,
        "runtimePlan": (
            dict(runtime_manifest.get("runtimePlan"))
            if isinstance(runtime_manifest.get("runtimePlan"), Mapping)
            else {}
        ),
        "diagnosticCounts": runtime_manifest.get("diagnosticCounts", {}),
        "diagnostics": runtime_manifest.get("diagnostics", []),
        "runtimeDiagnosticCounts": runtime_manifest.get("runtimeDiagnosticCounts", {}),
        "runtimeDiagnostics": runtime_manifest.get("runtimeDiagnostics", []),
    }


def _runtime_package_load_manifest(
    path: Path,
) -> tuple[Mapping[str, Any], list[ProjectDiagnostic]]:
    try:
        manifest = json.loads(path.read_text(encoding="utf-8"))
    except OSError as exc:
        return {}, [
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-package.manifest-read-failed",
                message=f"Runtime artifact manifest could not be read: {exc}",
                location=SourceLocation(file=str(path)),
                check_kind="runtime-package",
            )
        ]
    except json.JSONDecodeError as exc:
        return {}, [
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-package.manifest-json-invalid",
                message=f"Runtime artifact manifest is not valid JSON: {exc}",
                location=SourceLocation(
                    file=str(path), line=exc.lineno, column=exc.colno
                ),
                check_kind="runtime-package",
            )
        ]
    if not isinstance(manifest, Mapping):
        return {}, [
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-package.manifest-invalid",
                message="Runtime artifact manifest must be a JSON object.",
                location=SourceLocation(file=str(path)),
                check_kind="runtime-package",
            )
        ]
    return manifest, []


def _runtime_package_manifest_diagnostics(
    path: Path, manifest: Mapping[str, Any]
) -> list[ProjectDiagnostic]:
    diagnostics: list[ProjectDiagnostic] = []
    if manifest.get("schemaVersion") != REPORT_SCHEMA_VERSION:
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-package.manifest-schema-invalid",
                message=f"Runtime artifact manifest schemaVersion must be {REPORT_SCHEMA_VERSION}.",
                location=SourceLocation(file=str(path)),
                check_kind="runtime-package",
            )
        )
    if manifest.get("kind") != RUNTIME_ARTIFACT_MANIFEST_KIND:
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-package.manifest-kind-invalid",
                message=(
                    "Runtime package input must be a "
                    f"{RUNTIME_ARTIFACT_MANIFEST_KIND} document."
                ),
                location=SourceLocation(file=str(path)),
                check_kind="runtime-package",
            )
        )
    if manifest.get("success") is not True:
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-package.manifest-failed",
                message=(
                    "Runtime artifact manifest must be successful before it can "
                    "be packaged."
                ),
                location=SourceLocation(file=str(path)),
                check_kind="runtime-package",
            )
        )
    return diagnostics


def _runtime_package_project_root(
    path: Path, manifest: Mapping[str, Any]
) -> tuple[Path | None, list[ProjectDiagnostic]]:
    project = manifest.get("project")
    if not isinstance(project, Mapping):
        return None, [
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-package.project-missing",
                message="Runtime artifact manifest is missing a project object.",
                location=SourceLocation(file=str(path)),
                check_kind="runtime-package",
            )
        ]
    root = project.get("root")
    if not _is_non_empty_string(root):
        return None, [
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-package.project-root-missing",
                message="Runtime artifact manifest is missing project.root.",
                location=SourceLocation(file=str(path)),
                check_kind="runtime-package",
            )
        ]
    root_path = Path(root)
    if not root_path.is_absolute() or not root_path.exists() or not root_path.is_dir():
        return None, [
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-package.project-root-invalid",
                message=(
                    "Runtime artifact manifest project.root must be an existing "
                    f"absolute directory: {root}"
                ),
                location=SourceLocation(file=str(path)),
                check_kind="runtime-package",
            )
        ]
    return root_path.resolve(), []


def _runtime_package_artifact_source_path(
    root_path: Path,
    artifact: Mapping[str, Any],
    manifest_path: Path,
) -> tuple[Path | None, list[ProjectDiagnostic]]:
    source_path = artifact.get("path")
    artifact_id = artifact.get("id", "<unknown>")
    if not _is_non_empty_string(source_path) or not _is_report_identity_path(
        source_path
    ):
        return None, [
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-package.artifact-path-invalid",
                message=(
                    "Runtime artifact manifest artifact paths must be stable "
                    f"repository-relative POSIX paths: {artifact_id}"
                ),
                location=SourceLocation(file=str(manifest_path)),
                target=(
                    artifact.get("target")
                    if _is_non_empty_string(artifact.get("target"))
                    else None
                ),
                source_backend=(
                    artifact.get("sourceBackend")
                    if _is_non_empty_string(artifact.get("sourceBackend"))
                    else None
                ),
                variant=(
                    artifact.get("variant")
                    if _is_non_empty_string(artifact.get("variant"))
                    else None
                ),
                check_kind="runtime-package",
            )
        ]
    path = (root_path / source_path).resolve()
    if not _is_relative_to(path, root_path):
        return None, [
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-package.artifact-outside-project",
                message=(
                    "Runtime artifact manifest artifact path resolves outside "
                    f"project.root: {source_path}"
                ),
                location=SourceLocation(file=str(manifest_path)),
                check_kind="runtime-package",
            )
        ]
    return path, []


def _runtime_package_file_diagnostics(
    *,
    manifest_path: Path,
    artifact: Mapping[str, Any],
    source_path: Path,
    expected_hash: Any,
    expected_size: Any,
    label: str,
    missing_code: str,
    hash_code: str,
    size_code: str,
) -> list[ProjectDiagnostic]:
    diagnostics: list[ProjectDiagnostic] = []
    diagnostic_context = {
        "target": (
            artifact.get("target")
            if _is_non_empty_string(artifact.get("target"))
            else None
        ),
        "source_backend": (
            artifact.get("sourceBackend")
            if _is_non_empty_string(artifact.get("sourceBackend"))
            else None
        ),
        "variant": (
            artifact.get("variant")
            if _is_non_empty_string(artifact.get("variant"))
            else None
        ),
        "check_kind": "runtime-package",
    }
    if not source_path.exists() or not source_path.is_file():
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code=missing_code,
                message=f"Runtime package {label} is missing: {source_path}",
                location=SourceLocation(file=str(manifest_path)),
                **diagnostic_context,
            )
        )
        return diagnostics

    if isinstance(expected_hash, Mapping):
        actual_hash = _source_hash(source_path)
        if not _hash_matches_report(actual_hash, expected_hash):
            diagnostics.append(
                ProjectDiagnostic(
                    severity="error",
                    code=hash_code,
                    message=(
                        f"Runtime package {label} hash mismatch "
                        f"({_hash_mismatch_context(actual_hash, expected_hash)})"
                    ),
                    location=SourceLocation(file=str(manifest_path)),
                    **diagnostic_context,
                )
            )
    if _is_non_negative_int(expected_size):
        actual_size = source_path.stat().st_size
        if actual_size != expected_size:
            diagnostics.append(
                ProjectDiagnostic(
                    severity="error",
                    code=size_code,
                    message=(
                        f"Runtime package {label} size mismatch "
                        f"({_size_mismatch_context(expected_size, actual_size)})"
                    ),
                    location=SourceLocation(file=str(manifest_path)),
                    **diagnostic_context,
                )
            )
    return diagnostics


def _runtime_package_copy_file(
    source_path: Path, package_root: Path, package_relative_path: str
) -> None:
    destination = package_root / package_relative_path
    destination.parent.mkdir(parents=True, exist_ok=True)
    shutil.copy2(source_path, destination)


def _runtime_package_remap_payload(
    root_path: Path,
    manifest_path: Path,
    artifact: Mapping[str, Any],
) -> tuple[dict[str, Any] | None, list[ProjectDiagnostic], Path | None, str | None]:
    source_remap = artifact.get("sourceRemap")
    if not isinstance(source_remap, Mapping):
        return None, [], None, None

    source_remap_path = source_remap.get("path")
    if not _is_non_empty_string(source_remap_path) or not _is_report_identity_path(
        source_remap_path
    ):
        return (
            None,
            [
                ProjectDiagnostic(
                    severity="error",
                    code="project.runtime-package.source-remap-path-invalid",
                    message=(
                        "Runtime artifact manifest sourceRemap.path must be a stable "
                        f"repository-relative POSIX path: {artifact.get('id', '<unknown>')}"
                    ),
                    location=SourceLocation(file=str(manifest_path)),
                    check_kind="runtime-package",
                )
            ],
            None,
            None,
        )

    source_path = (root_path / source_remap_path).resolve()
    diagnostics = _runtime_package_file_diagnostics(
        manifest_path=manifest_path,
        artifact=artifact,
        source_path=source_path,
        expected_hash=source_remap.get("hash"),
        expected_size=source_remap.get("sizeBytes"),
        label="source remap",
        missing_code="project.runtime-package.source-remap-missing",
        hash_code="project.runtime-package.source-remap-hash-mismatch",
        size_code="project.runtime-package.source-remap-size-mismatch",
    )
    package_path = f"source-remaps/{source_remap_path}"
    return (
        {
            "sourcePath": source_remap_path,
            "packagePath": package_path,
            "hash": source_remap.get("hash"),
            "sizeBytes": source_remap.get("sizeBytes"),
        },
        diagnostics,
        source_path,
        package_path,
    )


def _runtime_package_artifact_payload(
    root_path: Path,
    package_root: Path,
    manifest_path: Path,
    artifact: Mapping[str, Any],
) -> tuple[dict[str, Any], list[ProjectDiagnostic]]:
    source_path, diagnostics = _runtime_package_artifact_source_path(
        root_path, artifact, manifest_path
    )
    source_path_text = (
        artifact.get("path") if _is_non_empty_string(artifact.get("path")) else ""
    )
    package_path = f"artifacts/{source_path_text}" if source_path_text else ""

    if source_path is not None:
        diagnostics.extend(
            _runtime_package_file_diagnostics(
                manifest_path=manifest_path,
                artifact=artifact,
                source_path=source_path,
                expected_hash=artifact.get("hash"),
                expected_size=artifact.get("sizeBytes"),
                label="artifact",
                missing_code="project.runtime-package.artifact-missing",
                hash_code="project.runtime-package.artifact-hash-mismatch",
                size_code="project.runtime-package.artifact-size-mismatch",
            )
        )

    (
        source_remap_payload,
        source_remap_diagnostics,
        source_remap_source_path,
        source_remap_package_path,
    ) = _runtime_package_remap_payload(root_path, manifest_path, artifact)
    diagnostics.extend(source_remap_diagnostics)

    status = "packaged" if not diagnostics and source_path is not None else "failed"
    if status == "packaged":
        _runtime_package_copy_file(source_path, package_root, package_path)
        if (
            source_remap_source_path is not None
            and source_remap_package_path is not None
        ):
            _runtime_package_copy_file(
                source_remap_source_path, package_root, source_remap_package_path
            )

    payload = {
        "id": artifact.get("id"),
        "status": status,
        "source": artifact.get("source"),
        "sourcePath": source_path_text,
        "packagePath": package_path if status == "packaged" else None,
        "target": artifact.get("target"),
        "sourceBackend": artifact.get("sourceBackend"),
        "stage": artifact.get("stage"),
        "variant": artifact.get("variant"),
        "defines": (
            dict(artifact.get("defines"))
            if isinstance(artifact.get("defines"), Mapping)
            else {}
        ),
        "entryPoint": (
            dict(artifact.get("entryPoint"))
            if isinstance(artifact.get("entryPoint"), Mapping)
            else None
        ),
        "templateMaterialization": (
            dict(artifact.get("templateMaterialization"))
            if isinstance(artifact.get("templateMaterialization"), Mapping)
            else None
        ),
        "specializationMaterialization": (
            dict(artifact.get("specializationMaterialization"))
            if isinstance(artifact.get("specializationMaterialization"), Mapping)
            else None
        ),
        "specializationConstants": [
            dict(constant)
            for constant in _record_sequence(artifact.get("specializationConstants"))
            if isinstance(constant, Mapping)
        ],
        "provenance": (
            dict(artifact.get("provenance"))
            if isinstance(artifact.get("provenance"), Mapping)
            else {}
        ),
        "sourceHash": artifact.get("sourceHash"),
        "sourceSizeBytes": artifact.get("sourceSizeBytes"),
        "hash": artifact.get("hash"),
        "sizeBytes": artifact.get("sizeBytes"),
        "sourceRemap": source_remap_payload,
        "hostInterface": (
            dict(artifact.get("hostInterface"))
            if isinstance(artifact.get("hostInterface"), Mapping)
            else None
        ),
    }
    return payload, diagnostics


def _runtime_package_target(
    target: str,
    artifacts: Sequence[Mapping[str, Any]],
    runtime_reference_count: int,
) -> dict[str, Any]:
    target_artifacts = [
        artifact for artifact in artifacts if artifact.get("target") == target
    ]
    packaged_artifacts = [
        artifact
        for artifact in target_artifacts
        if artifact.get("status") == "packaged"
    ]
    failed_artifacts = [
        artifact for artifact in target_artifacts if artifact.get("status") == "failed"
    ]
    return {
        "target": target,
        "artifactCount": len(target_artifacts),
        "packagedArtifactCount": len(packaged_artifacts),
        "failedArtifactCount": len(failed_artifacts),
        "runtimeReferenceCount": runtime_reference_count,
        "artifacts": [artifact.get("id") for artifact in packaged_artifacts],
    }


def _runtime_package_integration_guide(package: Mapping[str, Any]) -> str:
    lines = [
        "# CrossTL Runtime Package",
        "",
        "This package contains translated shader and GPU artifacts plus metadata for host or packaging tools.",
        "",
        f"- Package manifest: {package.get('packageManifest')}",
        f"- Runtime plan contract: {package.get('runtimePlan', {}).get('contract', '<none>')}",
        f"- Runtime references: {package.get('summary', {}).get('runtimeReferenceCount', 0)}",
        "",
        "Artifacts",
    ]
    artifacts = package.get("artifacts", [])
    if isinstance(artifacts, list) and artifacts:
        for artifact in artifacts:
            if not isinstance(artifact, Mapping):
                continue
            lines.append(
                "- "
                f"{artifact.get('target', 'unknown')}: "
                f"{artifact.get('packagePath') or '<not packaged>'}"
            )
    else:
        lines.append("- <none>")
    lines.extend(
        [
            "",
            "Scope",
            "",
            "The package preserves translated artifacts, source-remap sidecars, hashes, sizes, target identity, variants, and runtime planning metadata.",
            "It does not rewrite host application code, execute device code, generate runtime framework code, or install target SDKs.",
            "",
        ]
    )
    return "\n".join(lines)


def build_runtime_package(
    manifest_path: str | os.PathLike[str],
    package_dir: str | os.PathLike[str],
) -> dict[str, Any]:
    """Build a deterministic runtime handoff package from an artifact manifest."""

    manifest_file = _filesystem_path_arg(
        manifest_path, field_name="Runtime artifact manifest path"
    )
    package_root = _filesystem_path_arg(package_dir, field_name="Runtime package dir")
    manifest, diagnostics = _runtime_package_load_manifest(manifest_file)
    if manifest:
        diagnostics.extend(
            _runtime_package_manifest_diagnostics(manifest_file, manifest)
        )
    root_path, root_diagnostics = _runtime_package_project_root(manifest_file, manifest)
    diagnostics.extend(root_diagnostics)

    project_payload = (
        dict(manifest.get("project"))
        if isinstance(manifest.get("project"), Mapping)
        else {"targets": []}
    )
    targets = [
        target
        for target in project_payload.get("targets", [])
        if _is_non_empty_string(target)
    ]
    runtime_plan = (
        dict(manifest.get("runtimePlan"))
        if isinstance(manifest.get("runtimePlan"), Mapping)
        else {}
    )
    runtime_reference_count = (
        runtime_plan.get("runtimeReferenceCount")
        if _is_non_negative_int(runtime_plan.get("runtimeReferenceCount"))
        else 0
    )
    manifest_artifacts = [
        artifact
        for artifact in _record_sequence(manifest.get("artifacts"))
        if isinstance(artifact, Mapping)
    ]
    packaged_artifacts: list[dict[str, Any]] = []
    if root_path is not None and not diagnostics:
        package_root.mkdir(parents=True, exist_ok=True)
        for artifact in manifest_artifacts:
            artifact_payload, artifact_diagnostics = _runtime_package_artifact_payload(
                root_path, package_root, manifest_file, artifact
            )
            packaged_artifacts.append(artifact_payload)
            diagnostics.extend(artifact_diagnostics)
    else:
        for artifact in manifest_artifacts:
            packaged_artifacts.append(
                {
                    "id": artifact.get("id"),
                    "status": "failed",
                    "source": artifact.get("source"),
                    "sourcePath": artifact.get("path"),
                    "packagePath": None,
                    "target": artifact.get("target"),
                    "sourceBackend": artifact.get("sourceBackend"),
                    "stage": artifact.get("stage"),
                    "variant": artifact.get("variant"),
                    "defines": (
                        dict(artifact.get("defines"))
                        if isinstance(artifact.get("defines"), Mapping)
                        else {}
                    ),
                    "entryPoint": (
                        dict(artifact.get("entryPoint"))
                        if isinstance(artifact.get("entryPoint"), Mapping)
                        else None
                    ),
                    "templateMaterialization": (
                        dict(artifact.get("templateMaterialization"))
                        if isinstance(artifact.get("templateMaterialization"), Mapping)
                        else None
                    ),
                    "specializationMaterialization": (
                        dict(artifact.get("specializationMaterialization"))
                        if isinstance(
                            artifact.get("specializationMaterialization"), Mapping
                        )
                        else None
                    ),
                    "specializationConstants": [
                        dict(constant)
                        for constant in _record_sequence(
                            artifact.get("specializationConstants")
                        )
                        if isinstance(constant, Mapping)
                    ],
                    "provenance": (
                        dict(artifact.get("provenance"))
                        if isinstance(artifact.get("provenance"), Mapping)
                        else {}
                    ),
                    "sourceHash": artifact.get("sourceHash"),
                    "sourceSizeBytes": artifact.get("sourceSizeBytes"),
                    "hash": artifact.get("hash"),
                    "sizeBytes": artifact.get("sizeBytes"),
                    "sourceRemap": None,
                    "hostInterface": (
                        dict(artifact.get("hostInterface"))
                        if isinstance(artifact.get("hostInterface"), Mapping)
                        else None
                    ),
                }
            )

    packaged_count = sum(
        1 for artifact in packaged_artifacts if artifact.get("status") == "packaged"
    )
    failed_count = sum(
        1 for artifact in packaged_artifacts if artifact.get("status") == "failed"
    )
    source_remap_count = sum(
        1
        for artifact in packaged_artifacts
        if isinstance(artifact.get("sourceRemap"), Mapping)
        and artifact.get("status") == "packaged"
    )
    success = not any(diagnostic.severity == "error" for diagnostic in diagnostics)
    payload = {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": RUNTIME_PACKAGE_KIND,
        "sourceManifest": str(manifest_file),
        "sourceManifestHash": _optional_source_hash(manifest_file),
        "generatedAt": int(time.time()),
        "success": success,
        "scope": RUNTIME_PACKAGE_SCOPE,
        "nonGoals": list(RUNTIME_PACKAGE_NON_GOALS),
        "packageRoot": str(package_root),
        "packageManifest": "runtime-package.json",
        "integrationGuide": "INTEGRATION.md",
        "project": project_payload,
        "summary": {
            "targetCount": len(targets),
            "artifactCount": len(packaged_artifacts),
            "packagedArtifactCount": packaged_count,
            "failedArtifactCount": failed_count,
            "sourceRemapCount": source_remap_count,
            "runtimeReferenceCount": runtime_reference_count,
            "compilerRequestCount": (
                len(runtime_plan.get("compilerRequests", []))
                if isinstance(runtime_plan.get("compilerRequests"), list)
                else 0
            ),
        },
        "targets": [
            _runtime_package_target(target, packaged_artifacts, runtime_reference_count)
            for target in targets
        ],
        "artifacts": packaged_artifacts,
        "runtimePlan": runtime_plan,
        "diagnosticCounts": _diagnostic_counts(diagnostics),
        "diagnostics": [diagnostic.to_json() for diagnostic in diagnostics],
    }
    if root_path is not None:
        package_root.mkdir(parents=True, exist_ok=True)
        (package_root / "runtime-package.json").write_text(
            json.dumps(payload, indent=2, sort_keys=True) + "\n",
            encoding="utf-8",
        )
        (package_root / "INTEGRATION.md").write_text(
            _runtime_package_integration_guide(payload),
            encoding="utf-8",
        )
    return payload


def _runtime_host_binding_packaged_artifacts(
    package: Mapping[str, Any],
) -> list[Mapping[str, Any]]:
    return [
        artifact
        for artifact in _record_sequence(package.get("artifacts"))
        if isinstance(artifact, Mapping) and artifact.get("status") == "packaged"
    ]


def _runtime_host_binding_action(record: Mapping[str, Any]) -> dict[str, Any]:
    source_remap = record.get("sourceRemap")
    artifact = record.get("artifact", record.get("id"))
    return {
        "kind": "bind-runtime-artifact",
        "severity": "note",
        "message": (
            "Load packaged artifact "
            f"{record.get('packagePath')} for target {record.get('target')}."
        ),
        "target": record.get("target"),
        "artifact": artifact,
        "packagePath": record.get("packagePath"),
        "sourceRemap": (
            source_remap.get("packagePath")
            if isinstance(source_remap, Mapping)
            else source_remap if _is_non_empty_string(source_remap) else None
        ),
    }


def _runtime_host_binding_review_action(
    targets: Sequence[str], runtime_reference_count: int
) -> dict[str, Any] | None:
    if runtime_reference_count <= 0:
        return None
    target_label = ", ".join(targets) if targets else "packaged targets"
    return {
        "kind": "review-runtime-references",
        "severity": "warning",
        "message": (
            f"Review {runtime_reference_count} detected host or build runtime "
            f"references before wiring artifacts for {target_label}."
        ),
        "target": None,
        "artifact": None,
        "packagePath": None,
        "sourceRemap": None,
    }


def _runtime_host_binding_target(
    target: str,
    records: Sequence[Mapping[str, Any]],
    runtime_reference_count: int,
) -> dict[str, Any]:
    target_records = [record for record in records if record.get("target") == target]
    return {
        "target": target,
        "artifactCount": len(target_records),
        "runtimeReferenceCount": runtime_reference_count,
        "artifacts": [
            record.get("artifact", record.get("id")) for record in target_records
        ],
        "packagePaths": [record.get("packagePath") for record in target_records],
    }


def _runtime_host_binding_ready_bindings(
    bindings: Sequence[Mapping[str, Any]],
) -> list[Mapping[str, Any]]:
    return [binding for binding in bindings if binding.get("status") == "ready"]


def _runtime_host_binding_actions(
    bindings: Sequence[Mapping[str, Any]],
    targets: Sequence[str],
    runtime_reference_count: int,
) -> list[dict[str, Any]]:
    ready_bindings = _runtime_host_binding_ready_bindings(bindings)
    actions = [_runtime_host_binding_action(binding) for binding in ready_bindings]
    review_action = _runtime_host_binding_review_action(
        targets, runtime_reference_count
    )
    if review_action is not None and ready_bindings:
        actions.append(review_action)
    return actions


def _runtime_host_binding_package_inspection_summary(
    inspection: Mapping[str, Any],
) -> dict[str, Any]:
    summary = (
        inspection.get("summary")
        if isinstance(inspection.get("summary"), Mapping)
        else {}
    )
    return {
        "kind": inspection.get("kind"),
        "success": inspection.get("success"),
        "readyBindingCount": (
            summary.get("readyBindingCount")
            if _is_non_negative_int(summary.get("readyBindingCount"))
            else 0
        ),
        "failedBindingCount": (
            summary.get("failedBindingCount")
            if _is_non_negative_int(summary.get("failedBindingCount"))
            else 0
        ),
        "verifiedArtifactCount": (
            summary.get("verifiedArtifactCount")
            if _is_non_negative_int(summary.get("verifiedArtifactCount"))
            else 0
        ),
        "failedArtifactCount": (
            summary.get("failedArtifactCount")
            if _is_non_negative_int(summary.get("failedArtifactCount"))
            else 0
        ),
    }


def plan_runtime_host_bindings(
    package_manifest_path: str | os.PathLike[str],
) -> dict[str, Any]:
    """Build a host binding plan from a runtime package manifest."""

    package_path = _filesystem_path_arg(
        package_manifest_path, field_name="Runtime package manifest path"
    )
    inspection = inspect_runtime_package(package_path)
    project_payload = (
        dict(inspection.get("project"))
        if isinstance(inspection.get("project"), Mapping)
        else {"targets": []}
    )
    targets = [
        target
        for target in project_payload.get("targets", [])
        if _is_non_empty_string(target)
    ]
    runtime_plan = (
        dict(inspection.get("runtimePlan"))
        if isinstance(inspection.get("runtimePlan"), Mapping)
        else {}
    )
    inspection_summary = (
        inspection.get("summary")
        if isinstance(inspection.get("summary"), Mapping)
        else {}
    )
    runtime_reference_count = (
        inspection_summary.get("runtimeReferenceCount")
        if _is_non_negative_int(inspection_summary.get("runtimeReferenceCount"))
        else 0
    )
    bindings = [
        binding
        for binding in _record_sequence(inspection.get("bindings"))
        if isinstance(binding, Mapping)
    ]
    ready_bindings = _runtime_host_binding_ready_bindings(bindings)
    actions = _runtime_host_binding_actions(bindings, targets, runtime_reference_count)

    return {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": RUNTIME_HOST_BINDING_PLAN_KIND,
        "sourcePackage": str(package_path),
        "sourcePackageHash": _optional_source_hash(package_path),
        "generatedAt": int(time.time()),
        "success": bool(inspection.get("success")),
        "scope": RUNTIME_HOST_BINDING_PLAN_SCOPE,
        "nonGoals": list(RUNTIME_HOST_BINDING_PLAN_NON_GOALS),
        "packageRoot": inspection.get("packageRoot"),
        "project": project_payload,
        "summary": {
            "targetCount": len(targets),
            "artifactCount": len(ready_bindings),
            "actionCount": len(actions),
            "runtimeReferenceCount": runtime_reference_count,
        },
        "targets": [
            _runtime_host_binding_target(
                target, ready_bindings, runtime_reference_count
            )
            for target in targets
        ],
        "actions": actions,
        "runtimePlan": runtime_plan,
        "packageInspection": _runtime_host_binding_package_inspection_summary(
            inspection
        ),
        "diagnosticCounts": (
            dict(inspection.get("diagnosticCounts"))
            if isinstance(inspection.get("diagnosticCounts"), Mapping)
            else {}
        ),
        "diagnostics": (
            [dict(diagnostic) for diagnostic in inspection.get("diagnostics", [])]
            if isinstance(inspection.get("diagnostics"), list)
            else []
        ),
    }


def _runtime_package_inspection_load_package(
    path: Path,
) -> tuple[Mapping[str, Any], list[ProjectDiagnostic]]:
    try:
        package = json.loads(path.read_text(encoding="utf-8"))
    except OSError as exc:
        return {}, [
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-package-inspection.package-read-failed",
                message=f"Runtime package manifest could not be read: {exc}",
                location=SourceLocation(file=str(path)),
                check_kind="runtime-package-inspection",
            )
        ]
    except json.JSONDecodeError as exc:
        return {}, [
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-package-inspection.package-json-invalid",
                message=f"Runtime package manifest is not valid JSON: {exc}",
                location=SourceLocation(
                    file=str(path), line=exc.lineno, column=exc.colno
                ),
                check_kind="runtime-package-inspection",
            )
        ]
    if not isinstance(package, Mapping):
        return {}, [
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-package-inspection.package-invalid",
                message="Runtime package manifest must be a JSON object.",
                location=SourceLocation(file=str(path)),
                check_kind="runtime-package-inspection",
            )
        ]
    return package, []


def _runtime_package_inspection_package_diagnostics(
    path: Path, package: Mapping[str, Any]
) -> list[ProjectDiagnostic]:
    diagnostics: list[ProjectDiagnostic] = []
    if package.get("schemaVersion") != REPORT_SCHEMA_VERSION:
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-package-inspection.package-schema-invalid",
                message=f"Runtime package schemaVersion must be {REPORT_SCHEMA_VERSION}.",
                location=SourceLocation(file=str(path)),
                check_kind="runtime-package-inspection",
            )
        )
    if package.get("kind") != RUNTIME_PACKAGE_KIND:
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-package-inspection.package-kind-invalid",
                message=(
                    "Runtime package inspection input must be a "
                    f"{RUNTIME_PACKAGE_KIND} document."
                ),
                location=SourceLocation(file=str(path)),
                check_kind="runtime-package-inspection",
            )
        )
    if package.get("success") is not True:
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-package-inspection.package-failed",
                message=(
                    "Runtime package must be successful before it can be "
                    "inspected for host binding readiness."
                ),
                location=SourceLocation(file=str(path)),
                check_kind="runtime-package-inspection",
            )
        )
    return diagnostics


def _runtime_package_inspection_package_root(
    package_path: Path, package: Mapping[str, Any]
) -> Path:
    root = package.get("packageRoot")
    if _is_non_empty_string(root):
        candidate = Path(root)
        if candidate.is_absolute() and candidate.is_dir():
            return candidate.resolve()
        if not candidate.is_absolute():
            cwd_candidate = candidate.resolve()
            if cwd_candidate.is_dir():
                return cwd_candidate
            parent_candidate = (package_path.parent.parent / candidate).resolve()
            if parent_candidate.is_dir():
                return parent_candidate
    return package_path.parent.resolve()


def _runtime_package_inspection_file_diagnostics(
    *,
    package_path: Path,
    package_root: Path,
    artifact: Mapping[str, Any],
    package_relative_path: Any,
    expected_hash: Any,
    expected_size: Any,
    label: str,
    path_code: str,
    outside_code: str,
    missing_code: str,
    hash_code: str,
    size_code: str,
) -> list[ProjectDiagnostic]:
    artifact_id = artifact.get("id", "<unknown>")
    if not _is_non_empty_string(package_relative_path) or not _is_report_identity_path(
        package_relative_path
    ):
        return [
            ProjectDiagnostic(
                severity="error",
                code=path_code,
                message=(
                    f"Runtime package {label} path must be stable "
                    f"package-relative POSIX path: {artifact_id}"
                ),
                location=SourceLocation(file=str(package_path)),
                check_kind="runtime-package-inspection",
            )
        ]

    file_path = (package_root / package_relative_path).resolve()
    if not _is_relative_to(file_path, package_root):
        return [
            ProjectDiagnostic(
                severity="error",
                code=outside_code,
                message=(
                    f"Runtime package {label} path resolves outside package root: "
                    f"{package_relative_path}"
                ),
                location=SourceLocation(file=str(package_path)),
                check_kind="runtime-package-inspection",
            )
        ]
    if not file_path.is_file():
        return [
            ProjectDiagnostic(
                severity="error",
                code=missing_code,
                message=(
                    f"Runtime package {label} is missing: {package_relative_path}"
                ),
                location=SourceLocation(file=str(package_path)),
                check_kind="runtime-package-inspection",
            )
        ]

    diagnostics: list[ProjectDiagnostic] = []
    if isinstance(expected_hash, Mapping):
        actual_hash = _source_hash(file_path)
        if actual_hash != expected_hash:
            diagnostics.append(
                ProjectDiagnostic(
                    severity="error",
                    code=hash_code,
                    message=(
                        f"Runtime package {label} hash mismatch for "
                        f"{package_relative_path}."
                    ),
                    location=SourceLocation(file=str(package_path)),
                    check_kind="runtime-package-inspection",
                )
            )
    if _is_non_negative_int(expected_size):
        actual_size = file_path.stat().st_size
        if actual_size != expected_size:
            diagnostics.append(
                ProjectDiagnostic(
                    severity="error",
                    code=size_code,
                    message=(
                        f"Runtime package {label} size mismatch for "
                        f"{package_relative_path}: expected {expected_size}, "
                        f"found {actual_size}."
                    ),
                    location=SourceLocation(file=str(package_path)),
                    check_kind="runtime-package-inspection",
                )
            )
    return diagnostics


def _runtime_package_inspection_source_remap(
    *,
    package_path: Path,
    package_root: Path,
    artifact: Mapping[str, Any],
) -> tuple[dict[str, Any] | None, list[ProjectDiagnostic]]:
    source_remap = artifact.get("sourceRemap")
    if not isinstance(source_remap, Mapping):
        return None, []
    diagnostics = _runtime_package_inspection_file_diagnostics(
        package_path=package_path,
        package_root=package_root,
        artifact=artifact,
        package_relative_path=source_remap.get("packagePath"),
        expected_hash=source_remap.get("hash"),
        expected_size=source_remap.get("sizeBytes"),
        label="source remap",
        path_code="project.runtime-package-inspection.source-remap-path-invalid",
        outside_code="project.runtime-package-inspection.source-remap-outside-package",
        missing_code="project.runtime-package-inspection.source-remap-missing",
        hash_code="project.runtime-package-inspection.source-remap-hash-mismatch",
        size_code="project.runtime-package-inspection.source-remap-size-mismatch",
    )
    return {
        "sourcePath": source_remap.get("sourcePath"),
        "packagePath": source_remap.get("packagePath"),
        "hash": source_remap.get("hash"),
        "sizeBytes": source_remap.get("sizeBytes"),
        "status": "ready" if not diagnostics else "failed",
        "diagnostics": [diagnostic.code for diagnostic in diagnostics],
    }, diagnostics


def _runtime_package_inspection_binding_id(artifact: Mapping[str, Any]) -> str:
    return "|".join(
        str(part)
        for part in (
            artifact.get("id", ""),
            artifact.get("packagePath", ""),
        )
    )


def _runtime_host_interface_empty(
    status: str,
    *,
    parser: str | None = None,
    diagnostics: Sequence[str] = (),
    artifact_format: str | None = None,
) -> dict[str, Any]:
    return empty_host_interface_record(
        status,
        parser=parser,
        artifact_format=artifact_format,
        diagnostics=diagnostics,
    )


_RUNTIME_HOST_INTERFACE_STAGE_NAMES = frozenset(
    {
        "vertex",
        "fragment",
        "compute",
        "geometry",
        "tessellation_control",
        "tessellation_evaluation",
        "mesh",
        "task",
        "ray_generation",
        "ray_intersection",
        "ray_any_hit",
        "ray_closest_hit",
        "ray_miss",
        "ray_callable",
    }
)


def _runtime_host_interface_stage_name(stage: Any) -> str | None:
    if hasattr(stage, "value"):
        value = getattr(stage, "value")
        if not value:
            return None
        stage = value
    if stage is None:
        return None
    label = str(stage)
    if not label:
        return None
    label = label.rsplit(".", 1)[-1].lower().replace("-", "_")
    return {
        "frag": "fragment",
        "fs": "fragment",
        "vert": "vertex",
        "vs": "vertex",
        "comp": "compute",
        "cs": "compute",
        "geom": "geometry",
        "gs": "geometry",
        "tess_control": "tessellation_control",
        "tess_eval": "tessellation_evaluation",
    }.get(label, label)


def _runtime_host_interface_json_value(value: Any) -> Any:
    if isinstance(value, Mapping):
        return {
            str(key): _runtime_host_interface_json_value(nested)
            for key, nested in value.items()
        }
    if isinstance(value, (list, tuple)):
        return [_runtime_host_interface_json_value(item) for item in value]
    if isinstance(value, (str, int, float, bool)) or value is None:
        return value
    if hasattr(value, "value"):
        return _runtime_host_interface_json_value(getattr(value, "value"))
    if hasattr(value, "name"):
        return str(getattr(value, "name"))
    return str(value)


def _runtime_host_interface_type_name(type_node: Any) -> str | None:
    if type_node is None:
        return None
    class_name = type(type_node).__name__
    if class_name == "VectorType":
        element_type = _runtime_host_interface_type_name(
            getattr(type_node, "element_type", None)
        )
        return f"{element_type}{getattr(type_node, 'size', '')}"
    if class_name == "MatrixType":
        element_type = _runtime_host_interface_type_name(
            getattr(type_node, "element_type", None)
        )
        return f"{element_type}{type_node.rows}x{type_node.cols}"
    if class_name == "ArrayType":
        element_type = _runtime_host_interface_type_name(
            getattr(type_node, "element_type", None)
        )
        size = _runtime_host_interface_json_value(getattr(type_node, "size", None))
        return f"{element_type}[{size}]" if size is not None else f"{element_type}[]"
    if hasattr(type_node, "name"):
        name = str(getattr(type_node, "name"))
        generic_args = [
            generic_arg
            for generic_arg in getattr(type_node, "generic_args", []) or []
            if generic_arg is not None
        ]
        if generic_args:
            generic_labels = ", ".join(
                filter(
                    None,
                    (
                        _runtime_host_interface_type_name(generic_arg)
                        for generic_arg in generic_args
                    ),
                )
            )
            return f"{name}<{generic_labels}>"
        return name
    return str(type_node)


def _runtime_host_interface_attribute_value(node: Any, names: Sequence[str]) -> Any:
    normalized_names = {name.lower() for name in names}
    for layout_name in ("layout", "interface_layout"):
        layout = getattr(node, layout_name, None)
        if not isinstance(layout, Mapping):
            continue
        for key, value in layout.items():
            if str(key).lower() in normalized_names:
                return _runtime_host_interface_json_value(value)
    for attribute in getattr(node, "attributes", []) or []:
        attribute_name = str(getattr(attribute, "name", "")).lower()
        if attribute_name not in normalized_names:
            continue
        arguments = (
            getattr(attribute, "arguments", None)
            or getattr(attribute, "args", None)
            or []
        )
        if not arguments:
            return None
        return _runtime_host_interface_json_value(arguments[0])
    return None


def _runtime_host_interface_int_attribute(
    node: Any, names: Sequence[str]
) -> int | None:
    value = _runtime_host_interface_attribute_value(node, names)
    if isinstance(value, bool):
        return None
    if isinstance(value, int):
        return value
    if isinstance(value, str) and value.isdigit():
        return int(value)
    return None


def _runtime_host_interface_resource_access(node: Any) -> str | None:
    access = getattr(node, "access", None)
    if isinstance(access, str) and access:
        return access
    qualifiers = {
        str(qualifier).lower() for qualifier in getattr(node, "qualifiers", [])
    }
    attribute_names = {
        str(getattr(attribute, "name", "")).lower()
        for attribute in getattr(node, "attributes", []) or []
    }
    names = qualifiers | attribute_names
    if names & {"writeonly", "write_only"}:
        return "write"
    if names & {"readonly", "read_only", "constant"}:
        return "read"
    if names & {"read_write", "readwrite", "rw", "coherent"}:
        return "read_write"
    return None


def _runtime_host_interface_resource_kind(node: Any) -> str | None:
    class_name = type(node).__name__
    if class_name == "BufferNode":
        return "buffer"
    if class_name == "TextureResourceNode":
        return "texture"
    if class_name == "SamplerNode":
        return "sampler"

    type_name = (
        _runtime_host_interface_type_name(getattr(node, "var_type", None))
        or _runtime_host_interface_type_name(getattr(node, "vtype", None))
        or ""
    )
    type_label = type_name.lower()
    qualifiers = {
        str(qualifier).lower() for qualifier in getattr(node, "qualifiers", [])
    }
    attribute_names = {
        str(getattr(attribute, "name", "")).lower()
        for attribute in getattr(node, "attributes", []) or []
    }

    if "sampler" == type_label or type_label.endswith(" sampler"):
        return "sampler"
    if (
        "rwtexture" in type_label
        or "storage_texture" in type_label
        or re.match(r"^(?:[iu]?image)(?:1d|2d|2darray|3d|buffer|cube)", type_label)
        or "writeonly" in qualifiers
        or "uav" in attribute_names
    ):
        return "storage-texture"
    if "constant" in qualifiers:
        return "constant-buffer"
    if (
        "texture" in type_label
        or "sampler2d" in type_label
        or "texture" in attribute_names
    ):
        return "texture"
    if "buffer" in type_label or "buffer" in qualifiers or "buffer" in attribute_names:
        return "buffer"
    if "uniform" in qualifiers:
        return "uniform"
    return None


def _runtime_host_interface_resource_from_node(node: Any) -> dict[str, Any] | None:
    if _specialization_attribute_values(node):
        return None
    if _is_non_empty_string(getattr(node, "interface_block", None)):
        return None
    kind = _runtime_host_interface_resource_kind(node)
    if kind is None:
        return None

    type_name = (
        _runtime_host_interface_type_name(getattr(node, "buffer_type", None))
        or getattr(node, "texture_type", None)
        or _runtime_host_interface_type_name(getattr(node, "var_type", None))
        or _runtime_host_interface_type_name(getattr(node, "vtype", None))
    )
    return {
        "name": getattr(node, "name", None),
        "kind": kind,
        "type": type_name,
        "set": (
            getattr(node, "set", None)
            if isinstance(getattr(node, "set", None), int)
            else _runtime_host_interface_int_attribute(node, ("set", "space"))
        ),
        "binding": (
            getattr(node, "binding", None)
            if isinstance(getattr(node, "binding", None), int)
            else _runtime_host_interface_int_attribute(
                node, ("binding", "buffer", "texture", "sampler", "uav")
            )
        ),
        "access": _runtime_host_interface_resource_access(node),
    }


def _runtime_host_interface_cbuffer_resource(node: Any) -> dict[str, Any]:
    return {
        "name": getattr(node, "name", None),
        "kind": "constant-buffer",
        "type": getattr(node, "name", None),
        "set": _runtime_host_interface_int_attribute(node, ("set", "space")),
        "binding": _runtime_host_interface_int_attribute(node, ("binding",)),
        "access": "read",
    }


def _runtime_host_interface_resource_from_interface_block(
    node: Any,
) -> dict[str, Any] | None:
    if not getattr(node, "interface_block", False):
        return None
    qualifiers = {
        str(qualifier).lower()
        for qualifier in getattr(node, "interface_qualifiers", []) or []
    }
    if "uniform" in qualifiers:
        kind = "constant-buffer"
        access = "read"
    elif "buffer" in qualifiers:
        kind = "buffer"
        access = _runtime_host_interface_resource_access(node) or "read_write"
    else:
        return None
    return {
        "name": getattr(node, "name", None),
        "kind": kind,
        "type": getattr(node, "name", None),
        "set": _runtime_host_interface_int_attribute(node, ("set", "space")),
        "binding": _runtime_host_interface_int_attribute(node, ("binding",)),
        "access": access,
    }


def _runtime_host_interface_function_stage(function: Any, ast: Any) -> str | None:
    for qualifier in getattr(function, "qualifiers", []) or []:
        stage = _runtime_host_interface_stage_name(qualifier)
        if stage in _RUNTIME_HOST_INTERFACE_STAGE_NAMES:
            return stage
    if getattr(function, "name", None) == "main":
        stage = _runtime_host_interface_stage_name(getattr(ast, "shader_type", None))
        if stage in _RUNTIME_HOST_INTERFACE_STAGE_NAMES:
            return stage
    return None


def _runtime_host_interface_entry_points(ast: Any) -> list[dict[str, Any]]:
    entry_points: list[dict[str, Any]] = []
    stages = getattr(ast, "stages", None)
    stage_items = stages.items() if hasattr(stages, "items") else []
    for stage, stage_node in stage_items:
        entry_point = getattr(stage_node, "entry_point", None)
        if entry_point is None:
            continue
        entry_points.append(
            {
                "name": getattr(entry_point, "name", None),
                "stage": _runtime_host_interface_stage_name(stage),
                "executionConfig": _runtime_host_interface_json_value(
                    getattr(stage_node, "execution_config", {}) or {}
                ),
            }
        )
    seen = {
        (
            entry_point.get("name"),
            entry_point.get("stage"),
        )
        for entry_point in entry_points
    }
    for function in getattr(ast, "functions", []) or []:
        stage = _runtime_host_interface_function_stage(function, ast)
        if stage is None:
            continue
        key = (getattr(function, "name", None), stage)
        if key in seen:
            continue
        seen.add(key)
        entry_points.append(
            {
                "name": getattr(function, "name", None),
                "stage": stage,
                "executionConfig": {},
            }
        )
    return entry_points


def _runtime_host_interface_resources(ast: Any) -> list[dict[str, Any]]:
    resources: list[dict[str, Any]] = []
    for cbuffer in getattr(ast, "cbuffers", []) or []:
        resources.append(_runtime_host_interface_cbuffer_resource(cbuffer))
    for struct in getattr(ast, "structs", []) or []:
        resource = _runtime_host_interface_resource_from_interface_block(struct)
        if resource is not None:
            resources.append(resource)
    for variable_group in ("global_variables", "uniforms"):
        for variable in getattr(ast, variable_group, []) or []:
            resource = _runtime_host_interface_resource_from_node(variable)
            if resource is not None:
                resources.append(resource)
    for function in getattr(ast, "functions", []) or []:
        if _runtime_host_interface_function_stage(function, ast) is None:
            continue
        for parameter in getattr(function, "params", []) or []:
            resource = _runtime_host_interface_resource_from_node(parameter)
            if resource is not None:
                resources.append(resource)

    stages = getattr(ast, "stages", None)
    stage_values = stages.values() if hasattr(stages, "values") else []
    for stage_node in stage_values:
        for cbuffer in getattr(stage_node, "local_cbuffers", []) or []:
            resources.append(_runtime_host_interface_cbuffer_resource(cbuffer))
        for variable in getattr(stage_node, "local_variables", []) or []:
            resource = _runtime_host_interface_resource_from_node(variable)
            if resource is not None:
                resources.append(resource)
    return resources


def _runtime_host_interface_specialization_constants(
    ast: Any, *, parser: str
) -> list[dict[str, Any]]:
    constants = []
    for node, default_value, has_default in _specialization_ast_declaration_items(ast):
        attributes = _specialization_attribute_values(node)
        if not attributes:
            continue
        ids = {constant_id for _attribute, constant_id in attributes}
        constant_id = next(iter(ids)) if len(ids) == 1 else None
        attribute = attributes[0][0]
        source_type = (
            _runtime_host_interface_type_name(getattr(node, "var_type", None))
            or _runtime_host_interface_type_name(getattr(node, "vtype", None))
            or _runtime_host_interface_type_name(getattr(node, "const_type", None))
            or "unknown"
        )
        payload = {
            "name": getattr(node, "name", None),
            "id": constant_id,
            "kind": (
                "function-constant"
                if attribute == "function_constant"
                else "specialization-constant"
            ),
            "dtype": source_type,
            "sourceType": source_type,
            "required": not has_default,
            "overridden": False,
            "overrideStatus": "not-overridden",
            "status": "defaulted" if has_default else "required",
            "source": f"{parser}.{attribute}",
        }
        if has_default:
            value = _specialization_scalar_literal(default_value)
            payload["default"] = value
            payload["defaultValue"] = value
        constants.append(payload)
    return constants


def _runtime_host_interface_from_ast(
    ast: Any, parser: str, *, source: str = "package-artifact"
) -> dict[str, Any]:
    entry_points = _runtime_host_interface_entry_points(ast)
    resources = _runtime_host_interface_resources(ast)
    specialization_constants = _runtime_host_interface_specialization_constants(
        ast, parser=parser
    )
    return host_interface_record(
        status="ready",
        source=source,
        parser=parser,
        entry_points=entry_points,
        resources=resources,
        specialization_constants=specialization_constants,
    )


def _runtime_host_interface_for_wgsl_target(
    host_interface: Mapping[str, Any],
) -> dict[str, Any]:
    payload = dict(host_interface)
    stage_counts: Counter[str] = Counter()
    entry_points = []
    for entry_point in _record_sequence(payload.get("entryPoints")):
        if not isinstance(entry_point, Mapping):
            continue
        entry_payload = dict(entry_point)
        stage = _runtime_host_interface_stage_name(entry_payload.get("stage"))
        if stage in {"vertex", "fragment", "compute"}:
            stage_index = stage_counts[stage]
            stage_counts[stage] += 1
            entry_name = f"{stage}_main"
            if stage_index:
                entry_name = f"{entry_name}_{stage_index}"
            entry_payload["name"] = entry_name
            entry_payload["stage"] = stage
        entry_points.append(entry_payload)
    payload["entryPoints"] = entry_points
    payload["entryPointCount"] = len(entry_points)
    return payload


def _runtime_wgsl_reflect_entry_points(code: str) -> list[dict[str, Any]]:
    entry_points = []
    for match in RUNTIME_WGSL_ENTRY_RE.finditer(code):
        entry_points.append(
            {
                "name": match.group("name"),
                "stage": match.group("stage"),
                "executionConfig": {},
            }
        )
    return entry_points


def _runtime_wgsl_resource_kind(
    address_space: str | None, type_name: str
) -> tuple[str | None, str | None]:
    address_parts = [
        part.strip().lower()
        for part in (address_space or "").split(",")
        if part.strip()
    ]
    address_kind = address_parts[0] if address_parts else None
    access = address_parts[1] if len(address_parts) > 1 else None
    lowered_type = type_name.strip().lower()
    if address_kind == "uniform":
        return "uniform", "read"
    if address_kind == "storage":
        return "buffer", access or "read"
    if lowered_type.startswith("texture_storage_"):
        texture_access = None
        match = re.search(r"<[^,>]+,\s*([^>]+)>", type_name)
        if match:
            texture_access = match.group(1).strip()
        return "storage-texture", texture_access
    if lowered_type.startswith("texture_"):
        return "texture", None
    if lowered_type in {"sampler", "sampler_comparison"}:
        return "sampler", None
    return None, None


def _runtime_wgsl_reflect_resources(code: str) -> list[dict[str, Any]]:
    resources = []
    for match in RUNTIME_WGSL_RESOURCE_RE.finditer(code):
        type_name = match.group("type").strip()
        kind, access = _runtime_wgsl_resource_kind(match.group("address"), type_name)
        if kind is None:
            continue
        resources.append(
            {
                "name": match.group("name"),
                "kind": kind,
                "type": type_name,
                "set": int(match.group("set")),
                "binding": int(match.group("binding")),
                "access": access,
            }
        )
    return resources


def _runtime_wgsl_symbolic_resource_binding_diagnostics(code: str) -> list[str]:
    has_symbolic_resource_binding = False
    for match in RUNTIME_WGSL_BOUND_RESOURCE_RE.finditer(code):
        group = match.group("set").strip()
        binding = match.group("binding").strip()
        if group.isdigit() and binding.isdigit():
            continue
        type_name = match.group("type").strip()
        kind, _ = _runtime_wgsl_resource_kind(match.group("address"), type_name)
        if kind is not None:
            has_symbolic_resource_binding = True
    if has_symbolic_resource_binding:
        return [RUNTIME_WGSL_SYMBOLIC_RESOURCE_BINDING_DIAGNOSTIC]
    return []


def _runtime_host_interface_from_wgsl_source(
    code: str,
    *,
    parser: str = RUNTIME_WGSL_REFLECTION_PARSER,
    source: str = "package-artifact",
) -> dict[str, Any]:
    entry_points = _runtime_wgsl_reflect_entry_points(code)
    resources = _runtime_wgsl_reflect_resources(code)
    diagnostics = _runtime_wgsl_symbolic_resource_binding_diagnostics(code)
    return host_interface_record(
        status="unavailable" if diagnostics else "ready",
        source=source,
        parser=parser,
        artifact_format="WGSL source",
        entry_points=entry_points,
        resources=resources,
        diagnostics=diagnostics,
    )


def _runtime_package_inspection_parser_name(target_name: str) -> str | None:
    if not target_name:
        return None
    if target_name == "webgl":
        return "opengl"
    return SOURCE_REGISTRY.resolve_name(target_name)


def _runtime_package_artifact_host_interface(
    artifact: Mapping[str, Any],
) -> dict[str, Any] | None:
    host_interface = artifact.get("hostInterface")
    if not isinstance(host_interface, Mapping):
        return None
    if host_interface.get("status") != "ready":
        return None
    return host_interface_record(
        status=str(host_interface.get("status") or "ready"),
        source=str(host_interface.get("source") or "package-artifact"),
        parser=(
            str(host_interface.get("parser"))
            if _is_non_empty_string(host_interface.get("parser"))
            else None
        ),
        artifact_format=(
            str(host_interface.get("artifactFormat"))
            if _is_non_empty_string(host_interface.get("artifactFormat"))
            else None
        ),
        entry_points=[
            dict(entry_point)
            for entry_point in _record_sequence(host_interface.get("entryPoints"))
            if isinstance(entry_point, Mapping)
        ],
        resources=[
            dict(resource)
            for resource in _record_sequence(host_interface.get("resources"))
            if isinstance(resource, Mapping)
        ],
        constants=[
            dict(constant)
            for constant in _record_sequence(host_interface.get("constants"))
            if isinstance(constant, Mapping)
        ],
        specialization_constants=[
            dict(constant)
            for constant in _record_sequence(
                host_interface.get("specializationConstants")
            )
            if isinstance(constant, Mapping)
        ],
        diagnostics=[
            diagnostic
            for diagnostic in _record_sequence(host_interface.get("diagnostics"))
            if _is_non_empty_string(diagnostic)
        ],
    )


def _runtime_package_directx_execution_host_interface(
    package_root: Path,
    artifact: Mapping[str, Any],
) -> dict[str, Any] | None:
    if artifact.get("target") != "directx":
        return None
    package_path = artifact.get("packagePath")
    if not _is_non_empty_string(package_path):
        return None
    artifact_path = (package_root / str(package_path)).resolve()
    if not _is_relative_to(artifact_path, package_root) or not artifact_path.is_file():
        return None
    try:
        source = artifact_path.read_text(encoding="utf-8", errors="replace")
    except OSError:
        return None
    source = re.sub(r"/\*.*?\*/", "", source, flags=re.DOTALL)
    source = re.sub(r"//.*", "", source)

    declared_host_interface = artifact.get("hostInterface")
    declared_entries = {
        str(entry["name"]): entry
        for entry in _record_sequence(
            declared_host_interface.get("entryPoints")
            if isinstance(declared_host_interface, Mapping)
            else None
        )
        if isinstance(entry, Mapping) and _is_non_empty_string(entry.get("name"))
    }
    entries = []
    for match in DIRECTX_HLSL_FUNCTION_RE.finditer(source):
        attributes = match.group("attributes") or ""
        dimensions = DIRECTX_HLSL_NUMTHREADS_VALUES_RE.search(attributes)
        if dimensions is None:
            continue
        components = []
        for axis in ("x", "y", "z"):
            raw_value = dimensions.group(axis).strip()
            try:
                value: Any = parse_c_family_integral_literal(raw_value)
            except CFamilyIntegralLiteralError:
                value = raw_value
            components.append(value)
        execution_config: dict[str, Any] = {"numthreads": components}
        wave_sizes = list(DIRECTX_HLSL_WAVE_SIZE_RE.finditer(attributes))
        if wave_sizes:
            arguments = [
                wave_size.group("arguments").strip() for wave_size in wave_sizes
            ]
            if len(arguments) == 1 and "," not in arguments[0]:
                try:
                    subgroup_width: Any = parse_c_family_integral_literal(arguments[0])
                except CFamilyIntegralLiteralError:
                    subgroup_width = arguments[0]
            else:
                subgroup_width = arguments
            execution_config["subgroupWidth"] = subgroup_width
        else:
            declared_entry = declared_entries.get(str(match.group("name")))
            declared_config = (
                declared_entry.get("executionConfig")
                if isinstance(declared_entry, Mapping)
                else None
            )
            declared_subgroups = [
                declared_config.get(field_name)
                for field_name in _RUNTIME_VARIANT_SUBGROUP_WIDTH_FIELDS
                if isinstance(declared_config, Mapping)
                and declared_config.get(field_name) is not None
            ]
            if declared_subgroups:
                execution_config["subgroupWidth"] = {
                    "compiled": None,
                    "declared": declared_subgroups,
                }
        entries.append(
            {
                "name": match.group("name"),
                "stage": "compute",
                "executionConfig": execution_config,
            }
        )
    if not entries:
        return None
    return {
        "status": "ready",
        "entryPoints": entries,
    }


def _runtime_merge_host_interface_execution_entries(
    reflected: Mapping[str, Any],
    declared: Any,
) -> dict[str, Any]:
    if not isinstance(declared, Mapping):
        return dict(reflected)
    payload = dict(reflected)
    reflected_entries = [
        entry
        for entry in _record_sequence(reflected.get("entryPoints"))
        if isinstance(entry, Mapping) and _is_non_empty_string(entry.get("name"))
    ]
    declared_entries = [
        entry
        for entry in _record_sequence(declared.get("entryPoints"))
        if isinstance(entry, Mapping) and _is_non_empty_string(entry.get("name"))
    ]
    entries_by_name = {str(entry["name"]): dict(entry) for entry in reflected_entries}
    entry_order = [str(entry["name"]) for entry in reflected_entries]
    for declared_entry in sorted(
        declared_entries,
        key=_runtime_variant_canonical_json,
    ):
        name = str(declared_entry["name"])
        reflected_entry = entries_by_name.get(name)
        if reflected_entry is None:
            entries_by_name[name] = dict(declared_entry)
            entry_order.append(name)
            continue
        reflected_config = reflected_entry.get("executionConfig")
        declared_config = declared_entry.get("executionConfig")
        combined_config = (
            dict(reflected_config) if isinstance(reflected_config, Mapping) else {}
        )
        if isinstance(declared_config, Mapping):
            for field_name, value in declared_config.items():
                if field_name not in combined_config:
                    combined_config[field_name] = value
                    continue
                if combined_config[field_name] == value:
                    continue
                if (combined_config[field_name] is None) != (value is None):
                    combined_config[field_name] = {
                        "reflected": combined_config[field_name],
                        "declared": value,
                    }
                    continue
                conflict_fields = (
                    _RUNTIME_VARIANT_WORKGROUP_SIZE_FIELDS
                    if field_name in _RUNTIME_VARIANT_WORKGROUP_SIZE_FIELDS
                    else (
                        _RUNTIME_VARIANT_SUBGROUP_WIDTH_FIELDS
                        if field_name in _RUNTIME_VARIANT_SUBGROUP_WIDTH_FIELDS
                        else ()
                    )
                )
                conflict_field = next(
                    (
                        candidate
                        for candidate in conflict_fields
                        if candidate != field_name and candidate not in combined_config
                    ),
                    None,
                )
                if conflict_field is not None:
                    combined_config[conflict_field] = value
                elif conflict_fields:
                    combined_config[field_name] = {
                        "reflected": combined_config[field_name],
                        "declared": value,
                    }
        reflected_entry["executionConfig"] = combined_config
        if not _is_non_empty_string(reflected_entry.get("stage")):
            reflected_entry["stage"] = declared_entry.get("stage")
        entries_by_name[name] = reflected_entry
    payload["entryPoints"] = [entries_by_name[name] for name in entry_order]
    payload["entryPointCount"] = len(entries_by_name)
    if payload["entryPoints"] and payload.get("status") != "ready":
        payload["status"] = declared.get("status")
    return payload


def _runtime_package_inspection_host_interface(
    *,
    package_root: Path,
    artifact: Mapping[str, Any],
    artifact_diagnostics: Sequence[ProjectDiagnostic],
) -> dict[str, Any]:
    target = artifact.get("target")
    target_name = str(target).lower() if _is_non_empty_string(target) else ""
    parser_name = None
    source_spec = None
    try:
        register_default_sources()
        parser_name = _runtime_package_inspection_parser_name(target_name)
        source_spec = SOURCE_REGISTRY.get(parser_name) if parser_name else None
    except Exception:
        parser_name = None
        source_spec = None
    catalog_entry = _runtime_adapter_catalog_entry(target_name)
    artifact_format = catalog_entry.get("artifactFormat")

    if artifact_diagnostics:
        return _runtime_host_interface_empty(
            "not-inspected",
            parser=parser_name,
            artifact_format=artifact_format,
            diagnostics=(
                "project.runtime-package-inspection.host-interface-artifact-not-ready",
            ),
        )
    package_relative_path = artifact.get("packagePath")
    if target_name == "wgsl":
        if not _is_non_empty_string(package_relative_path):
            return _runtime_host_interface_empty(
                "not-inspected",
                parser=RUNTIME_WGSL_REFLECTION_PARSER,
                artifact_format="WGSL source",
                diagnostics=(
                    "project.runtime-package-inspection.host-interface-artifact-not-ready",
                ),
            )
        artifact_path = (package_root / package_relative_path).resolve()
        if (
            not _is_relative_to(artifact_path, package_root)
            or not artifact_path.is_file()
        ):
            return _runtime_host_interface_empty(
                "not-inspected",
                parser=RUNTIME_WGSL_REFLECTION_PARSER,
                artifact_format="WGSL source",
                diagnostics=(
                    "project.runtime-package-inspection.host-interface-artifact-not-ready",
                ),
            )
        try:
            host_interface = _runtime_host_interface_from_wgsl_source(
                artifact_path.read_text(encoding="utf-8", errors="replace")
            )
        except OSError:
            return _runtime_host_interface_empty(
                "not-inspected",
                parser=RUNTIME_WGSL_REFLECTION_PARSER,
                artifact_format="WGSL source",
                diagnostics=(
                    "project.runtime-package-inspection.host-interface-artifact-not-ready",
                ),
            )
        if (
            host_interface["entryPointCount"] == 0
            and host_interface["resourceCount"] == 0
            and host_interface.get("specializationConstantCount", 0) == 0
        ):
            return _runtime_host_interface_empty(
                "unavailable",
                parser=RUNTIME_WGSL_REFLECTION_PARSER,
                artifact_format="WGSL source",
                diagnostics=(
                    "project.runtime-package-inspection.host-interface-empty",
                ),
            )
        return host_interface

    reflected_targets = {"directx", "opengl", "webgl", "vulkan"}
    if target_name in reflected_targets:
        if not _is_non_empty_string(package_relative_path):
            return _runtime_host_interface_empty(
                "not-inspected",
                parser=f"{target_name}-reflection",
                artifact_format=artifact_format,
                diagnostics=(
                    "project.runtime-package-inspection.host-interface-artifact-not-ready",
                ),
            )
        artifact_path = (package_root / package_relative_path).resolve()
        if (
            not _is_relative_to(artifact_path, package_root)
            or not artifact_path.is_file()
        ):
            return _runtime_host_interface_empty(
                "not-inspected",
                parser=f"{target_name}-reflection",
                artifact_format=artifact_format,
                diagnostics=(
                    "project.runtime-package-inspection.host-interface-artifact-not-ready",
                ),
            )
        reflected_interface = reflect_target_host_interface(
            artifact_path,
            target=target_name,
            artifact_format=artifact_format,
            stage=(
                str(artifact.get("stage"))
                if _is_non_empty_string(artifact.get("stage"))
                else None
            ),
        )
        if isinstance(reflected_interface, Mapping):
            execution_interface = _runtime_package_directx_execution_host_interface(
                package_root,
                artifact,
            )
            reflected_with_execution = _runtime_merge_host_interface_execution_entries(
                reflected_interface,
                execution_interface,
            )
            return _runtime_merge_host_interface_execution_entries(
                reflected_with_execution,
                artifact.get("hostInterface"),
            )

    if source_spec is None:
        source_host_interface = _runtime_package_artifact_host_interface(artifact)
        if source_host_interface is not None:
            return source_host_interface
        return _runtime_host_interface_empty(
            "unavailable",
            artifact_format=artifact_format,
            diagnostics=(
                "project.runtime-package-inspection.host-interface-parser-unavailable",
            ),
        )

    if not _is_non_empty_string(package_relative_path):
        return _runtime_host_interface_empty(
            "not-inspected",
            parser=parser_name,
            artifact_format=artifact_format,
            diagnostics=(
                "project.runtime-package-inspection.host-interface-artifact-not-ready",
            ),
        )

    artifact_path = (package_root / package_relative_path).resolve()
    if not _is_relative_to(artifact_path, package_root) or not artifact_path.is_file():
        return _runtime_host_interface_empty(
            "not-inspected",
            parser=parser_name,
            artifact_format=artifact_format,
            diagnostics=(
                "project.runtime-package-inspection.host-interface-artifact-not-ready",
            ),
        )

    try:
        ast = source_spec.parse(
            artifact_path.read_text(encoding="utf-8"),
            file_path=str(artifact_path),
        )
    except Exception:
        return _runtime_host_interface_empty(
            "failed",
            parser=parser_name,
            artifact_format=artifact_format,
            diagnostics=(
                "project.runtime-package-inspection.host-interface-parse-failed",
            ),
        )
    host_interface = _runtime_host_interface_from_ast(ast, parser=parser_name or "")
    if (
        host_interface["entryPointCount"] == 0
        and host_interface["resourceCount"] == 0
        and host_interface.get("specializationConstantCount", 0) == 0
    ):
        return _runtime_host_interface_empty(
            "unavailable",
            parser=parser_name,
            artifact_format=artifact_format,
            diagnostics=("project.runtime-package-inspection.host-interface-empty",),
        )
    return host_interface


def _runtime_package_inspection_binding(
    *,
    package_path: Path,
    package_root: Path,
    artifact: Mapping[str, Any],
) -> tuple[dict[str, Any], list[ProjectDiagnostic]]:
    artifact_diagnostics = _runtime_package_inspection_file_diagnostics(
        package_path=package_path,
        package_root=package_root,
        artifact=artifact,
        package_relative_path=artifact.get("packagePath"),
        expected_hash=artifact.get("hash"),
        expected_size=artifact.get("sizeBytes"),
        label="artifact",
        path_code="project.runtime-package-inspection.artifact-path-invalid",
        outside_code="project.runtime-package-inspection.artifact-outside-package",
        missing_code="project.runtime-package-inspection.artifact-missing",
        hash_code="project.runtime-package-inspection.artifact-hash-mismatch",
        size_code="project.runtime-package-inspection.artifact-size-mismatch",
    )
    source_remap, source_remap_diagnostics = _runtime_package_inspection_source_remap(
        package_path=package_path,
        package_root=package_root,
        artifact=artifact,
    )
    host_interface = _runtime_package_inspection_host_interface(
        package_root=package_root,
        artifact=artifact,
        artifact_diagnostics=artifact_diagnostics,
    )
    diagnostics = [*artifact_diagnostics, *source_remap_diagnostics]
    return {
        "id": _runtime_package_inspection_binding_id(artifact),
        "status": "ready" if not diagnostics else "failed",
        "artifactStatus": "ready" if not artifact_diagnostics else "failed",
        "target": artifact.get("target"),
        "artifact": artifact.get("id"),
        "packagePath": artifact.get("packagePath"),
        "source": artifact.get("source"),
        "sourcePath": artifact.get("sourcePath"),
        "sourceBackend": artifact.get("sourceBackend"),
        "stage": artifact.get("stage"),
        "variant": artifact.get("variant"),
        "defines": (
            dict(artifact.get("defines"))
            if isinstance(artifact.get("defines"), Mapping)
            else {}
        ),
        "entryPoint": (
            dict(artifact.get("entryPoint"))
            if isinstance(artifact.get("entryPoint"), Mapping)
            else None
        ),
        "templateMaterialization": (
            dict(artifact.get("templateMaterialization"))
            if isinstance(artifact.get("templateMaterialization"), Mapping)
            else None
        ),
        "specializationMaterialization": (
            dict(artifact.get("specializationMaterialization"))
            if isinstance(artifact.get("specializationMaterialization"), Mapping)
            else None
        ),
        "specializationConstants": [
            dict(constant)
            for constant in _record_sequence(artifact.get("specializationConstants"))
            if isinstance(constant, Mapping)
        ],
        "provenance": (
            dict(artifact.get("provenance"))
            if isinstance(artifact.get("provenance"), Mapping)
            else {}
        ),
        "sourceHash": artifact.get("sourceHash"),
        "sourceSizeBytes": artifact.get("sourceSizeBytes"),
        "hash": artifact.get("hash"),
        "sizeBytes": artifact.get("sizeBytes"),
        "sourceRemap": source_remap,
        "hostInterface": host_interface,
        "diagnostics": [diagnostic.code for diagnostic in diagnostics],
    }, diagnostics


def _runtime_package_inspection_target(
    target: str,
    bindings: Sequence[Mapping[str, Any]],
    runtime_reference_count: int,
) -> dict[str, Any]:
    target_bindings = [
        binding for binding in bindings if binding.get("target") == target
    ]
    ready_bindings = [
        binding for binding in target_bindings if binding.get("status") == "ready"
    ]
    failed_bindings = [
        binding for binding in target_bindings if binding.get("status") == "failed"
    ]
    verified_artifacts = [
        binding
        for binding in target_bindings
        if binding.get("artifactStatus") == "ready"
    ]
    failed_artifacts = [
        binding
        for binding in target_bindings
        if binding.get("artifactStatus") == "failed"
    ]
    source_remap_count = sum(
        1
        for binding in target_bindings
        if isinstance(binding.get("sourceRemap"), Mapping)
    )
    verified_source_remap_count = sum(
        1
        for binding in target_bindings
        if isinstance(binding.get("sourceRemap"), Mapping)
        and binding["sourceRemap"].get("status") == "ready"
    )
    return {
        "target": target,
        "artifactCount": len(target_bindings),
        "verifiedArtifactCount": len(verified_artifacts),
        "failedArtifactCount": len(failed_artifacts),
        "sourceRemapCount": source_remap_count,
        "verifiedSourceRemapCount": verified_source_remap_count,
        "readyBindingCount": len(ready_bindings),
        "failedBindingCount": len(failed_bindings),
        "bindingCount": len(target_bindings),
        "runtimeReferenceCount": runtime_reference_count,
        "bindings": [binding.get("id") for binding in target_bindings],
    }


def inspect_runtime_package(
    package_manifest_path: str | os.PathLike[str],
) -> dict[str, Any]:
    """Inspect a runtime handoff package for host binding readiness."""

    package_path = _filesystem_path_arg(
        package_manifest_path, field_name="Runtime package manifest path"
    )
    package, diagnostics = _runtime_package_inspection_load_package(package_path)
    if package:
        diagnostics.extend(
            _runtime_package_inspection_package_diagnostics(package_path, package)
        )
    package_input_valid = not any(
        diagnostic.severity == "error" for diagnostic in diagnostics
    )
    package_root = _runtime_package_inspection_package_root(package_path, package)

    project_payload = (
        dict(package.get("project"))
        if isinstance(package.get("project"), Mapping)
        else {"targets": []}
    )
    targets = [
        target
        for target in project_payload.get("targets", [])
        if _is_non_empty_string(target)
    ]
    runtime_plan = (
        dict(package.get("runtimePlan"))
        if isinstance(package.get("runtimePlan"), Mapping)
        else {}
    )
    runtime_reference_count = (
        runtime_plan.get("runtimeReferenceCount")
        if _is_non_negative_int(runtime_plan.get("runtimeReferenceCount"))
        else 0
    )
    package_artifacts = (
        _runtime_host_binding_packaged_artifacts(package) if package_input_valid else []
    )
    bindings: list[dict[str, Any]] = []
    binding_diagnostics: list[ProjectDiagnostic] = []
    for artifact in package_artifacts:
        binding, artifact_diagnostics = _runtime_package_inspection_binding(
            package_path=package_path,
            package_root=package_root,
            artifact=artifact,
        )
        bindings.append(binding)
        binding_diagnostics.extend(artifact_diagnostics)
    diagnostics.extend(binding_diagnostics)
    ready_binding_count = sum(
        1 for binding in bindings if binding.get("status") == "ready"
    )
    failed_binding_count = sum(
        1 for binding in bindings if binding.get("status") == "failed"
    )
    verified_artifact_count = sum(
        1 for binding in bindings if binding.get("artifactStatus") == "ready"
    )
    failed_artifact_count = sum(
        1 for binding in bindings if binding.get("artifactStatus") == "failed"
    )
    source_remap_count = sum(
        1 for binding in bindings if isinstance(binding.get("sourceRemap"), Mapping)
    )
    verified_source_remap_count = sum(
        1
        for binding in bindings
        if isinstance(binding.get("sourceRemap"), Mapping)
        and binding["sourceRemap"].get("status") == "ready"
    )
    host_binding_actions = _runtime_host_binding_actions(
        bindings, targets, runtime_reference_count
    )

    return {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": RUNTIME_PACKAGE_INSPECTION_KIND,
        "sourcePackage": str(package_path),
        "sourcePackageHash": _optional_source_hash(package_path),
        "generatedAt": int(time.time()),
        "success": not any(
            diagnostic.severity == "error" for diagnostic in diagnostics
        ),
        "scope": RUNTIME_PACKAGE_INSPECTION_SCOPE,
        "nonGoals": list(RUNTIME_PACKAGE_INSPECTION_NON_GOALS),
        "packageRoot": (
            package.get("packageRoot") if isinstance(package, Mapping) else None
        ),
        "project": project_payload,
        "summary": {
            "targetCount": len(targets),
            "artifactCount": len(bindings),
            "verifiedArtifactCount": verified_artifact_count,
            "failedArtifactCount": failed_artifact_count,
            "sourceRemapCount": source_remap_count,
            "verifiedSourceRemapCount": verified_source_remap_count,
            "readyBindingCount": ready_binding_count,
            "failedBindingCount": failed_binding_count,
            "bindingCount": len(bindings),
            "runtimeReferenceCount": runtime_reference_count,
            "actionCount": len(host_binding_actions),
        },
        "hostBindingPlan": {
            "kind": RUNTIME_HOST_BINDING_PLAN_KIND,
            "actionCount": len(host_binding_actions),
            "runtimeReferenceCount": runtime_reference_count,
            "reviewRequired": runtime_reference_count > 0 and ready_binding_count > 0,
        },
        "targets": [
            _runtime_package_inspection_target(
                target, bindings, runtime_reference_count
            )
            for target in targets
        ],
        "bindings": bindings,
        "runtimePlan": runtime_plan,
        "diagnosticCounts": _diagnostic_counts(diagnostics),
        "diagnostics": [diagnostic.to_json() for diagnostic in diagnostics],
    }


def _runtime_adapter_catalog_entry(target: Any) -> Mapping[str, Any]:
    if not _is_non_empty_string(target):
        return RUNTIME_ADAPTER_DEFAULT_CATALOG_ENTRY
    return RUNTIME_ADAPTER_CATALOG.get(target, RUNTIME_ADAPTER_DEFAULT_CATALOG_ENTRY)


def _runtime_adapter_id(binding: Mapping[str, Any]) -> str:
    return "|".join(
        str(part)
        for part in (
            binding.get("target", ""),
            binding.get("id", ""),
            binding.get("packagePath", ""),
        )
    )


def _runtime_adapter_entry(binding: Mapping[str, Any]) -> dict[str, Any]:
    catalog_entry = _runtime_adapter_catalog_entry(binding.get("target"))
    source_remap = binding.get("sourceRemap")
    return {
        "id": _runtime_adapter_id(binding),
        "target": binding.get("target"),
        "adapterKind": catalog_entry["adapterKind"],
        "artifactFormat": catalog_entry["artifactFormat"],
        "binding": binding.get("id"),
        "artifact": binding.get("artifact"),
        "packagePath": binding.get("packagePath"),
        "source": binding.get("source"),
        "sourcePath": binding.get("sourcePath"),
        "sourceBackend": binding.get("sourceBackend"),
        "stage": binding.get("stage"),
        "variant": binding.get("variant"),
        "defines": (
            dict(binding.get("defines"))
            if isinstance(binding.get("defines"), Mapping)
            else {}
        ),
        "entryPoint": (
            dict(binding.get("entryPoint"))
            if isinstance(binding.get("entryPoint"), Mapping)
            else None
        ),
        "templateMaterialization": (
            dict(binding.get("templateMaterialization"))
            if isinstance(binding.get("templateMaterialization"), Mapping)
            else None
        ),
        "specializationMaterialization": (
            dict(binding.get("specializationMaterialization"))
            if isinstance(binding.get("specializationMaterialization"), Mapping)
            else None
        ),
        "specializationConstants": [
            dict(constant)
            for constant in _record_sequence(binding.get("specializationConstants"))
            if isinstance(constant, Mapping)
        ],
        "provenance": (
            dict(binding.get("provenance"))
            if isinstance(binding.get("provenance"), Mapping)
            else {}
        ),
        "sourceHash": binding.get("sourceHash"),
        "sourceSizeBytes": binding.get("sourceSizeBytes"),
        "hash": binding.get("hash"),
        "sizeBytes": binding.get("sizeBytes"),
        "sourceRemap": (
            {
                "packagePath": source_remap.get("packagePath"),
                "sourcePath": source_remap.get("sourcePath"),
                "status": source_remap.get("status"),
            }
            if isinstance(source_remap, Mapping)
            else None
        ),
        "hostInterface": (
            dict(binding.get("hostInterface"))
            if isinstance(binding.get("hostInterface"), Mapping)
            else _runtime_host_interface_empty(
                "not-inspected",
                diagnostics=(
                    "project.runtime-package-inspection.host-interface-not-recorded",
                ),
            )
        ),
        "requiredTools": list(catalog_entry["requiredTools"]),
        "hostResponsibilities": list(catalog_entry["loaderResponsibilities"]),
        "validation": {
            "packageInspection": binding.get("status"),
            "artifact": binding.get("artifactStatus"),
            "sourceRemap": (
                source_remap.get("status")
                if isinstance(source_remap, Mapping)
                else "not-recorded"
            ),
        },
    }


def _runtime_adapter_target(
    target: str,
    bindings: Sequence[Mapping[str, Any]],
    adapters: Sequence[Mapping[str, Any]],
    runtime_reference_count: int,
) -> dict[str, Any]:
    catalog_entry = _runtime_adapter_catalog_entry(target)
    target_bindings = [
        binding for binding in bindings if binding.get("target") == target
    ]
    target_adapters = [
        adapter for adapter in adapters if adapter.get("target") == target
    ]
    ready_bindings = [
        binding for binding in target_bindings if binding.get("status") == "ready"
    ]
    failed_bindings = [
        binding for binding in target_bindings if binding.get("status") == "failed"
    ]
    return {
        "target": target,
        "adapterKind": catalog_entry["adapterKind"],
        "artifactCount": len(target_bindings),
        "readyBindingCount": len(ready_bindings),
        "failedBindingCount": len(failed_bindings),
        "runtimeReferenceCount": runtime_reference_count,
        "requiredTools": list(catalog_entry["requiredTools"]),
        "loaderResponsibilities": list(catalog_entry["loaderResponsibilities"]),
        "bindings": [binding.get("id") for binding in target_bindings],
        "packagePaths": [
            adapter.get("packagePath")
            for adapter in target_adapters
            if _is_non_empty_string(adapter.get("packagePath"))
        ],
    }


def _runtime_adapter_action(adapter: Mapping[str, Any]) -> dict[str, Any]:
    return {
        "kind": "wire-runtime-adapter",
        "severity": "note",
        "message": (
            f"Wire {adapter.get('adapterKind')} to load "
            f"{adapter.get('packagePath')} for target {adapter.get('target')}."
        ),
        "target": adapter.get("target"),
        "adapter": adapter.get("id"),
        "binding": adapter.get("binding"),
        "packagePath": adapter.get("packagePath"),
    }


def _runtime_adapter_host_interface_action(
    adapter: Mapping[str, Any],
) -> dict[str, Any] | None:
    host_interface = adapter.get("hostInterface")
    if isinstance(host_interface, Mapping):
        status = host_interface.get("status")
        diagnostics = [
            diagnostic
            for diagnostic in _record_sequence(host_interface.get("diagnostics"))
            if _is_non_empty_string(diagnostic)
        ]
    else:
        status = "not-inspected"
        diagnostics = ["project.runtime-package-inspection.host-interface-not-recorded"]

    status = status if _is_non_empty_string(status) else "not-inspected"
    if status == "ready":
        return None

    diagnostic_suffix = (
        f" Diagnostics: {', '.join(diagnostics)}." if diagnostics else ""
    )
    return {
        "kind": "resolve-host-interface-metadata",
        "severity": "note" if status == "not-inspected" else "warning",
        "message": (
            f"Resolve host interface metadata for {adapter.get('packagePath')} "
            f"before wiring {adapter.get('adapterKind')}: status is {status}. "
            "Provide reflection data or backend-specific entry point and resource "
            f"binding metadata for host and build tooling.{diagnostic_suffix}"
        ),
        "target": adapter.get("target"),
        "adapter": adapter.get("id"),
        "binding": adapter.get("binding"),
        "packagePath": adapter.get("packagePath"),
    }


def _runtime_adapter_review_action(
    target: str, runtime_reference_count: int
) -> dict[str, Any] | None:
    if runtime_reference_count <= 0:
        return None
    return {
        "kind": "review-runtime-references",
        "severity": "warning",
        "message": (
            f"Review {runtime_reference_count} detected host or build runtime "
            f"references before wiring adapters for {target}."
        ),
        "target": target,
        "adapter": None,
        "binding": None,
        "packagePath": None,
    }


def plan_runtime_adapters(
    package_manifest_path: str | os.PathLike[str],
) -> dict[str, Any]:
    """Build a target adapter plan from a runtime package manifest."""

    package_path = _filesystem_path_arg(
        package_manifest_path, field_name="Runtime package manifest path"
    )
    inspection = inspect_runtime_package(package_path)
    project_payload = (
        dict(inspection.get("project"))
        if isinstance(inspection.get("project"), Mapping)
        else {"targets": []}
    )
    targets = [
        target
        for target in project_payload.get("targets", [])
        if _is_non_empty_string(target)
    ]
    bindings = [
        binding
        for binding in _record_sequence(inspection.get("bindings"))
        if isinstance(binding, Mapping)
    ]
    ready_bindings = [
        binding for binding in bindings if binding.get("status") == "ready"
    ]
    failed_binding_count = sum(
        1 for binding in bindings if binding.get("status") == "failed"
    )
    adapters = [_runtime_adapter_entry(binding) for binding in ready_bindings]
    runtime_plan = (
        dict(inspection.get("runtimePlan"))
        if isinstance(inspection.get("runtimePlan"), Mapping)
        else {}
    )
    summary = (
        inspection.get("summary")
        if isinstance(inspection.get("summary"), Mapping)
        else {}
    )
    runtime_reference_count = (
        summary.get("runtimeReferenceCount")
        if _is_non_negative_int(summary.get("runtimeReferenceCount"))
        else 0
    )
    actions = []
    for adapter in adapters:
        actions.append(_runtime_adapter_action(adapter))
        host_interface_action = _runtime_adapter_host_interface_action(adapter)
        if host_interface_action is not None:
            actions.append(host_interface_action)
    if adapters:
        for target in targets:
            review_action = _runtime_adapter_review_action(
                target, runtime_reference_count
            )
            if review_action is not None:
                actions.append(review_action)

    return {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": RUNTIME_ADAPTER_PLAN_KIND,
        "sourcePackage": str(package_path),
        "sourcePackageHash": _optional_source_hash(package_path),
        "generatedAt": int(time.time()),
        "success": bool(inspection.get("success")),
        "scope": RUNTIME_ADAPTER_PLAN_SCOPE,
        "nonGoals": list(RUNTIME_ADAPTER_PLAN_NON_GOALS),
        "packageRoot": inspection.get("packageRoot"),
        "project": project_payload,
        "summary": {
            "targetCount": len(targets),
            "bindingCount": len(bindings),
            "readyBindingCount": len(ready_bindings),
            "failedBindingCount": failed_binding_count,
            "adapterCount": len(adapters),
            "actionCount": len(actions),
            "runtimeReferenceCount": runtime_reference_count,
        },
        "targets": [
            _runtime_adapter_target(
                target,
                bindings,
                adapters,
                runtime_reference_count,
            )
            for target in targets
        ],
        "adapters": adapters,
        "actions": actions,
        "runtimePlan": runtime_plan,
        "packageInspection": {
            "kind": inspection.get("kind"),
            "success": inspection.get("success"),
            "readyBindingCount": len(ready_bindings),
            "failedBindingCount": failed_binding_count,
        },
        "diagnosticCounts": (
            dict(inspection.get("diagnosticCounts"))
            if isinstance(inspection.get("diagnosticCounts"), Mapping)
            else {}
        ),
        "diagnostics": (
            [dict(diagnostic) for diagnostic in inspection.get("diagnostics", [])]
            if isinstance(inspection.get("diagnostics"), list)
            else []
        ),
    }


def _runtime_adapter_descriptor_slug(value: Any, fallback: str) -> str:
    text = value if isinstance(value, str) else ""
    text = text.strip().lower()
    text = re.sub(r"[^a-z0-9._-]+", "-", text)
    text = re.sub(r"-+", "-", text).strip(".-_")
    text = re.sub(r"-+\.", ".", text)
    return text or fallback


def _runtime_adapter_descriptor_path(
    adapter: Mapping[str, Any], used: set[str], index: int
) -> str:
    target = _runtime_adapter_descriptor_slug(adapter.get("target"), "target")
    seed = adapter.get("id") or adapter.get("packagePath") or f"adapter-{index}"
    slug = _runtime_adapter_descriptor_slug(seed, f"adapter-{index}")
    candidate = f"adapters/{target}/{slug}.adapter.json"
    suffix = 2
    while candidate in used:
        candidate = f"adapters/{target}/{slug}-{suffix}.adapter.json"
        suffix += 1
    used.add(candidate)
    return candidate


def _runtime_adapter_descriptor_payload(
    adapter_plan: Mapping[str, Any], adapter: Mapping[str, Any]
) -> dict[str, Any]:
    source_hash = (
        dict(adapter_plan.get("sourcePackageHash"))
        if isinstance(adapter_plan.get("sourcePackageHash"), Mapping)
        else None
    )
    return {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": RUNTIME_ADAPTER_DESCRIPTOR_KIND,
        "sourcePackage": adapter_plan.get("sourcePackage"),
        "sourcePackageHash": source_hash,
        "packageRoot": adapter_plan.get("packageRoot"),
        "adapterPlan": {
            "kind": adapter_plan.get("kind"),
            "success": adapter_plan.get("success"),
            "scope": adapter_plan.get("scope"),
        },
        "id": adapter.get("id"),
        "target": adapter.get("target"),
        "adapterKind": adapter.get("adapterKind"),
        "artifactFormat": adapter.get("artifactFormat"),
        "binding": adapter.get("binding"),
        "artifact": adapter.get("artifact"),
        "packagePath": adapter.get("packagePath"),
        "sourcePath": adapter.get("sourcePath"),
        "sourceBackend": adapter.get("sourceBackend"),
        "stage": adapter.get("stage"),
        "variant": adapter.get("variant"),
        "defines": (
            dict(adapter.get("defines"))
            if isinstance(adapter.get("defines"), Mapping)
            else {}
        ),
        "sourceRemap": (
            dict(adapter.get("sourceRemap"))
            if isinstance(adapter.get("sourceRemap"), Mapping)
            else None
        ),
        "hostInterface": (
            dict(adapter.get("hostInterface"))
            if isinstance(adapter.get("hostInterface"), Mapping)
            else {}
        ),
        "requiredTools": (
            list(adapter.get("requiredTools"))
            if isinstance(adapter.get("requiredTools"), list)
            else []
        ),
        "hostResponsibilities": (
            list(adapter.get("hostResponsibilities"))
            if isinstance(adapter.get("hostResponsibilities"), list)
            else []
        ),
        "validation": (
            dict(adapter.get("validation"))
            if isinstance(adapter.get("validation"), Mapping)
            else {}
        ),
    }


def _runtime_adapter_descriptor_record(
    adapter: Mapping[str, Any], descriptor_path: str, descriptor_file: Path
) -> dict[str, Any]:
    host_interface = (
        adapter.get("hostInterface")
        if isinstance(adapter.get("hostInterface"), Mapping)
        else {}
    )
    return {
        "id": adapter.get("id"),
        "target": adapter.get("target"),
        "adapterKind": adapter.get("adapterKind"),
        "artifactFormat": adapter.get("artifactFormat"),
        "binding": adapter.get("binding"),
        "artifact": adapter.get("artifact"),
        "packagePath": adapter.get("packagePath"),
        "descriptorPath": descriptor_path,
        "descriptorHash": _source_hash(descriptor_file),
        "descriptorSizeBytes": descriptor_file.stat().st_size,
        "hostInterfaceStatus": host_interface.get("status"),
        "requiredTools": (
            list(adapter.get("requiredTools"))
            if isinstance(adapter.get("requiredTools"), list)
            else []
        ),
    }


def _runtime_adapter_package_target(
    target: Mapping[str, Any], descriptors: Sequence[Mapping[str, Any]]
) -> dict[str, Any]:
    target_name = target.get("target")
    target_descriptors = [
        descriptor
        for descriptor in descriptors
        if descriptor.get("target") == target_name
    ]
    ready_descriptors = [
        descriptor
        for descriptor in target_descriptors
        if descriptor.get("hostInterfaceStatus") == "ready"
    ]
    blocked_descriptors = [
        descriptor
        for descriptor in target_descriptors
        if descriptor.get("hostInterfaceStatus") != "ready"
    ]
    return {
        "target": target_name,
        "adapterKind": target.get("adapterKind"),
        "adapterCount": target.get("readyBindingCount", len(target_descriptors)),
        "descriptorCount": len(target_descriptors),
        "readyDescriptorCount": len(ready_descriptors),
        "blockedDescriptorCount": len(blocked_descriptors),
        "runtimeReferenceCount": target.get("runtimeReferenceCount", 0),
        "requiredTools": (
            list(target.get("requiredTools"))
            if isinstance(target.get("requiredTools"), list)
            else []
        ),
        "descriptors": [descriptor.get("id") for descriptor in target_descriptors],
        "packagePaths": [
            descriptor.get("packagePath")
            for descriptor in target_descriptors
            if _is_non_empty_string(descriptor.get("packagePath"))
        ],
    }


def _runtime_adapter_package_readme(payload: Mapping[str, Any]) -> str:
    lines = [
        "# CrossTL Runtime Adapter Descriptors",
        "",
        "This bundle contains metadata descriptors for downstream host loader or build-system tooling.",
        "",
        f"- Adapter manifest: {payload.get('adapterManifest')}",
        f"- Source package: {payload.get('sourcePackage')}",
        f"- Adapter descriptors: {payload.get('summary', {}).get('descriptorCount', 0)}",
        "",
        "Scope",
        "",
        "The descriptors preserve target adapter identity, packaged artifact paths, source-remap handoff paths, host-interface metadata, required tools, host responsibilities, and validation readiness.",
        "They do not rewrite host application code, execute device code, generate runtime framework code, or install target SDKs.",
        "",
    ]
    return "\n".join(lines)


def materialize_runtime_adapters(
    package_manifest_path: str | os.PathLike[str],
    adapter_dir: str | os.PathLike[str],
) -> dict[str, Any]:
    """Write deterministic runtime adapter descriptors from a runtime package."""

    package_path = _filesystem_path_arg(
        package_manifest_path, field_name="Runtime package manifest path"
    )
    adapter_root = _filesystem_path_arg(
        adapter_dir, field_name="Runtime adapter descriptor dir"
    )
    adapter_plan = plan_runtime_adapters(package_path)
    adapters = [
        adapter
        for adapter in _record_sequence(adapter_plan.get("adapters"))
        if isinstance(adapter, Mapping)
    ]
    targets = [
        target
        for target in _record_sequence(adapter_plan.get("targets"))
        if isinstance(target, Mapping)
    ]

    adapter_root.mkdir(parents=True, exist_ok=True)
    used_paths: set[str] = set()
    descriptors: list[dict[str, Any]] = []
    for index, adapter in enumerate(adapters, start=1):
        descriptor_path = _runtime_adapter_descriptor_path(adapter, used_paths, index)
        descriptor_file = adapter_root / descriptor_path
        descriptor_file.parent.mkdir(parents=True, exist_ok=True)
        descriptor_payload = _runtime_adapter_descriptor_payload(adapter_plan, adapter)
        descriptor_file.write_text(
            json.dumps(descriptor_payload, indent=2, sort_keys=True) + "\n",
            encoding="utf-8",
        )
        descriptors.append(
            _runtime_adapter_descriptor_record(
                adapter, descriptor_path, descriptor_file
            )
        )

    adapter_summary = (
        adapter_plan.get("summary")
        if isinstance(adapter_plan.get("summary"), Mapping)
        else {}
    )
    ready_descriptor_count = sum(
        1
        for descriptor in descriptors
        if descriptor.get("hostInterfaceStatus") == "ready"
    )
    blocked_descriptor_count = len(descriptors) - ready_descriptor_count
    payload = {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": RUNTIME_ADAPTER_PACKAGE_KIND,
        "sourcePackage": str(package_path),
        "sourcePackageHash": _optional_source_hash(package_path),
        "generatedAt": int(time.time()),
        "success": bool(adapter_plan.get("success")),
        "scope": RUNTIME_ADAPTER_PACKAGE_SCOPE,
        "nonGoals": list(RUNTIME_ADAPTER_PACKAGE_NON_GOALS),
        "packageRoot": adapter_plan.get("packageRoot"),
        "adapterRoot": str(adapter_root),
        "adapterManifest": "runtime-adapters.json",
        "project": (
            dict(adapter_plan.get("project"))
            if isinstance(adapter_plan.get("project"), Mapping)
            else {"targets": []}
        ),
        "summary": {
            "targetCount": adapter_summary.get("targetCount", 0),
            "adapterCount": len(adapters),
            "descriptorCount": len(descriptors),
            "readyDescriptorCount": ready_descriptor_count,
            "blockedDescriptorCount": blocked_descriptor_count,
            "actionCount": adapter_summary.get("actionCount", 0),
            "runtimeReferenceCount": adapter_summary.get("runtimeReferenceCount", 0),
        },
        "targets": [
            _runtime_adapter_package_target(target, descriptors) for target in targets
        ],
        "descriptors": descriptors,
        "actions": (
            [dict(action) for action in adapter_plan.get("actions", [])]
            if isinstance(adapter_plan.get("actions"), list)
            else []
        ),
        "runtimePlan": (
            dict(adapter_plan.get("runtimePlan"))
            if isinstance(adapter_plan.get("runtimePlan"), Mapping)
            else {}
        ),
        "adapterPlan": {
            "kind": adapter_plan.get("kind"),
            "success": adapter_plan.get("success"),
            "adapterCount": adapter_summary.get("adapterCount", len(adapters)),
            "actionCount": adapter_summary.get("actionCount", 0),
        },
        "packageInspection": (
            dict(adapter_plan.get("packageInspection"))
            if isinstance(adapter_plan.get("packageInspection"), Mapping)
            else {}
        ),
        "diagnosticCounts": (
            dict(adapter_plan.get("diagnosticCounts"))
            if isinstance(adapter_plan.get("diagnosticCounts"), Mapping)
            else {}
        ),
        "diagnostics": (
            [dict(diagnostic) for diagnostic in adapter_plan.get("diagnostics", [])]
            if isinstance(adapter_plan.get("diagnostics"), list)
            else []
        ),
    }
    (adapter_root / "runtime-adapters.json").write_text(
        json.dumps(payload, indent=2, sort_keys=True) + "\n",
        encoding="utf-8",
    )
    (adapter_root / "ADAPTERS.md").write_text(
        _runtime_adapter_package_readme(payload),
        encoding="utf-8",
    )
    return payload


def _runtime_loader_metadata_source(
    path: Any, field: str = "packagePath"
) -> dict[str, Any]:
    return {"field": field, "path": _runtime_loader_package_path(path)}


def _runtime_loader_package_path(package_path: Any) -> str:
    return PurePosixPath(str(package_path).replace("\\", "/")).as_posix()


def _runtime_loader_optional_package_path(package_path: Any) -> Any:
    if not _is_non_empty_string(package_path):
        return package_path
    return _runtime_loader_package_path(package_path)


def _runtime_loader_package_command_path(package_path: Any) -> str:
    return _runtime_loader_package_path(package_path)


def _runtime_loader_normalize_package_command_path(
    command: Sequence[str], package_path: Any
) -> list[str]:
    package_path_text = str(package_path)
    command_path = _runtime_loader_package_path(package_path)
    path_candidates = {
        package_path_text,
        package_path_text.replace("/", "\\"),
        package_path_text.replace("\\", "/"),
        str(Path(package_path_text)),
    }
    return [
        command_path if argument in path_candidates else argument
        for argument in command
    ]


def _runtime_loader_metadata_slug(value: Any, fallback: str) -> str:
    text = value if isinstance(value, str) else ""
    text = text.strip().lower()
    text = re.sub(r"[^a-z0-9._-]+", "-", text)
    text = re.sub(r"-+", "-", text).strip(".-_")
    text = re.sub(r"-+\.", ".", text)
    return text or fallback


def _runtime_loader_webgl_shader_type(stage: Any) -> str | None:
    if not _is_non_empty_string(stage):
        return None
    return {
        "vertex": "VERTEX_SHADER",
        "fragment": "FRAGMENT_SHADER",
    }.get(str(stage).lower())


def _runtime_loader_webgl_program_groups(
    adapters: Sequence[Mapping[str, Any]],
) -> dict[str, dict[str, Any]]:
    grouped: dict[
        tuple[Any, Any, tuple[tuple[str, str], ...]], list[Mapping[str, Any]]
    ] = {}
    for adapter in adapters:
        target = adapter.get("target")
        if not _is_non_empty_string(target):
            continue
        normalized_target = _normalized_targets([str(target)])[0]
        if normalized_target != "webgl":
            continue
        package_path = adapter.get("packagePath")
        if not _is_non_empty_string(package_path):
            continue
        package_path = _runtime_loader_package_path(package_path)
        binding_source_path = None
        binding_id = adapter.get("binding")
        if _is_non_empty_string(binding_id):
            binding_source_path = str(binding_id).split("|", 1)[0]
        source_group_path = (
            binding_source_path or adapter.get("sourcePath") or package_path
        )
        defines = (
            dict(adapter.get("defines"))
            if isinstance(adapter.get("defines"), Mapping)
            else {}
        )
        key = (
            source_group_path,
            adapter.get("variant"),
            tuple(sorted((str(key), str(value)) for key, value in defines.items())),
        )
        grouped.setdefault(key, []).append(adapter)

    groups_by_package_path: dict[str, dict[str, Any]] = {}
    stage_order = {"vertex": 0, "fragment": 1}
    for key, group_adapters in grouped.items():
        source_path, variant, defines_key = key
        group_key = json.dumps(
            {
                "sourcePath": source_path,
                "variant": variant,
                "defines": list(defines_key),
                "packagePaths": [
                    _runtime_loader_optional_package_path(adapter.get("packagePath"))
                    for adapter in group_adapters
                ],
            },
            sort_keys=True,
        )
        group_hash = hashlib.sha256(group_key.encode("utf-8")).hexdigest()[:12]
        group_slug = _runtime_loader_metadata_slug(source_path, "program")
        stages = []
        for adapter in sorted(
            group_adapters,
            key=lambda item: (
                stage_order.get(str(item.get("stage")).lower(), 99),
                str(item.get("packagePath") or ""),
            ),
        ):
            stage = adapter.get("stage")
            package_path = adapter.get("packagePath")
            if not _is_non_empty_string(package_path):
                continue
            package_path = _runtime_loader_package_path(package_path)
            stages.append(
                {
                    "stage": stage,
                    "packagePath": package_path,
                    "shaderType": _runtime_loader_webgl_shader_type(stage),
                }
            )
        group_payload = {
            "id": f"webgl-program:{group_slug}:{group_hash}",
            "sourcePath": source_path,
            "variant": variant,
            "defines": dict(defines_key),
            "stages": stages,
            "apiCalls": [
                "WebGLRenderingContext.attachShader",
                "WebGLRenderingContext.linkProgram",
            ],
        }
        for adapter in group_adapters:
            package_path = adapter.get("packagePath")
            if _is_non_empty_string(package_path):
                groups_by_package_path[_runtime_loader_package_path(package_path)] = (
                    group_payload
                )
    return groups_by_package_path


def _runtime_loader_host_entry_points(
    adapter: Mapping[str, Any],
) -> list[dict[str, Any]]:
    host_interface = adapter.get("hostInterface")
    if not isinstance(host_interface, Mapping):
        return []
    entry_points = []
    for entry_point in _record_sequence(host_interface.get("entryPoints")):
        if not isinstance(entry_point, Mapping):
            continue
        entry_points.append(
            {
                "name": entry_point.get("name"),
                "stage": entry_point.get("stage"),
                "executionConfig": (
                    dict(entry_point.get("executionConfig"))
                    if isinstance(entry_point.get("executionConfig"), Mapping)
                    else {}
                ),
            }
        )
    return entry_points


def _runtime_loader_package_artifact_path(
    package_path: Any, package_root: Path | None
) -> Path:
    artifact_path = Path(_runtime_loader_package_path(package_path))
    if package_root is not None and not artifact_path.is_absolute():
        return package_root / artifact_path
    return artifact_path


def _runtime_loader_directx_source(
    adapter: Mapping[str, Any], *, package_root: Path | None = None
) -> str:
    package_path = adapter.get("packagePath")
    if not _is_non_empty_string(package_path):
        return ""
    artifact_path = _runtime_loader_package_artifact_path(package_path, package_root)
    try:
        return artifact_path.read_text(encoding="utf-8", errors="replace")
    except (AttributeError, OSError):
        return ""


def _runtime_loader_directx_entry_profiles(
    adapter: Mapping[str, Any],
    *,
    package_root: Path | None = None,
) -> tuple[tuple[str, str], ...] | None:
    package_path = adapter.get("packagePath")
    if not _is_non_empty_string(package_path):
        return (DIRECTX_DXC_DEFAULT_ENTRY_PROFILE,)
    return _directx_dxc_entry_profiles(
        _runtime_loader_package_artifact_path(package_path, package_root),
        artifact=adapter,
    )


def _runtime_loader_directx_entry_profile_metadata(
    adapter: Mapping[str, Any],
    *,
    package_root: Path | None = None,
) -> list[dict[str, Any]]:
    entry_profiles = _runtime_loader_directx_entry_profiles(
        adapter, package_root=package_root
    )
    if entry_profiles is None:
        return [{"entry": None, "profile": "lib_6_3"}]
    return [{"entry": entry, "profile": profile} for entry, profile in entry_profiles]


def _runtime_loader_directx_commands(
    adapter: Mapping[str, Any],
    tools: Sequence[str],
    *,
    package_root: Path | None = None,
) -> list[list[str]]:
    package_path = adapter.get("packagePath")
    if not _is_non_empty_string(package_path) or not tools:
        return []
    command_path = _runtime_loader_package_command_path(package_path)
    source = _runtime_loader_directx_source(adapter, package_root=package_root)
    compiler_arguments = dxc_compiler_arguments_for_source(source)
    entry_profiles = _runtime_loader_directx_entry_profiles(
        adapter, package_root=package_root
    )
    tool = tools[0]
    if entry_profiles is None:
        return [
            [
                tool,
                "-T",
                dxc_profile_for_source("lib_6_3", source),
                *compiler_arguments,
                command_path,
                "-Fo",
                os.devnull,
            ]
        ]
    return [
        [
            tool,
            "-T",
            profile,
            *compiler_arguments,
            "-E",
            entry,
            command_path,
            "-Fo",
            os.devnull,
        ]
        for entry, profile in entry_profiles
    ]


def _runtime_loader_target_load_metadata(
    adapter: Mapping[str, Any],
    webgl_program_groups: Mapping[str, Mapping[str, Any]],
    *,
    package_root: Path | None = None,
) -> dict[str, Any]:
    target = adapter.get("target")
    package_path = adapter.get("packagePath")
    if not _is_non_empty_string(target) or not _is_non_empty_string(package_path):
        return {}
    normalized_target = _normalized_targets([str(target)])[0]
    if normalized_target == "wgsl":
        return {
            "runtime": "webgpu",
            "apiCalls": ["GPUDevice.createShaderModule"],
            "source": _runtime_loader_metadata_source(package_path),
            "shaderModuleDescriptor": {
                "code": _runtime_loader_metadata_source(package_path)
            },
            "entryPoints": _runtime_loader_host_entry_points(adapter),
        }
    if normalized_target == "webgl":
        stage = adapter.get("stage")
        metadata: dict[str, Any] = {
            "runtime": "webgl",
            "apiCalls": [
                "WebGLRenderingContext.createShader",
                "WebGLRenderingContext.shaderSource",
                "WebGLRenderingContext.compileShader",
            ],
            "source": _runtime_loader_metadata_source(package_path),
            "stage": stage,
            "shaderType": _runtime_loader_webgl_shader_type(stage),
        }
        program_group = webgl_program_groups.get(
            _runtime_loader_package_path(package_path)
        )
        if isinstance(program_group, Mapping):
            metadata["programGroup"] = dict(program_group)
        return metadata
    if normalized_target == "directx":
        source = _runtime_loader_directx_source(adapter, package_root=package_root)
        compiler_arguments = dxc_compiler_arguments_for_source(source)
        metadata = {
            "runtime": "directx",
            "artifactFormat": adapter.get("artifactFormat"),
            "compiler": "dxc",
            "targetProfiles": list(directx_target_profiles_for_source(source)),
            "source": _runtime_loader_metadata_source(package_path),
            "entryProfiles": _runtime_loader_directx_entry_profile_metadata(
                adapter, package_root=package_root
            ),
        }
        if compiler_arguments:
            metadata["compilerArguments"] = list(compiler_arguments)
            metadata["minimumShaderModel"] = "6.2"
        return metadata
    return {}


def _runtime_loader_validation_command_input_metadata(
    adapter: Mapping[str, Any],
    *,
    package_root: Path | None = None,
) -> dict[str, Any]:
    target = adapter.get("target")
    package_path = adapter.get("packagePath")
    if not _is_non_empty_string(target) or not _is_non_empty_string(package_path):
        return {}
    normalized_target = _normalized_targets([str(target)])[0]
    if normalized_target in {"opengl", "webgl"}:
        stage = None
        stage_label = adapter.get("stage")
        if _is_non_empty_string(stage_label):
            stage = WEBGL_PROJECT_GLSLANG_STAGE_BY_LABEL.get(str(stage_label))
        if stage is None:
            artifact_path = Path(str(package_path))
            if package_root is not None and not artifact_path.is_absolute():
                artifact_path = package_root / artifact_path
            stage = _glslang_stage(artifact_path, adapter)
        return {
            "mode": "stdin",
            "source": _runtime_loader_metadata_source(package_path),
            "stage": stage,
        }
    if normalized_target == "wgsl":
        return {
            "mode": "path",
            "source": _runtime_loader_metadata_source(package_path),
            "language": "wgsl",
        }
    if normalized_target == "directx":
        tools = TOOLCHAIN_BY_BACKEND.get(normalized_target, ())
        commands = _runtime_loader_directx_commands(
            adapter, tools, package_root=package_root
        )
        entry_profiles = _runtime_loader_directx_entry_profile_metadata(
            adapter, package_root=package_root
        )
        metadata: dict[str, Any] = {
            "mode": "path",
            "source": _runtime_loader_metadata_source(package_path),
            "language": "hlsl",
            "compiler": tools[0] if tools else "dxc",
            "entryProfiles": entry_profiles,
            "commands": commands,
        }
        if entry_profiles:
            first_profile = entry_profiles[0]
            if _is_non_empty_string(first_profile.get("entry")):
                metadata["entryPoint"] = first_profile.get("entry")
            if _is_non_empty_string(first_profile.get("profile")):
                metadata["shaderModel"] = first_profile.get("profile")
        return metadata
    return {
        "mode": "path",
        "source": _runtime_loader_metadata_source(package_path),
    }


def _runtime_loader_manifest_load_steps(
    adapter: Mapping[str, Any],
    *,
    package_root: Path | None = None,
    target_metadata: Mapping[str, Any] | None = None,
) -> list[dict[str, Any]]:
    package_path = _runtime_loader_optional_package_path(adapter.get("packagePath"))
    target = adapter.get("target")
    steps = [
        {
            "kind": "load-package-artifact",
            "message": (
                f"Load {adapter.get('artifactFormat')} artifact "
                f"{package_path} for target {target}."
            ),
            "target": target,
            "packagePath": package_path,
            "tools": [],
            "command": None,
            "hostInterfaceStatus": None,
            "metadata": dict(target_metadata) if target_metadata else {},
        }
    ]
    source_remap = adapter.get("sourceRemap")
    if isinstance(source_remap, Mapping) and _is_non_empty_string(
        source_remap.get("packagePath")
    ):
        source_remap_package_path = _runtime_loader_package_path(
            source_remap.get("packagePath")
        )
        steps.append(
            {
                "kind": "load-source-remap",
                "message": (
                    "Load source-remap metadata "
                    f"{source_remap_package_path} for diagnostics and "
                    "provenance."
                ),
                "target": target,
                "packagePath": source_remap_package_path,
                "tools": [],
                "command": None,
                "hostInterfaceStatus": None,
                "metadata": {
                    "source": {
                        "field": "sourceRemap.packagePath",
                        "path": source_remap_package_path,
                    }
                },
            }
        )

    host_interface = adapter.get("hostInterface")
    interface_status = (
        host_interface.get("status") if isinstance(host_interface, Mapping) else None
    )
    if interface_status == "ready":
        steps.append(
            {
                "kind": "bind-host-interface",
                "message": (
                    "Bind "
                    f"{host_interface.get('entryPointCount', 0)} entry points and "
                    f"{host_interface.get('resourceCount', 0)} resources from "
                    "host-interface metadata."
                ),
                "target": target,
                "packagePath": package_path,
                "tools": [],
                "command": None,
                "hostInterfaceStatus": interface_status,
                "metadata": {
                    "hostInterface": {
                        "entryPointCount": host_interface.get("entryPointCount", 0),
                        "resourceCount": host_interface.get("resourceCount", 0),
                    }
                },
            }
        )

    required_tools = [
        tool
        for tool in _record_sequence(adapter.get("requiredTools"))
        if _is_non_empty_string(tool)
    ]
    if required_tools:
        steps.append(
            {
                "kind": "validate-target-toolchain",
                "message": (
                    "Validate the loaded artifact with available target tools: "
                    f"{', '.join(required_tools)}."
                ),
                "target": target,
                "packagePath": package_path,
                "tools": required_tools,
                "command": _runtime_loader_validation_command(
                    adapter, package_root=package_root
                ),
                "hostInterfaceStatus": interface_status,
                "metadata": {
                    "commandInput": _runtime_loader_validation_command_input_metadata(
                        adapter, package_root=package_root
                    )
                },
            }
        )
    return steps


def _runtime_loader_validation_command(
    adapter: Mapping[str, Any],
    *,
    package_root: Path | None = None,
) -> list[str] | None:
    target = adapter.get("target")
    package_path = adapter.get("packagePath")
    if not _is_non_empty_string(target) or not _is_non_empty_string(package_path):
        return None

    normalized_target = _normalized_targets([str(target)])[0]
    tools = TOOLCHAIN_BY_BACKEND.get(normalized_target)
    if not tools:
        availability_command = TOOLCHAIN_AVAILABILITY_COMMANDS.get(normalized_target)
        return list(availability_command) if availability_command is not None else None

    if normalized_target in {"opengl", "webgl"}:
        stage = None
        stage_label = adapter.get("stage")
        if _is_non_empty_string(stage_label):
            stage = WEBGL_PROJECT_GLSLANG_STAGE_BY_LABEL.get(str(stage_label))
        if stage is None:
            artifact_path = Path(str(package_path))
            if package_root is not None and not artifact_path.is_absolute():
                artifact_path = package_root / artifact_path
            stage = _glslang_stage(artifact_path, adapter)
        return [tools[0], "--stdin", "-S", stage]

    if normalized_target == "wgsl":
        return [
            tools[0],
            "--input-kind",
            "wgsl",
            _runtime_loader_package_command_path(package_path),
        ]

    if normalized_target == "directx":
        commands = _runtime_loader_directx_commands(
            adapter, tools, package_root=package_root
        )
        return commands[0] if commands else None

    if normalized_target == "vulkan":
        command_path = _runtime_loader_package_command_path(package_path)
        if PurePosixPath(command_path).suffix.lower() == ".spvasm" and len(tools) > 1:
            return [tools[1], command_path, "-o", os.devnull]
        return [tools[0], command_path]

    smoke_command = _toolchain_smoke_command(
        normalized_target,
        tools,
        Path(str(package_path)),
        artifact=adapter,
    )
    if smoke_command is not None:
        return _runtime_loader_normalize_package_command_path(
            smoke_command[0], package_path
        )

    availability_command = TOOLCHAIN_AVAILABILITY_COMMANDS.get(normalized_target)
    return list(availability_command) if availability_command is not None else None


def _runtime_loader_manifest_blockers(
    adapter: Mapping[str, Any], actions: Sequence[Mapping[str, Any]]
) -> list[dict[str, Any]]:
    adapter_id = adapter.get("id")
    return [
        _runtime_loader_manifest_action(action)
        for action in actions
        if action.get("adapter") == adapter_id
        and action.get("kind") == "resolve-host-interface-metadata"
    ]


def _runtime_loader_manifest_action(action: Mapping[str, Any]) -> dict[str, Any]:
    payload = dict(action)
    if _is_non_empty_string(payload.get("packagePath")):
        payload["packagePath"] = _runtime_loader_package_path(payload["packagePath"])
    return payload


def _runtime_loader_manifest_source_remap(
    source_remap: Any,
) -> dict[str, Any] | None:
    if not isinstance(source_remap, Mapping):
        return None
    payload = dict(source_remap)
    if _is_non_empty_string(payload.get("packagePath")):
        payload["packagePath"] = _runtime_loader_package_path(payload["packagePath"])
    return payload


def _runtime_loader_manifest_load_unit(
    adapter: Mapping[str, Any],
    actions: Sequence[Mapping[str, Any]],
    *,
    package_root: Path | None = None,
    webgl_program_groups: Mapping[str, Mapping[str, Any]] | None = None,
) -> dict[str, Any]:
    blockers = _runtime_loader_manifest_blockers(adapter, actions)
    host_interface = adapter.get("hostInterface")
    host_interface_status = (
        host_interface.get("status") if isinstance(host_interface, Mapping) else None
    )
    validation = (
        dict(adapter.get("validation"))
        if isinstance(adapter.get("validation"), Mapping)
        else {}
    )
    validation["hostInterface"] = (
        host_interface_status
        if _is_non_empty_string(host_interface_status)
        else "not-inspected"
    )
    validation["loadReady"] = not blockers
    package_path = _runtime_loader_optional_package_path(adapter.get("packagePath"))
    return {
        "id": adapter.get("id"),
        "target": adapter.get("target"),
        "adapterKind": adapter.get("adapterKind"),
        "artifactFormat": adapter.get("artifactFormat"),
        "packagePath": package_path,
        "source": adapter.get("source"),
        "sourcePath": adapter.get("sourcePath"),
        "sourceBackend": adapter.get("sourceBackend"),
        "stage": adapter.get("stage"),
        "variant": adapter.get("variant"),
        "defines": (
            dict(adapter.get("defines"))
            if isinstance(adapter.get("defines"), Mapping)
            else {}
        ),
        "entryPoint": (
            dict(adapter.get("entryPoint"))
            if isinstance(adapter.get("entryPoint"), Mapping)
            else None
        ),
        "templateMaterialization": (
            dict(adapter.get("templateMaterialization"))
            if isinstance(adapter.get("templateMaterialization"), Mapping)
            else None
        ),
        "specializationMaterialization": (
            dict(adapter.get("specializationMaterialization"))
            if isinstance(adapter.get("specializationMaterialization"), Mapping)
            else None
        ),
        "specializationConstants": [
            dict(constant)
            for constant in _record_sequence(adapter.get("specializationConstants"))
            if isinstance(constant, Mapping)
        ],
        "provenance": (
            dict(adapter.get("provenance"))
            if isinstance(adapter.get("provenance"), Mapping)
            else {}
        ),
        "sourceHash": adapter.get("sourceHash"),
        "sourceSizeBytes": adapter.get("sourceSizeBytes"),
        "hash": adapter.get("hash"),
        "sizeBytes": adapter.get("sizeBytes"),
        "sourceRemap": _runtime_loader_manifest_source_remap(
            adapter.get("sourceRemap")
        ),
        "hostInterface": (
            dict(host_interface)
            if isinstance(host_interface, Mapping)
            else _runtime_host_interface_empty(
                "not-inspected",
                diagnostics=(
                    "project.runtime-package-inspection.host-interface-not-recorded",
                ),
            )
        ),
        "requiredTools": [
            tool
            for tool in _record_sequence(adapter.get("requiredTools"))
            if _is_non_empty_string(tool)
        ],
        "hostResponsibilities": [
            responsibility
            for responsibility in _record_sequence(adapter.get("hostResponsibilities"))
            if _is_non_empty_string(responsibility)
        ],
        "loadSteps": _runtime_loader_manifest_load_steps(
            adapter,
            package_root=package_root,
            target_metadata=_runtime_loader_target_load_metadata(
                adapter,
                webgl_program_groups or {},
                package_root=package_root,
            ),
        ),
        "blockers": blockers,
        "validation": validation,
    }


def _runtime_loader_manifest_target(
    target: Mapping[str, Any], load_units: Sequence[Mapping[str, Any]]
) -> dict[str, Any]:
    target_name = target.get("target")
    target_load_units = [
        load_unit for load_unit in load_units if load_unit.get("target") == target_name
    ]
    blocked_units = [
        load_unit for load_unit in target_load_units if load_unit.get("blockers")
    ]
    ready_units = [
        load_unit for load_unit in target_load_units if not load_unit.get("blockers")
    ]
    return {
        "target": target_name,
        "adapterKind": target.get("adapterKind"),
        "loadUnitCount": len(target_load_units),
        "readyLoadUnitCount": len(ready_units),
        "blockedLoadUnitCount": len(blocked_units),
        "runtimeReferenceCount": target.get("runtimeReferenceCount", 0),
        "requiredTools": (
            list(target.get("requiredTools"))
            if isinstance(target.get("requiredTools"), list)
            else []
        ),
        "loaderResponsibilities": (
            list(target.get("loaderResponsibilities"))
            if isinstance(target.get("loaderResponsibilities"), list)
            else []
        ),
        "packagePaths": [
            load_unit.get("packagePath")
            for load_unit in target_load_units
            if _is_non_empty_string(load_unit.get("packagePath"))
        ],
        "loadUnits": [load_unit.get("id") for load_unit in target_load_units],
    }


def build_runtime_loader_manifest(
    package_manifest_path: str | os.PathLike[str],
) -> dict[str, Any]:
    """Build a runtime loader manifest from a runtime package manifest."""

    package_path = _filesystem_path_arg(
        package_manifest_path, field_name="Runtime package manifest path"
    )
    adapter_plan = plan_runtime_adapters(package_path)
    actions = [
        action
        for action in _record_sequence(adapter_plan.get("actions"))
        if isinstance(action, Mapping)
    ]
    adapters = [
        adapter
        for adapter in _record_sequence(adapter_plan.get("adapters"))
        if isinstance(adapter, Mapping)
    ]
    targets = [
        target
        for target in _record_sequence(adapter_plan.get("targets"))
        if isinstance(target, Mapping)
    ]
    package_root = None
    if _is_non_empty_string(adapter_plan.get("packageRoot")):
        package_root = Path(str(adapter_plan["packageRoot"])).resolve()
    webgl_program_groups = _runtime_loader_webgl_program_groups(adapters)
    load_units = [
        _runtime_loader_manifest_load_unit(
            adapter,
            actions,
            package_root=package_root,
            webgl_program_groups=webgl_program_groups,
        )
        for adapter in adapters
    ]
    ready_load_unit_count = sum(
        1 for load_unit in load_units if not load_unit.get("blockers")
    )
    blocked_load_unit_count = sum(
        1 for load_unit in load_units if load_unit.get("blockers")
    )
    adapter_summary = (
        adapter_plan.get("summary")
        if isinstance(adapter_plan.get("summary"), Mapping)
        else {}
    )
    package_inspection = (
        dict(adapter_plan.get("packageInspection"))
        if isinstance(adapter_plan.get("packageInspection"), Mapping)
        else {}
    )
    return {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": RUNTIME_LOADER_MANIFEST_KIND,
        "sourcePackage": str(package_path),
        "sourcePackageHash": _optional_source_hash(package_path),
        "generatedAt": int(time.time()),
        "success": bool(adapter_plan.get("success")),
        "scope": RUNTIME_LOADER_MANIFEST_SCOPE,
        "nonGoals": list(RUNTIME_LOADER_MANIFEST_NON_GOALS),
        "packageRoot": adapter_plan.get("packageRoot"),
        "project": (
            dict(adapter_plan.get("project"))
            if isinstance(adapter_plan.get("project"), Mapping)
            else {"targets": []}
        ),
        "summary": {
            "targetCount": adapter_summary.get("targetCount", 0),
            "bindingCount": adapter_summary.get("bindingCount", 0),
            "loadUnitCount": len(load_units),
            "readyLoadUnitCount": ready_load_unit_count,
            "blockedLoadUnitCount": blocked_load_unit_count,
            "actionCount": len(actions),
            "runtimeReferenceCount": adapter_summary.get("runtimeReferenceCount", 0),
        },
        "targets": [
            _runtime_loader_manifest_target(target, load_units) for target in targets
        ],
        "loadUnits": load_units,
        "actions": [_runtime_loader_manifest_action(action) for action in actions],
        "runtimePlan": (
            dict(adapter_plan.get("runtimePlan"))
            if isinstance(adapter_plan.get("runtimePlan"), Mapping)
            else {}
        ),
        "adapterPlan": {
            "kind": adapter_plan.get("kind"),
            "success": adapter_plan.get("success"),
            "adapterCount": adapter_summary.get("adapterCount", 0),
            "actionCount": len(actions),
        },
        "packageInspection": package_inspection,
        "diagnosticCounts": (
            dict(adapter_plan.get("diagnosticCounts"))
            if isinstance(adapter_plan.get("diagnosticCounts"), Mapping)
            else {}
        ),
        "diagnostics": (
            [dict(diagnostic) for diagnostic in adapter_plan.get("diagnostics", [])]
            if isinstance(adapter_plan.get("diagnostics"), list)
            else []
        ),
    }


_RUNTIME_VARIANT_INPUT_LOCATION = "runtime-variant-input.json"
_RUNTIME_VARIANT_UNRESOLVED = "@unresolved"
_RUNTIME_VARIANT_PACKAGE_REQUIRED_ARTIFACT_FIELDS = frozenset(
    (
        "id",
        "status",
        "source",
        "sourcePath",
        "packagePath",
        "target",
        "sourceBackend",
        "stage",
        "variant",
        "defines",
        "hash",
        "sizeBytes",
        "sourceRemap",
        "hostInterface",
    )
)
_RUNTIME_VARIANT_LOADER_REQUIRED_UNIT_FIELDS = frozenset(
    (
        "id",
        "target",
        "adapterKind",
        "artifactFormat",
        "packagePath",
        "sourcePath",
        "sourceBackend",
        "stage",
        "variant",
        "defines",
        "sourceRemap",
        "hostInterface",
        "requiredTools",
        "hostResponsibilities",
        "loadSteps",
        "blockers",
        "validation",
    )
)


def _runtime_variant_canonical_json(value: Any) -> str:
    return json.dumps(
        value,
        ensure_ascii=True,
        allow_nan=False,
        separators=(",", ":"),
        sort_keys=True,
    )


def _runtime_variant_normalize_json(value: Any) -> Any:
    if isinstance(value, Mapping):
        return {
            str(key): _runtime_variant_normalize_json(item)
            for key, item in sorted(value.items(), key=lambda item: str(item[0]))
        }
    if isinstance(value, Sequence) and not isinstance(value, (str, bytes, bytearray)):
        return [_runtime_variant_normalize_json(item) for item in value]
    return value


def _runtime_variant_json_contract_reasons(prefix: str, value: Any) -> list[str]:
    if value is None or isinstance(value, (bool, int, str)):
        return []
    if isinstance(value, float):
        return [] if math.isfinite(value) else [f"{prefix} must be finite"]
    if isinstance(value, Mapping):
        reasons: list[str] = []
        for key, item in value.items():
            if not _is_non_empty_string(key):
                reasons.append(f"{prefix} keys must be non-empty strings")
                continue
            reasons.extend(
                _runtime_variant_json_contract_reasons(
                    f"{prefix}.{key}",
                    item,
                )
            )
        return reasons
    if isinstance(value, list):
        reasons = []
        for index, item in enumerate(value):
            reasons.extend(
                _runtime_variant_json_contract_reasons(
                    f"{prefix}[{index}]",
                    item,
                )
            )
        return reasons
    return [f"{prefix} must contain only JSON values"]


def _runtime_variant_scalar_contract_reasons(prefix: str, value: Any) -> list[str]:
    if value is None or isinstance(value, (bool, int, str)):
        return []
    if isinstance(value, float) and math.isfinite(value):
        return []
    return [f"{prefix} must be a finite JSON scalar"]


def _runtime_variant_mapping_contract_reasons(
    prefix: str,
    value: Any,
    *,
    scalar_values: bool = False,
    string_values: bool = False,
) -> list[str]:
    if not isinstance(value, Mapping):
        return [f"{prefix} must be an object"]
    reasons: list[str] = []
    for key, item in value.items():
        if not _is_non_empty_string(key):
            reasons.append(f"{prefix} keys must be non-empty strings")
            continue
        item_prefix = f"{prefix}.{key}"
        if string_values:
            if not isinstance(item, str):
                reasons.append(f"{item_prefix} must be a string")
        elif scalar_values:
            reasons.extend(_runtime_variant_scalar_contract_reasons(item_prefix, item))
        else:
            reasons.extend(_runtime_variant_json_contract_reasons(item_prefix, item))
    return reasons


def _runtime_variant_execution_contract_reasons(
    prefix: str,
    value: Any,
) -> list[str]:
    if not isinstance(value, Mapping):
        return [f"{prefix} must be an object"]
    reasons = _unsupported_mapping_field_reasons(
        prefix,
        value,
        RUNTIME_VARIANT_KEY_EXECUTION_FIELDS,
    )
    missing = sorted(RUNTIME_VARIANT_KEY_EXECUTION_FIELDS - set(value))
    if missing:
        reasons.append(f"{prefix} is missing fields: {', '.join(missing)}")

    workgroup_size = value.get("workgroupSize")
    if workgroup_size is not None:
        if not isinstance(workgroup_size, list) or len(workgroup_size) != 3:
            reasons.append(
                f"{prefix}.workgroupSize must be a three-component list or null"
            )
        else:
            for index, component in enumerate(workgroup_size):
                if (
                    not isinstance(component, int)
                    or isinstance(component, bool)
                    or component <= 0
                ):
                    reasons.append(
                        f"{prefix}.workgroupSize[{index}] must be a positive integer"
                    )

    subgroup_width = value.get("subgroupWidth")
    if subgroup_width is not None and (
        not isinstance(subgroup_width, int)
        or isinstance(subgroup_width, bool)
        or subgroup_width <= 0
    ):
        reasons.append(f"{prefix}.subgroupWidth must be a positive integer or null")
    return reasons


def _runtime_variant_normalized_execution(value: Any) -> Any:
    if value is None:
        return {"workgroupSize": None, "subgroupWidth": None}
    if not isinstance(value, Mapping):
        return value
    normalized = dict(value)
    workgroup_size = normalized.get("workgroupSize")
    if isinstance(workgroup_size, Sequence) and not isinstance(
        workgroup_size, (str, bytes, bytearray)
    ):
        normalized["workgroupSize"] = list(workgroup_size)
    normalized.setdefault("workgroupSize", None)
    normalized.setdefault("subgroupWidth", None)
    return _runtime_variant_normalize_json(normalized)


def _runtime_variant_selected_entry_execution(
    prefix: str,
    entry_point: Any,
) -> tuple[dict[str, Any], list[str]]:
    execution = {"workgroupSize": None, "subgroupWidth": None}
    if entry_point is None:
        return execution, []
    if not isinstance(entry_point, Mapping):
        return execution, [f"{prefix} must be an object or null"]
    execution_config = entry_point.get("executionConfig")
    if not isinstance(execution_config, Mapping):
        return execution, [f"{prefix}.executionConfig must be an object"]

    reasons: list[str] = []
    workgroup_candidates: list[tuple[str, list[int]]] = []
    for field_name in _RUNTIME_VARIANT_WORKGROUP_SIZE_FIELDS:
        if (
            field_name not in execution_config
            or execution_config.get(field_name) is None
        ):
            continue
        field_prefix = f"{prefix}.executionConfig.{field_name}"
        value = execution_config.get(field_name)
        if not isinstance(value, Sequence) or isinstance(
            value, (str, bytes, bytearray)
        ):
            reasons.append(f"{field_prefix} must be a three-component sequence")
            continue
        components = list(value)
        if len(components) != 3:
            reasons.append(f"{field_prefix} must contain exactly three components")
            continue
        if any(
            not isinstance(component, int)
            or isinstance(component, bool)
            or component <= 0
            for component in components
        ):
            reasons.append(f"{field_prefix} components must be exact positive integers")
            continue
        workgroup_candidates.append((field_name, list(components)))

    if any(
        field_name in execution_config
        for field_name in _RUNTIME_VARIANT_LOCAL_SIZE_FIELDS
    ):
        components = [
            execution_config.get(field_name, 1)
            for field_name in _RUNTIME_VARIANT_LOCAL_SIZE_FIELDS
        ]
        field_prefix = f"{prefix}.executionConfig.local_size"
        if any(
            not isinstance(component, int)
            or isinstance(component, bool)
            or component <= 0
            for component in components
        ):
            reasons.append(f"{field_prefix} components must be exact positive integers")
        else:
            workgroup_candidates.append(("local_size", list(components)))

    workgroup_values = {tuple(value) for _field, value in workgroup_candidates}
    if len(workgroup_values) > 1:
        reasons.append(f"{prefix}.executionConfig contains conflicting workgroup sizes")
    elif workgroup_values:
        execution["workgroupSize"] = list(next(iter(workgroup_values)))

    subgroup_candidates: list[tuple[str, int]] = []
    for field_name in _RUNTIME_VARIANT_SUBGROUP_WIDTH_FIELDS:
        if (
            field_name not in execution_config
            or execution_config.get(field_name) is None
        ):
            continue
        field_prefix = f"{prefix}.executionConfig.{field_name}"
        value = execution_config.get(field_name)
        if not isinstance(value, int) or isinstance(value, bool) or value <= 0:
            reasons.append(f"{field_prefix} must be an exact positive integer")
            continue
        subgroup_candidates.append((field_name, value))

    subgroup_values = {value for _field, value in subgroup_candidates}
    if len(subgroup_values) > 1:
        reasons.append(f"{prefix}.executionConfig contains conflicting subgroup widths")
    elif subgroup_values:
        execution["subgroupWidth"] = next(iter(subgroup_values))
    return execution, sorted(set(reasons))


def _runtime_variant_key_specialization_contract_reasons(
    prefix: str,
    values: Any,
) -> list[str]:
    if not isinstance(values, list):
        return [f"{prefix} must be a list"]
    reasons: list[str] = []
    identities: set[tuple[str, Any]] = set()
    for index, value in enumerate(values):
        item_prefix = f"{prefix}[{index}]"
        if not isinstance(value, Mapping):
            reasons.append(f"{item_prefix} must be an object")
            continue
        unsupported = sorted(set(value) - {"id", "name", "value"})
        if unsupported:
            reasons.append(
                f"{item_prefix} contains unsupported fields: "
                f"{', '.join(unsupported)}"
            )
        constant_id = value.get("id")
        name = value.get("name")
        if constant_id is not None and (
            not isinstance(constant_id, int)
            or isinstance(constant_id, bool)
            or constant_id < 0
        ):
            reasons.append(f"{item_prefix}.id must be a non-negative integer or null")
        if name is not None and not _is_non_empty_string(name):
            reasons.append(f"{item_prefix}.name must be a non-empty string or null")
        if constant_id is None and not _is_non_empty_string(name):
            reasons.append(f"{item_prefix} must identify the constant by id or name")
        reasons.extend(
            _runtime_variant_scalar_contract_reasons(
                f"{item_prefix}.value", value.get("value")
            )
        )
        identity = (
            ("id", constant_id) if constant_id is not None else ("name", str(name))
        )
        if identity in identities:
            reasons.append(
                f"{item_prefix} duplicates specialization identity {identity}"
            )
        identities.add(identity)
    return reasons


def _runtime_variant_key_payload_contract_reasons(value: Any) -> list[str]:
    if not isinstance(value, Mapping):
        return ["variant key payload must be an object"]
    reasons = _unsupported_mapping_field_reasons(
        "variant key payload",
        value,
        RUNTIME_VARIANT_KEY_FIELDS,
    )
    missing = sorted(RUNTIME_VARIANT_KEY_FIELDS - set(value))
    if missing:
        reasons.append("variant key payload is missing fields: " + ", ".join(missing))
    source_unit = value.get("sourceUnit")
    if not _is_non_empty_string(source_unit):
        reasons.append("variant key payload.sourceUnit must be a non-empty string")
    elif source_unit != _RUNTIME_VARIANT_UNRESOLVED and not _is_report_identity_path(
        source_unit
    ):
        reasons.append(
            "variant key payload.sourceUnit must be a stable relative POSIX path"
        )
    if not _is_non_empty_string(value.get("sourceEntry")):
        reasons.append("variant key payload.sourceEntry must be a non-empty string")
    target = value.get("target")
    if not _is_non_empty_string(target):
        reasons.append("variant key payload.target must be a non-empty string")
    elif _normalized_targets([str(target)])[0] != target:
        reasons.append("variant key payload.target must use its canonical backend name")
    profile = value.get("targetProfile")
    if profile is not None and not _is_non_empty_string(profile):
        reasons.append(
            "variant key payload.targetProfile must be a non-empty string or null"
        )
    reasons.extend(
        _runtime_variant_execution_contract_reasons(
            "variant key payload.execution",
            value.get("execution"),
        )
    )
    reasons.extend(
        _runtime_variant_mapping_contract_reasons(
            "variant key payload.typeArguments",
            value.get("typeArguments"),
            string_values=True,
        )
    )
    reasons.extend(
        _runtime_variant_mapping_contract_reasons(
            "variant key payload.valueArguments",
            value.get("valueArguments"),
            scalar_values=True,
        )
    )
    reasons.extend(
        _runtime_variant_key_specialization_contract_reasons(
            "variant key payload.specializationConstants",
            value.get("specializationConstants"),
        )
    )
    reasons.extend(
        _runtime_variant_mapping_contract_reasons(
            "variant key payload.defines",
            value.get("defines"),
            string_values=True,
        )
    )
    return sorted(set(reasons))


def _runtime_variant_normalized_key_specializations(
    values: Sequence[Mapping[str, Any]],
) -> list[dict[str, Any]]:
    normalized = [
        {
            "id": value.get("id"),
            "name": value.get("name"),
            "value": _runtime_variant_normalize_json(value.get("value")),
        }
        for value in values
    ]
    return sorted(
        normalized,
        key=lambda item: (
            item.get("id") is None,
            item.get("id") if item.get("id") is not None else 0,
            str(item.get("name") or ""),
            _runtime_variant_canonical_json(item.get("value")),
        ),
    )


def encode_runtime_variant_key(
    source_unit: str,
    source_entry: str,
    target: str,
    *,
    target_profile: str | None = None,
    execution: Mapping[str, Any] | None = None,
    type_arguments: Mapping[str, str] | None = None,
    value_arguments: Mapping[str, Any] | None = None,
    specialization_constants: Sequence[Mapping[str, Any]] = (),
    defines: Mapping[str, str] | None = None,
) -> str:
    """Encode one exact runtime variant identity as a canonical URL-safe key."""

    normalized_target = (
        _normalized_targets([target])[0] if _is_non_empty_string(target) else target
    )
    payload = {
        "sourceUnit": source_unit,
        "sourceEntry": source_entry,
        "target": normalized_target,
        "targetProfile": target_profile,
        "execution": _runtime_variant_normalized_execution(execution),
        "typeArguments": dict(sorted((type_arguments or {}).items())),
        "valueArguments": {
            key: _runtime_variant_normalize_json(value)
            for key, value in sorted((value_arguments or {}).items())
        },
        "specializationConstants": _runtime_variant_normalized_key_specializations(
            specialization_constants
        ),
        "defines": dict(sorted((defines or {}).items())),
    }
    reasons = _runtime_variant_key_payload_contract_reasons(payload)
    if reasons:
        raise ValueError("Invalid runtime variant key: " + "; ".join(reasons))
    encoded = base64.urlsafe_b64encode(
        _runtime_variant_canonical_json(payload).encode("utf-8")
    ).decode("ascii")
    return RUNTIME_VARIANT_KEY_PREFIX + encoded.rstrip("=")


def decode_runtime_variant_key(key: str) -> dict[str, Any]:
    """Decode and validate a canonical runtime variant key."""

    if isinstance(key, str) and key.startswith(_RUNTIME_VARIANT_LEGACY_KEY_PREFIX):
        raise ValueError(
            "Legacy runtime variant key schema v1 is not accepted by schema v2; "
            "regenerate the key and registry before lookup"
        )
    if not isinstance(key, str) or not key.startswith(RUNTIME_VARIANT_KEY_PREFIX):
        raise ValueError(
            f"Runtime variant key must start with {RUNTIME_VARIANT_KEY_PREFIX}"
        )
    encoded = key[len(RUNTIME_VARIANT_KEY_PREFIX) :]
    if not encoded:
        raise ValueError("Runtime variant key payload must not be empty")
    padding = "=" * (-len(encoded) % 4)
    try:
        decoded = base64.b64decode(
            encoded + padding,
            altchars=b"-_",
            validate=True,
        ).decode("utf-8")
        payload = json.loads(decoded)
    except (UnicodeDecodeError, ValueError, json.JSONDecodeError) as exc:
        raise ValueError("Runtime variant key payload is invalid") from exc
    reasons = _runtime_variant_key_payload_contract_reasons(payload)
    if reasons:
        raise ValueError("Invalid runtime variant key: " + "; ".join(reasons))
    canonical = encode_runtime_variant_key(
        payload["sourceUnit"],
        payload["sourceEntry"],
        payload["target"],
        target_profile=payload["targetProfile"],
        execution=payload["execution"],
        type_arguments=payload["typeArguments"],
        value_arguments=payload["valueArguments"],
        specialization_constants=payload["specializationConstants"],
        defines=payload["defines"],
    )
    if key != canonical:
        raise ValueError("Runtime variant key is not canonically encoded")
    return payload


def _runtime_variant_diagnostic(
    code: str,
    message: str,
    *,
    severity: str = "error",
    source: Any = None,
    target: Any = None,
    variant: Any = None,
    details: Mapping[str, Any] | None = None,
) -> ProjectDiagnostic:
    source_path = (
        str(source)
        if _is_non_empty_string(source) and _is_report_identity_path(str(source))
        else _RUNTIME_VARIANT_INPUT_LOCATION
    )
    return ProjectDiagnostic(
        severity=severity,
        code=code,
        message=message,
        location=SourceLocation(file=source_path),
        target=str(target) if _is_non_empty_string(target) else None,
        variant=str(variant) if _is_non_empty_string(variant) else None,
        check_kind="runtime-variant-registry",
        details=details or {},
    )


def _runtime_variant_registry_load_input(
    path: Path,
) -> tuple[Mapping[str, Any], list[ProjectDiagnostic]]:
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except OSError as exc:
        return {}, [
            _runtime_variant_diagnostic(
                "project.runtime-variant-registry.input-read-failed",
                f"Runtime variant registry input could not be read: {exc.strerror or 'I/O error'}.",
            )
        ]
    except json.JSONDecodeError as exc:
        return {}, [
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-variant-registry.input-json-invalid",
                message="Runtime variant registry input is not valid JSON.",
                location=SourceLocation(
                    file=_RUNTIME_VARIANT_INPUT_LOCATION,
                    line=exc.lineno,
                    column=exc.colno,
                ),
                check_kind="runtime-variant-registry",
                details={"line": exc.lineno, "column": exc.colno},
            )
        ]
    if not isinstance(payload, Mapping):
        return {}, [
            _runtime_variant_diagnostic(
                "project.runtime-variant-registry.input-invalid",
                "Runtime variant registry input must be a JSON object.",
            )
        ]
    return payload, []


def _runtime_variant_closed_record_reasons(
    prefix: str,
    value: Mapping[str, Any],
    *,
    allowed: frozenset[str],
    required: frozenset[str],
) -> list[str]:
    reasons = _unsupported_mapping_field_reasons(prefix, value, allowed)
    missing = sorted(required - set(value))
    if missing:
        reasons.append(f"{prefix} is missing fields: {', '.join(missing)}")
    return reasons


def _runtime_variant_specialization_input_contract_reasons(
    prefix: str,
    value: Any,
) -> list[str]:
    if not isinstance(value, list):
        return [f"{prefix} must be a list"]
    reasons: list[str] = []
    identities: set[tuple[str, Any]] = set()
    for index, constant in enumerate(value):
        item_prefix = f"{prefix}[{index}]"
        if not isinstance(constant, Mapping):
            reasons.append(f"{item_prefix} must be an object")
            continue
        reasons.extend(_runtime_variant_json_contract_reasons(item_prefix, constant))
        constant_id = constant.get("id", constant.get("constantId"))
        name = constant.get("name")
        if constant_id is not None and (
            not isinstance(constant_id, int)
            or isinstance(constant_id, bool)
            or constant_id < 0
        ):
            reasons.append(f"{item_prefix}.id must be a non-negative integer or null")
            constant_id = None
        if name is not None and not _is_non_empty_string(name):
            reasons.append(f"{item_prefix}.name must be a non-empty string or null")
            name = None
        identity = (
            ("id", constant_id)
            if constant_id is not None
            else ("name", name) if name is not None else None
        )
        if identity is None:
            reasons.append(f"{item_prefix} must identify the constant by id or name")
        elif identity in identities:
            reasons.append(
                f"{item_prefix} duplicates specialization identity {identity}"
            )
        else:
            identities.add(identity)
    return reasons


def _runtime_variant_host_interface_contract_reasons(
    prefix: str,
    value: Any,
) -> list[str]:
    if not isinstance(value, Mapping):
        return [f"{prefix} must be an object"]
    reasons = _runtime_variant_closed_record_reasons(
        prefix,
        value,
        allowed=RUNTIME_HOST_INTERFACE_FIELDS,
        required=RUNTIME_HOST_INTERFACE_FIELDS,
    )
    if not _is_non_empty_string(value.get("status")):
        reasons.append(f"{prefix}.status must be a non-empty string")
    if not _is_non_empty_string(value.get("source")):
        reasons.append(f"{prefix}.source must be a non-empty string")
    for field_name in ("parser", "artifactFormat"):
        field_value = value.get(field_name)
        if field_value is not None and not _is_non_empty_string(field_value):
            reasons.append(f"{prefix}.{field_name} must be a string or null")
    for field_name in (
        "entryPoints",
        "resources",
        "constants",
        "specializationConstants",
        "diagnostics",
        "diagnosticRecords",
    ):
        records = value.get(field_name)
        if not isinstance(records, list):
            reasons.append(f"{prefix}.{field_name} must be a list")
            continue
        reasons.extend(
            _runtime_variant_json_contract_reasons(f"{prefix}.{field_name}", records)
        )
    for count_field, records_field in (
        ("entryPointCount", "entryPoints"),
        ("resourceCount", "resources"),
        ("constantCount", "constants"),
        ("specializationConstantCount", "specializationConstants"),
    ):
        count = value.get(count_field)
        records = value.get(records_field)
        if not _is_non_negative_int(count):
            reasons.append(f"{prefix}.{count_field} must be a non-negative integer")
        elif isinstance(records, list) and count != len(records):
            reasons.append(f"{prefix}.{count_field} must match {records_field}")
    entry_points = value.get("entryPoints")
    if isinstance(entry_points, list):
        for index, entry_point in enumerate(entry_points):
            entry_prefix = f"{prefix}.entryPoints[{index}]"
            if not isinstance(entry_point, Mapping):
                continue
            reasons.extend(
                _runtime_variant_closed_record_reasons(
                    entry_prefix,
                    entry_point,
                    allowed=RUNTIME_HOST_INTERFACE_ENTRY_POINT_FIELDS,
                    required=RUNTIME_HOST_INTERFACE_ENTRY_POINT_FIELDS,
                )
            )
            if not _is_non_empty_string(entry_point.get("name")):
                reasons.append(f"{entry_prefix}.name must be a non-empty string")
            stage = entry_point.get("stage")
            if stage is not None and not _is_non_empty_string(stage):
                reasons.append(f"{entry_prefix}.stage must be a string or null")
            if not isinstance(entry_point.get("executionConfig"), Mapping):
                reasons.append(f"{entry_prefix}.executionConfig must be an object")
            else:
                _execution, execution_reasons = (
                    _runtime_variant_selected_entry_execution(
                        entry_prefix,
                        entry_point,
                    )
                )
                reasons.extend(execution_reasons)
    reasons.extend(
        _runtime_variant_specialization_input_contract_reasons(
            f"{prefix}.specializationConstants",
            value.get("specializationConstants"),
        )
    )
    return reasons


def _runtime_variant_entry_point_contract_reasons(prefix: str, value: Any) -> list[str]:
    if value is None:
        return []
    if not isinstance(value, Mapping):
        return [f"{prefix} must be an object or null"]
    reasons = _unsupported_mapping_field_reasons(
        prefix, value, REPORT_ARTIFACT_ENTRY_POINT_FIELDS
    )
    for field_name in ("source", "target"):
        if not _is_non_empty_string(value.get(field_name)):
            reasons.append(f"{prefix}.{field_name} must be a non-empty string")
    if "stage" in value and not _is_non_empty_string(value.get("stage")):
        reasons.append(f"{prefix}.stage must be a non-empty string")
    return reasons


def _runtime_variant_common_record_contract_reasons(
    prefix: str,
    value: Mapping[str, Any],
    *,
    require_source: bool,
    require_hash: bool,
    allow_null_host_interface: bool,
) -> list[str]:
    reasons: list[str] = []
    source = value.get("source")
    if require_source and not _is_non_empty_string(source):
        reasons.append(f"{prefix}.source must be a non-empty string")
    elif _is_non_empty_string(source) and not _is_report_identity_path(source):
        reasons.append(f"{prefix}.source must be a stable relative POSIX path")
    package_path = value.get("packagePath")
    if not _is_non_empty_string(package_path):
        reasons.append(f"{prefix}.packagePath must be a non-empty string")
    elif not _is_report_identity_path(package_path):
        reasons.append(f"{prefix}.packagePath must be a stable relative POSIX path")
    target = value.get("target")
    if not _is_non_empty_string(target):
        reasons.append(f"{prefix}.target must be a non-empty string")
    elif _normalized_targets([str(target)])[0] != target:
        reasons.append(f"{prefix}.target must use its canonical backend name")
    if not _is_non_empty_string(value.get("sourceBackend")):
        reasons.append(f"{prefix}.sourceBackend must be a non-empty string")
    stage = value.get("stage")
    if stage is not None and not _is_non_empty_string(stage):
        reasons.append(f"{prefix}.stage must be a non-empty string or null")
    variant = value.get("variant")
    if variant is not None and not _is_non_empty_string(variant):
        reasons.append(f"{prefix}.variant must be a non-empty string or null")
    reasons.extend(
        _runtime_variant_mapping_contract_reasons(
            f"{prefix}.defines", value.get("defines"), string_values=True
        )
    )
    reasons.extend(
        _runtime_variant_entry_point_contract_reasons(
            f"{prefix}.entryPoint", value.get("entryPoint")
        )
    )
    host_interface = value.get("hostInterface")
    if host_interface is not None or not allow_null_host_interface:
        reasons.extend(
            _runtime_variant_host_interface_contract_reasons(
                f"{prefix}.hostInterface", host_interface
            )
        )
    artifact_hash = value.get("hash")
    if artifact_hash is None and not require_hash:
        pass
    elif not isinstance(artifact_hash, Mapping):
        reasons.append(f"{prefix}.hash must be a sha256 hash object")
    else:
        reasons.extend(
            _hash_contract_reasons(
                f"{prefix}.hash",
                artifact_hash,
                require_closed_fields=True,
            )
        )
    size_bytes = value.get("sizeBytes")
    if size_bytes is not None and not _is_non_negative_int(size_bytes):
        reasons.append(f"{prefix}.sizeBytes must be a non-negative integer or null")
    for field_name in ("templateMaterialization", "specializationMaterialization"):
        field_value = value.get(field_name)
        if field_value is not None and not isinstance(field_value, Mapping):
            reasons.append(f"{prefix}.{field_name} must be an object or null")
        elif isinstance(field_value, Mapping):
            reasons.extend(
                _runtime_variant_json_contract_reasons(
                    f"{prefix}.{field_name}", field_value
                )
            )
    provenance = value.get("provenance")
    if provenance is not None and not isinstance(provenance, Mapping):
        reasons.append(f"{prefix}.provenance must be an object or null")
    elif isinstance(provenance, Mapping):
        reasons.extend(
            _runtime_variant_json_contract_reasons(f"{prefix}.provenance", provenance)
        )
    specialization_constants = value.get("specializationConstants")
    if specialization_constants is not None:
        reasons.extend(
            _runtime_variant_specialization_input_contract_reasons(
                f"{prefix}.specializationConstants",
                specialization_constants,
            )
        )
    source_hash = value.get("sourceHash")
    if source_hash is not None:
        reasons.extend(
            _hash_contract_reasons(
                f"{prefix}.sourceHash",
                source_hash,
                require_closed_fields=True,
            )
        )
    source_size = value.get("sourceSizeBytes")
    if source_size is not None and not _is_non_negative_int(source_size):
        reasons.append(
            f"{prefix}.sourceSizeBytes must be a non-negative integer or null"
        )
    return reasons


def _runtime_variant_registry_input_contract_reasons(
    payload: Mapping[str, Any],
) -> list[str]:
    reasons: list[str] = []
    if payload.get("schemaVersion") != REPORT_SCHEMA_VERSION:
        reasons.append(f"input.schemaVersion must be {REPORT_SCHEMA_VERSION}")
    kind = payload.get("kind")
    if kind not in {RUNTIME_PACKAGE_KIND, RUNTIME_LOADER_MANIFEST_KIND}:
        reasons.append(
            "input.kind must be "
            f"{RUNTIME_PACKAGE_KIND} or {RUNTIME_LOADER_MANIFEST_KIND}"
        )
        return sorted(set(reasons))
    allowed_fields = (
        RUNTIME_PACKAGE_FIELDS
        if kind == RUNTIME_PACKAGE_KIND
        else RUNTIME_LOADER_MANIFEST_FIELDS
    )
    reasons.extend(_unsupported_mapping_field_reasons("input", payload, allowed_fields))
    if payload.get("success") is not True:
        reasons.append("input.success must be true")
    project = payload.get("project")
    if not isinstance(project, Mapping):
        reasons.append("input.project must be an object")
    else:
        targets = project.get("targets")
        if not isinstance(targets, list) or not all(
            _is_non_empty_string(target) for target in targets
        ):
            reasons.append("input.project.targets must be a list of strings")
        elif targets != _normalized_targets(targets):
            reasons.append(
                "input.project.targets must be unique canonical backend names"
            )
    collection_name = "artifacts" if kind == RUNTIME_PACKAGE_KIND else "loadUnits"
    records = payload.get(collection_name)
    if not isinstance(records, list):
        reasons.append(f"input.{collection_name} must be a list")
        return sorted(set(reasons))
    allowed_record_fields = (
        RUNTIME_PACKAGE_ARTIFACT_FIELDS
        if kind == RUNTIME_PACKAGE_KIND
        else RUNTIME_LOADER_MANIFEST_LOAD_UNIT_FIELDS
    )
    required_record_fields = (
        _RUNTIME_VARIANT_PACKAGE_REQUIRED_ARTIFACT_FIELDS
        if kind == RUNTIME_PACKAGE_KIND
        else _RUNTIME_VARIANT_LOADER_REQUIRED_UNIT_FIELDS
    )
    for index, record in enumerate(records):
        prefix = f"input.{collection_name}[{index}]"
        if not isinstance(record, Mapping):
            reasons.append(f"{prefix} must be an object")
            continue
        reasons.extend(
            _runtime_variant_closed_record_reasons(
                prefix,
                record,
                allowed=allowed_record_fields,
                required=required_record_fields,
            )
        )
        if not _is_non_empty_string(record.get("id")):
            reasons.append(f"{prefix}.id must be a non-empty string")
        if kind == RUNTIME_PACKAGE_KIND and record.get("status") != "packaged":
            reasons.append(f"{prefix}.status must be packaged")
        reasons.extend(
            _runtime_variant_common_record_contract_reasons(
                prefix,
                record,
                require_source=kind == RUNTIME_PACKAGE_KIND,
                require_hash=kind == RUNTIME_PACKAGE_KIND,
                allow_null_host_interface=kind == RUNTIME_PACKAGE_KIND,
            )
        )
        if kind == RUNTIME_LOADER_MANIFEST_KIND:
            blockers = record.get("blockers")
            validation = record.get("validation")
            if not isinstance(blockers, list) or not all(
                isinstance(blocker, Mapping) for blocker in blockers
            ):
                reasons.append(f"{prefix}.blockers must be a list of objects")
            if not isinstance(validation, Mapping) or not isinstance(
                validation.get("loadReady"), bool
            ):
                reasons.append(f"{prefix}.validation.loadReady must be a boolean")
            elif isinstance(blockers, list) and bool(blockers) == validation.get(
                "loadReady"
            ):
                reasons.append(
                    f"{prefix}.validation.loadReady must be false exactly when "
                    "blockers are present"
                )
    return sorted(set(reasons))


def _runtime_variant_payload_hash(value: Any) -> dict[str, str]:
    encoded = _runtime_variant_canonical_json(value).encode("utf-8")
    return {
        "algorithm": "sha256",
        "value": hashlib.sha256(encoded).hexdigest(),
    }


def _runtime_variant_key_schema() -> dict[str, Any]:
    return {
        "version": 2,
        "encoding": RUNTIME_VARIANT_KEY_ENCODING,
        "prefix": RUNTIME_VARIANT_KEY_PREFIX,
        "matching": "exact",
        "defaulting": "none",
        "unresolvedToken": _RUNTIME_VARIANT_UNRESOLVED,
        "fields": [
            "sourceUnit",
            "sourceEntry",
            "target",
            "targetProfile",
            "execution",
            "typeArguments",
            "valueArguments",
            "specializationConstants",
            "defines",
        ],
    }


def _runtime_variant_template_scalar(value: Any) -> tuple[bool, Any]:
    if isinstance(value, (bool, int, float)) and not isinstance(value, str):
        return True, value
    if not isinstance(value, str):
        return False, value
    text = value.strip()
    lowered = text.lower()
    if lowered in {"true", "false"}:
        return True, lowered == "true"
    integer_match = re.fullmatch(
        r"(?P<sign>[+-]?)(?P<number>0[xX][0-9A-Fa-f]+|0[bB][01]+|[0-9]+)"
        r"(?P<suffix>[uUlL]*)",
        text,
    )
    if integer_match is not None:
        number = integer_match.group("number")
        base = (
            16
            if number.lower().startswith("0x")
            else 2 if number.lower().startswith("0b") else 10
        )
        parsed = int(number, base)
        if integer_match.group("sign") == "-":
            parsed = -parsed
        return True, parsed
    if re.fullmatch(
        r"[+-]?(?:[0-9]+\.[0-9]*|\.[0-9]+|[0-9]+)" r"(?:[eE][+-]?[0-9]+)?(?:[fFhH])?",
        text,
    ):
        return True, float(re.sub(r"[fFhH]$", "", text))
    return False, text


def _runtime_variant_template_specializations(
    record: Mapping[str, Any],
) -> list[Mapping[str, Any]]:
    materialization = record.get("templateMaterialization")
    if not isinstance(materialization, Mapping):
        return []
    return [
        specialization
        for specialization in _record_sequence(materialization.get("specializations"))
        if isinstance(specialization, Mapping)
        and _is_non_empty_string(specialization.get("name"))
    ]


def _runtime_variant_arguments(
    record: Mapping[str, Any],
    *,
    source_entry: str | None,
    target_entry: str | None,
) -> tuple[dict[str, str], dict[str, Any], dict[str, Any] | None]:
    specializations = _runtime_variant_template_specializations(record)
    matches = [
        specialization
        for specialization in specializations
        if specialization.get("name") == source_entry
        and (
            target_entry
            in {
                specialization.get("hostName"),
                specialization.get("materializedName"),
                specialization.get("name"),
            }
            or len(specializations) == 1
        )
    ]
    if not matches and len(specializations) == 1:
        matches = specializations
    specialization = matches[0] if len(matches) == 1 else None
    if specialization is None:
        return {}, {}, None

    parameters = specialization.get("parameters")
    parameter_kinds = specialization.get("parameterKinds")
    kinds = parameter_kinds if isinstance(parameter_kinds, Mapping) else {}
    type_arguments: dict[str, str] = {}
    value_arguments: dict[str, Any] = {}
    if isinstance(parameters, Mapping):
        for parameter, value in sorted(parameters.items()):
            if not _is_non_empty_string(parameter):
                continue
            kind = kinds.get(parameter)
            scalar, scalar_value = _runtime_variant_template_scalar(value)
            if kind == "value" or (kind is None and scalar):
                value_arguments[str(parameter)] = scalar_value
            else:
                type_arguments[str(parameter)] = str(value)
    provenance = {
        "source": specialization.get("source"),
        "parameterSources": (
            dict(sorted(specialization.get("parameterSources", {}).items()))
            if isinstance(specialization.get("parameterSources"), Mapping)
            else {}
        ),
    }
    return type_arguments, value_arguments, provenance


def _runtime_variant_interface_entries(
    record: Mapping[str, Any],
) -> list[Mapping[str, Any]]:
    host_interface = record.get("hostInterface")
    if not isinstance(host_interface, Mapping):
        return []
    entries = [
        entry
        for entry in _record_sequence(host_interface.get("entryPoints"))
        if isinstance(entry, Mapping) and _is_non_empty_string(entry.get("name"))
    ]
    return sorted(entries, key=_runtime_variant_canonical_json)


def _runtime_variant_entry_contexts(
    record: Mapping[str, Any],
) -> list[dict[str, Any]]:
    interface_entries = _runtime_variant_interface_entries(record)
    explicit = record.get("entryPoint")
    if isinstance(explicit, Mapping) and _is_non_empty_string(explicit.get("source")):
        target_entry = explicit.get("target")
        interface_entry = next(
            (entry for entry in interface_entries if entry.get("name") == target_entry),
            None,
        )
        if interface_entry is None and len(interface_entries) == 1:
            interface_entry = interface_entries[0]
        return [
            {
                "sourceEntry": str(explicit.get("source")),
                "targetEntry": (
                    str(target_entry)
                    if _is_non_empty_string(target_entry)
                    else (
                        str(interface_entry.get("name"))
                        if isinstance(interface_entry, Mapping)
                        else None
                    )
                ),
                "entryPoint": interface_entry,
                "stage": (
                    explicit.get("stage")
                    if _is_non_empty_string(explicit.get("stage"))
                    else (
                        interface_entry.get("stage")
                        if isinstance(interface_entry, Mapping)
                        else record.get("stage")
                    )
                ),
                "nameProvenance": "explicit-source-target-entry-point",
            }
        ]

    template_specializations = _runtime_variant_template_specializations(record)
    if template_specializations:
        contexts = []
        for specialization in template_specializations:
            target_entry = (
                specialization.get("hostName")
                or specialization.get("materializedName")
                or specialization.get("name")
            )
            interface_entry = next(
                (
                    entry
                    for entry in interface_entries
                    if entry.get("name") == target_entry
                ),
                None,
            )
            if (
                interface_entry is None
                and len(interface_entries) == 1
                and len(template_specializations) == 1
            ):
                interface_entry = interface_entries[0]
                target_entry = interface_entry.get("name")
            contexts.append(
                {
                    "sourceEntry": specialization.get("name"),
                    "targetEntry": target_entry,
                    "entryPoint": interface_entry,
                    "stage": (
                        interface_entry.get("stage")
                        if isinstance(interface_entry, Mapping)
                        else record.get("stage")
                    ),
                    "nameProvenance": "template-materialization",
                }
            )
        return contexts

    if interface_entries:
        return [
            {
                "sourceEntry": entry.get("name"),
                "targetEntry": entry.get("name"),
                "entryPoint": entry,
                "stage": entry.get("stage") or record.get("stage"),
                "nameProvenance": "identity-interface-entry-point",
            }
            for entry in interface_entries
        ]
    return [
        {
            "sourceEntry": None,
            "targetEntry": None,
            "entryPoint": None,
            "stage": record.get("stage"),
            "nameProvenance": "unresolved",
        }
    ]


def _runtime_variant_target_profile(
    record: Mapping[str, Any],
    context: Mapping[str, Any],
) -> str | None:
    target_entry = context.get("targetEntry")
    for step in _record_sequence(record.get("loadSteps")):
        if not isinstance(step, Mapping):
            continue
        metadata = step.get("metadata")
        if not isinstance(metadata, Mapping):
            continue
        entry_profiles = metadata.get("entryProfiles")
        for entry_profile in _record_sequence(entry_profiles):
            if not isinstance(entry_profile, Mapping):
                continue
            if entry_profile.get("entry") == target_entry and _is_non_empty_string(
                entry_profile.get("profile")
            ):
                return str(entry_profile["profile"])
        command_input = metadata.get("commandInput")
        if isinstance(command_input, Mapping):
            if command_input.get("entryPoint") == target_entry and _is_non_empty_string(
                command_input.get("shaderModel")
            ):
                return str(command_input["shaderModel"])
    target = record.get("target")
    entry_point = context.get("entryPoint")
    if target == "directx":
        profile_entry = dict(entry_point) if isinstance(entry_point, Mapping) else {}
        if not _is_non_empty_string(
            profile_entry.get("stage")
        ) and _is_non_empty_string(context.get("stage")):
            profile_entry["stage"] = context["stage"]
        profile = _directx_dxc_profile_for_entry_record(profile_entry)
        return str(profile) if _is_non_empty_string(profile) else None
    return None


def _runtime_variant_constant_value(
    constant: Mapping[str, Any],
) -> tuple[bool, Any, str | None]:
    for field_name in ("concreteValue", "value", "defaultValue", "default"):
        if field_name in constant:
            value = constant.get(field_name)
            if value is None:
                continue
            if not _runtime_variant_scalar_contract_reasons("value", value):
                return True, _runtime_variant_normalize_json(value), field_name
            return False, value, field_name
    return False, None, None


def _runtime_variant_blocker(
    code: str,
    message: str,
    *,
    details: Mapping[str, Any] | None = None,
) -> dict[str, Any]:
    return {
        "code": code,
        "message": message,
        "details": _runtime_variant_normalize_json(details or {}),
    }


def _runtime_variant_specialization_records(
    record: Mapping[str, Any],
) -> tuple[list[dict[str, Any]], list[dict[str, Any]], list[dict[str, Any]]]:
    host_interface = record.get("hostInterface")
    reflected = (
        [
            constant
            for constant in _record_sequence(
                host_interface.get("specializationConstants")
            )
            if isinstance(constant, Mapping)
        ]
        if isinstance(host_interface, Mapping)
        else []
    )
    source = [
        constant
        for constant in _record_sequence(record.get("specializationConstants"))
        if isinstance(constant, Mapping)
    ]
    merged = _runtime_merge_specialization_constant_records(reflected, source)
    normalized: list[dict[str, Any]] = []
    key_records: list[dict[str, Any]] = []
    blockers: list[dict[str, Any]] = []
    identities: dict[tuple[str, Any], dict[str, Any]] = {}
    for constant in merged:
        name = constant.get("name")
        constant_id = constant.get("id", constant.get("constantId"))
        if constant_id is not None and (
            not isinstance(constant_id, int)
            or isinstance(constant_id, bool)
            or constant_id < 0
        ):
            blockers.append(
                _runtime_variant_blocker(
                    "project.runtime-variant-registry.specialization-id-invalid",
                    "Specialization constant IDs must be non-negative integers.",
                    details={"name": name, "id": constant_id},
                )
            )
            constant_id = None
        if not _is_non_empty_string(name):
            name = None
        identity = (
            ("id", constant_id)
            if constant_id is not None
            else ("name", name) if name is not None else None
        )
        if identity is None:
            blockers.append(
                _runtime_variant_blocker(
                    "project.runtime-variant-registry.specialization-identity-missing",
                    "A specialization constant is missing both its ID and name.",
                )
            )
            continue
        has_value, value, value_source = _runtime_variant_constant_value(constant)
        if not has_value:
            blockers.append(
                _runtime_variant_blocker(
                    "project.runtime-variant-registry.specialization-value-missing",
                    "Exact variant selection requires a concrete or default "
                    "specialization value.",
                    details={"name": name, "id": constant_id},
                )
            )
            value = None
        payload = {
            "id": constant_id,
            "name": name,
            "kind": constant.get("kind") or "specialization-constant",
            "dtype": constant.get("dtype") or constant.get("sourceType"),
            "value": _runtime_variant_normalize_json(value),
            "valueSource": value_source,
            "required": bool(constant.get("required")),
            "status": constant.get("status"),
            "source": constant.get("source"),
            "runtimeRole": "pipeline-specialization",
        }
        previous = identities.get(identity)
        if previous is not None:
            blockers.append(
                _runtime_variant_blocker(
                    "project.runtime-variant-registry.specialization-identity-duplicate",
                    "Specialization constant identity is duplicated.",
                    details={"identity": list(identity)},
                )
            )
        identities[identity] = payload
        normalized.append(payload)
        key_records.append({"id": constant_id, "name": name, "value": payload["value"]})
    normalized.sort(
        key=lambda item: (
            item.get("id") is None,
            item.get("id") if item.get("id") is not None else 0,
            str(item.get("name") or ""),
        )
    )
    return (
        normalized,
        _runtime_variant_normalized_key_specializations(key_records),
        blockers,
    )


def _runtime_variant_record_applies_to_entry(
    value: Mapping[str, Any], target_entry: str | None
) -> bool:
    metadata = value.get("metadata")
    if not isinstance(metadata, Mapping) or target_entry is None:
        return True
    names: list[str] = []
    for field_name in ("entryPoint", "entry_point"):
        entry = metadata.get(field_name)
        if _is_non_empty_string(entry):
            names.append(str(entry))
    for field_name in ("entryPoints", "entry_points"):
        entries = metadata.get(field_name)
        if isinstance(entries, list):
            names.extend(str(entry) for entry in entries if _is_non_empty_string(entry))
    return not names or target_entry in names


def _runtime_variant_binding_interface(
    record: Mapping[str, Any],
    context: Mapping[str, Any],
    specialization_constants: Sequence[Mapping[str, Any]],
) -> dict[str, Any]:
    host_interface = record.get("hostInterface")
    host = host_interface if isinstance(host_interface, Mapping) else {}
    target_entry = context.get("targetEntry")
    resources = [
        _runtime_variant_normalize_json(resource)
        for resource in _record_sequence(host.get("resources"))
        if isinstance(resource, Mapping)
        and _runtime_variant_record_applies_to_entry(resource, target_entry)
    ]
    constants = [
        _runtime_variant_normalize_json(constant)
        for constant in _record_sequence(host.get("constants"))
        if isinstance(constant, Mapping)
        and _runtime_variant_record_applies_to_entry(constant, target_entry)
    ]
    entry_point = context.get("entryPoint")
    normalized_entry_point = (
        _runtime_variant_normalize_json(entry_point)
        if isinstance(entry_point, Mapping)
        else None
    )
    normalized_specializations = [dict(item) for item in specialization_constants]
    return {
        "status": host.get("status") or "not-inspected",
        "source": host.get("source"),
        "parser": host.get("parser"),
        "artifactFormat": host.get("artifactFormat") or record.get("artifactFormat"),
        "entryPoint": normalized_entry_point,
        "entryPointCount": 1 if normalized_entry_point is not None else 0,
        "resources": sorted(resources, key=_runtime_variant_canonical_json),
        "resourceCount": len(resources),
        "constants": sorted(constants, key=_runtime_variant_canonical_json),
        "constantCount": len(constants),
        "specializationConstants": normalized_specializations,
        "specializationConstantCount": len(normalized_specializations),
        "diagnostics": sorted(
            str(diagnostic)
            for diagnostic in _record_sequence(host.get("diagnostics"))
            if _is_non_empty_string(diagnostic)
        ),
        "diagnosticRecords": sorted(
            (
                _runtime_variant_normalize_json(diagnostic)
                for diagnostic in _record_sequence(host.get("diagnosticRecords"))
                if isinstance(diagnostic, Mapping)
            ),
            key=_runtime_variant_canonical_json,
        ),
    }


def _runtime_variant_input_blockers(
    record: Mapping[str, Any],
    *,
    stale_codes: Sequence[str] = (),
) -> list[dict[str, Any]]:
    blockers = [
        _runtime_variant_blocker(
            str(blocker.get("code") or blocker.get("kind") or "input-blocked"),
            str(blocker.get("message") or "Runtime loader input is blocked."),
            details={
                key: value
                for key, value in blocker.items()
                if key not in {"code", "kind", "message"}
            },
        )
        for blocker in _record_sequence(record.get("blockers"))
        if isinstance(blocker, Mapping)
    ]
    for code in sorted(set(stale_codes)):
        blockers.append(
            _runtime_variant_blocker(
                code,
                "Runtime package inspection found stale or invalid packaged input.",
                details={"artifact": record.get("id")},
            )
        )
    return blockers


def _runtime_variant_candidate(
    record: Mapping[str, Any],
    context: Mapping[str, Any],
    *,
    input_kind: str,
    stale_codes: Sequence[str] = (),
) -> dict[str, Any]:
    source_unit = record.get("source")
    source_entry = context.get("sourceEntry")
    target_entry = context.get("targetEntry")
    target = str(record.get("target"))
    target_profile = _runtime_variant_target_profile(record, context)
    type_arguments, value_arguments, template_provenance = _runtime_variant_arguments(
        record,
        source_entry=source_entry,
        target_entry=target_entry,
    )
    specialization_constants, key_specializations, specialization_blockers = (
        _runtime_variant_specialization_records(record)
    )
    execution, execution_reasons = _runtime_variant_selected_entry_execution(
        "selected host-interface entry",
        context.get("entryPoint"),
    )
    blockers = [
        *_runtime_variant_input_blockers(record, stale_codes=stale_codes),
        *specialization_blockers,
    ]
    if execution_reasons:
        blockers.append(
            _runtime_variant_blocker(
                "project.runtime-variant-registry.execution-metadata-invalid",
                "Selected entry execution metadata is not exact and canonical.",
                details={"reasons": execution_reasons},
            )
        )
    if not _is_non_empty_string(source_unit):
        blockers.append(
            _runtime_variant_blocker(
                "project.runtime-variant-registry.source-unit-missing",
                "Runtime variant source unit metadata is missing.",
            )
        )
    if not _is_non_empty_string(source_entry):
        blockers.append(
            _runtime_variant_blocker(
                "project.runtime-variant-registry.source-entry-missing",
                "Runtime variant source entry metadata is missing.",
            )
        )
    if not _is_non_empty_string(target_entry):
        blockers.append(
            _runtime_variant_blocker(
                "project.runtime-variant-registry.target-entry-missing",
                "Runtime variant target entry point metadata is missing.",
            )
        )
    host_interface = record.get("hostInterface")
    interface_status = (
        host_interface.get("status")
        if isinstance(host_interface, Mapping)
        else "not-inspected"
    )
    if interface_status != "ready":
        blockers.append(
            _runtime_variant_blocker(
                "project.runtime-variant-registry.interface-blocked",
                "Runtime variant binding interface is not ready.",
                details={"status": interface_status},
            )
        )
    artifact_hash = record.get("hash")
    if not isinstance(artifact_hash, Mapping):
        blockers.append(
            _runtime_variant_blocker(
                "project.runtime-variant-registry.artifact-hash-missing",
                "Runtime variant artifact hash metadata is missing.",
            )
        )
    blockers = sorted(
        {
            _runtime_variant_canonical_json(blocker): blocker for blocker in blockers
        }.values(),
        key=_runtime_variant_canonical_json,
    )
    status = (
        "stale"
        if stale_codes or execution_reasons
        else "blocked" if blockers else "ready"
    )
    key = encode_runtime_variant_key(
        (
            str(source_unit)
            if _is_non_empty_string(source_unit)
            else _RUNTIME_VARIANT_UNRESOLVED
        ),
        (
            str(source_entry)
            if _is_non_empty_string(source_entry)
            else _RUNTIME_VARIANT_UNRESOLVED
        ),
        target,
        target_profile=target_profile,
        execution=execution,
        type_arguments=type_arguments,
        value_arguments=value_arguments,
        specialization_constants=key_specializations,
        defines=(
            record.get("defines") if isinstance(record.get("defines"), Mapping) else {}
        ),
    )
    source_remap = record.get("sourceRemap")
    catalog_entry = _runtime_adapter_catalog_entry(target)
    artifact_format = record.get("artifactFormat")
    if not _is_non_empty_string(artifact_format) and isinstance(
        host_interface, Mapping
    ):
        artifact_format = host_interface.get("artifactFormat")
    if not _is_non_empty_string(artifact_format):
        artifact_format = catalog_entry.get("artifactFormat")
    artifact_id = record.get("artifact") or record.get("id")
    return {
        "key": key,
        "status": status,
        "source": {
            "unit": source_unit,
            "backend": record.get("sourceBackend"),
            "entry": source_entry,
        },
        "target": {
            "backend": target,
            "profile": target_profile,
            "stage": context.get("stage"),
            "entryPoint": target_entry,
        },
        "variant": record.get("variant"),
        "arguments": {
            "types": type_arguments,
            "values": value_arguments,
        },
        "defines": dict(sorted(record.get("defines", {}).items())),
        "specializationConstants": specialization_constants,
        "execution": execution,
        "bindingInterface": _runtime_variant_binding_interface(
            record, context, specialization_constants
        ),
        "artifact": {
            "id": artifact_id,
            "path": _runtime_loader_optional_package_path(record.get("packagePath")),
            "format": artifact_format,
            "hash": (
                _runtime_variant_normalize_json(artifact_hash)
                if isinstance(artifact_hash, Mapping)
                else None
            ),
            "sizeBytes": record.get("sizeBytes"),
        },
        "provenance": {
            "inputKind": input_kind,
            "artifactId": artifact_id,
            "sourceHash": (
                _runtime_variant_normalize_json(record.get("sourceHash"))
                if isinstance(record.get("sourceHash"), Mapping)
                else None
            ),
            "sourceSizeBytes": record.get("sourceSizeBytes"),
            "translation": (
                _runtime_variant_normalize_json(record.get("provenance"))
                if isinstance(record.get("provenance"), Mapping)
                else {}
            ),
            "entryPointNames": context.get("nameProvenance"),
            "templateArguments": template_provenance,
            "sourceRemap": (
                _runtime_variant_normalize_json(source_remap)
                if isinstance(source_remap, Mapping)
                else None
            ),
        },
        "lookup": {"mode": "exact", "eligible": status == "ready"},
        "blockers": blockers,
    }


def _runtime_variant_package_candidates(
    path: Path,
    payload: Mapping[str, Any],
) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    inspection = inspect_runtime_package(path)
    bindings = [
        binding
        for binding in _record_sequence(inspection.get("bindings"))
        if isinstance(binding, Mapping)
    ]
    artifacts = [
        artifact
        for artifact in _record_sequence(payload.get("artifacts"))
        if isinstance(artifact, Mapping)
    ]
    candidates: list[dict[str, Any]] = []
    for index, artifact in enumerate(artifacts):
        binding = bindings[index] if index < len(bindings) else None
        merged = dict(artifact)
        stale_codes: list[str] = []
        if isinstance(binding, Mapping):
            if isinstance(binding.get("hostInterface"), Mapping):
                merged["hostInterface"] = dict(binding["hostInterface"])
            stale_codes.extend(
                str(code)
                for code in _record_sequence(binding.get("diagnostics"))
                if _is_non_empty_string(code)
            )
        else:
            stale_codes.append(
                "project.runtime-variant-registry.package-inspection-record-missing"
            )
        for context in _runtime_variant_entry_contexts(merged):
            candidates.append(
                _runtime_variant_candidate(
                    merged,
                    context,
                    input_kind=RUNTIME_PACKAGE_KIND,
                    stale_codes=stale_codes,
                )
            )
    summary = inspection.get("summary")
    summary_mapping = summary if isinstance(summary, Mapping) else {}
    return candidates, {
        "kind": RUNTIME_PACKAGE_INSPECTION_KIND,
        "success": bool(inspection.get("success")),
        "verifiedArtifactCount": summary_mapping.get("verifiedArtifactCount", 0),
        "failedArtifactCount": summary_mapping.get("failedArtifactCount", 0),
        "readyBindingCount": summary_mapping.get("readyBindingCount", 0),
        "failedBindingCount": summary_mapping.get("failedBindingCount", 0),
    }


def _runtime_variant_loader_candidates(
    payload: Mapping[str, Any],
) -> tuple[list[dict[str, Any]], dict[str, Any]]:
    candidates = []
    for load_unit in _record_sequence(payload.get("loadUnits")):
        if not isinstance(load_unit, Mapping):
            continue
        for context in _runtime_variant_entry_contexts(load_unit):
            candidates.append(
                _runtime_variant_candidate(
                    load_unit,
                    context,
                    input_kind=RUNTIME_LOADER_MANIFEST_KIND,
                )
            )
    inspection = payload.get("packageInspection")
    inspection_mapping = inspection if isinstance(inspection, Mapping) else {}
    return candidates, {
        "kind": inspection_mapping.get("kind") or RUNTIME_PACKAGE_INSPECTION_KIND,
        "success": bool(inspection_mapping.get("success")),
        "readyBindingCount": inspection_mapping.get("readyBindingCount", 0),
        "failedBindingCount": inspection_mapping.get("failedBindingCount", 0),
    }


def _runtime_variant_registry_empty_payload(
    *,
    source_kind: Any,
    source_schema_version: Any,
    diagnostics: Sequence[ProjectDiagnostic],
) -> dict[str, Any]:
    key_schema = _runtime_variant_key_schema()
    variants: dict[str, Any] = {}
    registry_hash = _runtime_variant_payload_hash(
        {
            "schemaVersion": REPORT_SCHEMA_VERSION,
            "keySchema": key_schema,
            "variants": variants,
        }
    )
    return {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": RUNTIME_VARIANT_REGISTRY_KIND,
        "success": False,
        "status": "failed",
        "scope": RUNTIME_VARIANT_REGISTRY_SCOPE,
        "nonGoals": list(RUNTIME_VARIANT_REGISTRY_NON_GOALS),
        "source": {
            "kind": source_kind if _is_non_empty_string(source_kind) else None,
            "schemaVersion": source_schema_version,
        },
        "keySchema": key_schema,
        "summary": {
            "targetCount": 0,
            "candidateCount": 0,
            "variantCount": 0,
            "readyVariantCount": 0,
            "blockedVariantCount": 0,
            "staleVariantCount": 0,
            "duplicateKeyCount": 0,
            "conflictingKeyCount": 0,
            "rejectedCandidateCount": 0,
        },
        "targets": [],
        "variants": variants,
        "lookup": {
            "mode": "exact",
            "defaulting": "none",
            "availableKeys": [],
            "readyKeys": [],
            "blockedKeys": [],
        },
        "inputInspection": None,
        "registryHash": registry_hash,
        "diagnosticCounts": _diagnostic_counts(diagnostics),
        "diagnostics": [diagnostic.to_json() for diagnostic in diagnostics],
    }


def _runtime_variant_record_comparison_payload(record: Mapping[str, Any]) -> Any:
    return _runtime_variant_normalize_json(record)


def _runtime_variant_registry_target(
    target: str,
    variants: Mapping[str, Mapping[str, Any]],
) -> dict[str, Any]:
    records = [
        record
        for record in variants.values()
        if record.get("target", {}).get("backend") == target
    ]
    keys = sorted(record.get("key") for record in records)
    return {
        "target": target,
        "variantCount": len(records),
        "readyVariantCount": sum(record.get("status") == "ready" for record in records),
        "blockedVariantCount": sum(
            record.get("status") == "blocked" for record in records
        ),
        "staleVariantCount": sum(record.get("status") == "stale" for record in records),
        "keys": keys,
    }


def _runtime_variant_lookup_execution_alternatives(
    variants: Mapping[str, Any],
    requested_payload: Mapping[str, Any],
) -> list[dict[str, Any]]:
    requested_identity = {
        field: requested_payload.get(field)
        for field in RUNTIME_VARIANT_KEY_FIELDS
        if field != "execution"
    }
    alternatives = []
    for key, record in sorted(variants.items()):
        try:
            candidate_payload = decode_runtime_variant_key(str(key))
        except ValueError:
            continue
        candidate_identity = {
            field: candidate_payload.get(field)
            for field in RUNTIME_VARIANT_KEY_FIELDS
            if field != "execution"
        }
        if candidate_identity != requested_identity:
            continue
        alternatives.append(
            {
                "key": str(key),
                "status": record.get("status") if isinstance(record, Mapping) else None,
                "execution": candidate_payload["execution"],
            }
        )
    return alternatives


def _runtime_variant_lookup_registry_contract_reasons(
    registry: Mapping[str, Any],
) -> list[str]:
    reasons = _unsupported_mapping_field_reasons(
        "runtime variant registry",
        registry,
        RUNTIME_VARIANT_REGISTRY_FIELDS,
    )
    missing = sorted(RUNTIME_VARIANT_REGISTRY_FIELDS - set(registry))
    if missing:
        reasons.append(
            "runtime variant registry is missing fields: " + ", ".join(missing)
        )

    key_schema = registry.get("keySchema")
    expected_key_schema = _runtime_variant_key_schema()
    if key_schema != expected_key_schema:
        reasons.append("runtime variant registry.keySchema is not canonical")

    variants = registry.get("variants")
    if not isinstance(variants, Mapping):
        reasons.append("runtime variant registry.variants must be an object")
        return sorted(set(reasons))

    expected_hash = _runtime_variant_payload_hash(
        {
            "schemaVersion": REPORT_SCHEMA_VERSION,
            "keySchema": expected_key_schema,
            "variants": variants,
        }
    )
    if registry.get("registryHash") != expected_hash:
        reasons.append(
            "runtime variant registry.registryHash does not match its variants"
        )

    for key, record in variants.items():
        prefix = f"runtime variant registry.variants[{key!r}]"
        try:
            decoded_key = decode_runtime_variant_key(key)
        except ValueError as exc:
            reasons.append(f"{prefix} uses an invalid canonical key: {exc}")
            continue
        if not isinstance(record, Mapping):
            reasons.append(f"{prefix} must be an object")
            continue
        reasons.extend(
            _unsupported_mapping_field_reasons(
                prefix,
                record,
                RUNTIME_VARIANT_REGISTRY_RECORD_FIELDS,
            )
        )
        missing_record_fields = sorted(
            RUNTIME_VARIANT_REGISTRY_RECORD_FIELDS - set(record)
        )
        if missing_record_fields:
            reasons.append(
                f"{prefix} is missing fields: " + ", ".join(missing_record_fields)
            )
        if record.get("key") != key:
            reasons.append(f"{prefix}.key must match its registry key")

        status = record.get("status")
        if status not in {"ready", "blocked", "stale"}:
            reasons.append(f"{prefix}.status must be ready, blocked, or stale")
        lookup = record.get("lookup")
        if not isinstance(lookup, Mapping):
            reasons.append(f"{prefix}.lookup must be an object")
        elif lookup.get("eligible") is not (status == "ready"):
            reasons.append(f"{prefix}.lookup.eligible must match record readiness")

        source = record.get("source")
        target = record.get("target")
        arguments = record.get("arguments")
        defines = record.get("defines")
        constants = record.get("specializationConstants")
        execution = record.get("execution")
        binding_interface = record.get("bindingInterface")
        if not all(
            isinstance(value, Mapping)
            for value in (
                source,
                target,
                arguments,
                defines,
                execution,
                binding_interface,
            )
        ) or not isinstance(constants, list):
            reasons.append(f"{prefix} cannot reconstruct its canonical identity")
            continue
        execution_reasons = _runtime_variant_execution_contract_reasons(
            f"{prefix}.execution",
            execution,
        )
        reasons.extend(execution_reasons)
        selected_execution, selected_execution_reasons = (
            _runtime_variant_selected_entry_execution(
                f"{prefix}.bindingInterface.entryPoint",
                binding_interface.get("entryPoint"),
            )
        )
        reasons.extend(selected_execution_reasons)
        if not execution_reasons and not selected_execution_reasons:
            if execution != selected_execution:
                reasons.append(
                    f"{prefix}.execution must match its selected "
                    "bindingInterface entry point"
                )
            if decoded_key.get("execution") != execution:
                reasons.append(
                    f"{prefix}.execution must match its decoded canonical key"
                )
        type_arguments = arguments.get("types")
        value_arguments = arguments.get("values")
        if (
            not isinstance(type_arguments, Mapping)
            or not isinstance(value_arguments, Mapping)
            or not all(isinstance(constant, Mapping) for constant in constants)
        ):
            reasons.append(f"{prefix} cannot reconstruct its canonical identity")
            continue
        try:
            expected_key = encode_runtime_variant_key(
                source.get("unit"),
                source.get("entry"),
                target.get("backend"),
                target_profile=target.get("profile"),
                execution=execution,
                type_arguments=type_arguments,
                value_arguments=value_arguments,
                specialization_constants=constants,
                defines=defines,
            )
        except (TypeError, ValueError) as exc:
            reasons.append(f"{prefix} has an invalid canonical identity: {exc}")
            continue
        if expected_key != key:
            reasons.append(f"{prefix} identity does not match its canonical key")
    return sorted(set(reasons))


def build_runtime_variant_registry(
    manifest_path: str | os.PathLike[str],
) -> dict[str, Any]:
    """Build a deterministic exact-lookup registry from a package or loader manifest."""

    path = _filesystem_path_arg(
        manifest_path, field_name="Runtime package or loader manifest path"
    )
    payload, diagnostics = _runtime_variant_registry_load_input(path)
    if diagnostics:
        return _runtime_variant_registry_empty_payload(
            source_kind=None,
            source_schema_version=None,
            diagnostics=diagnostics,
        )
    reasons = _runtime_variant_registry_input_contract_reasons(payload)
    if reasons:
        diagnostic = _runtime_variant_diagnostic(
            "project.runtime-variant-registry.input-schema-invalid",
            "Runtime variant registry input does not satisfy the package or loader schema.",
            details={"reasons": reasons},
        )
        return _runtime_variant_registry_empty_payload(
            source_kind=payload.get("kind"),
            source_schema_version=payload.get("schemaVersion"),
            diagnostics=[diagnostic],
        )

    input_kind = str(payload.get("kind"))
    if input_kind == RUNTIME_PACKAGE_KIND:
        candidates, input_inspection = _runtime_variant_package_candidates(
            path, payload
        )
    else:
        candidates, input_inspection = _runtime_variant_loader_candidates(payload)
    candidates = sorted(
        candidates,
        key=lambda record: (
            str(record.get("key") or ""),
            _runtime_variant_canonical_json(record),
        ),
    )
    groups: dict[str, list[dict[str, Any]]] = {}
    for candidate in candidates:
        groups.setdefault(str(candidate["key"]), []).append(candidate)

    variants: dict[str, dict[str, Any]] = {}
    duplicate_key_count = 0
    conflicting_key_count = 0
    rejected_candidate_count = 0
    registry_diagnostics: list[ProjectDiagnostic] = []
    for key, records in sorted(groups.items()):
        if len(records) == 1:
            variants[key] = records[0]
            continue
        rejected_candidate_count += len(records)
        comparison_payloads = {
            _runtime_variant_canonical_json(
                _runtime_variant_record_comparison_payload(record)
            )
            for record in records
        }
        conflict = len(comparison_payloads) > 1
        if conflict:
            conflicting_key_count += 1
            code = "project.runtime-variant-registry.conflicting-key"
            message = "Multiple runtime records map one key to conflicting artifacts or metadata."
        else:
            duplicate_key_count += 1
            code = "project.runtime-variant-registry.duplicate-key"
            message = "The runtime variant input contains a duplicate canonical key."
        registry_diagnostics.append(
            _runtime_variant_diagnostic(
                code,
                message,
                details={
                    "key": key,
                    "recordCount": len(records),
                    "artifactIds": sorted(
                        str(record.get("artifact", {}).get("id") or "")
                        for record in records
                    ),
                },
            )
        )

    for key, record in sorted(variants.items()):
        for blocker in record.get("blockers", []):
            stale = record.get("status") == "stale"
            registry_diagnostics.append(
                _runtime_variant_diagnostic(
                    str(
                        blocker.get("code")
                        or "project.runtime-variant-registry.blocked"
                    ),
                    str(blocker.get("message") or "Runtime variant is blocked."),
                    severity="error" if stale else "warning",
                    source=record.get("source", {}).get("unit"),
                    target=record.get("target", {}).get("backend"),
                    variant=record.get("variant"),
                    details={
                        "key": key,
                        **(
                            blocker.get("details")
                            if isinstance(blocker.get("details"), Mapping)
                            else {}
                        ),
                    },
                )
            )
    registry_diagnostics = sorted(
        registry_diagnostics,
        key=lambda diagnostic: (
            diagnostic.code,
            diagnostic.message,
            _runtime_variant_canonical_json(diagnostic.details),
        ),
    )
    variants = {key: variants[key] for key in sorted(variants)}
    ready_keys = sorted(
        key for key, record in variants.items() if record.get("status") == "ready"
    )
    blocked_keys = sorted(
        key for key, record in variants.items() if record.get("status") != "ready"
    )
    stale_variant_count = sum(
        record.get("status") == "stale" for record in variants.values()
    )
    blocked_variant_count = sum(
        record.get("status") == "blocked" for record in variants.values()
    )
    has_error = any(
        diagnostic.severity == "error" for diagnostic in registry_diagnostics
    )
    success = not has_error
    if not success:
        status = "failed"
    elif blocked_variant_count and not ready_keys:
        status = "blocked"
    elif blocked_variant_count:
        status = "partial"
    else:
        status = "ready"
    target_names = sorted(
        {
            str(record.get("target", {}).get("backend"))
            for record in variants.values()
            if _is_non_empty_string(record.get("target", {}).get("backend"))
        }
    )
    key_schema = _runtime_variant_key_schema()
    registry_hash = _runtime_variant_payload_hash(
        {
            "schemaVersion": REPORT_SCHEMA_VERSION,
            "keySchema": key_schema,
            "variants": variants,
        }
    )
    return {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": RUNTIME_VARIANT_REGISTRY_KIND,
        "success": success,
        "status": status,
        "scope": RUNTIME_VARIANT_REGISTRY_SCOPE,
        "nonGoals": list(RUNTIME_VARIANT_REGISTRY_NON_GOALS),
        "source": {
            "kind": input_kind,
            "schemaVersion": payload.get("schemaVersion"),
        },
        "keySchema": key_schema,
        "summary": {
            "targetCount": len(target_names),
            "candidateCount": len(candidates),
            "variantCount": len(variants),
            "readyVariantCount": len(ready_keys),
            "blockedVariantCount": blocked_variant_count,
            "staleVariantCount": stale_variant_count,
            "duplicateKeyCount": duplicate_key_count,
            "conflictingKeyCount": conflicting_key_count,
            "rejectedCandidateCount": rejected_candidate_count,
        },
        "targets": [
            _runtime_variant_registry_target(target, variants)
            for target in target_names
        ],
        "variants": variants,
        "lookup": {
            "mode": "exact",
            "defaulting": "none",
            "availableKeys": sorted(variants),
            "readyKeys": ready_keys,
            "blockedKeys": blocked_keys,
        },
        "inputInspection": input_inspection,
        "registryHash": registry_hash,
        "diagnosticCounts": _diagnostic_counts(registry_diagnostics),
        "diagnostics": [diagnostic.to_json() for diagnostic in registry_diagnostics],
    }


def lookup_runtime_variant(
    registry: Mapping[str, Any],
    key: str,
) -> dict[str, Any]:
    """Perform one exact registry lookup without defaults or best-match logic."""

    diagnostics: list[ProjectDiagnostic] = []
    requested_payload: dict[str, Any] | None = None
    if not isinstance(registry, Mapping):
        diagnostics.append(
            _runtime_variant_diagnostic(
                "project.runtime-variant-registry.lookup-registry-invalid",
                "Runtime variant lookup requires a registry object.",
            )
        )
        variants: Mapping[str, Any] = {}
        requested_key = key if isinstance(key, str) else ""
    elif (
        registry.get("schemaVersion") != REPORT_SCHEMA_VERSION
        or registry.get("kind") != RUNTIME_VARIANT_REGISTRY_KIND
    ):
        diagnostics.append(
            _runtime_variant_diagnostic(
                "project.runtime-variant-registry.lookup-registry-schema-invalid",
                "Runtime variant lookup requires a schema-v1 runtime variant registry.",
            )
        )
        variants = {}
        requested_key = key if isinstance(key, str) else ""
    else:
        requested_key = key if isinstance(key, str) else ""
        registry_reasons = _runtime_variant_lookup_registry_contract_reasons(registry)
        if registry_reasons:
            diagnostics.append(
                _runtime_variant_diagnostic(
                    "project.runtime-variant-registry.lookup-registry-invalid",
                    "Runtime variant lookup rejected an invalid or modified registry.",
                    details={"reasons": registry_reasons},
                )
            )
            variants = {}
        else:
            variants = registry["variants"]
            try:
                requested_payload = decode_runtime_variant_key(requested_key)
            except ValueError as exc:
                diagnostics.append(
                    _runtime_variant_diagnostic(
                        "project.runtime-variant-registry.lookup-key-invalid",
                        str(exc),
                        details={"requestedKey": requested_key},
                    )
                )
    record = variants.get(requested_key) if not diagnostics else None
    available_keys = sorted(str(candidate) for candidate in variants)
    if record is None and not diagnostics:
        execution_alternatives = (
            _runtime_variant_lookup_execution_alternatives(
                variants,
                requested_payload,
            )
            if requested_payload is not None
            else []
        )
        diagnostics.append(
            _runtime_variant_diagnostic(
                "project.runtime-variant-registry.variant-not-found",
                "No runtime variant exactly matches the requested key.",
                details={
                    "requestedKey": requested_key,
                    "requestedExecution": (
                        requested_payload.get("execution")
                        if requested_payload is not None
                        else None
                    ),
                    "availableExecutionAlternatives": execution_alternatives,
                    "availableKeys": available_keys,
                },
            )
        )
    elif isinstance(record, Mapping) and record.get("status") != "ready":
        diagnostics.append(
            _runtime_variant_diagnostic(
                "project.runtime-variant-registry.variant-blocked",
                "The exact runtime variant exists but is not lookup-ready.",
                details={
                    "requestedKey": requested_key,
                    "status": record.get("status"),
                    "blockers": record.get("blockers", []),
                },
            )
        )
    success = isinstance(record, Mapping) and record.get("status") == "ready"
    status = "ready" if success else "blocked" if record is not None else "not-found"
    if diagnostics and diagnostics[0].code.endswith(("invalid", "schema-invalid")):
        status = "invalid"
    return {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": RUNTIME_VARIANT_LOOKUP_KIND,
        "success": success,
        "status": status,
        "match": "exact" if record is not None else None,
        "requestedKey": requested_key,
        "record": dict(record) if isinstance(record, Mapping) else None,
        "availableKeys": available_keys,
        "diagnosticCounts": _diagnostic_counts(diagnostics),
        "diagnostics": [diagnostic.to_json() for diagnostic in diagnostics],
    }


def _runtime_host_loader_scaffold_slug(value: Any, fallback: str) -> str:
    text = value if isinstance(value, str) else ""
    text = text.strip().lower()
    text = re.sub(r"[^a-z0-9._-]+", "-", text)
    text = re.sub(r"-+", "-", text).strip(".-_")
    text = re.sub(r"-+\.", ".", text)
    return text or fallback


def _runtime_host_loader_scaffold_unique_slug(
    value: Any, fallback: str, used: set[str]
) -> str:
    slug = _runtime_host_loader_scaffold_slug(value, fallback)
    candidate = slug
    index = 2
    while candidate in used:
        candidate = f"{slug}-{index}"
        index += 1
    used.add(candidate)
    return candidate


def _runtime_host_loader_scaffold_load_manifest(
    path: Path,
) -> tuple[Mapping[str, Any], list[ProjectDiagnostic]]:
    try:
        manifest = json.loads(path.read_text(encoding="utf-8"))
    except OSError as exc:
        return {}, [
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-host-loader-scaffolds.manifest-read-failed",
                message=f"Runtime loader manifest could not be read: {exc}",
                location=SourceLocation(file=str(path)),
                check_kind="runtime-host-loader-scaffolds",
            )
        ]
    except json.JSONDecodeError as exc:
        return {}, [
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-host-loader-scaffolds.manifest-json-invalid",
                message=f"Runtime loader manifest is not valid JSON: {exc}",
                location=SourceLocation(
                    file=str(path), line=exc.lineno, column=exc.colno
                ),
                check_kind="runtime-host-loader-scaffolds",
            )
        ]
    if not isinstance(manifest, Mapping):
        return {}, [
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-host-loader-scaffolds.manifest-invalid",
                message="Runtime loader manifest must be a JSON object.",
                location=SourceLocation(file=str(path)),
                check_kind="runtime-host-loader-scaffolds",
            )
        ]
    return manifest, []


def _runtime_host_loader_scaffold_manifest_diagnostics(
    path: Path, manifest: Mapping[str, Any]
) -> list[ProjectDiagnostic]:
    diagnostics: list[ProjectDiagnostic] = []
    if manifest.get("schemaVersion") != REPORT_SCHEMA_VERSION:
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-host-loader-scaffolds.manifest-schema-invalid",
                message=f"Runtime loader manifest schemaVersion must be {REPORT_SCHEMA_VERSION}.",
                location=SourceLocation(file=str(path)),
                check_kind="runtime-host-loader-scaffolds",
            )
        )
    if manifest.get("kind") != RUNTIME_LOADER_MANIFEST_KIND:
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-host-loader-scaffolds.manifest-kind-invalid",
                message=(
                    "Host loader scaffold input must be a "
                    f"{RUNTIME_LOADER_MANIFEST_KIND} document."
                ),
                location=SourceLocation(file=str(path)),
                check_kind="runtime-host-loader-scaffolds",
            )
        )
    if manifest.get("success") is not True:
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-host-loader-scaffolds.manifest-failed",
                message=(
                    "Runtime loader manifest must be successful before host "
                    "loader scaffolds can be generated."
                ),
                location=SourceLocation(file=str(path)),
                check_kind="runtime-host-loader-scaffolds",
            )
        )
    if not isinstance(manifest.get("loadUnits"), list):
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code="project.runtime-host-loader-scaffolds.load-units-invalid",
                message="Runtime loader manifest loadUnits must be a list.",
                location=SourceLocation(file=str(path)),
                check_kind="runtime-host-loader-scaffolds",
            )
        )
    return diagnostics


def _runtime_host_loader_scaffold_status(
    ready_count: int, blocked_count: int, *, failed: bool = False
) -> str:
    if failed:
        return "failed"
    if blocked_count and ready_count:
        return "partial"
    if blocked_count:
        return "blocked"
    if ready_count:
        return "ready"
    return "empty"


def _runtime_host_loader_scaffold_generated_file(
    path: str, kind: str, target: str | None = None
) -> dict[str, Any]:
    return {"path": path, "kind": kind, "target": target}


def _runtime_host_loader_scaffold_record(
    load_unit: Mapping[str, Any],
    output_path: str | None,
) -> dict[str, Any]:
    blockers = [
        dict(blocker)
        for blocker in _record_sequence(load_unit.get("blockers"))
        if isinstance(blocker, Mapping)
    ]
    validation = (
        load_unit.get("validation")
        if isinstance(load_unit.get("validation"), Mapping)
        else {}
    )
    ready = not blockers and validation.get("loadReady") is True
    source_remap = load_unit.get("sourceRemap")
    host_interface = load_unit.get("hostInterface")
    return {
        "id": f"{load_unit.get('id') or 'load-unit'}:host-loader",
        "target": load_unit.get("target"),
        "status": "ready" if ready else "blocked",
        "adapterKind": load_unit.get("adapterKind"),
        "artifactFormat": load_unit.get("artifactFormat"),
        "packagePath": load_unit.get("packagePath"),
        "sourcePath": load_unit.get("sourcePath"),
        "sourceBackend": load_unit.get("sourceBackend"),
        "variant": load_unit.get("variant"),
        "defines": (
            dict(load_unit.get("defines"))
            if isinstance(load_unit.get("defines"), Mapping)
            else {}
        ),
        "loadUnit": load_unit.get("id"),
        "outputPath": output_path if ready else None,
        "scaffoldKind": "host-loader-metadata",
        "sourceRemap": (
            dict(source_remap) if isinstance(source_remap, Mapping) else None
        ),
        "hostInterface": (
            dict(host_interface) if isinstance(host_interface, Mapping) else None
        ),
        "requiredTools": [
            tool
            for tool in _record_sequence(load_unit.get("requiredTools"))
            if _is_non_empty_string(tool)
        ],
        "hostResponsibilities": [
            responsibility
            for responsibility in _record_sequence(
                load_unit.get("hostResponsibilities")
            )
            if _is_non_empty_string(responsibility)
        ],
        "loadSteps": [
            dict(step)
            for step in _record_sequence(load_unit.get("loadSteps"))
            if isinstance(step, Mapping)
        ],
        "blockers": blockers,
    }


def _runtime_host_loader_scaffold_unit_payload(
    scaffold: Mapping[str, Any],
) -> dict[str, Any]:
    return {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": "crosstl-runtime-host-loader-unit",
        "scaffold": scaffold.get("id"),
        "status": scaffold.get("status"),
        "target": scaffold.get("target"),
        "adapterKind": scaffold.get("adapterKind"),
        "artifactFormat": scaffold.get("artifactFormat"),
        "packagePath": scaffold.get("packagePath"),
        "sourceRemap": scaffold.get("sourceRemap"),
        "hostInterface": scaffold.get("hostInterface"),
        "requiredTools": (
            list(scaffold.get("requiredTools"))
            if isinstance(scaffold.get("requiredTools"), list)
            else []
        ),
        "hostResponsibilities": (
            list(scaffold.get("hostResponsibilities"))
            if isinstance(scaffold.get("hostResponsibilities"), list)
            else []
        ),
        "loadSteps": (
            list(scaffold.get("loadSteps"))
            if isinstance(scaffold.get("loadSteps"), list)
            else []
        ),
    }


def _runtime_host_loader_scaffold_target(
    target: Mapping[str, Any],
    scaffolds: Sequence[Mapping[str, Any]],
) -> dict[str, Any]:
    target_name = target.get("target")
    target_scaffolds = [
        scaffold for scaffold in scaffolds if scaffold.get("target") == target_name
    ]
    ready_scaffolds = [
        scaffold for scaffold in target_scaffolds if scaffold.get("status") == "ready"
    ]
    blocked_scaffolds = [
        scaffold for scaffold in target_scaffolds if scaffold.get("status") == "blocked"
    ]
    return {
        "target": target_name,
        "status": _runtime_host_loader_scaffold_status(
            len(ready_scaffolds), len(blocked_scaffolds)
        ),
        "adapterKind": target.get("adapterKind"),
        "loadUnitCount": len(target_scaffolds),
        "readyLoadUnitCount": len(ready_scaffolds),
        "blockedLoadUnitCount": len(blocked_scaffolds),
        "runtimeReferenceCount": target.get("runtimeReferenceCount", 0),
        "requiredTools": (
            list(target.get("requiredTools"))
            if isinstance(target.get("requiredTools"), list)
            else []
        ),
        "loaderResponsibilities": (
            list(target.get("loaderResponsibilities"))
            if isinstance(target.get("loaderResponsibilities"), list)
            else []
        ),
        "packagePaths": [
            scaffold.get("packagePath")
            for scaffold in target_scaffolds
            if _is_non_empty_string(scaffold.get("packagePath"))
        ],
        "loadUnitIds": [
            scaffold.get("loadUnit")
            for scaffold in target_scaffolds
            if _is_non_empty_string(scaffold.get("loadUnit"))
        ],
        "scaffoldFiles": [
            scaffold.get("outputPath")
            for scaffold in ready_scaffolds
            if _is_non_empty_string(scaffold.get("outputPath"))
        ],
    }


def _runtime_host_loader_scaffold_guide(payload: Mapping[str, Any]) -> str:
    summary = (
        payload.get("summary") if isinstance(payload.get("summary"), Mapping) else {}
    )
    lines = [
        "# CrossTL Runtime Host Loader Scaffolds",
        "",
        "This bundle contains metadata files for host loader or build-system tooling.",
        "",
        f"- Source loader manifest: {payload.get('sourceLoaderManifest')}",
        f"- Scaffold manifest: {payload.get('scaffoldManifest')}",
        f"- Status: {payload.get('status')}",
        f"- Load units: {summary.get('loadUnitCount', 0)}",
        f"- Ready load units: {summary.get('readyLoadUnitCount', 0)}",
        f"- Blocked load units: {summary.get('blockedLoadUnitCount', 0)}",
        "",
        "Scope",
        "",
        "The scaffold records artifact paths, source-remap handoff paths, host interface metadata, required tools, host responsibilities, loader steps, and blockers.",
        "It does not rewrite host application code, execute device code, generate runtime framework code, or install target SDKs.",
        "",
        "Targets",
    ]
    targets = payload.get("targets")
    if isinstance(targets, list) and targets:
        for target in targets:
            if not isinstance(target, Mapping):
                continue
            lines.append(
                "- "
                f"{target.get('target', 'unknown')}: {target.get('status', 'unknown')}, "
                f"{target.get('readyLoadUnitCount', 0)} ready, "
                f"{target.get('blockedLoadUnitCount', 0)} blocked"
            )
    else:
        lines.append("- <none>")

    scaffolds = payload.get("scaffolds")
    ready_scaffolds = [
        scaffold
        for scaffold in _record_sequence(scaffolds)
        if isinstance(scaffold, Mapping) and scaffold.get("status") == "ready"
    ]
    blocked_scaffolds = [
        scaffold
        for scaffold in _record_sequence(scaffolds)
        if isinstance(scaffold, Mapping) and scaffold.get("status") == "blocked"
    ]
    lines.extend(["", "Ready loader metadata"])
    if ready_scaffolds:
        for scaffold in ready_scaffolds:
            lines.append(
                "- "
                f"{scaffold.get('target', 'unknown')}: "
                f"{scaffold.get('outputPath')} loads "
                f"{scaffold.get('packagePath') or '<missing package path>'}"
            )
    else:
        lines.append("- <none>")

    lines.extend(["", "Blocked load units"])
    if blocked_scaffolds:
        for scaffold in blocked_scaffolds:
            blockers = [
                blocker
                for blocker in _record_sequence(scaffold.get("blockers"))
                if isinstance(blocker, Mapping)
            ]
            blocker_labels = [
                blocker.get("kind")
                for blocker in blockers
                if _is_non_empty_string(blocker.get("kind"))
            ]
            suffix = f": {', '.join(blocker_labels)}" if blocker_labels else ""
            lines.append(
                "- "
                f"{scaffold.get('target', 'unknown')}: "
                f"{scaffold.get('packagePath') or '<missing package path>'}"
                f"{suffix}"
            )
    else:
        lines.append("- <none>")
    lines.append("")
    return "\n".join(lines)


def build_runtime_host_loader_scaffolds(
    loader_manifest_path: str | os.PathLike[str],
    scaffold_dir: str | os.PathLike[str],
) -> dict[str, Any]:
    """Build deterministic host loader scaffold metadata from a loader manifest."""

    manifest_file = _filesystem_path_arg(
        loader_manifest_path, field_name="Runtime loader manifest path"
    )
    scaffold_root = _filesystem_path_arg(
        scaffold_dir, field_name="Runtime host loader scaffold dir"
    )
    manifest, diagnostics = _runtime_host_loader_scaffold_load_manifest(manifest_file)
    if manifest:
        diagnostics.extend(
            _runtime_host_loader_scaffold_manifest_diagnostics(manifest_file, manifest)
        )

    load_units = [
        load_unit
        for load_unit in _record_sequence(manifest.get("loadUnits"))
        if isinstance(load_unit, Mapping)
    ]
    targets = [
        target
        for target in _record_sequence(manifest.get("targets"))
        if isinstance(target, Mapping)
    ]
    target_names = [
        target.get("target")
        for target in targets
        if _is_non_empty_string(target.get("target"))
    ]
    for load_unit in load_units:
        target_name = load_unit.get("target")
        if _is_non_empty_string(target_name) and target_name not in target_names:
            targets.append({"target": target_name, "adapterKind": None})
            target_names.append(target_name)

    target_slugs: dict[Any, str] = {}
    used_target_slugs: set[str] = set()
    for target_name in target_names:
        target_slugs[target_name] = _runtime_host_loader_scaffold_unique_slug(
            target_name, "target", used_target_slugs
        )

    used_unit_slugs_by_target: dict[str, set[str]] = {}
    scaffolds: list[dict[str, Any]] = []
    generated_files: list[dict[str, Any]] = []
    if not diagnostics:
        generated_files.extend(
            [
                _runtime_host_loader_scaffold_generated_file(
                    "host-loader-scaffolds.json",
                    "host-loader-scaffold-manifest",
                    None,
                ),
                _runtime_host_loader_scaffold_generated_file(
                    "HOST_LOADERS.md",
                    "host-loader-integration-guide",
                    None,
                ),
            ]
        )
    for load_unit in load_units:
        target_name = load_unit.get("target")
        target_slug = target_slugs.get(target_name, "target")
        unit_slugs = used_unit_slugs_by_target.setdefault(target_slug, set())
        unit_slug = _runtime_host_loader_scaffold_unique_slug(
            load_unit.get("packagePath") or load_unit.get("id"),
            "load-unit",
            unit_slugs,
        )
        output_path = f"targets/{target_slug}/{unit_slug}.loader.json"
        scaffold = _runtime_host_loader_scaffold_record(load_unit, output_path)
        if scaffold["status"] == "ready" and not diagnostics:
            generated_files.append(
                _runtime_host_loader_scaffold_generated_file(
                    output_path, "host-loader-unit", scaffold.get("target")
                )
            )
        scaffolds.append(scaffold)

    ready_count = sum(1 for scaffold in scaffolds if scaffold.get("status") == "ready")
    blocked_count = sum(
        1 for scaffold in scaffolds if scaffold.get("status") == "blocked"
    )
    scaffold_count = ready_count if not diagnostics else 0
    failed = any(diagnostic.severity == "error" for diagnostic in diagnostics)
    manifest_summary = (
        manifest.get("summary") if isinstance(manifest.get("summary"), Mapping) else {}
    )
    manifest_diagnostics = (
        [dict(diagnostic) for diagnostic in manifest.get("diagnostics", [])]
        if isinstance(manifest.get("diagnostics"), list)
        else []
    )
    current_diagnostics = [diagnostic.to_json() for diagnostic in diagnostics]
    diagnostic_counts = (
        _diagnostic_counts(diagnostics)
        if diagnostics
        else (
            dict(manifest.get("diagnosticCounts"))
            if isinstance(manifest.get("diagnosticCounts"), Mapping)
            else {"note": 0, "warning": 0, "error": 0}
        )
    )
    payload = {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": RUNTIME_HOST_LOADER_SCAFFOLDS_KIND,
        "sourceLoaderManifest": str(manifest_file),
        "sourceLoaderManifestHash": _optional_source_hash(manifest_file),
        "generatedAt": int(time.time()),
        "success": not failed,
        "status": _runtime_host_loader_scaffold_status(
            ready_count, blocked_count, failed=failed
        ),
        "scope": RUNTIME_HOST_LOADER_SCAFFOLDS_SCOPE,
        "nonGoals": list(RUNTIME_HOST_LOADER_SCAFFOLDS_NON_GOALS),
        "scaffoldRoot": str(scaffold_root),
        "scaffoldManifest": "host-loader-scaffolds.json",
        "integrationGuide": "HOST_LOADERS.md",
        "project": (
            dict(manifest.get("project"))
            if isinstance(manifest.get("project"), Mapping)
            else {"targets": []}
        ),
        "summary": {
            "targetCount": len(targets),
            "loadUnitCount": len(load_units),
            "readyLoadUnitCount": ready_count,
            "blockedLoadUnitCount": blocked_count,
            "scaffoldCount": scaffold_count,
            "generatedFileCount": len(generated_files),
            "actionCount": (
                len(manifest.get("actions"))
                if isinstance(manifest.get("actions"), list)
                else 0
            ),
            "runtimeReferenceCount": manifest_summary.get("runtimeReferenceCount", 0),
        },
        "targets": [
            _runtime_host_loader_scaffold_target(target, scaffolds)
            for target in targets
        ],
        "scaffolds": scaffolds,
        "actions": (
            [dict(action) for action in manifest.get("actions", [])]
            if isinstance(manifest.get("actions"), list)
            else []
        ),
        "runtimePlan": (
            dict(manifest.get("runtimePlan"))
            if isinstance(manifest.get("runtimePlan"), Mapping)
            else {}
        ),
        "loaderManifest": {
            "kind": manifest.get("kind"),
            "success": manifest.get("success"),
            "loadUnitCount": manifest_summary.get("loadUnitCount", 0),
            "readyLoadUnitCount": manifest_summary.get("readyLoadUnitCount", 0),
            "blockedLoadUnitCount": manifest_summary.get("blockedLoadUnitCount", 0),
        },
        "generatedFiles": generated_files,
        "diagnosticCounts": diagnostic_counts,
        "diagnostics": manifest_diagnostics + current_diagnostics,
    }

    if not failed:
        scaffold_root.mkdir(parents=True, exist_ok=True)
        for scaffold in scaffolds:
            output_path = scaffold.get("outputPath")
            if scaffold.get("status") != "ready" or not _is_non_empty_string(
                output_path
            ):
                continue
            target_path = scaffold_root / Path(output_path)
            target_path.parent.mkdir(parents=True, exist_ok=True)
            target_path.write_text(
                json.dumps(
                    _runtime_host_loader_scaffold_unit_payload(scaffold),
                    indent=2,
                    sort_keys=True,
                )
                + "\n",
                encoding="utf-8",
            )
        (scaffold_root / "host-loader-scaffolds.json").write_text(
            json.dumps(payload, indent=2, sort_keys=True) + "\n",
            encoding="utf-8",
        )
        (scaffold_root / "HOST_LOADERS.md").write_text(
            _runtime_host_loader_scaffold_guide(payload),
            encoding="utf-8",
        )
    return payload


def _runtime_host_loader_scaffold_inspection_load_manifest(
    path: Path,
) -> tuple[Mapping[str, Any], list[ProjectDiagnostic]]:
    try:
        manifest = json.loads(path.read_text(encoding="utf-8"))
    except OSError as exc:
        return {}, [
            ProjectDiagnostic(
                severity="error",
                code=(
                    "project.runtime-host-loader-scaffolds-inspection."
                    "manifest-read-failed"
                ),
                message=f"Host loader scaffold manifest could not be read: {exc}",
                location=SourceLocation(file=str(path)),
                check_kind="runtime-host-loader-scaffolds-inspection",
            )
        ]
    except json.JSONDecodeError as exc:
        return {}, [
            ProjectDiagnostic(
                severity="error",
                code=(
                    "project.runtime-host-loader-scaffolds-inspection."
                    "manifest-json-invalid"
                ),
                message=f"Host loader scaffold manifest is not valid JSON: {exc}",
                location=SourceLocation(
                    file=str(path), line=exc.lineno, column=exc.colno
                ),
                check_kind="runtime-host-loader-scaffolds-inspection",
            )
        ]
    if not isinstance(manifest, Mapping):
        return {}, [
            ProjectDiagnostic(
                severity="error",
                code=(
                    "project.runtime-host-loader-scaffolds-inspection."
                    "manifest-invalid"
                ),
                message="Host loader scaffold manifest must be a JSON object.",
                location=SourceLocation(file=str(path)),
                check_kind="runtime-host-loader-scaffolds-inspection",
            )
        ]
    return manifest, []


def _runtime_host_loader_scaffold_inspection_manifest_diagnostics(
    path: Path, manifest: Mapping[str, Any]
) -> list[ProjectDiagnostic]:
    diagnostics: list[ProjectDiagnostic] = []
    if manifest.get("schemaVersion") != REPORT_SCHEMA_VERSION:
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code=(
                    "project.runtime-host-loader-scaffolds-inspection."
                    "manifest-schema-invalid"
                ),
                message=(
                    "Host loader scaffold manifest schemaVersion must be "
                    f"{REPORT_SCHEMA_VERSION}."
                ),
                location=SourceLocation(file=str(path)),
                check_kind="runtime-host-loader-scaffolds-inspection",
            )
        )
    if manifest.get("kind") != RUNTIME_HOST_LOADER_SCAFFOLDS_KIND:
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code=(
                    "project.runtime-host-loader-scaffolds-inspection."
                    "manifest-kind-invalid"
                ),
                message=(
                    "Host loader scaffold inspection input must be a "
                    f"{RUNTIME_HOST_LOADER_SCAFFOLDS_KIND} document."
                ),
                location=SourceLocation(file=str(path)),
                check_kind="runtime-host-loader-scaffolds-inspection",
            )
        )
    if manifest.get("success") is not True:
        diagnostics.append(
            ProjectDiagnostic(
                severity="error",
                code=(
                    "project.runtime-host-loader-scaffolds-inspection."
                    "manifest-failed"
                ),
                message=(
                    "Host loader scaffold manifest must be successful before "
                    "it can be inspected as runtime-ready metadata."
                ),
                location=SourceLocation(file=str(path)),
                check_kind="runtime-host-loader-scaffolds-inspection",
            )
        )
    for field_name in ("scaffolds", "generatedFiles"):
        if not isinstance(manifest.get(field_name), list):
            diagnostics.append(
                ProjectDiagnostic(
                    severity="error",
                    code=(
                        "project.runtime-host-loader-scaffolds-inspection."
                        f"{field_name}-invalid"
                    ),
                    message=(
                        "Host loader scaffold manifest " f"{field_name} must be a list."
                    ),
                    location=SourceLocation(file=str(path)),
                    check_kind="runtime-host-loader-scaffolds-inspection",
                )
            )
    return diagnostics


def _runtime_host_loader_scaffold_inspection_path_diagnostic(
    manifest_path: Path,
    code: str,
    message: str,
    *,
    target: Any = None,
) -> ProjectDiagnostic:
    return ProjectDiagnostic(
        severity="error",
        code=f"project.runtime-host-loader-scaffolds-inspection.{code}",
        message=message,
        location=SourceLocation(file=str(manifest_path)),
        target=target if _is_non_empty_string(target) else None,
        check_kind="runtime-host-loader-scaffolds-inspection",
    )


def _runtime_host_loader_scaffold_inspection_resolve_path(
    manifest_path: Path,
    root: Path,
    relative_path: Any,
    *,
    field_name: str,
    code_prefix: str,
    target: Any = None,
) -> tuple[Path | None, list[ProjectDiagnostic]]:
    if not _is_non_empty_string(relative_path):
        return None, [
            _runtime_host_loader_scaffold_inspection_path_diagnostic(
                manifest_path,
                f"{code_prefix}-path-missing",
                f"{field_name} must be a non-empty relative path.",
                target=target,
            )
        ]
    if _is_absolute_or_windows_drive_path(relative_path):
        return None, [
            _runtime_host_loader_scaffold_inspection_path_diagnostic(
                manifest_path,
                f"{code_prefix}-path-absolute",
                f"{field_name} must be relative to the scaffold manifest.",
                target=target,
            )
        ]
    candidate = root / Path(relative_path)
    if not _is_relative_to(candidate, root):
        return None, [
            _runtime_host_loader_scaffold_inspection_path_diagnostic(
                manifest_path,
                f"{code_prefix}-path-outside-root",
                f"{field_name} resolves outside the scaffold root.",
                target=target,
            )
        ]
    return candidate, []


def _runtime_host_loader_scaffold_inspection_file_diagnostics(
    manifest_path: Path,
    path: Path,
    *,
    relative_path: str,
    code_prefix: str,
    target: Any = None,
) -> list[ProjectDiagnostic]:
    if not path.exists():
        return [
            _runtime_host_loader_scaffold_inspection_path_diagnostic(
                manifest_path,
                f"{code_prefix}-missing",
                f"Host loader scaffold file is missing: {relative_path}.",
                target=target,
            )
        ]
    if not path.is_file():
        return [
            _runtime_host_loader_scaffold_inspection_path_diagnostic(
                manifest_path,
                f"{code_prefix}-not-file",
                f"Host loader scaffold path is not a file: {relative_path}.",
                target=target,
            )
        ]
    return []


def _runtime_host_loader_scaffold_inspection_load_unit(
    manifest_path: Path,
    unit_path: Path,
    *,
    relative_path: str,
    scaffold: Mapping[str, Any],
) -> tuple[Mapping[str, Any] | None, list[ProjectDiagnostic]]:
    target = scaffold.get("target")
    try:
        unit = json.loads(unit_path.read_text(encoding="utf-8"))
    except OSError as exc:
        return None, [
            _runtime_host_loader_scaffold_inspection_path_diagnostic(
                manifest_path,
                "unit-read-failed",
                f"Host loader unit could not be read: {relative_path}: {exc}",
                target=target,
            )
        ]
    except json.JSONDecodeError as exc:
        return None, [
            ProjectDiagnostic(
                severity="error",
                code=(
                    "project.runtime-host-loader-scaffolds-inspection."
                    "unit-json-invalid"
                ),
                message=(
                    "Host loader unit is not valid JSON: " f"{relative_path}: {exc}"
                ),
                location=SourceLocation(
                    file=str(unit_path), line=exc.lineno, column=exc.colno
                ),
                target=target if _is_non_empty_string(target) else None,
                check_kind="runtime-host-loader-scaffolds-inspection",
            )
        ]
    if not isinstance(unit, Mapping):
        return None, [
            _runtime_host_loader_scaffold_inspection_path_diagnostic(
                manifest_path,
                "unit-invalid",
                f"Host loader unit must be a JSON object: {relative_path}.",
                target=target,
            )
        ]

    diagnostics: list[ProjectDiagnostic] = []
    expected_fields = (
        ("schemaVersion", REPORT_SCHEMA_VERSION, "unit-schema-invalid"),
        ("kind", "crosstl-runtime-host-loader-unit", "unit-kind-invalid"),
        ("scaffold", scaffold.get("id"), "unit-scaffold-mismatch"),
        ("status", "ready", "unit-status-invalid"),
        ("target", scaffold.get("target"), "unit-target-mismatch"),
        ("adapterKind", scaffold.get("adapterKind"), "unit-adapter-kind-mismatch"),
        ("packagePath", scaffold.get("packagePath"), "unit-package-path-mismatch"),
    )
    for field_name, expected_value, code in expected_fields:
        if unit.get(field_name) != expected_value:
            diagnostics.append(
                _runtime_host_loader_scaffold_inspection_path_diagnostic(
                    manifest_path,
                    code,
                    (
                        f"Host loader unit {relative_path} has invalid "
                        f"{field_name}: expected {expected_value!r}, got "
                        f"{unit.get(field_name)!r}."
                    ),
                    target=target,
                )
            )
    return unit, diagnostics


def _runtime_host_loader_scaffold_inspection_generated_file(
    manifest_path: Path,
    root: Path,
    generated_file: Mapping[str, Any],
) -> tuple[dict[str, Any], list[ProjectDiagnostic]]:
    relative_path = generated_file.get("path")
    target = generated_file.get("target")
    diagnostics: list[ProjectDiagnostic] = []
    resolved_path, path_diagnostics = (
        _runtime_host_loader_scaffold_inspection_resolve_path(
            manifest_path,
            root,
            relative_path,
            field_name="generated file path",
            code_prefix="generated-file",
            target=target,
        )
    )
    diagnostics.extend(path_diagnostics)
    if resolved_path is not None:
        diagnostics.extend(
            _runtime_host_loader_scaffold_inspection_file_diagnostics(
                manifest_path,
                resolved_path,
                relative_path=relative_path,
                code_prefix="generated-file",
                target=target,
            )
        )
    return {
        "path": relative_path,
        "kind": generated_file.get("kind"),
        "target": target,
        "status": "ready" if not diagnostics else "failed",
        "diagnostics": [diagnostic.code for diagnostic in diagnostics],
    }, diagnostics


def _runtime_host_loader_scaffold_inspection_scaffold(
    manifest_path: Path,
    root: Path,
    scaffold: Mapping[str, Any],
) -> tuple[dict[str, Any], list[ProjectDiagnostic]]:
    manifest_status = scaffold.get("status")
    output_path = scaffold.get("outputPath")
    target = scaffold.get("target")
    blockers = [
        blocker
        for blocker in _record_sequence(scaffold.get("blockers"))
        if isinstance(blocker, Mapping)
    ]
    diagnostics: list[ProjectDiagnostic] = []
    file_status = "not-expected"
    unit_kind = None
    unit_status = None
    if manifest_status == "ready":
        resolved_path, path_diagnostics = (
            _runtime_host_loader_scaffold_inspection_resolve_path(
                manifest_path,
                root,
                output_path,
                field_name="scaffold outputPath",
                code_prefix="scaffold",
                target=target,
            )
        )
        diagnostics.extend(path_diagnostics)
        if resolved_path is not None:
            file_diagnostics = (
                _runtime_host_loader_scaffold_inspection_file_diagnostics(
                    manifest_path,
                    resolved_path,
                    relative_path=output_path,
                    code_prefix="scaffold",
                    target=target,
                )
            )
            diagnostics.extend(file_diagnostics)
            if not file_diagnostics:
                unit, unit_diagnostics = (
                    _runtime_host_loader_scaffold_inspection_load_unit(
                        manifest_path,
                        resolved_path,
                        relative_path=output_path,
                        scaffold=scaffold,
                    )
                )
                diagnostics.extend(unit_diagnostics)
                if isinstance(unit, Mapping):
                    unit_kind = unit.get("kind")
                    unit_status = unit.get("status")
        file_status = "ready" if not diagnostics else "failed"
    elif manifest_status == "blocked":
        if _is_non_empty_string(output_path):
            diagnostics.append(
                _runtime_host_loader_scaffold_inspection_path_diagnostic(
                    manifest_path,
                    "blocked-output-path-unexpected",
                    "Blocked host loader scaffold records must not declare outputPath.",
                    target=target,
                )
            )
        file_status = "blocked"
    else:
        diagnostics.append(
            _runtime_host_loader_scaffold_inspection_path_diagnostic(
                manifest_path,
                "scaffold-status-invalid",
                f"Host loader scaffold status is invalid: {manifest_status!r}.",
                target=target,
            )
        )
        file_status = "failed"

    if diagnostics:
        status = "failed"
    elif manifest_status == "blocked":
        status = "blocked"
    else:
        status = "ready"
    return {
        "id": scaffold.get("id"),
        "target": target,
        "status": status,
        "manifestStatus": manifest_status,
        "outputPath": output_path,
        "packagePath": scaffold.get("packagePath"),
        "fileStatus": file_status,
        "unitKind": unit_kind,
        "unitStatus": unit_status,
        "blockerCount": len(blockers),
        "diagnostics": [diagnostic.code for diagnostic in diagnostics],
    }, diagnostics


def _runtime_host_loader_scaffold_inspection_status(
    ready_count: int, blocked_count: int, failed_count: int
) -> str:
    if failed_count:
        return "failed"
    return _runtime_host_loader_scaffold_status(ready_count, blocked_count)


def _runtime_host_loader_scaffold_inspection_target(
    target_name: Any,
    scaffolds: Sequence[Mapping[str, Any]],
    generated_files: Sequence[Mapping[str, Any]],
) -> dict[str, Any]:
    target_scaffolds = [
        scaffold for scaffold in scaffolds if scaffold.get("target") == target_name
    ]
    target_generated_files = [
        generated_file
        for generated_file in generated_files
        if generated_file.get("target") == target_name
    ]
    ready_count = sum(
        1 for scaffold in target_scaffolds if scaffold.get("status") == "ready"
    )
    blocked_count = sum(
        1 for scaffold in target_scaffolds if scaffold.get("status") == "blocked"
    )
    failed_count = sum(
        1 for scaffold in target_scaffolds if scaffold.get("status") == "failed"
    )
    return {
        "target": target_name,
        "status": _runtime_host_loader_scaffold_inspection_status(
            ready_count, blocked_count, failed_count
        ),
        "scaffoldCount": len(target_scaffolds),
        "readyScaffoldCount": ready_count,
        "blockedScaffoldCount": blocked_count,
        "failedScaffoldCount": failed_count,
        "generatedFileCount": len(target_generated_files),
        "packagePaths": [
            scaffold.get("packagePath")
            for scaffold in target_scaffolds
            if _is_non_empty_string(scaffold.get("packagePath"))
        ],
        "scaffoldFiles": [
            scaffold.get("outputPath")
            for scaffold in target_scaffolds
            if _is_non_empty_string(scaffold.get("outputPath"))
        ],
    }


def inspect_runtime_host_loader_scaffolds(
    scaffold_manifest_path: str | os.PathLike[str],
) -> dict[str, Any]:
    """Inspect host loader scaffold files before runtime tooling consumes them."""

    manifest_path = _filesystem_path_arg(
        scaffold_manifest_path, field_name="Host loader scaffold manifest path"
    )
    scaffold_root = manifest_path.parent
    manifest, diagnostics = _runtime_host_loader_scaffold_inspection_load_manifest(
        manifest_path
    )
    if manifest:
        diagnostics.extend(
            _runtime_host_loader_scaffold_inspection_manifest_diagnostics(
                manifest_path, manifest
            )
        )

    generated_file_records: list[dict[str, Any]] = []
    generated_file_diagnostics: list[ProjectDiagnostic] = []
    scaffold_records: list[dict[str, Any]] = []
    scaffold_diagnostics: list[ProjectDiagnostic] = []
    if not any(diagnostic.severity == "error" for diagnostic in diagnostics):
        generated_file_records = []
        for generated_file in _record_sequence(manifest.get("generatedFiles")):
            if not isinstance(generated_file, Mapping):
                continue
            record, record_diagnostics = (
                _runtime_host_loader_scaffold_inspection_generated_file(
                    manifest_path, scaffold_root, generated_file
                )
            )
            generated_file_records.append(record)
            generated_file_diagnostics.extend(record_diagnostics)
        for scaffold in _record_sequence(manifest.get("scaffolds")):
            if not isinstance(scaffold, Mapping):
                continue
            record, record_diagnostics = (
                _runtime_host_loader_scaffold_inspection_scaffold(
                    manifest_path, scaffold_root, scaffold
                )
            )
            scaffold_records.append(record)
            scaffold_diagnostics.extend(record_diagnostics)
    diagnostics.extend(generated_file_diagnostics)
    diagnostics.extend(scaffold_diagnostics)

    ready_count = sum(
        1 for scaffold in scaffold_records if scaffold.get("status") == "ready"
    )
    blocked_count = sum(
        1 for scaffold in scaffold_records if scaffold.get("status") == "blocked"
    )
    failed_count = sum(
        1 for scaffold in scaffold_records if scaffold.get("status") == "failed"
    )
    verified_generated_count = sum(
        1
        for generated_file in generated_file_records
        if generated_file.get("status") == "ready"
    )
    failed_generated_count = sum(
        1
        for generated_file in generated_file_records
        if generated_file.get("status") != "ready"
    )
    target_names = sorted(
        {
            scaffold.get("target")
            for scaffold in scaffold_records
            if _is_non_empty_string(scaffold.get("target"))
        }
    )
    manifest_summary = (
        manifest.get("summary") if isinstance(manifest.get("summary"), Mapping) else {}
    )
    failed = any(diagnostic.severity == "error" for diagnostic in diagnostics)
    return {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": RUNTIME_HOST_LOADER_SCAFFOLDS_INSPECTION_KIND,
        "sourceScaffoldManifest": str(manifest_path),
        "sourceScaffoldManifestHash": _optional_source_hash(manifest_path),
        "generatedAt": int(time.time()),
        "success": not failed,
        "status": (
            _runtime_host_loader_scaffold_inspection_status(
                ready_count, blocked_count, failed_count
            )
            if not failed
            else "failed"
        ),
        "scope": RUNTIME_HOST_LOADER_SCAFFOLDS_INSPECTION_SCOPE,
        "nonGoals": list(RUNTIME_HOST_LOADER_SCAFFOLDS_INSPECTION_NON_GOALS),
        "scaffoldRoot": str(scaffold_root),
        "project": (
            dict(manifest.get("project"))
            if isinstance(manifest.get("project"), Mapping)
            else {"targets": []}
        ),
        "summary": {
            "targetCount": len(target_names),
            "scaffoldCount": len(scaffold_records),
            "readyScaffoldCount": ready_count,
            "blockedScaffoldCount": blocked_count,
            "failedScaffoldCount": failed_count,
            "generatedFileCount": len(generated_file_records),
            "verifiedGeneratedFileCount": verified_generated_count,
            "failedGeneratedFileCount": failed_generated_count,
            "blockerCount": sum(
                scaffold.get("blockerCount", 0) for scaffold in scaffold_records
            ),
            "actionCount": (
                len(manifest.get("actions"))
                if isinstance(manifest.get("actions"), list)
                else 0
            ),
            "runtimeReferenceCount": manifest_summary.get("runtimeReferenceCount", 0),
        },
        "targets": [
            _runtime_host_loader_scaffold_inspection_target(
                target_name, scaffold_records, generated_file_records
            )
            for target_name in target_names
        ],
        "scaffolds": scaffold_records,
        "generatedFiles": generated_file_records,
        "loaderManifest": {
            "kind": manifest.get("kind"),
            "success": manifest.get("success"),
            "status": manifest.get("status"),
            "scaffoldCount": manifest_summary.get("scaffoldCount", 0),
            "generatedFileCount": manifest_summary.get("generatedFileCount", 0),
        },
        "diagnosticCounts": _diagnostic_counts(diagnostics),
        "diagnostics": [diagnostic.to_json() for diagnostic in diagnostics],
    }


def _runtime_host_loader_consumption_diagnostic(
    path: Path,
    code: str,
    message: str,
    *,
    severity: str = "error",
    target: Any = None,
) -> ProjectDiagnostic:
    return ProjectDiagnostic(
        severity=severity,
        code=f"project.runtime-host-loader-consumption-plan.{code}",
        message=message,
        location=SourceLocation(file=str(path)),
        target=target if _is_non_empty_string(target) else None,
        check_kind="runtime-host-loader-consumption-plan",
    )


def _runtime_host_loader_consumption_resolve_path(
    inspection_path: Path,
    root: Path,
    relative_path: Any,
    *,
    field_name: str,
    code_prefix: str,
    target: Any = None,
) -> tuple[Path | None, list[ProjectDiagnostic]]:
    if not _is_non_empty_string(relative_path):
        return None, [
            _runtime_host_loader_consumption_diagnostic(
                inspection_path,
                f"{code_prefix}-path-missing",
                f"{field_name} must be a non-empty relative path.",
                target=target,
            )
        ]
    if _is_absolute_or_windows_drive_path(relative_path):
        return None, [
            _runtime_host_loader_consumption_diagnostic(
                inspection_path,
                f"{code_prefix}-path-absolute",
                f"{field_name} must be relative to the scaffold root.",
                target=target,
            )
        ]
    candidate = root / Path(relative_path)
    if not _is_relative_to(candidate, root):
        return None, [
            _runtime_host_loader_consumption_diagnostic(
                inspection_path,
                f"{code_prefix}-path-outside-root",
                f"{field_name} resolves outside the scaffold root.",
                target=target,
            )
        ]
    return candidate, []


def _runtime_host_loader_consumption_load_unit(
    inspection_path: Path,
    unit_path: Path,
    scaffold: Mapping[str, Any],
) -> tuple[dict[str, Any], list[ProjectDiagnostic]]:
    target = scaffold.get("target")
    try:
        unit = json.loads(unit_path.read_text(encoding="utf-8"))
    except OSError as exc:
        return {}, [
            _runtime_host_loader_consumption_diagnostic(
                inspection_path,
                "unit-read-failed",
                f"Host loader unit could not be read: {exc}",
                target=target,
            )
        ]
    except json.JSONDecodeError as exc:
        return {}, [
            _runtime_host_loader_consumption_diagnostic(
                inspection_path,
                "unit-json-invalid",
                f"Host loader unit is not valid JSON: {exc}",
                target=target,
            )
        ]
    if not isinstance(unit, dict):
        return {}, [
            _runtime_host_loader_consumption_diagnostic(
                inspection_path,
                "unit-invalid",
                "Host loader unit must be a JSON object.",
                target=target,
            )
        ]

    diagnostics: list[ProjectDiagnostic] = []
    if unit.get("schemaVersion") != REPORT_SCHEMA_VERSION:
        diagnostics.append(
            _runtime_host_loader_consumption_diagnostic(
                inspection_path,
                "unit-schema-invalid",
                f"Host loader unit schemaVersion must be {REPORT_SCHEMA_VERSION}.",
                target=target,
            )
        )
    if unit.get("kind") != "crosstl-runtime-host-loader-unit":
        diagnostics.append(
            _runtime_host_loader_consumption_diagnostic(
                inspection_path,
                "unit-kind-invalid",
                "Host loader unit kind must be crosstl-runtime-host-loader-unit.",
                target=target,
            )
        )
    expected_pairs = (
        ("scaffold", scaffold.get("id"), "unit-scaffold-mismatch"),
        ("target", scaffold.get("target"), "unit-target-mismatch"),
        ("packagePath", scaffold.get("packagePath"), "unit-package-path-mismatch"),
    )
    for field_name, expected_value, code in expected_pairs:
        if unit.get(field_name) != expected_value:
            diagnostics.append(
                _runtime_host_loader_consumption_diagnostic(
                    inspection_path,
                    code,
                    f"Host loader unit {field_name} does not match inspection record.",
                    target=target,
                )
            )
    return unit, diagnostics


def _runtime_host_loader_consumption_blockers(
    scaffold: Mapping[str, Any],
) -> list[dict[str, Any]]:
    diagnostics = [
        diagnostic
        for diagnostic in _record_sequence(scaffold.get("diagnostics"))
        if _is_non_empty_string(diagnostic)
    ]
    blockers: list[dict[str, Any]] = []
    if scaffold.get("status") == "blocked":
        blocker_count = scaffold.get("blockerCount")
        message = (
            "Resolve loader scaffold blockers recorded during scaffold generation "
            f"for {scaffold.get('packagePath') or '<missing package path>'}."
        )
        if _is_non_negative_int(blocker_count) and blocker_count:
            message += f" Blocker count: {blocker_count}."
        blockers.append(
            {
                "kind": "resolve-loader-scaffold-blockers",
                "severity": "warning",
                "message": message,
            }
        )
    for diagnostic in diagnostics:
        blockers.append(
            {
                "kind": "resolve-loader-scaffold-diagnostic",
                "severity": "warning",
                "message": f"Resolve host loader scaffold diagnostic: {diagnostic}.",
            }
        )
    return blockers


def _runtime_host_loader_consumption_unit(
    inspection_path: Path,
    scaffold_root: Path,
    scaffold: Mapping[str, Any],
) -> tuple[dict[str, Any], list[ProjectDiagnostic]]:
    target = scaffold.get("target")
    diagnostics: list[ProjectDiagnostic] = []
    output_path = scaffold.get("outputPath")
    blockers = _runtime_host_loader_consumption_blockers(scaffold)
    if scaffold.get("status") != "ready":
        status = (
            scaffold.get("status")
            if _is_non_empty_string(scaffold.get("status"))
            else "blocked"
        )
        return (
            {
                "id": scaffold.get("id"),
                "target": target,
                "status": status,
                "scaffold": scaffold.get("id"),
                "outputPath": output_path,
                "packagePath": scaffold.get("packagePath"),
                "adapterKind": None,
                "artifactFormat": None,
                "requiredTools": [],
                "hostResponsibilities": [],
                "loadSteps": [],
                "hostInterface": None,
                "blockers": blockers,
                "diagnostics": [
                    diagnostic
                    for diagnostic in _record_sequence(scaffold.get("diagnostics"))
                    if _is_non_empty_string(diagnostic)
                ],
            },
            diagnostics,
        )

    unit_path, path_diagnostics = _runtime_host_loader_consumption_resolve_path(
        inspection_path,
        scaffold_root,
        output_path,
        field_name="host loader unit outputPath",
        code_prefix="unit",
        target=target,
    )
    diagnostics.extend(path_diagnostics)
    unit: dict[str, Any] = {}
    if unit_path is not None and not path_diagnostics:
        if not unit_path.is_file():
            diagnostics.append(
                _runtime_host_loader_consumption_diagnostic(
                    inspection_path,
                    "unit-missing",
                    f"Host loader unit is missing: {output_path}.",
                    target=target,
                )
            )
        else:
            unit, unit_diagnostics = _runtime_host_loader_consumption_load_unit(
                inspection_path, unit_path, scaffold
            )
            diagnostics.extend(unit_diagnostics)

    failed = any(diagnostic.severity == "error" for diagnostic in diagnostics)
    required_tools = [
        tool
        for tool in _record_sequence(unit.get("requiredTools"))
        if _is_non_empty_string(tool)
    ]
    host_responsibilities = [
        responsibility
        for responsibility in _record_sequence(unit.get("hostResponsibilities"))
        if _is_non_empty_string(responsibility)
    ]
    load_steps = [
        dict(step)
        for step in _record_sequence(unit.get("loadSteps"))
        if isinstance(step, Mapping)
    ]
    return (
        {
            "id": scaffold.get("id"),
            "target": target,
            "status": "failed" if failed else "ready",
            "scaffold": unit.get("scaffold", scaffold.get("id")),
            "outputPath": output_path,
            "packagePath": unit.get("packagePath", scaffold.get("packagePath")),
            "adapterKind": unit.get("adapterKind"),
            "artifactFormat": unit.get("artifactFormat"),
            "requiredTools": required_tools,
            "hostResponsibilities": host_responsibilities,
            "loadSteps": load_steps,
            "hostInterface": (
                dict(unit.get("hostInterface"))
                if isinstance(unit.get("hostInterface"), Mapping)
                else None
            ),
            "blockers": blockers,
            "diagnostics": [diagnostic.code for diagnostic in diagnostics],
        },
        diagnostics,
    )


def _runtime_host_loader_consumption_actions(
    unit: Mapping[str, Any],
) -> list[dict[str, Any]]:
    target = unit.get("target")
    unit_id = unit.get("id")
    output_path = unit.get("outputPath")
    package_path = unit.get("packagePath")
    actions: list[dict[str, Any]] = []
    if unit.get("status") == "ready":
        actions.append(
            {
                "kind": "consume-host-loader-unit",
                "severity": "note",
                "message": (
                    f"Consume host loader scaffold {output_path} into the host build "
                    f"or runtime bootstrap for target {target}."
                ),
                "target": target,
                "loaderUnit": unit_id,
                "scaffold": unit.get("scaffold"),
                "packagePath": package_path,
                "outputPath": output_path,
                "tools": [],
            }
        )
        for step in _record_sequence(unit.get("loadSteps")):
            if not isinstance(step, Mapping):
                continue
            tools = [
                tool
                for tool in _record_sequence(step.get("tools"))
                if _is_non_empty_string(tool)
            ]
            actions.append(
                {
                    "kind": step.get("kind") or "run-loader-step",
                    "severity": "note",
                    "message": step.get("message") or "Run host loader step.",
                    "target": target,
                    "loaderUnit": unit_id,
                    "scaffold": unit.get("scaffold"),
                    "packagePath": step.get("packagePath") or package_path,
                    "outputPath": output_path,
                    "tools": tools,
                }
            )
        for responsibility in _record_sequence(unit.get("hostResponsibilities")):
            if not _is_non_empty_string(responsibility):
                continue
            actions.append(
                {
                    "kind": "satisfy-host-responsibility",
                    "severity": "note",
                    "message": (
                        f"Account for host responsibility before enabling {target}: "
                        f"{responsibility}."
                    ),
                    "target": target,
                    "loaderUnit": unit_id,
                    "scaffold": unit.get("scaffold"),
                    "packagePath": package_path,
                    "outputPath": output_path,
                    "tools": [],
                }
            )
        return actions

    blockers = [
        blocker
        for blocker in _record_sequence(unit.get("blockers"))
        if isinstance(blocker, Mapping)
    ]
    if not blockers:
        fallback_kind = (
            "repair-host-loader-scaffold"
            if unit.get("status") == "failed"
            else "resolve-host-loader-unit"
        )
        blockers = [
            {
                "kind": fallback_kind,
                "severity": "warning",
                "message": (
                    f"Resolve host loader unit readiness for target {target} "
                    f"before consuming {package_path or '<missing package path>'}."
                ),
            }
        ]
    for blocker in blockers:
        actions.append(
            {
                "kind": blocker.get("kind") or "resolve-host-loader-unit",
                "severity": blocker.get("severity") or "warning",
                "message": blocker.get("message") or "Resolve host loader unit.",
                "target": target,
                "loaderUnit": unit_id,
                "scaffold": unit.get("scaffold"),
                "packagePath": package_path,
                "outputPath": output_path,
                "tools": [],
            }
        )
    return actions


def _runtime_host_loader_consumption_target(
    target_name: str,
    units: Sequence[Mapping[str, Any]],
    actions: Sequence[Mapping[str, Any]],
) -> dict[str, Any]:
    target_units = [unit for unit in units if unit.get("target") == target_name]
    ready_units = [unit for unit in target_units if unit.get("status") == "ready"]
    blocked_units = [unit for unit in target_units if unit.get("status") == "blocked"]
    failed_units = [unit for unit in target_units if unit.get("status") == "failed"]
    target_actions = [
        action for action in actions if action.get("target") == target_name
    ]
    required_tools = sorted(
        {
            tool
            for unit in target_units
            for tool in _record_sequence(unit.get("requiredTools"))
            if _is_non_empty_string(tool)
        }
    )
    host_responsibilities = sorted(
        {
            responsibility
            for unit in target_units
            for responsibility in _record_sequence(unit.get("hostResponsibilities"))
            if _is_non_empty_string(responsibility)
        }
    )
    return {
        "target": target_name,
        "status": _runtime_host_loader_scaffold_status(
            len(ready_units),
            len(blocked_units),
            failed=bool(failed_units),
        ),
        "loaderUnitCount": len(target_units),
        "readyLoaderUnitCount": len(ready_units),
        "blockedLoaderUnitCount": len(blocked_units),
        "failedLoaderUnitCount": len(failed_units),
        "actionCount": len(target_actions),
        "requiredTools": required_tools,
        "hostResponsibilities": host_responsibilities,
        "packagePaths": [
            unit.get("packagePath")
            for unit in target_units
            if _is_non_empty_string(unit.get("packagePath"))
        ],
        "scaffoldFiles": [
            unit.get("outputPath")
            for unit in target_units
            if _is_non_empty_string(unit.get("outputPath"))
        ],
    }


def plan_runtime_host_loader_consumption(
    scaffold_manifest_path: str | os.PathLike[str],
) -> dict[str, Any]:
    """Build a read-only host loader consumption plan from scaffold inspection."""

    manifest_path = _filesystem_path_arg(
        scaffold_manifest_path,
        field_name="Host loader scaffold manifest path",
    )
    inspection = inspect_runtime_host_loader_scaffolds(manifest_path)
    diagnostics_payload = [
        dict(diagnostic)
        for diagnostic in _record_sequence(inspection.get("diagnostics"))
        if isinstance(diagnostic, Mapping)
    ]
    scaffold_root_value = inspection.get("scaffoldRoot")
    scaffold_root = (
        Path(scaffold_root_value)
        if _is_non_empty_string(scaffold_root_value)
        else manifest_path.parent
    )
    units: list[dict[str, Any]] = []
    unit_diagnostics: list[ProjectDiagnostic] = []
    if inspection.get("success") is True:
        for scaffold in _record_sequence(inspection.get("scaffolds")):
            if not isinstance(scaffold, Mapping):
                continue
            unit, current_diagnostics = _runtime_host_loader_consumption_unit(
                manifest_path, scaffold_root, scaffold
            )
            units.append(unit)
            unit_diagnostics.extend(current_diagnostics)
    diagnostics_payload.extend(diagnostic.to_json() for diagnostic in unit_diagnostics)

    actions: list[dict[str, Any]] = []
    for unit in units:
        actions.extend(_runtime_host_loader_consumption_actions(unit))

    ready_count = sum(1 for unit in units if unit.get("status") == "ready")
    blocked_count = sum(1 for unit in units if unit.get("status") == "blocked")
    failed_count = sum(1 for unit in units if unit.get("status") == "failed")
    target_names = sorted(
        {
            unit.get("target")
            for unit in units
            if _is_non_empty_string(unit.get("target"))
        }
    )
    failed = any(
        diagnostic.get("severity") == "error" for diagnostic in diagnostics_payload
    )
    required_tools = sorted(
        {
            tool
            for unit in units
            for tool in _record_sequence(unit.get("requiredTools"))
            if _is_non_empty_string(tool)
        }
    )
    host_responsibilities = sorted(
        {
            responsibility
            for unit in units
            for responsibility in _record_sequence(unit.get("hostResponsibilities"))
            if _is_non_empty_string(responsibility)
        }
    )
    load_step_count = sum(
        len(_record_sequence(unit.get("loadSteps"))) for unit in units
    )
    summary = {
        "targetCount": len(target_names),
        "loaderUnitCount": len(units),
        "readyLoaderUnitCount": ready_count,
        "blockedLoaderUnitCount": blocked_count,
        "failedLoaderUnitCount": failed_count,
        "actionCount": len(actions),
        "requiredToolCount": len(required_tools),
        "hostResponsibilityCount": len(host_responsibilities),
        "loadStepCount": load_step_count,
    }
    return {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": RUNTIME_HOST_LOADER_CONSUMPTION_PLAN_KIND,
        "sourceScaffoldManifest": str(manifest_path),
        "sourceScaffoldManifestHash": _optional_source_hash(manifest_path),
        "generatedAt": int(time.time()),
        "success": not failed,
        "status": (
            _runtime_host_loader_scaffold_status(
                ready_count,
                blocked_count,
                failed=bool(failed_count),
            )
            if not failed
            else "failed"
        ),
        "scope": RUNTIME_HOST_LOADER_CONSUMPTION_PLAN_SCOPE,
        "nonGoals": list(RUNTIME_HOST_LOADER_CONSUMPTION_PLAN_NON_GOALS),
        "scaffoldRoot": str(scaffold_root),
        "project": (
            dict(inspection.get("project"))
            if isinstance(inspection.get("project"), Mapping)
            else {"targets": []}
        ),
        "summary": summary,
        "targets": [
            _runtime_host_loader_consumption_target(target_name, units, actions)
            for target_name in target_names
        ],
        "loaderUnits": units,
        "actions": actions,
        "scaffoldInspection": {
            "kind": inspection.get("kind"),
            "success": inspection.get("success"),
            "status": inspection.get("status"),
            "readyScaffoldCount": (
                inspection.get("summary", {}).get("readyScaffoldCount", 0)
                if isinstance(inspection.get("summary"), Mapping)
                else 0
            ),
            "blockedScaffoldCount": (
                inspection.get("summary", {}).get("blockedScaffoldCount", 0)
                if isinstance(inspection.get("summary"), Mapping)
                else 0
            ),
            "failedScaffoldCount": (
                inspection.get("summary", {}).get("failedScaffoldCount", 0)
                if isinstance(inspection.get("summary"), Mapping)
                else 0
            ),
        },
        "diagnosticCounts": _diagnostic_payload_counts(diagnostics_payload),
        "diagnostics": diagnostics_payload,
    }


def _runtime_host_integration_handoff_diagnostic(
    path: Path,
    code: str,
    message: str,
    *,
    severity: str = "error",
    target: Any = None,
) -> ProjectDiagnostic:
    return ProjectDiagnostic(
        severity=severity,
        code=f"project.runtime-host-integration-handoff.{code}",
        message=message,
        location=SourceLocation(file=str(path)),
        target=target if _is_non_empty_string(target) else None,
        check_kind="runtime-host-integration-handoff",
    )


def _runtime_host_integration_handoff_load_plan(
    path: Path,
) -> tuple[dict[str, Any], list[ProjectDiagnostic]]:
    try:
        plan = json.loads(path.read_text(encoding="utf-8"))
    except OSError as exc:
        return {}, [
            _runtime_host_integration_handoff_diagnostic(
                path,
                "plan-read-failed",
                f"Host loader consumption plan could not be read: {exc}",
            )
        ]
    except json.JSONDecodeError as exc:
        return {}, [
            _runtime_host_integration_handoff_diagnostic(
                path,
                "plan-json-invalid",
                f"Host loader consumption plan is not valid JSON: {exc}",
            )
        ]
    if not isinstance(plan, dict):
        return {}, [
            _runtime_host_integration_handoff_diagnostic(
                path,
                "plan-invalid",
                "Host integration handoff input must be a JSON object.",
            )
        ]
    return plan, []


def _runtime_host_integration_handoff_plan_diagnostics(
    path: Path, plan: Mapping[str, Any]
) -> list[ProjectDiagnostic]:
    diagnostics: list[ProjectDiagnostic] = []
    if plan.get("schemaVersion") != REPORT_SCHEMA_VERSION:
        diagnostics.append(
            _runtime_host_integration_handoff_diagnostic(
                path,
                "plan-schema-invalid",
                f"Host loader consumption plan schemaVersion must be {REPORT_SCHEMA_VERSION}.",
            )
        )
    if plan.get("kind") != RUNTIME_HOST_LOADER_CONSUMPTION_PLAN_KIND:
        diagnostics.append(
            _runtime_host_integration_handoff_diagnostic(
                path,
                "plan-kind-invalid",
                "Host integration handoff input must be a "
                f"{RUNTIME_HOST_LOADER_CONSUMPTION_PLAN_KIND} document.",
            )
        )
    if plan.get("success") is not True:
        diagnostics.append(
            _runtime_host_integration_handoff_diagnostic(
                path,
                "plan-failed",
                "Host loader consumption plan must be successful before "
                "host integration handoff files can be written.",
            )
        )
    if not isinstance(plan.get("loaderUnits"), list):
        diagnostics.append(
            _runtime_host_integration_handoff_diagnostic(
                path,
                "plan-loader-units-invalid",
                "Host loader consumption plan loaderUnits must be a list.",
            )
        )
    if not isinstance(plan.get("actions"), list):
        diagnostics.append(
            _runtime_host_integration_handoff_diagnostic(
                path,
                "plan-actions-invalid",
                "Host loader consumption plan actions must be a list.",
            )
        )
    return diagnostics


def _runtime_host_integration_handoff_generated_file(
    path: str, kind: str, target: str | None = None
) -> dict[str, Any]:
    return {"path": path, "kind": kind, "target": target}


def _runtime_host_integration_handoff_unit(unit: Mapping[str, Any]) -> dict[str, Any]:
    return {
        "id": unit.get("id"),
        "target": unit.get("target"),
        "status": unit.get("status"),
        "scaffold": unit.get("scaffold"),
        "outputPath": unit.get("outputPath"),
        "packagePath": unit.get("packagePath"),
        "adapterKind": unit.get("adapterKind"),
        "artifactFormat": unit.get("artifactFormat"),
        "requiredTools": [
            tool
            for tool in _record_sequence(unit.get("requiredTools"))
            if _is_non_empty_string(tool)
        ],
        "hostResponsibilities": [
            responsibility
            for responsibility in _record_sequence(unit.get("hostResponsibilities"))
            if _is_non_empty_string(responsibility)
        ],
        "loadSteps": [
            dict(step)
            for step in _record_sequence(unit.get("loadSteps"))
            if isinstance(step, Mapping)
        ],
        "blockers": [
            dict(blocker)
            for blocker in _record_sequence(unit.get("blockers"))
            if isinstance(blocker, Mapping)
        ],
    }


def _runtime_host_integration_handoff_action(
    action: Mapping[str, Any],
) -> dict[str, Any]:
    return {
        "kind": action.get("kind"),
        "severity": action.get("severity"),
        "message": action.get("message"),
        "target": action.get("target"),
        "loaderUnit": action.get("loaderUnit"),
        "scaffold": action.get("scaffold"),
        "packagePath": action.get("packagePath"),
        "outputPath": action.get("outputPath"),
        "tools": [
            tool
            for tool in _record_sequence(action.get("tools"))
            if _is_non_empty_string(tool)
        ],
    }


def _runtime_host_integration_handoff_target_status(
    units: Sequence[Mapping[str, Any]],
) -> str:
    ready_count = sum(1 for unit in units if unit.get("status") == "ready")
    blocked_count = sum(1 for unit in units if unit.get("status") == "blocked")
    failed_count = sum(1 for unit in units if unit.get("status") == "failed")
    return _runtime_host_loader_scaffold_status(
        ready_count,
        blocked_count,
        failed=bool(failed_count),
    )


def _runtime_host_integration_handoff_target_record(
    target_name: str,
    units: Sequence[Mapping[str, Any]],
    actions: Sequence[Mapping[str, Any]],
    handoff_file: str,
) -> dict[str, Any]:
    target_units = [unit for unit in units if unit.get("target") == target_name]
    target_actions = [
        action for action in actions if action.get("target") == target_name
    ]
    required_tools = sorted(
        {
            tool
            for unit in target_units
            for tool in _record_sequence(unit.get("requiredTools"))
            if _is_non_empty_string(tool)
        }
    )
    host_responsibilities = sorted(
        {
            responsibility
            for unit in target_units
            for responsibility in _record_sequence(unit.get("hostResponsibilities"))
            if _is_non_empty_string(responsibility)
        }
    )
    return {
        "target": target_name,
        "status": _runtime_host_integration_handoff_target_status(target_units),
        "loaderUnitCount": len(target_units),
        "readyLoaderUnitCount": sum(
            1 for unit in target_units if unit.get("status") == "ready"
        ),
        "blockedLoaderUnitCount": sum(
            1 for unit in target_units if unit.get("status") == "blocked"
        ),
        "failedLoaderUnitCount": sum(
            1 for unit in target_units if unit.get("status") == "failed"
        ),
        "actionCount": len(target_actions),
        "requiredTools": required_tools,
        "hostResponsibilities": host_responsibilities,
        "packagePaths": [
            unit.get("packagePath")
            for unit in target_units
            if _is_non_empty_string(unit.get("packagePath"))
        ],
        "scaffoldFiles": [
            unit.get("outputPath")
            for unit in target_units
            if _is_non_empty_string(unit.get("outputPath"))
        ],
        "handoffFile": handoff_file,
    }


def _runtime_host_integration_handoff_target_payload(
    target: Mapping[str, Any],
    units: Sequence[Mapping[str, Any]],
    actions: Sequence[Mapping[str, Any]],
) -> dict[str, Any]:
    target_name = target.get("target")
    target_units = [unit for unit in units if unit.get("target") == target_name]
    target_actions = [
        action for action in actions if action.get("target") == target_name
    ]
    return {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": "crosstl-runtime-host-integration-target",
        "target": target_name,
        "status": target.get("status"),
        "nonGoals": list(RUNTIME_HOST_INTEGRATION_HANDOFF_NON_GOALS),
        "loaderUnits": [dict(unit) for unit in target_units],
        "actions": [dict(action) for action in target_actions],
        "requiredTools": list(target.get("requiredTools", [])),
        "hostResponsibilities": list(target.get("hostResponsibilities", [])),
        "packagePaths": list(target.get("packagePaths", [])),
        "scaffoldFiles": list(target.get("scaffoldFiles", [])),
    }


def _runtime_host_integration_handoff_guide(payload: Mapping[str, Any]) -> str:
    lines = [
        "# CrossTL Host Integration Handoff",
        "",
        f"- Source consumption plan: {payload.get('sourceConsumptionPlan')}",
        f"- Handoff manifest: {payload.get('handoffManifest')}",
        f"- Status: {payload.get('status')}",
        "",
        "This bundle is metadata for host build and runtime integration tooling. "
        "It does not rewrite host application code, execute device code, generate "
        "runtime framework code, or install target SDKs.",
        "",
    ]
    summary = payload.get("summary")
    if isinstance(summary, Mapping):
        lines.extend(
            [
                "## Summary",
                "",
                f"- Targets: {summary.get('targetCount', 0)}",
                f"- Loader units: {summary.get('loaderUnitCount', 0)}",
                f"- Ready loader units: {summary.get('readyLoaderUnitCount', 0)}",
                f"- Blocked loader units: {summary.get('blockedLoaderUnitCount', 0)}",
                f"- Actions: {summary.get('actionCount', 0)}",
                "",
            ]
        )
    targets = payload.get("targets")
    if isinstance(targets, list) and targets:
        lines.extend(["## Targets", ""])
        for target in targets:
            if not isinstance(target, Mapping):
                continue
            lines.append(
                "- "
                f"{target.get('target', 'unknown')}: {target.get('status', 'unknown')} "
                f"({target.get('loaderUnitCount', 0)} units, "
                f"{target.get('actionCount', 0)} actions) -> "
                f"{target.get('handoffFile')}"
            )
        lines.append("")
    actions = payload.get("actions")
    if isinstance(actions, list) and actions:
        lines.extend(["## Actions", ""])
        for action in actions:
            if not isinstance(action, Mapping):
                continue
            lines.append(
                "- "
                f"{action.get('target', 'unknown')}: "
                f"{action.get('kind', 'unknown')} - "
                f"{action.get('message', '')}"
            )
        lines.append("")
    return "\n".join(lines)


def build_runtime_host_integration_handoff(
    consumption_plan_path: str | os.PathLike[str],
    handoff_dir: str | os.PathLike[str],
) -> dict[str, Any]:
    """Build a deterministic host integration handoff bundle."""

    plan_path = _filesystem_path_arg(
        consumption_plan_path, field_name="Host loader consumption plan path"
    )
    handoff_root = _filesystem_path_arg(
        handoff_dir, field_name="Host integration handoff dir"
    )
    plan, diagnostics = _runtime_host_integration_handoff_load_plan(plan_path)
    if plan:
        diagnostics.extend(
            _runtime_host_integration_handoff_plan_diagnostics(plan_path, plan)
        )

    units: list[dict[str, Any]] = []
    actions: list[dict[str, Any]] = []
    targets: list[dict[str, Any]] = []
    generated_files: list[dict[str, Any]] = []
    if not any(diagnostic.severity == "error" for diagnostic in diagnostics):
        units = [
            _runtime_host_integration_handoff_unit(unit)
            for unit in _record_sequence(plan.get("loaderUnits"))
            if isinstance(unit, Mapping)
        ]
        actions = [
            _runtime_host_integration_handoff_action(action)
            for action in _record_sequence(plan.get("actions"))
            if isinstance(action, Mapping)
        ]
        target_names = sorted(
            {
                unit.get("target")
                for unit in units
                if _is_non_empty_string(unit.get("target"))
            }
        )
        used_slugs: set[str] = set()
        for target_name in target_names:
            target_slug = _runtime_host_loader_scaffold_unique_slug(
                target_name, "target", used_slugs
            )
            handoff_file = f"targets/{target_slug}.integration.json"
            targets.append(
                _runtime_host_integration_handoff_target_record(
                    target_name, units, actions, handoff_file
                )
            )
            generated_files.append(
                _runtime_host_integration_handoff_generated_file(
                    handoff_file, "host-integration-target", target_name
                )
            )
        generated_files.insert(
            0,
            _runtime_host_integration_handoff_generated_file(
                "host-integration.json", "host-integration-manifest"
            ),
        )
        generated_files.insert(
            1,
            _runtime_host_integration_handoff_generated_file(
                "HOST_INTEGRATION.md", "host-integration-guide"
            ),
        )

    ready_count = sum(1 for unit in units if unit.get("status") == "ready")
    blocked_count = sum(1 for unit in units if unit.get("status") == "blocked")
    failed_count = sum(1 for unit in units if unit.get("status") == "failed")
    required_tools = sorted(
        {
            tool
            for unit in units
            for tool in _record_sequence(unit.get("requiredTools"))
            if _is_non_empty_string(tool)
        }
    )
    host_responsibilities = sorted(
        {
            responsibility
            for unit in units
            for responsibility in _record_sequence(unit.get("hostResponsibilities"))
            if _is_non_empty_string(responsibility)
        }
    )
    failed = any(diagnostic.severity == "error" for diagnostic in diagnostics)
    payload = {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": RUNTIME_HOST_INTEGRATION_HANDOFF_KIND,
        "sourceConsumptionPlan": str(plan_path),
        "sourceConsumptionPlanHash": _optional_source_hash(plan_path),
        "generatedAt": int(time.time()),
        "success": not failed,
        "status": (
            _runtime_host_loader_scaffold_status(
                ready_count,
                blocked_count,
                failed=bool(failed_count),
            )
            if not failed
            else "failed"
        ),
        "scope": RUNTIME_HOST_INTEGRATION_HANDOFF_SCOPE,
        "nonGoals": list(RUNTIME_HOST_INTEGRATION_HANDOFF_NON_GOALS),
        "handoffRoot": str(handoff_root),
        "handoffManifest": "host-integration.json",
        "integrationGuide": "HOST_INTEGRATION.md",
        "project": (
            dict(plan.get("project"))
            if isinstance(plan.get("project"), Mapping)
            else {"targets": []}
        ),
        "summary": {
            "targetCount": len(targets),
            "loaderUnitCount": len(units),
            "readyLoaderUnitCount": ready_count,
            "blockedLoaderUnitCount": blocked_count,
            "failedLoaderUnitCount": failed_count,
            "actionCount": len(actions),
            "requiredToolCount": len(required_tools),
            "hostResponsibilityCount": len(host_responsibilities),
            "generatedFileCount": len(generated_files),
        },
        "targets": targets,
        "loaderUnits": units,
        "actions": actions,
        "consumptionPlan": {
            "kind": plan.get("kind"),
            "success": plan.get("success"),
            "status": plan.get("status"),
            "loaderUnitCount": (
                plan.get("summary", {}).get("loaderUnitCount", 0)
                if isinstance(plan.get("summary"), Mapping)
                else 0
            ),
            "actionCount": (
                plan.get("summary", {}).get("actionCount", 0)
                if isinstance(plan.get("summary"), Mapping)
                else 0
            ),
        },
        "generatedFiles": generated_files,
        "diagnosticCounts": _diagnostic_counts(diagnostics),
        "diagnostics": [diagnostic.to_json() for diagnostic in diagnostics],
    }

    if payload["success"]:
        handoff_root.mkdir(parents=True, exist_ok=True)
        (handoff_root / "targets").mkdir(parents=True, exist_ok=True)
        for target in targets:
            handoff_file = target.get("handoffFile")
            if not _is_non_empty_string(handoff_file):
                continue
            target_path = handoff_root / Path(handoff_file)
            target_path.write_text(
                json.dumps(
                    _runtime_host_integration_handoff_target_payload(
                        target, units, actions
                    ),
                    indent=2,
                    sort_keys=True,
                )
                + "\n",
                encoding="utf-8",
            )
        (handoff_root / "host-integration.json").write_text(
            json.dumps(payload, indent=2, sort_keys=True) + "\n",
            encoding="utf-8",
        )
        (handoff_root / "HOST_INTEGRATION.md").write_text(
            _runtime_host_integration_handoff_guide(payload),
            encoding="utf-8",
        )
    return payload


def _runtime_host_integration_handoff_inspection_diagnostic(
    path: Path,
    code: str,
    message: str,
    *,
    target: Any = None,
) -> ProjectDiagnostic:
    return ProjectDiagnostic(
        severity="error",
        code=f"project.runtime-host-integration-handoff-inspection.{code}",
        message=message,
        location=SourceLocation(file=str(path)),
        target=target if _is_non_empty_string(target) else None,
        check_kind="runtime-host-integration-handoff-inspection",
    )


def _runtime_host_integration_handoff_inspection_load_manifest(
    path: Path,
) -> tuple[dict[str, Any], list[ProjectDiagnostic]]:
    try:
        manifest = json.loads(path.read_text(encoding="utf-8"))
    except OSError as exc:
        return {}, [
            _runtime_host_integration_handoff_inspection_diagnostic(
                path,
                "manifest-read-failed",
                f"Host integration handoff manifest could not be read: {exc}",
            )
        ]
    except json.JSONDecodeError as exc:
        return {}, [
            _runtime_host_integration_handoff_inspection_diagnostic(
                path,
                "manifest-json-invalid",
                f"Host integration handoff manifest is not valid JSON: {exc}",
            )
        ]
    if not isinstance(manifest, dict):
        return {}, [
            _runtime_host_integration_handoff_inspection_diagnostic(
                path,
                "manifest-invalid",
                "Host integration handoff manifest must be a JSON object.",
            )
        ]
    return manifest, []


def _runtime_host_integration_handoff_inspection_manifest_diagnostics(
    path: Path, manifest: Mapping[str, Any]
) -> list[ProjectDiagnostic]:
    diagnostics: list[ProjectDiagnostic] = []
    if manifest.get("schemaVersion") != REPORT_SCHEMA_VERSION:
        diagnostics.append(
            _runtime_host_integration_handoff_inspection_diagnostic(
                path,
                "manifest-schema-invalid",
                f"Host integration handoff schemaVersion must be {REPORT_SCHEMA_VERSION}.",
            )
        )
    if manifest.get("kind") != RUNTIME_HOST_INTEGRATION_HANDOFF_KIND:
        diagnostics.append(
            _runtime_host_integration_handoff_inspection_diagnostic(
                path,
                "manifest-kind-invalid",
                "Host integration handoff inspection input must be a "
                f"{RUNTIME_HOST_INTEGRATION_HANDOFF_KIND} document.",
            )
        )
    if manifest.get("success") is not True:
        diagnostics.append(
            _runtime_host_integration_handoff_inspection_diagnostic(
                path,
                "manifest-failed",
                "Host integration handoff manifest must be successful before "
                "handoff files can be inspected.",
            )
        )
    for field_name in ("targets", "generatedFiles"):
        if not isinstance(manifest.get(field_name), list):
            diagnostics.append(
                _runtime_host_integration_handoff_inspection_diagnostic(
                    path,
                    f"manifest-{field_name}-invalid",
                    f"Host integration handoff manifest {field_name} must be a list.",
                )
            )
    return diagnostics


def _runtime_host_integration_handoff_inspection_resolve_path(
    manifest_path: Path,
    root: Path,
    relative_path: Any,
    *,
    field_name: str,
    code_prefix: str,
    target: Any = None,
) -> tuple[Path | None, list[ProjectDiagnostic]]:
    if not _is_non_empty_string(relative_path):
        return None, [
            _runtime_host_integration_handoff_inspection_diagnostic(
                manifest_path,
                f"{code_prefix}-path-missing",
                f"{field_name} must be a non-empty relative path.",
                target=target,
            )
        ]
    if _is_absolute_or_windows_drive_path(relative_path):
        return None, [
            _runtime_host_integration_handoff_inspection_diagnostic(
                manifest_path,
                f"{code_prefix}-path-absolute",
                f"{field_name} must be relative to the handoff root.",
                target=target,
            )
        ]
    candidate = root / Path(relative_path)
    if not _is_relative_to(candidate, root):
        return None, [
            _runtime_host_integration_handoff_inspection_diagnostic(
                manifest_path,
                f"{code_prefix}-path-outside-root",
                f"{field_name} resolves outside the handoff root.",
                target=target,
            )
        ]
    return candidate, []


def _runtime_host_integration_handoff_inspection_file_diagnostics(
    manifest_path: Path,
    path: Path | None,
    relative_path: Any,
    *,
    code_prefix: str,
    target: Any = None,
) -> list[ProjectDiagnostic]:
    if path is None:
        return []
    if not path.exists():
        return [
            _runtime_host_integration_handoff_inspection_diagnostic(
                manifest_path,
                f"{code_prefix}-missing",
                f"Host integration handoff file is missing: {relative_path}.",
                target=target,
            )
        ]
    if not path.is_file():
        return [
            _runtime_host_integration_handoff_inspection_diagnostic(
                manifest_path,
                f"{code_prefix}-not-file",
                f"Host integration handoff path is not a file: {relative_path}.",
                target=target,
            )
        ]
    return []


def _runtime_host_integration_handoff_inspection_load_target(
    manifest_path: Path,
    target_path: Path,
    target: Mapping[str, Any],
) -> tuple[dict[str, Any], list[ProjectDiagnostic]]:
    target_name = target.get("target")
    try:
        payload = json.loads(target_path.read_text(encoding="utf-8"))
    except OSError as exc:
        return {}, [
            _runtime_host_integration_handoff_inspection_diagnostic(
                manifest_path,
                "target-read-failed",
                f"Host integration target file could not be read: {exc}",
                target=target_name,
            )
        ]
    except json.JSONDecodeError as exc:
        return {}, [
            _runtime_host_integration_handoff_inspection_diagnostic(
                manifest_path,
                "target-json-invalid",
                f"Host integration target file is not valid JSON: {exc}",
                target=target_name,
            )
        ]
    if not isinstance(payload, dict):
        return {}, [
            _runtime_host_integration_handoff_inspection_diagnostic(
                manifest_path,
                "target-invalid",
                "Host integration target file must be a JSON object.",
                target=target_name,
            )
        ]

    diagnostics: list[ProjectDiagnostic] = []
    if payload.get("schemaVersion") != REPORT_SCHEMA_VERSION:
        diagnostics.append(
            _runtime_host_integration_handoff_inspection_diagnostic(
                manifest_path,
                "target-schema-invalid",
                f"Host integration target schemaVersion must be {REPORT_SCHEMA_VERSION}.",
                target=target_name,
            )
        )
    if payload.get("kind") != "crosstl-runtime-host-integration-target":
        diagnostics.append(
            _runtime_host_integration_handoff_inspection_diagnostic(
                manifest_path,
                "target-kind-invalid",
                "Host integration target kind must be "
                "crosstl-runtime-host-integration-target.",
                target=target_name,
            )
        )
    for field_name, code in (
        ("target", "target-name-mismatch"),
        ("status", "target-status-mismatch"),
    ):
        if payload.get(field_name) != target.get(field_name):
            diagnostics.append(
                _runtime_host_integration_handoff_inspection_diagnostic(
                    manifest_path,
                    code,
                    f"Host integration target {field_name} does not match manifest.",
                    target=target_name,
                )
            )
    if not isinstance(payload.get("loaderUnits"), list):
        diagnostics.append(
            _runtime_host_integration_handoff_inspection_diagnostic(
                manifest_path,
                "target-loader-units-invalid",
                "Host integration target loaderUnits must be a list.",
                target=target_name,
            )
        )
    if not isinstance(payload.get("actions"), list):
        diagnostics.append(
            _runtime_host_integration_handoff_inspection_diagnostic(
                manifest_path,
                "target-actions-invalid",
                "Host integration target actions must be a list.",
                target=target_name,
            )
        )
    return payload, diagnostics


def _runtime_host_integration_handoff_inspection_generated_file(
    manifest_path: Path,
    root: Path,
    generated_file: Mapping[str, Any],
) -> tuple[dict[str, Any], list[ProjectDiagnostic]]:
    target = generated_file.get("target")
    relative_path = generated_file.get("path")
    path, diagnostics = _runtime_host_integration_handoff_inspection_resolve_path(
        manifest_path,
        root,
        relative_path,
        field_name="generated file path",
        code_prefix="generated-file",
        target=target,
    )
    diagnostics.extend(
        _runtime_host_integration_handoff_inspection_file_diagnostics(
            manifest_path,
            path,
            relative_path,
            code_prefix="generated-file",
            target=target,
        )
    )
    return (
        {
            "path": relative_path,
            "kind": generated_file.get("kind"),
            "target": target,
            "status": "failed" if diagnostics else "ready",
            "diagnostics": [diagnostic.code for diagnostic in diagnostics],
        },
        diagnostics,
    )


def _runtime_host_integration_handoff_inspection_target(
    manifest_path: Path,
    root: Path,
    target: Mapping[str, Any],
    generated_paths: set[str],
) -> tuple[dict[str, Any], list[ProjectDiagnostic]]:
    target_name = target.get("target")
    handoff_file = target.get("handoffFile")
    path, diagnostics = _runtime_host_integration_handoff_inspection_resolve_path(
        manifest_path,
        root,
        handoff_file,
        field_name="target handoffFile",
        code_prefix="target",
        target=target_name,
    )
    if _is_non_empty_string(handoff_file) and handoff_file not in generated_paths:
        diagnostics.append(
            _runtime_host_integration_handoff_inspection_diagnostic(
                manifest_path,
                "target-generated-file-missing",
                "Host integration target handoffFile is not listed in generatedFiles.",
                target=target_name,
            )
        )
    diagnostics.extend(
        _runtime_host_integration_handoff_inspection_file_diagnostics(
            manifest_path,
            path,
            handoff_file,
            code_prefix="target",
            target=target_name,
        )
    )
    target_payload: dict[str, Any] = {}
    if path is not None and not diagnostics:
        target_payload, target_diagnostics = (
            _runtime_host_integration_handoff_inspection_load_target(
                manifest_path, path, target
            )
        )
        diagnostics.extend(target_diagnostics)

    loader_unit_count = (
        len(target_payload.get("loaderUnits"))
        if isinstance(target_payload.get("loaderUnits"), list)
        else 0
    )
    action_count = (
        len(target_payload.get("actions"))
        if isinstance(target_payload.get("actions"), list)
        else 0
    )
    for field_name, actual_count, code in (
        ("loaderUnitCount", loader_unit_count, "target-loader-unit-count-mismatch"),
        ("actionCount", action_count, "target-action-count-mismatch"),
    ):
        expected_count = target.get(field_name)
        if (
            _is_non_negative_int(expected_count)
            and target_payload
            and actual_count != expected_count
        ):
            diagnostics.append(
                _runtime_host_integration_handoff_inspection_diagnostic(
                    manifest_path,
                    code,
                    f"Host integration target {field_name} does not match manifest.",
                    target=target_name,
                )
            )

    failed = any(diagnostic.severity == "error" for diagnostic in diagnostics)
    return (
        {
            "target": target_name,
            "status": "failed" if failed else target.get("status"),
            "manifestStatus": target.get("status"),
            "handoffFile": handoff_file,
            "fileStatus": "failed" if failed else "ready",
            "targetKind": target_payload.get("kind"),
            "targetStatus": target_payload.get("status"),
            "loaderUnitCount": loader_unit_count,
            "actionCount": action_count,
            "diagnostics": [diagnostic.code for diagnostic in diagnostics],
        },
        diagnostics,
    )


def _runtime_host_integration_handoff_inspection_status(
    ready_count: int, blocked_count: int, failed_count: int
) -> str:
    return _runtime_host_loader_scaffold_status(
        ready_count,
        blocked_count,
        failed=bool(failed_count),
    )


def inspect_runtime_host_integration_handoff(
    handoff_manifest_path: str | os.PathLike[str],
) -> dict[str, Any]:
    """Inspect host integration handoff files before runtime tooling consumes them."""

    manifest_path = _filesystem_path_arg(
        handoff_manifest_path, field_name="Host integration handoff manifest path"
    )
    handoff_root = manifest_path.parent
    manifest, diagnostics = _runtime_host_integration_handoff_inspection_load_manifest(
        manifest_path
    )
    if manifest:
        diagnostics.extend(
            _runtime_host_integration_handoff_inspection_manifest_diagnostics(
                manifest_path, manifest
            )
        )

    generated_file_records: list[dict[str, Any]] = []
    target_records: list[dict[str, Any]] = []
    if not any(diagnostic.severity == "error" for diagnostic in diagnostics):
        for generated_file in _record_sequence(manifest.get("generatedFiles")):
            if not isinstance(generated_file, Mapping):
                continue
            record, current_diagnostics = (
                _runtime_host_integration_handoff_inspection_generated_file(
                    manifest_path, handoff_root, generated_file
                )
            )
            generated_file_records.append(record)
            diagnostics.extend(current_diagnostics)
        generated_paths = {
            generated_file.get("path")
            for generated_file in generated_file_records
            if _is_non_empty_string(generated_file.get("path"))
        }
        for target in _record_sequence(manifest.get("targets")):
            if not isinstance(target, Mapping):
                continue
            record, current_diagnostics = (
                _runtime_host_integration_handoff_inspection_target(
                    manifest_path, handoff_root, target, generated_paths
                )
            )
            target_records.append(record)
            diagnostics.extend(current_diagnostics)

    ready_count = sum(1 for target in target_records if target.get("status") == "ready")
    blocked_count = sum(
        1 for target in target_records if target.get("status") == "blocked"
    )
    failed_count = sum(
        1 for target in target_records if target.get("status") == "failed"
    )
    verified_generated_count = sum(
        1
        for generated_file in generated_file_records
        if generated_file.get("status") == "ready"
    )
    failed_generated_count = sum(
        1
        for generated_file in generated_file_records
        if generated_file.get("status") != "ready"
    )
    manifest_summary = (
        manifest.get("summary") if isinstance(manifest.get("summary"), Mapping) else {}
    )
    failed = any(diagnostic.severity == "error" for diagnostic in diagnostics)
    return {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": RUNTIME_HOST_INTEGRATION_HANDOFF_INSPECTION_KIND,
        "sourceHandoffManifest": str(manifest_path),
        "sourceHandoffManifestHash": _optional_source_hash(manifest_path),
        "generatedAt": int(time.time()),
        "success": not failed,
        "status": (
            _runtime_host_integration_handoff_inspection_status(
                ready_count,
                blocked_count,
                failed_count,
            )
            if not failed
            else "failed"
        ),
        "scope": RUNTIME_HOST_INTEGRATION_HANDOFF_INSPECTION_SCOPE,
        "nonGoals": list(RUNTIME_HOST_INTEGRATION_HANDOFF_INSPECTION_NON_GOALS),
        "handoffRoot": str(handoff_root),
        "project": (
            dict(manifest.get("project"))
            if isinstance(manifest.get("project"), Mapping)
            else {"targets": []}
        ),
        "summary": {
            "targetCount": len(target_records),
            "readyTargetCount": ready_count,
            "blockedTargetCount": blocked_count,
            "failedTargetCount": failed_count,
            "generatedFileCount": len(generated_file_records),
            "verifiedGeneratedFileCount": verified_generated_count,
            "failedGeneratedFileCount": failed_generated_count,
            "loaderUnitCount": manifest_summary.get("loaderUnitCount", 0),
            "actionCount": manifest_summary.get("actionCount", 0),
            "requiredToolCount": manifest_summary.get("requiredToolCount", 0),
            "hostResponsibilityCount": manifest_summary.get(
                "hostResponsibilityCount", 0
            ),
        },
        "targets": target_records,
        "generatedFiles": generated_file_records,
        "handoffManifest": {
            "kind": manifest.get("kind"),
            "success": manifest.get("success"),
            "status": manifest.get("status"),
            "targetCount": manifest_summary.get("targetCount", 0),
            "generatedFileCount": manifest_summary.get("generatedFileCount", 0),
        },
        "diagnosticCounts": _diagnostic_counts(diagnostics),
        "diagnostics": [diagnostic.to_json() for diagnostic in diagnostics],
    }


def _runtime_host_integration_execution_plan_diagnostic(
    path: Path,
    code: str,
    message: str,
    *,
    target: Any = None,
) -> ProjectDiagnostic:
    return ProjectDiagnostic(
        severity="error",
        code=f"project.runtime-host-integration-execution-plan.{code}",
        message=message,
        location=SourceLocation(file=str(path)),
        target=target if _is_non_empty_string(target) else None,
        check_kind="runtime-host-integration-execution-plan",
    )


def _runtime_host_integration_execution_plan_load_manifest(
    path: Path,
) -> tuple[dict[str, Any], list[ProjectDiagnostic]]:
    try:
        manifest = json.loads(path.read_text(encoding="utf-8"))
    except OSError as exc:
        return {}, [
            _runtime_host_integration_execution_plan_diagnostic(
                path,
                "manifest-read-failed",
                f"Host integration handoff manifest could not be read: {exc}",
            )
        ]
    except json.JSONDecodeError as exc:
        return {}, [
            _runtime_host_integration_execution_plan_diagnostic(
                path,
                "manifest-json-invalid",
                f"Host integration handoff manifest is not valid JSON: {exc}",
            )
        ]
    if not isinstance(manifest, dict):
        return {}, [
            _runtime_host_integration_execution_plan_diagnostic(
                path,
                "manifest-invalid",
                "Host integration handoff manifest must be a JSON object.",
            )
        ]
    return manifest, []


def _runtime_host_integration_execution_host_root(
    host_root: str | os.PathLike[str] | None,
    *,
    manifest_path: Path,
) -> tuple[str | None, str, list[ProjectDiagnostic]]:
    if host_root is None:
        return None, "not-provided", []
    root = _filesystem_path_arg(host_root, field_name="Host root")
    if not root.exists():
        return (
            str(root),
            "missing",
            [
                _runtime_host_integration_execution_plan_diagnostic(
                    manifest_path,
                    "host-root-missing",
                    f"Host root does not exist: {root}",
                )
            ],
        )
    if not root.is_dir():
        return (
            str(root),
            "not-directory",
            [
                _runtime_host_integration_execution_plan_diagnostic(
                    manifest_path,
                    "host-root-not-directory",
                    f"Host root is not a directory: {root}",
                )
            ],
        )
    return str(root), "ready", []


def _runtime_host_integration_execution_action_phase(kind: Any) -> str:
    if kind == "consume-host-loader-unit":
        return "consume-loader"
    if kind == "load-package-artifact":
        return "load-artifact"
    if kind == "satisfy-host-responsibility":
        return "satisfy-host-responsibility"
    if _is_non_empty_string(kind) and str(kind).startswith("resolve-"):
        return "resolve-blockers"
    return "run-host-action"


def _runtime_host_integration_execution_action_status(action: Mapping[str, Any]) -> str:
    kind = action.get("kind")
    severity = action.get("severity")
    if kind == "resolve-loader-scaffold-blockers":
        return "blocked"
    if severity == "error":
        return "failed"
    if severity == "warning":
        return "blocked"
    return "ready"


def _runtime_host_integration_execution_action_step(
    action: Mapping[str, Any],
    index: int,
    *,
    unit_by_id: Mapping[Any, Mapping[str, Any]],
    used_ids: set[str],
) -> dict[str, Any]:
    target = action.get("target")
    kind = action.get("kind") or "run-host-action"
    loader_unit = action.get("loaderUnit")
    unit = unit_by_id.get(loader_unit, {})
    target_slug = _runtime_host_loader_scaffold_unique_slug(
        target if _is_non_empty_string(target) else "target",
        "target",
        set(),
    )
    kind_slug = _runtime_host_loader_scaffold_unique_slug(kind, "step", set())
    step_id = _runtime_host_loader_scaffold_unique_slug(
        f"{target_slug}-{index + 1:04d}-{kind_slug}",
        f"step-{index + 1:04d}",
        used_ids,
    )
    return {
        "id": step_id,
        "target": target,
        "phase": _runtime_host_integration_execution_action_phase(kind),
        "kind": kind,
        "status": _runtime_host_integration_execution_action_status(action),
        "severity": action.get("severity") or "note",
        "message": action.get("message") or "Run host integration action.",
        "loaderUnit": loader_unit,
        "scaffold": action.get("scaffold"),
        "packagePath": action.get("packagePath"),
        "outputPath": action.get("outputPath"),
        "tools": [
            tool
            for tool in _record_sequence(action.get("tools"))
            if _is_non_empty_string(tool)
        ],
        "hostResponsibilities": [
            responsibility
            for responsibility in _record_sequence(unit.get("hostResponsibilities"))
            if _is_non_empty_string(responsibility)
        ],
        "sourceActionKind": action.get("kind"),
    }


def _runtime_host_integration_execution_tool_step(
    target: Any,
    tool: str,
    index: int,
    *,
    used_ids: set[str],
) -> dict[str, Any]:
    target_slug = _runtime_host_loader_scaffold_unique_slug(
        target if _is_non_empty_string(target) else "target",
        "target",
        set(),
    )
    tool_slug = _runtime_host_loader_scaffold_unique_slug(tool, "tool", set())
    step_id = _runtime_host_loader_scaffold_unique_slug(
        f"{target_slug}-{index + 1:04d}-prepare-{tool_slug}",
        f"step-{index + 1:04d}",
        used_ids,
    )
    return {
        "id": step_id,
        "target": target,
        "phase": "prepare-tools",
        "kind": "verify-host-tool",
        "status": "ready",
        "severity": "note",
        "message": f"Verify host integration tool is available: {tool}.",
        "loaderUnit": None,
        "scaffold": None,
        "packagePath": None,
        "outputPath": None,
        "tools": [tool],
        "hostResponsibilities": [],
        "sourceActionKind": None,
    }


def _runtime_host_integration_execution_target(
    target: Mapping[str, Any],
    steps: Sequence[Mapping[str, Any]],
) -> dict[str, Any]:
    target_name = target.get("target")
    target_steps = [step for step in steps if step.get("target") == target_name]
    ready_steps = [step for step in target_steps if step.get("status") == "ready"]
    blocked_steps = [step for step in target_steps if step.get("status") == "blocked"]
    failed_steps = [step for step in target_steps if step.get("status") == "failed"]
    return {
        "target": target_name,
        "status": target.get("status"),
        "loaderUnitCount": target.get("loaderUnitCount", 0),
        "readyLoaderUnitCount": target.get("readyLoaderUnitCount", 0),
        "blockedLoaderUnitCount": target.get("blockedLoaderUnitCount", 0),
        "failedLoaderUnitCount": target.get("failedLoaderUnitCount", 0),
        "stepCount": len(target_steps),
        "readyStepCount": len(ready_steps),
        "blockedStepCount": len(blocked_steps),
        "failedStepCount": len(failed_steps),
        "requiredTools": [
            tool
            for tool in _record_sequence(target.get("requiredTools"))
            if _is_non_empty_string(tool)
        ],
        "hostResponsibilities": [
            responsibility
            for responsibility in _record_sequence(target.get("hostResponsibilities"))
            if _is_non_empty_string(responsibility)
        ],
        "packagePaths": [
            package_path
            for package_path in _record_sequence(target.get("packagePaths"))
            if _is_non_empty_string(package_path)
        ],
        "scaffoldFiles": [
            scaffold_file
            for scaffold_file in _record_sequence(target.get("scaffoldFiles"))
            if _is_non_empty_string(scaffold_file)
        ],
    }


def _runtime_host_integration_execution_plan_device_execution(
    targets: Sequence[Mapping[str, Any]],
) -> dict[str, Any]:
    target_payloads: list[dict[str, Any]] = []
    requires_adapter_count = 0
    blocked_count = 0
    failed_count = 0
    for target in targets:
        target_name = target.get("target")
        target_status = str(target.get("status") or "unknown")
        if target_status == "ready":
            execution_status = "requires-adapter-descriptor"
            requires_adapter_count += 1
        elif target_status == "failed":
            execution_status = "failed"
            failed_count += 1
        else:
            execution_status = "blocked"
            blocked_count += 1
        target_payloads.append(
            {
                "target": target_name,
                "status": execution_status,
                "targetStatus": target_status,
            }
        )
    status = "empty"
    if failed_count:
        status = "failed"
    elif requires_adapter_count and not blocked_count:
        status = "requires-adapter-descriptors"
    elif requires_adapter_count or blocked_count:
        status = "blocked"
    return {
        "mode": "adapter-backed-device-dispatch",
        "status": status,
        "requiredInputs": [
            "runtime-package-root",
            "runtime-adapter-descriptor-root",
            "target-runtime-runner",
        ],
        "targetCount": len(target_payloads),
        "readyTargetCount": 0,
        "requiresAdapterDescriptorTargetCount": requires_adapter_count,
        "blockedTargetCount": blocked_count,
        "failedTargetCount": failed_count,
        "targets": target_payloads,
    }


def plan_runtime_host_integration_execution(
    handoff_manifest_path: str | os.PathLike[str],
    *,
    host_root: str | os.PathLike[str] | None = None,
) -> dict[str, Any]:
    """Build a read-only host integration execution plan from a handoff bundle."""

    manifest_path = _filesystem_path_arg(
        handoff_manifest_path, field_name="Host integration handoff manifest path"
    )
    host_root_value, host_root_status, host_root_diagnostics = (
        _runtime_host_integration_execution_host_root(
            host_root, manifest_path=manifest_path
        )
    )
    inspection = inspect_runtime_host_integration_handoff(manifest_path)
    diagnostics_payload = [
        dict(diagnostic)
        for diagnostic in _record_sequence(inspection.get("diagnostics"))
        if isinstance(diagnostic, Mapping)
    ]
    diagnostics_payload.extend(
        diagnostic.to_json() for diagnostic in host_root_diagnostics
    )

    handoff: dict[str, Any] = {}
    load_diagnostics: list[ProjectDiagnostic] = []
    if inspection.get("success") is True:
        handoff, load_diagnostics = (
            _runtime_host_integration_execution_plan_load_manifest(manifest_path)
        )
        diagnostics_payload.extend(
            diagnostic.to_json() for diagnostic in load_diagnostics
        )

    targets = [
        dict(target)
        for target in _record_sequence(handoff.get("targets"))
        if isinstance(target, Mapping)
    ]
    units = [
        dict(unit)
        for unit in _record_sequence(handoff.get("loaderUnits"))
        if isinstance(unit, Mapping)
    ]
    actions = [
        dict(action)
        for action in _record_sequence(handoff.get("actions"))
        if isinstance(action, Mapping)
    ]
    unit_by_id = {unit.get("id"): unit for unit in units if unit.get("id") is not None}
    used_ids: set[str] = set()
    steps: list[dict[str, Any]] = []
    for target in targets:
        for tool in _record_sequence(target.get("requiredTools")):
            if not _is_non_empty_string(tool):
                continue
            steps.append(
                _runtime_host_integration_execution_tool_step(
                    target.get("target"),
                    tool,
                    len(steps),
                    used_ids=used_ids,
                )
            )
    for action in actions:
        steps.append(
            _runtime_host_integration_execution_action_step(
                action,
                len(steps),
                unit_by_id=unit_by_id,
                used_ids=used_ids,
            )
        )

    ready_steps = [step for step in steps if step.get("status") == "ready"]
    blocked_steps = [step for step in steps if step.get("status") == "blocked"]
    failed_steps = [step for step in steps if step.get("status") == "failed"]
    ready_units = [unit for unit in units if unit.get("status") == "ready"]
    blocked_units = [unit for unit in units if unit.get("status") == "blocked"]
    failed_units = [unit for unit in units if unit.get("status") == "failed"]
    required_tools = sorted(
        {
            tool
            for target in targets
            for tool in _record_sequence(target.get("requiredTools"))
            if _is_non_empty_string(tool)
        }
    )
    host_responsibilities = sorted(
        {
            responsibility
            for target in targets
            for responsibility in _record_sequence(target.get("hostResponsibilities"))
            if _is_non_empty_string(responsibility)
        }
    )
    failed = any(
        diagnostic.get("severity") == "error" for diagnostic in diagnostics_payload
    ) or bool(failed_steps)
    status = (
        _runtime_host_loader_scaffold_status(
            len(ready_units),
            len(blocked_units) + len(blocked_steps),
            failed=bool(failed_units or failed_steps),
        )
        if not failed
        else "failed"
    )
    return {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": RUNTIME_HOST_INTEGRATION_EXECUTION_PLAN_KIND,
        "sourceHandoffManifest": str(manifest_path),
        "sourceHandoffManifestHash": _optional_source_hash(manifest_path),
        "generatedAt": int(time.time()),
        "success": not failed,
        "status": status,
        "scope": RUNTIME_HOST_INTEGRATION_EXECUTION_PLAN_SCOPE,
        "nonGoals": list(RUNTIME_HOST_INTEGRATION_EXECUTION_PLAN_NON_GOALS),
        "handoffRoot": str(manifest_path.parent),
        "hostRoot": host_root_value,
        "hostRootStatus": host_root_status,
        "project": (
            dict(handoff.get("project"))
            if isinstance(handoff.get("project"), Mapping)
            else {"targets": []}
        ),
        "summary": {
            "targetCount": len(targets),
            "loaderUnitCount": len(units),
            "readyLoaderUnitCount": len(ready_units),
            "blockedLoaderUnitCount": len(blocked_units),
            "failedLoaderUnitCount": len(failed_units),
            "stepCount": len(steps),
            "readyStepCount": len(ready_steps),
            "blockedStepCount": len(blocked_steps),
            "failedStepCount": len(failed_steps),
            "requiredToolCount": len(required_tools),
            "hostResponsibilityCount": len(host_responsibilities),
        },
        "targets": [
            _runtime_host_integration_execution_target(target, steps)
            for target in targets
        ],
        "steps": steps,
        "deviceExecution": _runtime_host_integration_execution_plan_device_execution(
            targets
        ),
        "handoffInspection": {
            "kind": inspection.get("kind"),
            "success": inspection.get("success"),
            "status": inspection.get("status"),
            "targetCount": (
                inspection.get("summary", {}).get("targetCount", 0)
                if isinstance(inspection.get("summary"), Mapping)
                else 0
            ),
            "generatedFileCount": (
                inspection.get("summary", {}).get("generatedFileCount", 0)
                if isinstance(inspection.get("summary"), Mapping)
                else 0
            ),
        },
        "diagnosticCounts": _diagnostic_payload_counts(diagnostics_payload),
        "diagnostics": diagnostics_payload,
    }


def _runtime_host_integration_execution_result_diagnostic(
    path: Path,
    code: str,
    message: str,
    *,
    severity: str = "error",
    target: Any = None,
) -> ProjectDiagnostic:
    return ProjectDiagnostic(
        severity=severity,
        code=f"project.runtime-host-integration-execution.{code}",
        message=message,
        location=SourceLocation(file=str(path)),
        target=target if _is_non_empty_string(target) else None,
        check_kind="runtime-host-integration-execution",
    )


def _runtime_host_integration_execution_load_plan(
    path: Path,
) -> tuple[dict[str, Any], list[ProjectDiagnostic]]:
    try:
        plan = json.loads(path.read_text(encoding="utf-8"))
    except OSError as exc:
        return {}, [
            _runtime_host_integration_execution_result_diagnostic(
                path,
                "plan-read-failed",
                f"Host integration execution plan could not be read: {exc}",
            )
        ]
    except json.JSONDecodeError as exc:
        return {}, [
            _runtime_host_integration_execution_result_diagnostic(
                path,
                "plan-json-invalid",
                f"Host integration execution plan is not valid JSON: {exc}",
            )
        ]
    if not isinstance(plan, dict):
        return {}, [
            _runtime_host_integration_execution_result_diagnostic(
                path,
                "plan-invalid",
                "Host integration execution input must be a JSON object.",
            )
        ]
    return plan, []


def _runtime_host_integration_execution_plan_diagnostics(
    path: Path, plan: Mapping[str, Any]
) -> list[ProjectDiagnostic]:
    diagnostics: list[ProjectDiagnostic] = []
    if plan.get("schemaVersion") != REPORT_SCHEMA_VERSION:
        diagnostics.append(
            _runtime_host_integration_execution_result_diagnostic(
                path,
                "plan-schema-invalid",
                f"Host integration execution plan schemaVersion must be {REPORT_SCHEMA_VERSION}.",
            )
        )
    if plan.get("kind") != RUNTIME_HOST_INTEGRATION_EXECUTION_PLAN_KIND:
        diagnostics.append(
            _runtime_host_integration_execution_result_diagnostic(
                path,
                "plan-kind-invalid",
                "Host integration execution input must be a "
                f"{RUNTIME_HOST_INTEGRATION_EXECUTION_PLAN_KIND} document.",
            )
        )
    if plan.get("success") is not True:
        diagnostics.append(
            _runtime_host_integration_execution_result_diagnostic(
                path,
                "plan-failed",
                "Host integration execution plan must be successful before "
                "host integration execution can run.",
            )
        )
    if not isinstance(plan.get("steps"), list):
        diagnostics.append(
            _runtime_host_integration_execution_result_diagnostic(
                path,
                "plan-steps-invalid",
                "Host integration execution plan steps must be a list.",
            )
        )
    if not isinstance(plan.get("targets"), list):
        diagnostics.append(
            _runtime_host_integration_execution_result_diagnostic(
                path,
                "plan-targets-invalid",
                "Host integration execution plan targets must be a list.",
            )
        )
    return diagnostics


def _runtime_host_integration_execution_package_root(
    package_root: str | os.PathLike[str] | None,
    *,
    plan_path: Path,
) -> tuple[Path | None, str | None, str, list[ProjectDiagnostic]]:
    if package_root is None:
        return None, None, "not-provided", []
    root = _filesystem_path_arg(package_root, field_name="Runtime package root")
    if not root.exists():
        return (
            None,
            str(root),
            "missing",
            [
                _runtime_host_integration_execution_result_diagnostic(
                    plan_path,
                    "package-root-missing",
                    f"Runtime package root does not exist: {root}",
                )
            ],
        )
    if not root.is_dir():
        return (
            None,
            str(root),
            "not-directory",
            [
                _runtime_host_integration_execution_result_diagnostic(
                    plan_path,
                    "package-root-not-directory",
                    f"Runtime package root is not a directory: {root}",
                )
            ],
        )
    return root, str(root), "ready", []


