def _runtime_host_integration_execution_result_host_root(
    host_root: str | os.PathLike[str] | None,
    plan: Mapping[str, Any],
    *,
    plan_path: Path,
) -> tuple[str | None, str, list[ProjectDiagnostic]]:
    if host_root is None:
        planned_host_root = plan.get("hostRoot")
        if not _is_non_empty_string(planned_host_root):
            planned_status = plan.get("hostRootStatus")
            return (
                None,
                (
                    str(planned_status)
                    if _is_non_empty_string(planned_status)
                    else "not-provided"
                ),
                [],
            )
        root_arg: str | os.PathLike[str] = str(planned_host_root)
    else:
        root_arg = host_root

    root = _filesystem_path_arg(root_arg, field_name="Host root")
    if not root.exists():
        return (
            str(root),
            "missing",
            [
                _runtime_host_integration_execution_result_diagnostic(
                    plan_path,
                    "host-root-missing",
                    f"Host root does not exist: {root}",
                )
            ],
        )
    if not root.is_dir():
        return (
            str(root),
            "not-directory",
            [
                _runtime_host_integration_execution_result_diagnostic(
                    plan_path,
                    "host-root-not-directory",
                    f"Host root is not a directory: {root}",
                )
            ],
        )
    return str(root), "ready", []


def _runtime_host_integration_execution_adapter_package_empty(
    status: str, manifest_status: str | None = None
) -> dict[str, Any]:
    return {
        "kind": None,
        "success": status not in {"failed", "missing", "invalid"},
        "status": status,
        "adapterManifest": None,
        "adapterManifestStatus": manifest_status or status,
        "descriptorCount": 0,
        "verifiedDescriptorCount": 0,
        "failedDescriptorCount": 0,
        "readyDescriptorCount": 0,
        "blockedDescriptorCount": 0,
        "descriptors": [],
    }


def _runtime_host_integration_execution_adapter_manifest(
    adapter_root: Path | None,
    *,
    plan_path: Path,
) -> tuple[dict[str, Any], list[ProjectDiagnostic]]:
    if adapter_root is None:
        return (
            _runtime_host_integration_execution_adapter_package_empty("not-provided"),
            [],
        )

    manifest_path = adapter_root / "runtime-adapters.json"
    if not manifest_path.is_file():
        return _runtime_host_integration_execution_adapter_package_empty(
            "failed", "missing"
        ), [
            _runtime_host_integration_execution_result_diagnostic(
                plan_path,
                "adapter-manifest-missing",
                f"Runtime adapter descriptor manifest does not exist: {manifest_path}",
            )
        ]

    try:
        manifest = json.loads(manifest_path.read_text(encoding="utf-8"))
    except OSError as exc:
        return _runtime_host_integration_execution_adapter_package_empty(
            "failed", "unreadable"
        ), [
            _runtime_host_integration_execution_result_diagnostic(
                plan_path,
                "adapter-manifest-read-failed",
                f"Runtime adapter descriptor manifest could not be read: {exc}",
            )
        ]
    except json.JSONDecodeError as exc:
        return _runtime_host_integration_execution_adapter_package_empty(
            "failed", "invalid-json"
        ), [
            _runtime_host_integration_execution_result_diagnostic(
                plan_path,
                "adapter-manifest-json-invalid",
                f"Runtime adapter descriptor manifest is not valid JSON: {exc}",
            )
        ]

    diagnostics: list[ProjectDiagnostic] = []
    if not isinstance(manifest, Mapping):
        diagnostics.append(
            _runtime_host_integration_execution_result_diagnostic(
                plan_path,
                "adapter-manifest-invalid",
                "Runtime adapter descriptor manifest must be a JSON object.",
            )
        )
        return (
            _runtime_host_integration_execution_adapter_package_empty(
                "failed", "invalid"
            ),
            diagnostics,
        )

    if manifest.get("schemaVersion") != REPORT_SCHEMA_VERSION:
        diagnostics.append(
            _runtime_host_integration_execution_result_diagnostic(
                plan_path,
                "adapter-manifest-schema-invalid",
                f"Runtime adapter descriptor manifest schemaVersion must be {REPORT_SCHEMA_VERSION}.",
            )
        )
    if manifest.get("kind") != RUNTIME_ADAPTER_PACKAGE_KIND:
        diagnostics.append(
            _runtime_host_integration_execution_result_diagnostic(
                plan_path,
                "adapter-manifest-kind-invalid",
                "Runtime adapter descriptor manifest must be a "
                f"{RUNTIME_ADAPTER_PACKAGE_KIND} document.",
            )
        )
    if manifest.get("success") is not True:
        diagnostics.append(
            _runtime_host_integration_execution_result_diagnostic(
                plan_path,
                "adapter-package-failed",
                "Runtime adapter descriptor package must be successful before "
                "host integration execution can use it.",
            )
        )

    raw_descriptors = manifest.get("descriptors")
    if not isinstance(raw_descriptors, list):
        diagnostics.append(
            _runtime_host_integration_execution_result_diagnostic(
                plan_path,
                "adapter-descriptors-invalid",
                "Runtime adapter descriptor manifest descriptors must be a list.",
            )
        )
        raw_descriptors = []

    descriptor_results: list[dict[str, Any]] = []
    for index, descriptor in enumerate(raw_descriptors, start=1):
        descriptor_diagnostics: list[ProjectDiagnostic] = []
        if not isinstance(descriptor, Mapping):
            descriptor_diagnostics.append(
                _runtime_host_integration_execution_result_diagnostic(
                    plan_path,
                    "adapter-descriptor-invalid",
                    f"Runtime adapter descriptor entry {index} must be an object.",
                )
            )
            descriptor_results.append(
                {
                    "id": None,
                    "target": None,
                    "descriptorPath": None,
                    "status": "failed",
                    "checks": [
                        _runtime_host_integration_execution_check_payload(
                            "adapter-descriptor-entry", "failed"
                        )
                    ],
                }
            )
            diagnostics.extend(descriptor_diagnostics)
            continue

        descriptor_path = descriptor.get("descriptorPath")
        checks: list[dict[str, Any]] = []
        descriptor_target = descriptor.get("target")
        if not _is_non_empty_string(descriptor_path):
            descriptor_diagnostics.append(
                _runtime_host_integration_execution_result_diagnostic(
                    plan_path,
                    "adapter-descriptor-path-missing",
                    "Runtime adapter descriptor path must be a non-empty relative path.",
                    target=descriptor_target,
                )
            )
            checks.append(
                _runtime_host_integration_execution_check_payload(
                    "adapter-descriptor-file", "failed", field="descriptorPath"
                )
            )
            descriptor_file = None
        else:
            path_text = str(descriptor_path)
            descriptor_file = adapter_root / Path(path_text)
            if _is_absolute_or_windows_drive_path(path_text):
                descriptor_diagnostics.append(
                    _runtime_host_integration_execution_result_diagnostic(
                        plan_path,
                        "adapter-descriptor-path-absolute",
                        "Runtime adapter descriptor path must be relative to "
                        "the adapter descriptor root.",
                        target=descriptor_target,
                    )
                )
                checks.append(
                    _runtime_host_integration_execution_check_payload(
                        "adapter-descriptor-file",
                        "failed",
                        field="descriptorPath",
                        path=path_text,
                    )
                )
                descriptor_file = None
            elif not _is_relative_to(descriptor_file, adapter_root):
                descriptor_diagnostics.append(
                    _runtime_host_integration_execution_result_diagnostic(
                        plan_path,
                        "adapter-descriptor-path-outside-root",
                        "Runtime adapter descriptor path resolves outside "
                        f"the adapter descriptor root: {path_text}.",
                        target=descriptor_target,
                    )
                )
                checks.append(
                    _runtime_host_integration_execution_check_payload(
                        "adapter-descriptor-file",
                        "failed",
                        field="descriptorPath",
                        path=path_text,
                    )
                )
                descriptor_file = None
            elif not descriptor_file.is_file():
                descriptor_diagnostics.append(
                    _runtime_host_integration_execution_result_diagnostic(
                        plan_path,
                        "adapter-descriptor-missing",
                        f"Runtime adapter descriptor does not exist: {descriptor_file}",
                        target=descriptor_target,
                    )
                )
                checks.append(
                    _runtime_host_integration_execution_check_payload(
                        "adapter-descriptor-file",
                        "failed",
                        field="descriptorPath",
                        path=str(descriptor_file),
                    )
                )
                descriptor_file = None
            else:
                checks.append(
                    _runtime_host_integration_execution_check_payload(
                        "adapter-descriptor-file",
                        "passed",
                        field="descriptorPath",
                        path=str(descriptor_file),
                    )
                )

        descriptor_payload: Mapping[str, Any] | None = None
        if descriptor_file is not None:
            try:
                loaded_descriptor = json.loads(
                    descriptor_file.read_text(encoding="utf-8")
                )
            except OSError as exc:
                descriptor_diagnostics.append(
                    _runtime_host_integration_execution_result_diagnostic(
                        plan_path,
                        "adapter-descriptor-read-failed",
                        f"Runtime adapter descriptor could not be read: {exc}",
                        target=descriptor_target,
                    )
                )
                checks.append(
                    _runtime_host_integration_execution_check_payload(
                        "adapter-descriptor-json",
                        "failed",
                        field="descriptorPath",
                        path=str(descriptor_file),
                    )
                )
            except json.JSONDecodeError as exc:
                descriptor_diagnostics.append(
                    _runtime_host_integration_execution_result_diagnostic(
                        plan_path,
                        "adapter-descriptor-json-invalid",
                        f"Runtime adapter descriptor is not valid JSON: {exc}",
                        target=descriptor_target,
                    )
                )
                checks.append(
                    _runtime_host_integration_execution_check_payload(
                        "adapter-descriptor-json",
                        "failed",
                        field="descriptorPath",
                        path=str(descriptor_file),
                    )
                )
            else:
                if isinstance(loaded_descriptor, Mapping):
                    descriptor_payload = loaded_descriptor
                    checks.append(
                        _runtime_host_integration_execution_check_payload(
                            "adapter-descriptor-json",
                            "passed",
                            field="descriptorPath",
                            path=str(descriptor_file),
                        )
                    )
                else:
                    descriptor_diagnostics.append(
                        _runtime_host_integration_execution_result_diagnostic(
                            plan_path,
                            "adapter-descriptor-invalid",
                            "Runtime adapter descriptor must be a JSON object.",
                            target=descriptor_target,
                        )
                    )
                    checks.append(
                        _runtime_host_integration_execution_check_payload(
                            "adapter-descriptor-json",
                            "failed",
                            field="descriptorPath",
                            path=str(descriptor_file),
                        )
                    )

        descriptor_hash = descriptor.get("descriptorHash")
        if descriptor_file is not None and isinstance(descriptor_hash, Mapping):
            current_hash = _source_hash(descriptor_file)
            if current_hash == dict(descriptor_hash):
                checks.append(
                    _runtime_host_integration_execution_check_payload(
                        "adapter-descriptor-hash",
                        "passed",
                        field="descriptorHash",
                        path=str(descriptor_file),
                    )
                )
            else:
                descriptor_diagnostics.append(
                    _runtime_host_integration_execution_result_diagnostic(
                        plan_path,
                        "adapter-descriptor-hash-mismatch",
                        f"Runtime adapter descriptor hash does not match manifest: {descriptor_file}",
                        target=descriptor_target,
                    )
                )
                checks.append(
                    _runtime_host_integration_execution_check_payload(
                        "adapter-descriptor-hash",
                        "failed",
                        field="descriptorHash",
                        path=str(descriptor_file),
                    )
                )

        if descriptor_payload is not None:
            if descriptor_payload.get("kind") != RUNTIME_ADAPTER_DESCRIPTOR_KIND:
                descriptor_diagnostics.append(
                    _runtime_host_integration_execution_result_diagnostic(
                        plan_path,
                        "adapter-descriptor-kind-invalid",
                        "Runtime adapter descriptor file must be a "
                        f"{RUNTIME_ADAPTER_DESCRIPTOR_KIND} document.",
                        target=descriptor_target,
                    )
                )
                checks.append(
                    _runtime_host_integration_execution_check_payload(
                        "adapter-descriptor-kind", "failed"
                    )
                )
            else:
                checks.append(
                    _runtime_host_integration_execution_check_payload(
                        "adapter-descriptor-kind", "passed"
                    )
                )
            for field_name in ("id", "target", "packagePath"):
                expected = descriptor.get(field_name)
                observed = descriptor_payload.get(field_name)
                if not _is_non_empty_string(expected) or not _is_non_empty_string(
                    observed
                ):
                    continue
                if expected == observed:
                    continue
                descriptor_diagnostics.append(
                    _runtime_host_integration_execution_result_diagnostic(
                        plan_path,
                        f"adapter-descriptor-{field_name}-mismatch",
                        f"Runtime adapter descriptor {field_name} does not match manifest for {descriptor_path}.",
                        target=descriptor_target,
                    )
                )
                checks.append(
                    _runtime_host_integration_execution_check_payload(
                        "adapter-descriptor-field",
                        "failed",
                        field=field_name,
                    )
                )

        status = (
            "failed"
            if any(
                diagnostic.severity == "error" for diagnostic in descriptor_diagnostics
            )
            or any(check.get("status") == "failed" for check in checks)
            else "ready"
        )
        descriptor_results.append(
            {
                "id": descriptor.get("id"),
                "target": descriptor_target,
                "descriptorPath": descriptor_path,
                "status": status,
                "checks": checks,
            }
        )
        diagnostics.extend(descriptor_diagnostics)

    summary = (
        manifest.get("summary") if isinstance(manifest.get("summary"), Mapping) else {}
    )
    failed_descriptor_count = sum(
        1 for descriptor in descriptor_results if descriptor.get("status") == "failed"
    )
    verified_descriptor_count = sum(
        1 for descriptor in descriptor_results if descriptor.get("status") == "ready"
    )
    status = (
        "failed"
        if any(diagnostic.severity == "error" for diagnostic in diagnostics)
        else "ready"
    )
    return {
        "kind": manifest.get("kind"),
        "success": status != "failed",
        "status": status,
        "adapterManifest": str(manifest_path),
        "adapterManifestStatus": "ready" if status != "failed" else "failed",
        "descriptorCount": len(descriptor_results),
        "verifiedDescriptorCount": verified_descriptor_count,
        "failedDescriptorCount": failed_descriptor_count,
        "readyDescriptorCount": (
            summary.get("readyDescriptorCount", 0)
            if _is_non_negative_int(summary.get("readyDescriptorCount"))
            else 0
        ),
        "blockedDescriptorCount": (
            summary.get("blockedDescriptorCount", 0)
            if _is_non_negative_int(summary.get("blockedDescriptorCount"))
            else 0
        ),
        "descriptors": descriptor_results,
    }, diagnostics


def _runtime_host_integration_execution_runner_manifest_empty(
    status: str, manifest_status: str | None = None
) -> dict[str, Any]:
    return {
        "kind": None,
        "success": status not in {"failed", "missing", "invalid"},
        "status": status,
        "manifest": None,
        "manifestStatus": manifest_status or status,
        "runnerCount": 0,
        "readyRunnerCount": 0,
        "failedRunnerCount": 0,
        "blockedRunnerCount": 0,
        "runners": [],
    }


def _runtime_host_integration_execution_runner_manifest(
    runner_manifest: str | os.PathLike[str] | None,
    *,
    plan_path: Path,
) -> tuple[dict[str, Any], str | None, str, list[ProjectDiagnostic]]:
    if runner_manifest is None:
        return (
            _runtime_host_integration_execution_runner_manifest_empty("not-provided"),
            None,
            "not-provided",
            [],
        )

    manifest_path = _filesystem_path_arg(
        runner_manifest, field_name="Runtime device runner manifest"
    )
    if not manifest_path.is_file():
        return (
            _runtime_host_integration_execution_runner_manifest_empty(
                "failed", "missing"
            ),
            str(manifest_path),
            "missing",
            [
                _runtime_host_integration_execution_result_diagnostic(
                    plan_path,
                    "runner-manifest-missing",
                    f"Runtime device runner manifest does not exist: {manifest_path}",
                )
            ],
        )

    try:
        manifest = json.loads(manifest_path.read_text(encoding="utf-8"))
    except OSError as exc:
        return (
            _runtime_host_integration_execution_runner_manifest_empty(
                "failed", "unreadable"
            ),
            str(manifest_path),
            "unreadable",
            [
                _runtime_host_integration_execution_result_diagnostic(
                    plan_path,
                    "runner-manifest-read-failed",
                    f"Runtime device runner manifest could not be read: {exc}",
                )
            ],
        )
    except json.JSONDecodeError as exc:
        return (
            _runtime_host_integration_execution_runner_manifest_empty(
                "failed", "invalid-json"
            ),
            str(manifest_path),
            "invalid-json",
            [
                _runtime_host_integration_execution_result_diagnostic(
                    plan_path,
                    "runner-manifest-json-invalid",
                    f"Runtime device runner manifest is not valid JSON: {exc}",
                )
            ],
        )

    diagnostics: list[ProjectDiagnostic] = []
    if not isinstance(manifest, Mapping):
        diagnostics.append(
            _runtime_host_integration_execution_result_diagnostic(
                plan_path,
                "runner-manifest-invalid",
                "Runtime device runner manifest must be a JSON object.",
            )
        )
        return (
            _runtime_host_integration_execution_runner_manifest_empty(
                "failed", "invalid"
            ),
            str(manifest_path),
            "invalid",
            diagnostics,
        )

    if manifest.get("schemaVersion") != REPORT_SCHEMA_VERSION:
        diagnostics.append(
            _runtime_host_integration_execution_result_diagnostic(
                plan_path,
                "runner-manifest-schema-invalid",
                f"Runtime device runner manifest schemaVersion must be {REPORT_SCHEMA_VERSION}.",
            )
        )
    if manifest.get("kind") != RUNTIME_DEVICE_RUNNER_MANIFEST_KIND:
        diagnostics.append(
            _runtime_host_integration_execution_result_diagnostic(
                plan_path,
                "runner-manifest-kind-invalid",
                "Runtime device runner manifest must be a "
                f"{RUNTIME_DEVICE_RUNNER_MANIFEST_KIND} document.",
            )
        )

    raw_runners = manifest.get("runners")
    if not isinstance(raw_runners, list):
        diagnostics.append(
            _runtime_host_integration_execution_result_diagnostic(
                plan_path,
                "runner-manifest-runners-invalid",
                "Runtime device runner manifest runners must be a list.",
            )
        )
        raw_runners = []

    runner_results: list[dict[str, Any]] = []
    for index, runner in enumerate(raw_runners, start=1):
        runner_diagnostics: list[ProjectDiagnostic] = []
        if not isinstance(runner, Mapping):
            runner_diagnostics.append(
                _runtime_host_integration_execution_result_diagnostic(
                    plan_path,
                    "runner-entry-invalid",
                    f"Runtime device runner entry {index} must be an object.",
                )
            )
            runner_results.append(
                {
                    "id": None,
                    "target": None,
                    "status": "failed",
                    "capabilities": [],
                    "command": [],
                }
            )
            diagnostics.extend(runner_diagnostics)
            continue
        runner_id = runner.get("id")
        runner_target = runner.get("target")
        runner_status = str(runner.get("status") or "ready")
        if not _is_non_empty_string(runner_id):
            runner_diagnostics.append(
                _runtime_host_integration_execution_result_diagnostic(
                    plan_path,
                    "runner-id-missing",
                    "Runtime device runner id must be a non-empty string.",
                    target=runner_target,
                )
            )
        if not _is_non_empty_string(runner_target):
            runner_diagnostics.append(
                _runtime_host_integration_execution_result_diagnostic(
                    plan_path,
                    "runner-target-missing",
                    "Runtime device runner target must be a non-empty string.",
                )
            )
        if runner_status not in {"ready", "blocked", "failed"}:
            runner_diagnostics.append(
                _runtime_host_integration_execution_result_diagnostic(
                    plan_path,
                    "runner-status-invalid",
                    "Runtime device runner status must be ready, blocked, or failed.",
                    target=runner_target,
                )
            )
        capabilities = [
            capability
            for capability in _record_sequence(runner.get("capabilities"))
            if _is_non_empty_string(capability)
        ]
        command = [
            part
            for part in _record_sequence(runner.get("command"))
            if _is_non_empty_string(part)
        ]
        status = "failed" if runner_diagnostics else runner_status
        runner_results.append(
            {
                "id": runner_id,
                "target": runner_target,
                "status": status,
                "capabilities": capabilities,
                "command": command,
            }
        )
        diagnostics.extend(runner_diagnostics)

    failed_runner_count = sum(
        1 for runner in runner_results if runner.get("status") == "failed"
    )
    ready_runner_count = sum(
        1 for runner in runner_results if runner.get("status") == "ready"
    )
    blocked_runner_count = sum(
        1 for runner in runner_results if runner.get("status") == "blocked"
    )
    status = (
        "failed"
        if any(diagnostic.severity == "error" for diagnostic in diagnostics)
        else "ready"
    )
    return (
        {
            "kind": manifest.get("kind"),
            "success": status != "failed",
            "status": status,
            "manifest": str(manifest_path),
            "manifestStatus": "ready" if status != "failed" else "failed",
            "runnerCount": len(runner_results),
            "readyRunnerCount": ready_runner_count,
            "failedRunnerCount": failed_runner_count,
            "blockedRunnerCount": blocked_runner_count,
            "runners": runner_results,
        },
        str(manifest_path),
        "ready" if status != "failed" else "failed",
        diagnostics,
    )


def _runtime_host_integration_execution_check_payload(
    kind: str,
    status: str,
    *,
    field: str | None = None,
    path: str | None = None,
    tool: str | None = None,
    reason: str | None = None,
) -> dict[str, Any]:
    payload: dict[str, Any] = {"kind": kind, "status": status}
    if field is not None:
        payload["field"] = field
    if path is not None:
        payload["path"] = path
    if tool is not None:
        payload["tool"] = tool
    if reason is not None:
        payload["reason"] = reason
    return payload


def _runtime_host_integration_execution_file_check(
    root: Path | None,
    relative_path: Any,
    *,
    plan_path: Path,
    step: Mapping[str, Any],
    field_name: str,
    root_label: str,
    code_prefix: str,
) -> tuple[list[dict[str, Any]], list[ProjectDiagnostic]]:
    if root is None:
        return [
            _runtime_host_integration_execution_check_payload(
                "file-exists",
                "skipped",
                field=field_name,
                reason=f"{root_label} is not provided.",
            )
        ], []
    if not _is_non_empty_string(relative_path):
        diagnostic = _runtime_host_integration_execution_result_diagnostic(
            plan_path,
            f"{code_prefix}-path-missing",
            f"{field_name} must be a non-empty relative path.",
            target=step.get("target"),
        )
        return [
            _runtime_host_integration_execution_check_payload(
                "file-exists", "failed", field=field_name
            )
        ], [diagnostic]
    path_text = str(relative_path)
    if _is_absolute_or_windows_drive_path(path_text):
        diagnostic = _runtime_host_integration_execution_result_diagnostic(
            plan_path,
            f"{code_prefix}-path-absolute",
            f"{field_name} must be relative to {root_label}.",
            target=step.get("target"),
        )
        return [
            _runtime_host_integration_execution_check_payload(
                "file-exists", "failed", field=field_name, path=path_text
            )
        ], [diagnostic]
    candidate = root / Path(path_text)
    if not _is_relative_to(candidate, root):
        diagnostic = _runtime_host_integration_execution_result_diagnostic(
            plan_path,
            f"{code_prefix}-path-outside-root",
            f"{field_name} resolves outside {root_label}: {path_text}.",
            target=step.get("target"),
        )
        return [
            _runtime_host_integration_execution_check_payload(
                "file-exists", "failed", field=field_name, path=path_text
            )
        ], [diagnostic]
    if candidate.is_file():
        return [
            _runtime_host_integration_execution_check_payload(
                "file-exists",
                "passed",
                field=field_name,
                path=str(candidate),
            )
        ], []
    diagnostic = _runtime_host_integration_execution_result_diagnostic(
        plan_path,
        f"{code_prefix}-missing",
        f"{field_name} does not exist: {candidate}",
        target=step.get("target"),
    )
    return [
        _runtime_host_integration_execution_check_payload(
            "file-exists",
            "failed",
            field=field_name,
            path=str(candidate),
        )
    ], [diagnostic]


def _runtime_host_integration_execution_tool_checks(
    step: Mapping[str, Any],
    *,
    plan_path: Path,
) -> tuple[list[dict[str, Any]], list[ProjectDiagnostic]]:
    checks: list[dict[str, Any]] = []
    diagnostics: list[ProjectDiagnostic] = []
    for tool in _record_sequence(step.get("tools")):
        if not _is_non_empty_string(tool):
            continue
        resolved = shutil.which(str(tool))
        if resolved:
            checks.append(
                _runtime_host_integration_execution_check_payload(
                    "tool-available",
                    "passed",
                    tool=str(tool),
                    path=resolved,
                )
            )
            continue
        checks.append(
            _runtime_host_integration_execution_check_payload(
                "tool-available",
                "blocked",
                tool=str(tool),
                reason="Tool is not available on PATH.",
            )
        )
        diagnostics.append(
            _runtime_host_integration_execution_result_diagnostic(
                plan_path,
                "tool-unavailable",
                f"Host integration tool is not available on PATH: {tool}",
                severity="warning",
                target=step.get("target"),
            )
        )
    if not checks:
        checks.append(
            _runtime_host_integration_execution_check_payload(
                "tool-available",
                "skipped",
                reason="No host integration tools were listed for this step.",
            )
        )
    return checks, diagnostics


def _runtime_host_integration_execution_step_status(
    checks: Sequence[Mapping[str, Any]],
    diagnostics: Sequence[ProjectDiagnostic],
    fallback: str,
) -> str:
    statuses = {check.get("status") for check in checks}
    if any(diagnostic.severity == "error" for diagnostic in diagnostics):
        return "failed"
    if "failed" in statuses:
        return "failed"
    if "blocked" in statuses:
        return "blocked"
    if statuses and statuses <= {"skipped"}:
        return "skipped"
    if "skipped" in statuses and "passed" not in statuses:
        return "skipped"
    return fallback


def _runtime_host_integration_execution_step_result(
    step: Mapping[str, Any],
    *,
    plan_path: Path,
    scaffold_root: Path | None,
    package_root: Path | None,
) -> tuple[dict[str, Any], list[ProjectDiagnostic]]:
    checks: list[dict[str, Any]] = []
    diagnostics: list[ProjectDiagnostic] = []
    plan_status = step.get("status")
    kind = step.get("kind")
    phase = step.get("phase")
    fallback_status = "passed" if plan_status == "ready" else str(plan_status)

    if plan_status == "failed":
        diagnostics.append(
            _runtime_host_integration_execution_result_diagnostic(
                plan_path,
                "plan-step-failed",
                f"Host integration plan step failed before execution: {step.get('id')}",
                target=step.get("target"),
            )
        )
        checks.append(
            _runtime_host_integration_execution_check_payload(
                "plan-step-status", "failed", reason="Plan step is failed."
            )
        )
    elif plan_status == "blocked":
        checks.append(
            _runtime_host_integration_execution_check_payload(
                "plan-step-status", "blocked", reason="Plan step is blocked."
            )
        )
        fallback_status = "blocked"
    elif phase == "prepare-tools":
        step_checks, step_diagnostics = _runtime_host_integration_execution_tool_checks(
            step, plan_path=plan_path
        )
        checks.extend(step_checks)
        diagnostics.extend(step_diagnostics)
    elif kind == "consume-host-loader-unit":
        step_checks, step_diagnostics = _runtime_host_integration_execution_file_check(
            scaffold_root,
            step.get("outputPath"),
            plan_path=plan_path,
            step=step,
            field_name="outputPath",
            root_label="host loader scaffold root",
            code_prefix="output",
        )
        checks.extend(step_checks)
        diagnostics.extend(step_diagnostics)
    elif kind in {"load-package-artifact", "load-source-remap"}:
        step_checks, step_diagnostics = _runtime_host_integration_execution_file_check(
            package_root,
            step.get("packagePath"),
            plan_path=plan_path,
            step=step,
            field_name="packagePath",
            root_label="runtime package root",
            code_prefix="package",
        )
        checks.extend(step_checks)
        diagnostics.extend(step_diagnostics)
    elif kind == "satisfy-host-responsibility":
        checks.append(
            _runtime_host_integration_execution_check_payload(
                "host-responsibility",
                "skipped",
                reason="Requires project-specific host code changes.",
            )
        )
    else:
        checks.append(
            _runtime_host_integration_execution_check_payload(
                "plan-step-ready", "passed"
            )
        )

    result_status = _runtime_host_integration_execution_step_status(
        checks, diagnostics, fallback_status
    )
    return {
        "id": step.get("id"),
        "target": step.get("target"),
        "phase": phase,
        "kind": kind,
        "planStatus": plan_status,
        "resultStatus": result_status,
        "message": step.get("message"),
        "loaderUnit": step.get("loaderUnit"),
        "packagePath": step.get("packagePath"),
        "outputPath": step.get("outputPath"),
        "tools": [
            tool
            for tool in _record_sequence(step.get("tools"))
            if _is_non_empty_string(tool)
        ],
        "hostResponsibilities": [
            responsibility
            for responsibility in _record_sequence(step.get("hostResponsibilities"))
            if _is_non_empty_string(responsibility)
        ],
        "sourceActionKind": step.get("sourceActionKind"),
        "checks": checks,
        "diagnostics": [diagnostic.to_json() for diagnostic in diagnostics],
    }, diagnostics


def _runtime_host_integration_execution_result_status(
    step_results: Sequence[Mapping[str, Any]], diagnostics: Sequence[Mapping[str, Any]]
) -> str:
    if any(diagnostic.get("severity") == "error" for diagnostic in diagnostics):
        return "failed"
    statuses = {step.get("resultStatus") for step in step_results}
    if "failed" in statuses:
        return "failed"
    if "blocked" in statuses:
        return "blocked"
    if "skipped" in statuses and ("passed" in statuses or len(statuses) == 1):
        return "partial" if "passed" in statuses else "skipped"
    if "passed" in statuses:
        return "passed"
    return "empty"


def _runtime_host_integration_execution_result_target(
    target: Mapping[str, Any],
    step_results: Sequence[Mapping[str, Any]],
) -> dict[str, Any]:
    target_name = target.get("target")
    target_steps = [step for step in step_results if step.get("target") == target_name]
    passed_steps = [
        step for step in target_steps if step.get("resultStatus") == "passed"
    ]
    skipped_steps = [
        step for step in target_steps if step.get("resultStatus") == "skipped"
    ]
    blocked_steps = [
        step for step in target_steps if step.get("resultStatus") == "blocked"
    ]
    failed_steps = [
        step for step in target_steps if step.get("resultStatus") == "failed"
    ]
    status = _runtime_host_integration_execution_result_status(target_steps, [])
    return {
        "target": target_name,
        "status": status,
        "stepCount": len(target_steps),
        "passedStepCount": len(passed_steps),
        "skippedStepCount": len(skipped_steps),
        "blockedStepCount": len(blocked_steps),
        "failedStepCount": len(failed_steps),
        "requiredTools": [
            tool
            for tool in _record_sequence(target.get("requiredTools"))
            if _is_non_empty_string(tool)
        ],
        "hostResponsibilities": [
            responsibility
            for responsibility in _record_sequence(target.get("hostResponsibilities"))
            if _is_non_empty_string(responsibility)
        ],
        "packagePaths": [
            package_path
            for package_path in _record_sequence(target.get("packagePaths"))
            if _is_non_empty_string(package_path)
        ],
        "scaffoldFiles": [
            scaffold_file
            for scaffold_file in _record_sequence(target.get("scaffoldFiles"))
            if _is_non_empty_string(scaffold_file)
        ],
    }


def _runtime_host_integration_execution_result_device_execution(
    targets: Sequence[Mapping[str, Any]],
    *,
    package_root_status: str,
    adapter_package: Mapping[str, Any],
    runner_manifest: Mapping[str, Any],
) -> dict[str, Any]:
    descriptors = [
        descriptor
        for descriptor in _record_sequence(adapter_package.get("descriptors"))
        if isinstance(descriptor, Mapping)
    ]
    ready_targets = {
        str(descriptor.get("target"))
        for descriptor in descriptors
        if descriptor.get("status") == "ready"
        and _is_non_empty_string(descriptor.get("target"))
    }
    adapter_status = str(adapter_package.get("status") or "not-provided")
    runners = [
        runner
        for runner in _record_sequence(runner_manifest.get("runners"))
        if isinstance(runner, Mapping)
    ]
    ready_runners_by_target = {
        str(runner.get("target")): runner
        for runner in runners
        if runner.get("status") == "ready"
        and _is_non_empty_string(runner.get("target"))
    }
    runner_manifest_status = str(runner_manifest.get("status") or "not-provided")
    target_payloads: list[dict[str, Any]] = []
    ready_count = 0
    blocked_count = 0
    failed_count = 0
    for target in targets:
        target_name = target.get("target")
        target_text = str(target_name) if _is_non_empty_string(target_name) else None
        if adapter_status == "failed" or package_root_status in {
            "missing",
            "not-directory",
        }:
            status = "failed"
            reason = "Required runtime package or adapter descriptors are invalid."
            failed_count += 1
        elif adapter_status == "not-provided":
            status = "not-configured"
            reason = "Runtime adapter descriptor root was not provided."
            blocked_count += 1
        elif package_root_status != "ready":
            status = "blocked"
            reason = "Runtime package root is required before device execution."
            blocked_count += 1
        elif target_text not in ready_targets:
            status = "blocked"
            reason = "No verified runtime adapter descriptor was found for this target."
            blocked_count += 1
        elif runner_manifest_status == "not-provided":
            status = "ready-for-runner"
            reason = "Runtime package and adapter descriptor are ready for a runner."
            blocked_count += 1
        elif runner_manifest_status == "failed":
            status = "failed"
            reason = "Runtime device runner manifest is invalid."
            failed_count += 1
        elif target_text in ready_runners_by_target:
            status = "ready"
            reason = "Runtime package, adapter descriptor, and runner are ready."
            ready_count += 1
        else:
            status = "blocked"
            reason = "No ready runtime device runner was found for this target."
            blocked_count += 1
        target_payload = {
            "target": target_name,
            "status": status,
            "reason": reason,
        }
        if status == "ready" and target_text in ready_runners_by_target:
            target_payload["runner"] = ready_runners_by_target[target_text].get("id")
        target_payloads.append(target_payload)

    status = "empty"
    if failed_count:
        status = "failed"
    elif ready_count and not blocked_count:
        status = "ready"
    elif ready_count:
        status = "partial"
    elif blocked_count:
        if adapter_status == "not-provided":
            status = "not-configured"
        elif runner_manifest_status == "not-provided":
            status = "ready-for-runner"
        else:
            status = "blocked"
    return {
        "mode": "adapter-backed-device-dispatch",
        "status": status,
        "runner": None,
        "adapterPackageStatus": adapter_status,
        "runnerManifestStatus": runner_manifest_status,
        "packageRootStatus": package_root_status,
        "targetCount": len(target_payloads),
        "readyTargetCount": ready_count,
        "blockedTargetCount": blocked_count,
        "failedTargetCount": failed_count,
        "verifiedDescriptorCount": adapter_package.get("verifiedDescriptorCount", 0),
        "targets": target_payloads,
    }


def execute_runtime_host_integration(
    execution_plan_path: str | os.PathLike[str],
    *,
    host_root: str | os.PathLike[str] | None = None,
    scaffold_root: str | os.PathLike[str] | None = None,
    package_root: str | os.PathLike[str] | None = None,
    adapter_root: str | os.PathLike[str] | None = None,
    runner_manifest: str | os.PathLike[str] | None = None,
) -> dict[str, Any]:
    """Execute deterministic host integration checks from an execution plan."""

    plan_path = _filesystem_path_arg(
        execution_plan_path, field_name="Host integration execution plan path"
    )
    plan, load_diagnostics = _runtime_host_integration_execution_load_plan(plan_path)
    diagnostics = list(load_diagnostics)
    if plan:
        diagnostics.extend(
            _runtime_host_integration_execution_plan_diagnostics(plan_path, plan)
        )
    host_root_value, host_root_status, host_root_diagnostics = (
        _runtime_host_integration_execution_result_host_root(
            host_root, plan, plan_path=plan_path
        )
    )
    package_root_path, package_root_value, package_root_status, package_diagnostics = (
        _runtime_host_integration_execution_package_root(
            package_root, plan_path=plan_path
        )
    )
    (
        scaffold_root_path,
        scaffold_root_value,
        scaffold_root_status,
        scaffold_diagnostics,
    ) = _runtime_host_integration_execution_scaffold_root(
        scaffold_root, plan_path=plan_path
    )
    adapter_root_path, adapter_root_value, adapter_root_status, adapter_diagnostics = (
        _runtime_host_integration_execution_adapter_root(
            adapter_root, plan_path=plan_path
        )
    )
    adapter_package, adapter_package_diagnostics = (
        _runtime_host_integration_execution_adapter_manifest(
            adapter_root_path,
            plan_path=plan_path,
        )
    )
    (
        device_runner_manifest,
        device_runner_manifest_value,
        device_runner_manifest_status,
        runner_manifest_diagnostics,
    ) = _runtime_host_integration_execution_runner_manifest(
        runner_manifest,
        plan_path=plan_path,
    )
    diagnostics.extend(host_root_diagnostics)
    diagnostics.extend(package_diagnostics)
    diagnostics.extend(scaffold_diagnostics)
    diagnostics.extend(adapter_diagnostics)
    diagnostics.extend(adapter_package_diagnostics)
    diagnostics.extend(runner_manifest_diagnostics)

    diagnostics_payload = [diagnostic.to_json() for diagnostic in diagnostics]
    plan_ready = bool(plan) and not any(
        diagnostic.severity == "error" for diagnostic in diagnostics
    )
    step_results: list[dict[str, Any]] = []
    if plan_ready:
        for step in _record_sequence(plan.get("steps")):
            if not isinstance(step, Mapping):
                continue
            result, step_diagnostics = _runtime_host_integration_execution_step_result(
                step,
                plan_path=plan_path,
                scaffold_root=scaffold_root_path,
                package_root=package_root_path,
            )
            step_results.append(result)
            diagnostics_payload.extend(
                diagnostic.to_json() for diagnostic in step_diagnostics
            )

    passed_steps = [
        step for step in step_results if step.get("resultStatus") == "passed"
    ]
    skipped_steps = [
        step for step in step_results if step.get("resultStatus") == "skipped"
    ]
    blocked_steps = [
        step for step in step_results if step.get("resultStatus") == "blocked"
    ]
    failed_steps = [
        step for step in step_results if step.get("resultStatus") == "failed"
    ]
    targets = [
        dict(target)
        for target in _record_sequence(plan.get("targets"))
        if isinstance(target, Mapping)
    ]
    required_tools = sorted(
        {
            tool
            for target in targets
            for tool in _record_sequence(target.get("requiredTools"))
            if _is_non_empty_string(tool)
        }
    )
    host_responsibilities = sorted(
        {
            responsibility
            for target in targets
            for responsibility in _record_sequence(target.get("hostResponsibilities"))
            if _is_non_empty_string(responsibility)
        }
    )
    status = _runtime_host_integration_execution_result_status(
        step_results, diagnostics_payload
    )
    device_execution = _runtime_host_integration_execution_result_device_execution(
        targets,
        package_root_status=package_root_status,
        adapter_package=adapter_package,
        runner_manifest=device_runner_manifest,
    )
    return {
        "schemaVersion": REPORT_SCHEMA_VERSION,
        "kind": RUNTIME_HOST_INTEGRATION_EXECUTION_RESULT_KIND,
        "sourceExecutionPlan": str(plan_path),
        "sourceExecutionPlanHash": _optional_source_hash(plan_path),
        "generatedAt": int(time.time()),
        "success": status != "failed",
        "status": status,
        "scope": RUNTIME_HOST_INTEGRATION_EXECUTION_RESULT_SCOPE,
        "nonGoals": list(RUNTIME_HOST_INTEGRATION_EXECUTION_RESULT_NON_GOALS),
        "handoffRoot": plan.get("handoffRoot") if plan else None,
        "hostRoot": host_root_value,
        "hostRootStatus": host_root_status,
        "scaffoldRoot": scaffold_root_value,
        "scaffoldRootStatus": scaffold_root_status,
        "packageRoot": package_root_value,
        "packageRootStatus": package_root_status,
        "adapterRoot": adapter_root_value,
        "adapterRootStatus": adapter_root_status,
        "adapterPackage": adapter_package,
        "deviceRunnerManifest": device_runner_manifest_value,
        "deviceRunnerManifestStatus": device_runner_manifest_status,
        "project": (
            dict(plan.get("project"))
            if isinstance(plan.get("project"), Mapping)
            else {"targets": []}
        ),
        "summary": {
            "targetCount": len(targets),
            "stepCount": len(step_results),
            "passedStepCount": len(passed_steps),
            "skippedStepCount": len(skipped_steps),
            "blockedStepCount": len(blocked_steps),
            "failedStepCount": len(failed_steps),
            "requiredToolCount": len(required_tools),
            "hostResponsibilityCount": len(host_responsibilities),
        },
        "targets": [
            _runtime_host_integration_execution_result_target(target, step_results)
            for target in targets
        ],
        "stepResults": step_results,
        "deviceExecution": device_execution,
        "executionPlan": {
            "kind": plan.get("kind") if plan else None,
            "success": plan.get("success") if plan else False,
            "status": plan.get("status") if plan else "failed",
            "stepCount": (
                (
                    plan.get("summary", {}).get("stepCount", 0)
                    if isinstance(plan.get("summary"), Mapping)
                    else 0
                )
                if plan
                else 0
            ),
        },
        "diagnosticCounts": _diagnostic_payload_counts(diagnostics_payload),
        "diagnostics": diagnostics_payload,
    }


def _inspection_artifact_matrix_summary(
    artifact_matrix: Any,
    artifacts: Any,
    *,
    project: Any = None,
    units: Any = None,
    sample_limit: int = ARTIFACT_MATRIX_INSPECTION_SAMPLE_LIMIT,
) -> dict[str, Any]:
    sample_limit = max(0, sample_limit)
    artifact_records = _record_sequence(artifacts)
    if not isinstance(artifact_matrix, Mapping) and not artifact_records:
        return {"available": False}

    matrix_source = "report"
    for _attempt in range(2):
        if isinstance(artifact_matrix, Mapping):
            fields = {
                field_name: artifact_matrix.get(field_name)
                for field_name in (
                    "unitCount",
                    "targetCount",
                    "variantCount",
                    "expectedArtifactCount",
                )
            }
            variant_mode = artifact_matrix.get("variantMode")
            if all(
                isinstance(value, int) and not isinstance(value, bool) and value >= 0
                for value in fields.values()
            ) and variant_mode in {"none", "named"}:
                break
        if matrix_source == "derived" or not isinstance(project, Mapping):
            return {"available": False}
        artifact_matrix = _expected_artifact_matrix_metadata(
            project, units, artifact_records
        )
        matrix_source = "derived"
    else:  # pragma: no cover - loop always returns or breaks within two attempts
        return {"available": False}

    emitted_count = len(artifact_records)
    translated_count = sum(
        1 for artifact in artifact_records if artifact.get("status") == "translated"
    )
    failed_count = sum(
        1 for artifact in artifact_records if artifact.get("status") == "failed"
    )
    expected_count = fields["expectedArtifactCount"]
    (
        expected_identities,
        emitted_identities,
    ) = _inspection_artifact_matrix_identity_sets(
        project,
        units,
        artifact_records,
    )
    identity_coverage_available = (
        expected_identities is not None and emitted_identities is not None
    )
    if expected_identities is None or emitted_identities is None:
        missing_identities = None
        extra_identities = None
        missing_count = max(0, expected_count - emitted_count)
        extra_count = max(0, emitted_count - expected_count)
        status_by_target = {}
        status_by_source_backend = {}
        status_by_variant = {}
    else:
        missing_identities = expected_identities - emitted_identities
        extra_identities = emitted_identities - expected_identities
        missing_count = len(missing_identities)
        extra_count = len(extra_identities)
        source_backend_by_identity = _artifact_matrix_source_backend_by_identity(
            expected_identities,
            artifact_records,
            _artifact_matrix_unit_source_backends(_record_sequence(units)),
        )
        status_by_target = _artifact_matrix_status_by_field(
            expected_identities,
            artifact_records,
            missing_identities,
            extra_identities,
            "target",
        )
        status_by_source_backend = _artifact_matrix_status_by_field(
            expected_identities,
            artifact_records,
            missing_identities,
            extra_identities,
            "sourceBackend",
            source_backend_by_identity=source_backend_by_identity,
        )
        status_by_variant = _artifact_matrix_status_by_field(
            expected_identities,
            artifact_records,
            missing_identities,
            extra_identities,
            "variant",
        )
    missing_identity_list = sorted(missing_identities or ())
    extra_identity_list = sorted(extra_identities or ())
    missing_samples = [
        _artifact_identity_payload(identity)
        for identity in missing_identity_list[:sample_limit]
    ]
    extra_samples = [
        _artifact_identity_payload(identity)
        for identity in extra_identity_list[:sample_limit]
    ]
    return {
        "available": True,
        "source": matrix_source,
        **fields,
        "variantMode": variant_mode,
        "emittedArtifactCount": emitted_count,
        "translatedCount": translated_count,
        "failedCount": failed_count,
        "identityCoverageAvailable": identity_coverage_available,
        "missingArtifactCount": missing_count,
        "extraArtifactCount": extra_count,
        "missingArtifacts": missing_samples,
        "extraArtifacts": extra_samples,
        "truncatedMissingArtifactCount": max(0, missing_count - len(missing_samples)),
        "truncatedExtraArtifactCount": max(0, extra_count - len(extra_samples)),
        "complete": missing_count == 0 and extra_count == 0,
        "statusByTarget": status_by_target,
        "statusBySourceBackend": status_by_source_backend,
        "statusByVariant": status_by_variant,
    }


def _inspection_validation_artifact(artifact: Any) -> dict[str, Any] | None:
    if not isinstance(artifact, Mapping):
        return None

    sample = {
        "source": artifact.get("source"),
        "sourceBackend": artifact.get("sourceBackend"),
        "target": artifact.get("target"),
        "path": artifact.get("path"),
        "stage": artifact.get("stage"),
        "status": artifact.get("status"),
        "exists": artifact.get("exists"),
        "sourceHashStatus": artifact.get("sourceHashStatus"),
        "sourceSizeStatus": artifact.get("sourceSizeStatus"),
        "generatedHashStatus": artifact.get("generatedHashStatus"),
        "generatedSizeStatus": artifact.get("generatedSizeStatus"),
        "sourceMapStatus": artifact.get("sourceMapStatus"),
        "sourceRemapStatus": artifact.get("sourceRemapStatus"),
    }
    if "variant" in artifact:
        sample["variant"] = artifact.get("variant")
    return {key: value for key, value in sample.items() if value is not None}


def _inspection_validation_toolchain_run(run: Any) -> dict[str, Any] | None:
    if not isinstance(run, Mapping):
        return None

    sample = {
        "source": run.get("source"),
        "sourceBackend": run.get("sourceBackend"),
        "target": run.get("target"),
        "path": run.get("path"),
        "stage": run.get("stage"),
        "checkKind": run.get("checkKind"),
        "status": run.get("status"),
        "returncode": run.get("returncode"),
    }
    returncode = run.get("returncode")
    if run.get("status") == "failed" or (
        isinstance(returncode, int) and not isinstance(returncode, bool) and returncode
    ):
        failure_reason = _toolchain_run_failure_reason(run)
        if failure_reason:
            sample["failureReason"] = failure_reason
    command = run.get("command")
    if isinstance(command, list) and all(
        _is_non_empty_string(part) for part in command
    ):
        sample["command"] = list(command)
    for field_name in ("stdout", "stderr"):
        value = run.get(field_name)
        if isinstance(value, str):
            sample[f"{field_name}Length"] = len(value)
    if "variant" in run:
        sample["variant"] = run.get("variant")
    return {key: value for key, value in sample.items() if value is not None}


def _inspection_artifact_matrix_identity_sets(
    project: Any,
    units: Any,
    artifact_records: Sequence[Mapping[str, Any]],
) -> tuple[set[ArtifactIdentity] | None, set[ArtifactIdentity] | None]:
    if not isinstance(project, Mapping) or not isinstance(units, list):
        return None, None

    root = project.get("root")
    output_dir = project.get("outputDir")
    targets = project.get("targets")
    variants = project.get("variants", {})
    if not (
        _is_non_empty_string(root)
        and _is_non_empty_string(output_dir)
        and isinstance(targets, list)
        and all(_is_non_empty_string(target) for target in targets)
        and isinstance(variants, Mapping)
        and all(_is_non_empty_string(name) for name in variants)
    ):
        return None, None

    root_path = Path(root).resolve()
    project_output_path = _project_output_path(root_path, output_dir).resolve()
    variant_names: list[str | None] = sorted(variants) if variants else [None]
    preserve_source_suffix = _artifact_source_suffix_pairs(units, targets)
    expected_identities = _expected_artifact_identities(
        root_path,
        project_output_path,
        units,
        _normalized_targets(targets),
        variant_names,
        preserve_source_suffix,
        artifacts=artifact_records,
        variants_by_source_target=_report_translation_variants_by_source_target(
            project,
            units,
            targets,
        ),
    )

    emitted_identities = {
        identity
        for artifact in artifact_records
        for identity in (_artifact_identity(artifact),)
        if identity is not None
    }
    return expected_identities, emitted_identities


def _artifact_identity_payload(identity: ArtifactIdentity) -> dict[str, Any]:
    source, target, path, variant = identity
    payload = {
        "source": source,
        "target": target,
        "path": path,
    }
    if variant is not None:
        payload["variant"] = variant
    return payload


def _inspection_project_summary(project: Any) -> dict[str, Any]:
    if not isinstance(project, Mapping):
        return {}
    summary = {
        "root": project.get("root"),
        "targets": (
            list(project.get("targets", []))
            if isinstance(project.get("targets"), list)
            else []
        ),
        "outputDir": project.get("outputDir"),
    }
    if "config" in project:
        summary["config"] = project.get("config")
    config_hash = project.get("configHash")
    if isinstance(config_hash, Mapping):
        summary["configHash"] = dict(config_hash)
    for field_name in (
        "sourceRoots",
        "includePatterns",
        "excludePatterns",
        "includeDirs",
    ):
        values = project.get(field_name)
        if isinstance(values, list):
            summary[field_name] = [value for value in values if isinstance(value, str)]
    defines = project.get("defines")
    if isinstance(defines, Mapping):
        define_names = _inspection_define_names(defines)
        summary["defineNames"] = define_names
        if define_names:
            summary["defineFingerprint"] = _inspection_define_fingerprint(defines)
    for field_name in (
        "sourceRootCount",
        "sourceRootStatus",
        "sourceRootStatusCounts",
        "includePatternCount",
        "excludePatternCount",
        "sourceOverrideCount",
        "includeDirCount",
        "includeDirStatus",
        "includeDirStatusCounts",
        "defineCount",
        "variantCount",
        "variantDefineCounts",
        "dispatchContractCount",
        "dispatchVariantCount",
        "dispatchArtifactCount",
        "externalCorpusManifest",
    ):
        if field_name in project:
            summary[field_name] = project[field_name]
    source_overrides = project.get("sourceOverrides")
    if isinstance(source_overrides, Mapping):
        summary["sourceOverrides"] = {
            path: backend
            for path, backend in sorted(source_overrides.items())
            if isinstance(path, str) and isinstance(backend, str)
        }
    variants = project.get("variants")
    if isinstance(variants, Mapping):
        summary["variantNames"] = sorted(
            name for name in variants if isinstance(name, str) and name
        )
        variant_define_names = {}
        variant_define_fingerprints = {}
        for name, defines in sorted(variants.items()):
            if (
                not isinstance(name, str)
                or not name
                or not isinstance(defines, Mapping)
            ):
                continue
            define_names = _inspection_define_names(defines)
            variant_define_names[name] = define_names
            if define_names:
                variant_define_fingerprints[name] = _inspection_define_fingerprint(
                    defines
                )
        summary["variantDefineNames"] = variant_define_names
        summary["variantDefineFingerprints"] = variant_define_fingerprints
        if "variantDefineCounts" not in summary:
            summary["variantDefineCounts"] = _variant_define_counts(variants)
    selected_variants = project.get("selectedVariants")
    if isinstance(selected_variants, list):
        summary["selectedVariants"] = [
            name for name in selected_variants if isinstance(name, str) and name
        ]
    dispatch_contract_files = project.get("dispatchContractFiles")
    if isinstance(dispatch_contract_files, list):
        summary["dispatchContractFiles"] = [
            path for path in dispatch_contract_files if isinstance(path, str) and path
        ]
    return summary


def _inspection_define_names(defines: Mapping[Any, Any]) -> list[str]:
    return sorted(name for name in defines if _is_non_empty_string(name))


def _inspection_define_fingerprint(defines: Mapping[Any, Any]) -> dict[str, str]:
    normalized = {
        name: value
        for name, value in sorted(defines.items())
        if _is_non_empty_string(name) and isinstance(value, str)
    }
    encoded = json.dumps(
        normalized,
        sort_keys=True,
        separators=(",", ":"),
    ).encode("utf-8")
    return {
        "algorithm": "sha256",
        "value": hashlib.sha256(encoded).hexdigest(),
    }


def _inspection_define_processing_config_context(project: Any) -> dict[str, Any]:
    context: dict[str, Any] = {
        "projectDefineCount": 0,
        "projectDefineNames": [],
        "variantCount": 0,
        "selectedVariantCount": 0,
        "selectedVariants": [],
        "variantDefineRecords": [],
    }
    if not isinstance(project, Mapping):
        return context

    defines = project.get("defines")
    if isinstance(defines, Mapping):
        define_names = _inspection_define_names(defines)
        context["projectDefineCount"] = len(define_names)
        context["projectDefineNames"] = define_names
        if define_names:
            context["projectDefineFingerprint"] = _inspection_define_fingerprint(
                defines
            )

    selected_variant_values = project.get("selectedVariants")
    selected_variants = (
        [name for name in selected_variant_values if _is_non_empty_string(name)]
        if isinstance(selected_variant_values, list)
        else []
    )
    context["selectedVariantCount"] = len(selected_variants)
    context["selectedVariants"] = selected_variants
    selected_variant_names = set(selected_variants)

    variant_records = []
    variants = project.get("variants")
    if isinstance(variants, Mapping):
        for name, variant_defines in sorted(variants.items()):
            if not _is_non_empty_string(name) or not isinstance(
                variant_defines, Mapping
            ):
                continue
            define_names = _inspection_define_names(variant_defines)
            record = {
                "name": name,
                "defineCount": len(define_names),
                "defineNames": define_names,
                "selected": name in selected_variant_names,
            }
            if define_names:
                record["defineFingerprint"] = _inspection_define_fingerprint(
                    variant_defines
                )
            variant_records.append(record)
    context["variantCount"] = len(variant_records)
    context["variantDefineRecords"] = variant_records
    return context


def _inspection_skipped_source_sample(
    record: Mapping[str, Any],
) -> dict[str, Any] | None:
    path = record.get("path")
    reason = record.get("reason")
    if not (_is_non_empty_string(path) and _is_non_empty_string(reason)):
        return None
    sample = {
        "path": path,
        "reason": reason,
        "extension": _extension_rollup_key(Path(path).suffix.lower()),
    }
    source_override = record.get("sourceOverride")
    if _is_non_empty_string(source_override):
        sample["sourceOverride"] = source_override
    return sample


def _inspection_skipped_source_summary(
    summary: Any,
    skipped: Any = None,
    *,
    sample_limit: int = SKIPPED_SOURCE_INSPECTION_SAMPLE_LIMIT,
) -> dict[str, Any]:
    sample_limit = max(0, sample_limit)
    if not isinstance(summary, Mapping):
        return {"available": False}

    by_reason = summary.get("skippedByReason")
    by_extension = summary.get("skippedByExtension")
    by_source_override = summary.get("skippedBySourceOverride")
    if not isinstance(by_reason, Mapping) or not isinstance(by_extension, Mapping):
        return {"available": False}

    skipped_sources = [
        sample
        for record in _record_sequence(skipped)
        if isinstance(record, Mapping)
        for sample in (_inspection_skipped_source_sample(record),)
        if sample is not None
    ]
    return {
        "available": True,
        "skippedCount": len(skipped_sources),
        "truncatedSkippedCount": max(0, len(skipped_sources) - sample_limit),
        "byReason": dict(by_reason),
        "byExtension": dict(by_extension),
        "bySourceOverride": (
            dict(by_source_override) if isinstance(by_source_override, Mapping) else {}
        ),
        "sources": skipped_sources[:sample_limit],
    }


def _inspection_define_processing_artifact(
    artifact: Mapping[str, Any],
) -> dict[str, Any] | None:
    define_processing = artifact.get("defineProcessing")
    if not isinstance(define_processing, Mapping):
        return None
    define_count = define_processing.get("defineCount")

    sample = {
        "source": artifact.get("source"),
        "sourceBackend": artifact.get("sourceBackend"),
        "target": artifact.get("target"),
        "path": artifact.get("path"),
        "status": define_processing.get("status"),
        "frontend": define_processing.get("frontend"),
        "supportsDefines": define_processing.get("supportsDefines"),
    }
    if (
        isinstance(define_count, int)
        and not isinstance(define_count, bool)
        and define_count >= 0
    ):
        sample["defineCount"] = define_count
    defines = artifact.get("defines")
    if isinstance(defines, Mapping):
        define_names = sorted(name for name in defines if _is_non_empty_string(name))
        if define_names:
            sample["defineNames"] = define_names
            sample["defineFingerprint"] = _inspection_define_fingerprint(defines)
    if "variant" in artifact:
        sample["variant"] = artifact.get("variant")
    return {key: value for key, value in sample.items() if value is not None}


def _inspection_unsupported_define_processing_artifact(
    artifact: Mapping[str, Any],
) -> dict[str, Any] | None:
    sample = _inspection_define_processing_artifact(artifact)
    if sample is None or sample.get("status") != "not-supported":
        return None
    define_count = sample.get("defineCount")
    if (
        not isinstance(define_count, int)
        or isinstance(define_count, bool)
        or define_count <= 0
    ):
        return None
    return sample


def _inspection_define_processing_summary(
    summary: Any,
    artifacts: Any = None,
    *,
    project: Any = None,
    sample_limit: int = DEFINE_PROCESSING_INSPECTION_SAMPLE_LIMIT,
) -> dict[str, Any]:
    sample_limit = max(0, sample_limit)
    if not isinstance(summary, Mapping):
        return {"available": False}

    by_status = summary.get("defineProcessingByStatus")
    by_source_backend = summary.get("defineProcessingBySourceBackend")
    by_target = summary.get("defineProcessingByTarget")
    by_variant = summary.get("defineProcessingByVariant")
    if not isinstance(by_status, Mapping) or not isinstance(by_source_backend, Mapping):
        return {"available": False}

    define_processing_artifacts = []
    not_supported_artifacts = []
    for artifact in _record_sequence(artifacts):
        if not isinstance(artifact, Mapping):
            continue
        sample = _inspection_define_processing_artifact(artifact)
        if sample:
            define_processing_artifacts.append(sample)
        sample = _inspection_unsupported_define_processing_artifact(artifact)
        if sample:
            not_supported_artifacts.append(sample)

    config_context = _inspection_define_processing_config_context(project)

    return {
        "available": True,
        "byStatus": dict(by_status),
        "bySourceBackend": {
            source_backend: dict(counts)
            for source_backend, counts in by_source_backend.items()
            if isinstance(source_backend, str) and isinstance(counts, Mapping)
        },
        "byTarget": (
            {
                target: dict(counts)
                for target, counts in by_target.items()
                if isinstance(target, str) and isinstance(counts, Mapping)
            }
            if isinstance(by_target, Mapping)
            else {}
        ),
        "byVariant": (
            {
                variant: dict(counts)
                for variant, counts in by_variant.items()
                if isinstance(variant, str) and isinstance(counts, Mapping)
            }
            if isinstance(by_variant, Mapping)
            else {}
        ),
        **config_context,
        "artifactCount": len(define_processing_artifacts),
        "truncatedArtifactCount": max(
            0,
            len(define_processing_artifacts) - sample_limit,
        ),
        "artifacts": define_processing_artifacts[:sample_limit],
        "notSupportedArtifactCount": len(not_supported_artifacts),
        "truncatedNotSupportedArtifactCount": max(
            0,
            len(not_supported_artifacts) - sample_limit,
        ),
        "notSupportedArtifacts": not_supported_artifacts[:sample_limit],
    }


