def _source_map_span_reasons(prefix: str, value: Any) -> list[str]:
    if not isinstance(value, Mapping):
        return [f"{prefix} must be an object"]

    reasons = _unsupported_mapping_field_reasons(
        prefix, value, SOURCE_MAP_SPAN_FIELD_SET
    )
    if not _is_non_empty_string(value.get("file")):
        reasons.append(f"{prefix}.file must be a string")
    for field_name in SOURCE_MAP_SPAN_FIELDS[1:]:
        if not _is_non_negative_int(value.get(field_name)):
            reasons.append(f"{prefix}.{field_name} must be a non-negative integer")
    if reasons:
        return reasons

    reasons.extend(_span_consistency_contract_reasons(prefix, value))
    return reasons


def _source_map_anchor_reasons(
    index: int, source_map: Mapping[str, Any], artifact: Mapping[str, Any]
) -> list[str]:
    prefix = f"artifacts[{index}].sourceMap"
    reasons = []
    source = source_map.get("source")
    generated = source_map.get("generated")
    is_file_granularity = source_map.get("mappingGranularity") == "file"

    if isinstance(source, Mapping) and _is_non_empty_string(source.get("file")):
        if _is_non_empty_string(artifact.get("source")):
            if source.get("file") != artifact.get("source"):
                reasons.append(
                    f"{prefix}.source.file must match artifacts[{index}].source "
                    f"({_value_mismatch_context(source.get('file'), artifact.get('source'))})"
                )
    if isinstance(generated, Mapping) and _is_non_empty_string(generated.get("file")):
        if _is_non_empty_string(artifact.get("path")):
            if generated.get("file") != artifact.get("path"):
                reasons.append(
                    f"{prefix}.generated.file must match artifacts[{index}].path "
                    f"({_value_mismatch_context(generated.get('file'), artifact.get('path'))})"
                )

    mappings = source_map.get("mappings")
    if not isinstance(mappings, list):
        return reasons

    for mapping_index, mapping in enumerate(mappings):
        mapping_prefix = f"{prefix}.mappings[{mapping_index}]"
        if not isinstance(mapping, Mapping):
            continue
        mapping_source = mapping.get("source")
        if isinstance(source, Mapping) and isinstance(mapping_source, Mapping):
            if is_file_granularity:
                if dict(mapping_source) != dict(source):
                    reasons.append(
                        f"{mapping_prefix}.source must match {prefix}.source "
                        f"({_value_mismatch_context(dict(mapping_source), dict(source))})"
                    )
            elif (
                _is_non_empty_string(source.get("file"))
                and _is_non_empty_string(mapping_source.get("file"))
                and mapping_source.get("file") != source.get("file")
            ):
                reasons.append(
                    f"{mapping_prefix}.source.file must match {prefix}.source.file "
                    f"({_value_mismatch_context(mapping_source.get('file'), source.get('file'))})"
                )
        mapping_generated = mapping.get("generated")
        if isinstance(generated, Mapping) and isinstance(mapping_generated, Mapping):
            if is_file_granularity:
                if dict(mapping_generated) != dict(generated):
                    reasons.append(
                        f"{mapping_prefix}.generated must match {prefix}.generated "
                        f"({_value_mismatch_context(dict(mapping_generated), dict(generated))})"
                    )
            elif (
                _is_non_empty_string(generated.get("file"))
                and _is_non_empty_string(mapping_generated.get("file"))
                and mapping_generated.get("file") != generated.get("file")
            ):
                reasons.append(
                    f"{mapping_prefix}.generated.file must match "
                    f"{prefix}.generated.file "
                    f"({_value_mismatch_context(mapping_generated.get('file'), generated.get('file'))})"
                )
    return reasons


def _fine_grained_source_map_span_reasons(prefix: str, value: Any) -> list[str]:
    if not isinstance(value, Mapping):
        return []
    reasons = []
    if _is_non_negative_int(value.get("length")) and value["length"] <= 0:
        reasons.append(f"{prefix}.length must be greater than zero")
    return reasons


def _source_map_span_within_anchor_reasons(
    prefix: str,
    value: Any,
    anchor: Any,
    anchor_prefix: str,
) -> list[str]:
    if not isinstance(value, Mapping) or not isinstance(anchor, Mapping):
        return []
    offset = value.get("offset")
    end_offset = value.get("endOffset")
    anchor_offset = anchor.get("offset")
    anchor_end_offset = anchor.get("endOffset")
    if not all(
        _is_non_negative_int(candidate)
        for candidate in (offset, end_offset, anchor_offset, anchor_end_offset)
    ):
        return []
    out_of_bounds = offset < anchor_offset or end_offset > anchor_end_offset
    line = value.get("line")
    column = value.get("column")
    end_line = value.get("endLine")
    end_column = value.get("endColumn")
    anchor_line = anchor.get("line")
    anchor_column = anchor.get("column")
    anchor_end_line = anchor.get("endLine")
    anchor_end_column = anchor.get("endColumn")
    if all(
        _is_non_negative_int(candidate)
        for candidate in (
            line,
            column,
            end_line,
            end_column,
            anchor_line,
            anchor_column,
            anchor_end_line,
            anchor_end_column,
        )
    ):
        out_of_bounds = (
            out_of_bounds
            or (line, column) < (anchor_line, anchor_column)
            or (end_line, end_column) > (anchor_end_line, anchor_end_column)
        )
    if out_of_bounds:
        return [f"{prefix} must be within {anchor_prefix}"]
    return []


def _source_map_contract_reasons(
    index: int,
    artifact: Mapping[str, Any],
    *,
    required: bool = False,
    declared_targets: set[str] | None = None,
    require_canonical: bool = False,
) -> list[str]:
    if "sourceMap" not in artifact:
        if required:
            return [f"artifacts[{index}].sourceMap must be an object"]
        return []

    prefix = f"artifacts[{index}].sourceMap"
    source_map = artifact.get("sourceMap")
    if not isinstance(source_map, Mapping):
        return [f"{prefix} must be an object"]

    reasons = _unsupported_mapping_field_reasons(
        prefix, source_map, SOURCE_MAP_PAYLOAD_FIELDS
    )
    if source_map.get("schemaVersion") != 1:
        reasons.append(f"{prefix}.schemaVersion must be 1")
    if source_map.get("kind") != "crosstl-artifact-source-map":
        reasons.append(f"{prefix}.kind must be crosstl-artifact-source-map")
    mapping_granularity = source_map.get("mappingGranularity")
    if mapping_granularity not in SOURCE_MAP_GRANULARITIES:
        reasons.append(
            f"{prefix}.mappingGranularity must be one of "
            f"{', '.join(SOURCE_MAP_GRANULARITIES)}"
        )

    target = source_map.get("target")
    target_reasons = _target_name_contract_reasons(
        f"{prefix}.target",
        target,
        declared_targets=declared_targets,
        require_canonical=require_canonical,
    )
    reasons.extend(target_reasons)
    if (
        _is_non_empty_string(target)
        and _is_non_empty_string(artifact.get("target"))
        and target != artifact["target"]
    ):
        reasons.append(
            f"{prefix}.target must match artifacts[{index}].target "
            f"({_value_mismatch_context(target, artifact['target'])})"
        )

    reasons.extend(
        _source_map_span_reasons(f"{prefix}.source", source_map.get("source"))
    )
    reasons.extend(
        _source_map_span_reasons(f"{prefix}.generated", source_map.get("generated"))
    )
    source_anchor = source_map.get("source")
    generated_anchor = source_map.get("generated")

    mappings = source_map.get("mappings")
    if not isinstance(mappings, list):
        reasons.append(f"{prefix}.mappings must be a list")
    elif not mappings:
        reasons.append(f"{prefix}.mappings must not be empty")
    elif mapping_granularity == "file" and len(mappings) != 1:
        reasons.append(f"{prefix}.mappings must contain one file-level mapping")
    else:
        for mapping_index, mapping in enumerate(mappings):
            mapping_prefix = f"{prefix}.mappings[{mapping_index}]"
            if not isinstance(mapping, Mapping):
                reasons.append(f"{mapping_prefix} must be an object")
                continue
            reasons.extend(
                _unsupported_mapping_field_reasons(
                    mapping_prefix, mapping, SOURCE_MAP_MAPPING_FIELDS
                )
            )
            reasons.extend(
                _source_map_span_reasons(
                    f"{mapping_prefix}.source", mapping.get("source")
                )
            )
            reasons.extend(
                _source_map_span_reasons(
                    f"{mapping_prefix}.generated", mapping.get("generated")
                )
            )
            if mapping_granularity != "file":
                reasons.extend(
                    _fine_grained_source_map_span_reasons(
                        f"{mapping_prefix}.source", mapping.get("source")
                    )
                )
                reasons.extend(
                    _source_map_span_within_anchor_reasons(
                        f"{mapping_prefix}.source",
                        mapping.get("source"),
                        source_anchor,
                        f"{prefix}.source",
                    )
                )
                reasons.extend(
                    _fine_grained_source_map_span_reasons(
                        f"{mapping_prefix}.generated", mapping.get("generated")
                    )
                )
                reasons.extend(
                    _source_map_span_within_anchor_reasons(
                        f"{mapping_prefix}.generated",
                        mapping.get("generated"),
                        generated_anchor,
                        f"{prefix}.generated",
                    )
                )

    reasons.extend(_source_map_anchor_reasons(index, source_map, artifact))
    return reasons


def _source_remap_contract_reasons(
    index: int,
    artifact: Mapping[str, Any],
    *,
    required: bool = False,
    require_closed_fields: bool = False,
    declared_targets: set[str] | None = None,
    require_canonical: bool = False,
) -> list[str]:
    if "sourceRemap" not in artifact:
        if required:
            return [f"artifacts[{index}].sourceRemap must be an object"]
        return []

    prefix = f"artifacts[{index}].sourceRemap"
    source_remap = artifact.get("sourceRemap")
    if not isinstance(source_remap, Mapping):
        return [f"{prefix} must be an object"]

    reasons = (
        _unsupported_mapping_field_reasons(
            prefix, source_remap, REPORT_ARTIFACT_SOURCE_REMAP_FIELDS
        )
        if require_closed_fields
        else []
    )
    if source_remap.get("schemaVersion") != SOURCE_REMAP_SCHEMA_VERSION:
        reasons.append(f"{prefix}.schemaVersion must be 1")

    path = source_remap.get("path")
    if not _is_non_empty_string(path):
        reasons.append(f"{prefix}.path must be a string")
    elif not _is_report_identity_path(path):
        reasons.append(f"{prefix}.path must be repository-relative")

    artifact_path = artifact.get("path")
    if _is_non_empty_string(path) and _is_non_empty_string(artifact_path):
        expected_path = _source_remap_report_path(artifact_path)
        if path != expected_path:
            reasons.append(
                f"{prefix}.path must match artifacts[{index}].path "
                f"({_value_mismatch_context(path, expected_path)})"
            )

    target = source_remap.get("target")
    target_reasons = _target_name_contract_reasons(
        f"{prefix}.target",
        target,
        declared_targets=declared_targets,
        require_canonical=require_canonical,
    )
    reasons.extend(target_reasons)
    if (
        _is_non_empty_string(target)
        and _is_non_empty_string(artifact.get("target"))
        and target != artifact["target"]
    ):
        reasons.append(
            f"{prefix}.target must match artifacts[{index}].target "
            f"({_value_mismatch_context(target, artifact['target'])})"
        )

    generated_file = source_remap.get("generatedFile")
    if not _is_non_empty_string(generated_file):
        reasons.append(f"{prefix}.generatedFile must be a string")
    elif _is_non_empty_string(artifact_path) and generated_file != artifact_path:
        reasons.append(
            f"{prefix}.generatedFile must match artifacts[{index}].path "
            f"({_value_mismatch_context(generated_file, artifact_path)})"
        )

    mapping_granularity = source_remap.get("mappingGranularity")
    source_map = artifact.get("sourceMap")
    if mapping_granularity not in SOURCE_MAP_GRANULARITIES:
        reasons.append(
            f"{prefix}.mappingGranularity must be one of "
            f"{', '.join(SOURCE_MAP_GRANULARITIES)}"
        )
    else:
        if isinstance(source_map, Mapping):
            source_map_granularity = source_map.get("mappingGranularity")
            if (
                source_map_granularity in SOURCE_MAP_GRANULARITIES
                and mapping_granularity != source_map_granularity
            ):
                reasons.append(
                    f"{prefix}.mappingGranularity must match "
                    f"artifacts[{index}].sourceMap.mappingGranularity "
                    f"({_value_mismatch_context(mapping_granularity, source_map_granularity)})"
                )
    mapping_count = source_remap.get("mappingCount")
    if mapping_count is None:
        if required:
            reasons.append(f"{prefix}.mappingCount must be a non-negative integer")
    elif not _is_non_negative_int(mapping_count):
        reasons.append(f"{prefix}.mappingCount must be a non-negative integer")
    elif isinstance(source_map, Mapping):
        mappings = source_map.get("mappings")
        if isinstance(mappings, list) and mapping_count != len(mappings):
            reasons.append(
                f"{prefix}.mappingCount must match "
                f"artifacts[{index}].sourceMap.mappings "
                f"({_value_mismatch_context(mapping_count, len(mappings))})"
            )
    size_bytes = source_remap.get("sizeBytes")
    if size_bytes is None:
        if required:
            reasons.append(f"{prefix}.sizeBytes must be a non-negative integer")
    elif not _is_non_negative_int(size_bytes):
        reasons.append(f"{prefix}.sizeBytes must be a non-negative integer")
    reasons.extend(
        _hash_contract_reasons(
            f"{prefix}.hash",
            source_remap.get("hash"),
            require_closed_fields=require_closed_fields,
        )
    )
    return reasons


def _template_specialization_contract_reasons(prefix: str, value: Any) -> list[str]:
    if not isinstance(value, Mapping):
        return [f"{prefix} must be an object"]

    reasons = _unsupported_mapping_field_reasons(
        prefix,
        value,
        REPORT_ARTIFACT_TEMPLATE_SPECIALIZATION_FIELDS,
    )
    for field_name in ("name", "materializedName"):
        if not _is_non_empty_string(value.get(field_name)):
            reasons.append(f"{prefix}.{field_name} must be a string")
    parameters = value.get("parameters")
    parameter_reasons = _string_mapping_contract_reasons(
        f"{prefix}.parameters", parameters
    )
    reasons.extend(parameter_reasons)
    expected_parameters = (
        set(parameters)
        if not parameter_reasons and isinstance(parameters, Mapping)
        else None
    )
    reasons.extend(
        _template_parameter_source_mapping_contract_reasons(
            f"{prefix}.parameterSources",
            value.get("parameterSources"),
            expected_parameters=expected_parameters,
        )
    )
    source = value.get("source")
    if source not in TEMPLATE_PARAMETER_SOURCE_VALUES:
        reasons.append(
            f"{prefix}.source must be one of "
            f"{', '.join(sorted(TEMPLATE_PARAMETER_SOURCE_VALUES))}"
        )
    if "hostName" in value and not _is_non_empty_string(value.get("hostName")):
        reasons.append(f"{prefix}.hostName must be a string")
    return reasons


def _template_source_declaration_contract_reasons(
    prefix: str,
    value: Any,
) -> list[str]:
    if not isinstance(value, Mapping):
        return [f"{prefix} must be an object"]
    reasons = _unsupported_mapping_field_reasons(
        prefix,
        value,
        REPORT_ARTIFACT_TEMPLATE_DECLARATION_FIELDS,
    )
    if not _is_non_empty_string(value.get("file")):
        reasons.append(f"{prefix}.file must be a string")
    if not _is_non_empty_string(value.get("name")):
        reasons.append(f"{prefix}.name must be a string")
    for field_name in ("line", "column"):
        field_value = value.get(field_name)
        if (
            not isinstance(field_value, int)
            or isinstance(field_value, bool)
            or field_value <= 0
        ):
            reasons.append(f"{prefix}.{field_name} must be a positive integer")
    return reasons


def _template_parameter_source_mapping_contract_reasons(
    prefix: str,
    value: Any,
    *,
    expected_parameters: set[str] | None = None,
) -> list[str]:
    reasons = _string_mapping_contract_reasons(prefix, value)
    if reasons:
        return reasons
    for parameter, source in value.items():
        if source not in TEMPLATE_PARAMETER_SOURCE_VALUES:
            reasons.append(
                f"{_mapping_key_path(prefix, parameter)} must be one of "
                f"{', '.join(sorted(TEMPLATE_PARAMETER_SOURCE_VALUES))}"
            )
    if expected_parameters is not None and set(value) != expected_parameters:
        reasons.append(f"{prefix} keys must match parameters")
    return reasons


def _unsupported_template_contract_reasons(prefix: str, value: Any) -> list[str]:
    if not isinstance(value, Mapping):
        return [f"{prefix} must be an object"]

    reasons = _unsupported_mapping_field_reasons(
        prefix,
        value,
        REPORT_ARTIFACT_TEMPLATE_UNSUPPORTED_FIELDS,
    )
    if not _is_non_empty_string(value.get("name")):
        reasons.append(f"{prefix}.name must be a string")
    reasons.extend(
        _string_list_contract_reasons(f"{prefix}.parameters", value.get("parameters"))
    )
    reasons.extend(
        _string_list_contract_reasons(
            f"{prefix}.missingParameters", value.get("missingParameters")
        )
    )
    if value.get("reason") != "missing-template-arguments":
        reasons.append(f"{prefix}.reason must be missing-template-arguments")
    reasons.extend(
        _template_source_declaration_contract_reasons(
            f"{prefix}.sourceDeclaration",
            value.get("sourceDeclaration"),
        )
    )
    if not _is_non_empty_string(value.get("target")):
        reasons.append(f"{prefix}.target must be a string")
    if not _is_non_empty_string(value.get("requiredSignature")):
        reasons.append(f"{prefix}.requiredSignature must be a string")
    return reasons


def _artifact_template_materialization_contract_reasons(
    index: int,
    artifact: Mapping[str, Any],
    *,
    required: bool = False,
) -> list[str]:
    if not required and "templateMaterialization" not in artifact:
        return []

    prefix = f"artifacts[{index}].templateMaterialization"
    materialization = artifact.get("templateMaterialization")
    if not isinstance(materialization, Mapping):
        return [f"{prefix} must be an object"]

    reasons = _unsupported_mapping_field_reasons(
        prefix,
        materialization,
        REPORT_ARTIFACT_TEMPLATE_MATERIALIZATION_FIELDS,
    )
    status = materialization.get("status")
    if status not in {"materialized", "unsupported"}:
        reasons.append(f"{prefix}.status must be materialized or unsupported")

    configured_parameters = materialization.get("configuredParameters")
    configured_parameter_reasons = _string_mapping_contract_reasons(
        f"{prefix}.configuredParameters", configured_parameters
    )
    reasons.extend(configured_parameter_reasons)
    configured_parameter_names = (
        set(configured_parameters)
        if not configured_parameter_reasons
        and isinstance(configured_parameters, Mapping)
        else None
    )
    reasons.extend(
        _template_parameter_source_mapping_contract_reasons(
            f"{prefix}.configuredParameterSources",
            materialization.get("configuredParameterSources"),
            expected_parameters=configured_parameter_names,
        )
    )
    configured_parameter_count = materialization.get("configuredParameterCount")
    if not _is_non_negative_int(configured_parameter_count):
        reasons.append(
            f"{prefix}.configuredParameterCount must be a non-negative integer"
        )
    elif not configured_parameter_reasons and configured_parameter_count != len(
        configured_parameters
    ):
        reasons.append(
            f"{prefix}.configuredParameterCount must match configuredParameters"
        )

    specializations = materialization.get("specializations")
    if not isinstance(specializations, list):
        reasons.append(f"{prefix}.specializations must be a list")
    else:
        for item_index, specialization in enumerate(specializations):
            reasons.extend(
                _template_specialization_contract_reasons(
                    f"{prefix}.specializations[{item_index}]",
                    specialization,
                )
            )
    specialization_count = materialization.get("specializationCount")
    if not _is_non_negative_int(specialization_count):
        reasons.append(f"{prefix}.specializationCount must be a non-negative integer")
    elif isinstance(specializations, list) and specialization_count != len(
        specializations
    ):
        reasons.append(f"{prefix}.specializationCount must match specializations")

    if "accounting" in materialization:
        accounting_prefix = f"{prefix}.accounting"
        accounting = materialization.get("accounting")
        if not isinstance(accounting, Mapping):
            reasons.append(f"{accounting_prefix} must be an object")
        else:
            reasons.extend(
                _unsupported_mapping_field_reasons(
                    accounting_prefix,
                    accounting,
                    REPORT_ARTIFACT_TEMPLATE_MATERIALIZATION_ACCOUNTING_FIELDS,
                )
            )
            for field_name in sorted(
                REPORT_ARTIFACT_TEMPLATE_MATERIALIZATION_ACCOUNTING_FIELDS
            ):
                if not _is_non_negative_int(accounting.get(field_name)):
                    reasons.append(
                        f"{accounting_prefix}.{field_name} must be a "
                        "non-negative integer"
                    )

    unsupported = materialization.get("unsupported")
    if not isinstance(unsupported, list):
        reasons.append(f"{prefix}.unsupported must be a list")
    else:
        for item_index, record in enumerate(unsupported):
            reasons.extend(
                _unsupported_template_contract_reasons(
                    f"{prefix}.unsupported[{item_index}]",
                    record,
                )
            )
    if status == "materialized" and isinstance(unsupported, list) and unsupported:
        reasons.append(
            f"{prefix}.unsupported must be empty when status is materialized"
        )
    if status == "unsupported" and isinstance(unsupported, list) and not unsupported:
        reasons.append(
            f"{prefix}.unsupported must not be empty when status is unsupported"
        )
    return reasons


def _artifact_bfloat16_lowering_contract_reasons(
    index: int,
    artifact: Mapping[str, Any],
) -> list[str]:
    if "bfloat16Lowering" not in artifact:
        return []

    prefix = f"artifacts[{index}].bfloat16Lowering"
    contract = artifact.get("bfloat16Lowering")
    if not isinstance(contract, Mapping):
        return [f"{prefix} must be an object"]

    reasons = _unsupported_mapping_field_reasons(
        prefix,
        contract,
        REPORT_ARTIFACT_BFLOAT16_LOWERING_FIELDS,
    )
    target = artifact.get("target")
    if (
        not _is_non_empty_string(target)
        or _normalized_targets([target])[0] != "directx"
    ):
        reasons.append(f"{prefix} is only supported for DirectX artifacts")
    if contract.get("status") != "exact":
        reasons.append(f"{prefix}.status must be exact")
    if contract.get("approximationUsed") is not False:
        reasons.append(f"{prefix}.approximationUsed must be false")
    if contract.get("registerRepresentation") != "uint-low-16-bits":
        reasons.append(f"{prefix}.registerRepresentation must be uint-low-16-bits")
    if contract.get("storageRepresentation") not in {
        "native-uint16",
        "not-required",
    }:
        reasons.append(
            f"{prefix}.storageRepresentation must be native-uint16 or not-required"
        )
    if contract.get("roundingMode") != "round-to-nearest-ties-to-even":
        reasons.append(f"{prefix}.roundingMode must be round-to-nearest-ties-to-even")
    return reasons


def _report_contract_diagnostics(path: Path, report: Any) -> list[ProjectDiagnostic]:
    if not isinstance(report, Mapping):
        return [_invalid_report_diagnostic(path, ["expected a JSON object"])]

    reasons = []
    has_summary = "summary" in report
    if has_summary:
        reasons.extend(
            _unsupported_mapping_field_reasons("report", report, REPORT_FIELDS)
        )
    if report.get("schemaVersion") != REPORT_SCHEMA_VERSION:
        reasons.append(f"expected schemaVersion {REPORT_SCHEMA_VERSION}")
    if report.get("kind") != REPORT_KIND:
        reasons.append(f"expected kind {REPORT_KIND}")
    if has_summary or "generatedAt" in report:
        if not _is_non_negative_int(report.get("generatedAt")):
            reasons.append("generatedAt must be a non-negative integer")
    reasons.extend(_generator_contract_reasons(report, require_generator=has_summary))

    project = report.get("project")
    root_path: Path | None = None
    project_output_path: Path | None = None
    if not isinstance(project, Mapping):
        reasons.append("missing project object")
    else:
        root = project.get("root")
        if not _is_non_empty_string(root):
            reasons.append("missing project.root")
        else:
            root_path = Path(root)
            if not root_path.is_absolute():
                reasons.append("project.root must be an absolute path")
            elif not root_path.exists():
                reasons.append("project.root does not exist")
            elif not root_path.is_dir():
                reasons.append("project.root must be a directory")
        targets = project.get("targets", [])
        target_reasons = _target_list_contract_reasons(
            "project.targets", targets, require_canonical=has_summary
        )
        reasons.extend(target_reasons)
        output_dir = project.get("outputDir", DEFAULT_OUTPUT_DIR)
        if not _is_non_empty_string(output_dir):
            reasons.append("project.outputDir must be a string")
        elif root_path is not None and root_path.is_absolute() and root_path.is_dir():
            output_path = _project_output_path(root_path, output_dir)
            if not _is_relative_to(output_path, root_path):
                reasons.append("project.outputDir must resolve inside project.root")
            else:
                project_output_path = output_path.resolve()
        reasons.extend(
            _project_metadata_contract_reasons(
                project, require_full_metadata=has_summary
            )
        )

    units = report.get("units", [])
    if has_summary and "units" not in report:
        reasons.append("units must be a list")
    if has_summary or "units" in report:
        if not isinstance(units, list):
            reasons.append("units must be a list")
        else:
            for index, unit in enumerate(units):
                reasons.extend(
                    _unit_contract_reasons(
                        index,
                        unit,
                        root_path=root_path,
                        project=project if isinstance(project, Mapping) else None,
                        require_source_hash=has_summary,
                        require_registered_source_backend=has_summary,
                        require_declared_source_override=has_summary,
                        require_closed_fields=has_summary,
                        check_current_source_hash=(
                            has_summary
                            and isinstance(report.get("artifacts", []), list)
                            and not report.get("artifacts", [])
                        ),
                    )
                )
            reasons.extend(_duplicate_path_contract_reasons("units", units))

    if isinstance(project, Mapping):
        reasons.extend(
            _dispatch_artifact_plan_metadata_reasons(
                project,
                units,
                require_full_metadata=has_summary,
            )
        )

    skipped = report.get("skipped", [])
    if has_summary and "skipped" not in report:
        reasons.append("skipped must be a list")
    if has_summary or "skipped" in report:
        if not isinstance(skipped, list):
            reasons.append("skipped must be a list")
        else:
            for index, skipped_record in enumerate(skipped):
                reasons.extend(
                    _skipped_contract_reasons(
                        index,
                        skipped_record,
                        project=project if isinstance(project, Mapping) else None,
                        require_declared_source_override=has_summary,
                        require_closed_fields=has_summary,
                    )
                )
            reasons.extend(_duplicate_path_contract_reasons("skipped", skipped))
            if isinstance(units, list):
                reasons.extend(_unit_skipped_path_contract_reasons(units, skipped))

    native_directives = report.get("nativeDirectives", [])
    if has_summary and "nativeDirectives" not in report:
        reasons.append("nativeDirectives must be a list")
    if has_summary or "nativeDirectives" in report:
        if not isinstance(native_directives, list):
            reasons.append("nativeDirectives must be a list")
        else:
            units_by_path = _declared_units_by_path(
                units, require_full_metadata=has_summary
            )
            for index, native_directive in enumerate(native_directives):
                reasons.extend(
                    _native_directive_contract_reasons(
                        index,
                        native_directive,
                        units_by_path=units_by_path,
                        project=project if isinstance(project, Mapping) else None,
                        require_registered_source_backend=has_summary,
                        require_closed_fields=has_summary,
                    )
                )

    if has_summary and isinstance(units, list) and isinstance(skipped, list):
        reasons.extend(
            _current_project_scan_contract_reasons(
                project if isinstance(project, Mapping) else None,
                units,
                skipped,
                root_path=root_path,
                report_path=path,
            )
        )

    project_targets = project.get("targets", []) if isinstance(project, Mapping) else []
    project_targets_valid = isinstance(project_targets, list) and all(
        _is_non_empty_string(target) for target in project_targets
    )
    declared_targets = (
        set(_normalized_targets(project_targets)) if project_targets_valid else set()
    )

    artifacts = report.get("artifacts", [])
    if has_summary and "artifacts" not in report:
        reasons.append("artifacts must be a list")
    if not isinstance(artifacts, list):
        reasons.append("artifacts must be a list")
    else:
        artifact_matrix = report.get("artifactMatrix")
        if has_summary and isinstance(project, Mapping):
            reasons.extend(
                _artifact_matrix_metadata_contract_reasons(
                    project,
                    units,
                    artifacts,
                    artifact_matrix,
                    required=bool(artifacts),
                )
            )
        declared_units_by_path = _declared_units_by_path(
            units, require_full_metadata=has_summary
        )
        project_variants = (
            project.get("variants", {}) if isinstance(project, Mapping) else {}
        )
        project_variants_valid = isinstance(project_variants, Mapping) and all(
            _is_non_empty_string(name) for name in project_variants
        )
        declared_variants = set(project_variants) if project_variants_valid else set()
        preserve_source_suffix = (
            _artifact_source_suffix_pairs(units, project_targets)
            if isinstance(units, list) and project_targets_valid
            else set()
        )
        artifact_identities: dict[ArtifactIdentity, int] = {}
        for index, artifact in enumerate(artifacts):
            if not isinstance(artifact, Mapping):
                reasons.append(f"artifacts[{index}] must be an object")
                continue
            if has_summary:
                reasons.extend(
                    _unsupported_mapping_field_reasons(
                        f"artifacts[{index}]", artifact, REPORT_ARTIFACT_FIELDS
                    )
                )
            for field_name in ("source", "path", "status"):
                if not _is_non_empty_string(artifact.get(field_name)):
                    reasons.append(f"artifacts[{index}].{field_name} must be a string")
            source = artifact.get("source")
            if _is_non_empty_string(source) and not _is_report_identity_path(source):
                reasons.append(f"artifacts[{index}].source must be repository-relative")
            elif (
                declared_units_by_path is not None
                and _is_non_empty_string(source)
                and source not in declared_units_by_path
            ):
                reasons.append(f"artifacts[{index}].source must be listed in units")
            path = artifact.get("path")
            target = artifact.get("target")
            variant = artifact.get("variant")
            reasons.extend(
                _target_name_contract_reasons(
                    f"artifacts[{index}].target",
                    target,
                    declared_targets=(
                        declared_targets if project_targets_valid else None
                    ),
                    require_canonical=has_summary,
                )
            )
            if _is_non_empty_string(path) and not _is_report_identity_path(path):
                reasons.append(f"artifacts[{index}].path must be repository-relative")
            elif (
                root_path is not None
                and project_output_path is not None
                and _is_non_empty_string(path)
                and not _is_relative_to(root_path / path, project_output_path)
            ):
                reasons.append(
                    f"artifacts[{index}].path must be under project.outputDir"
                )
            elif (
                root_path is not None
                and project_output_path is not None
                and _is_non_empty_string(path)
                and _is_non_empty_string(target)
            ):
                expected_output_base = (
                    project_output_path / _normalized_targets([target])[0]
                )
                if _is_non_empty_string(variant):
                    expected_output_base = (
                        expected_output_base / _variant_output_segment(variant)
                    )
                if not _is_relative_to(root_path / path, expected_output_base):
                    reasons.append(
                        f"artifacts[{index}].path must be under "
                        "project.outputDir target/variant directory"
                    )
                elif not _artifact_path_matches_target_extension(path, target):
                    expected_extension = _artifact_target_extension(target)
                    actual_extension = _artifact_path_extension(path)
                    reasons.append(
                        f"artifacts[{index}].path suffix must match "
                        f"artifacts[{index}].target "
                        f"({_value_mismatch_context(expected_extension, actual_extension)})"
                    )
                elif _is_non_empty_string(source) and _is_report_identity_path(source):
                    normalized_target = _normalized_targets([target])[0]
                    expected_relative = _artifact_relative_path(
                        source,
                        normalized_target,
                        preserve_source_suffix=(source, normalized_target)
                        in preserve_source_suffix,
                        entry_point=_artifact_entry_point_source(artifact),
                    )
                    if normalized_target == "webgl" and _is_non_empty_string(
                        artifact.get("stage")
                    ):
                        expected_relative = _webgl_stage_relative_path(
                            expected_relative, str(artifact["stage"])
                        )
                    expected_path = (expected_output_base / expected_relative).resolve()
                    if (root_path / path).resolve() != expected_path:
                        reasons.append(
                            f"artifacts[{index}].path must match "
                            "project.outputDir target/variant directory plus "
                            f"artifacts[{index}].source "
                            f"({_value_mismatch_context(_relpath(expected_path, root_path), path)})"
                        )
            source_backend = artifact.get("sourceBackend")
            if has_summary or "sourceBackend" in artifact:
                source_backend_reasons = _source_backend_contract_reasons(
                    f"artifacts[{index}].sourceBackend",
                    source_backend,
                    require_registered=has_summary,
                )
                reasons.extend(source_backend_reasons)
                if (
                    not source_backend_reasons
                    and declared_units_by_path is not None
                    and _is_non_empty_string(source)
                    and source in declared_units_by_path
                ):
                    unit_index, declared_unit = declared_units_by_path[source]
                    if source_backend != declared_unit.get("sourceBackend"):
                        reasons.append(
                            f"artifacts[{index}].sourceBackend must match "
                            f"units[{unit_index}].sourceBackend "
                            f"({_value_mismatch_context(declared_unit.get('sourceBackend'), source_backend)})"
                        )
            status = artifact.get("status")
            if isinstance(status, str) and status not in {"translated", "failed"}:
                reasons.append(
                    f"artifacts[{index}].status must be translated or failed"
                )
            reasons.extend(
                _artifact_dispatch_artifact_contract_reasons(
                    index,
                    artifact,
                    project if isinstance(project, Mapping) else None,
                )
            )
            reasons.extend(
                _artifact_entry_point_contract_reasons(
                    f"artifacts[{index}]",
                    artifact,
                    project=project if isinstance(project, Mapping) else None,
                )
            )
            reasons.extend(
                _artifact_execution_contract_reasons(
                    f"artifacts[{index}]",
                    artifact,
                    project if isinstance(project, Mapping) else None,
                )
            )
            if "error" in artifact or (has_summary and status == "failed"):
                if not _is_non_empty_string(artifact.get("error")):
                    reasons.append(f"artifacts[{index}].error must be a string")
            if has_summary and status == "translated" and "error" in artifact:
                reasons.append(
                    f"artifacts[{index}].error must be omitted "
                    "for translated artifacts"
                )
            if has_summary and status == "failed":
                if "generatedHash" in artifact:
                    reasons.append(
                        f"artifacts[{index}].generatedHash must be omitted "
                        "for failed artifacts"
                    )
                if "generatedSizeBytes" in artifact:
                    reasons.append(
                        f"artifacts[{index}].generatedSizeBytes must be omitted "
                        "for failed artifacts"
                    )
                if "sourceMap" in artifact:
                    reasons.append(
                        f"artifacts[{index}].sourceMap must be omitted "
                        "for failed artifacts"
                    )
                if "sourceRemap" in artifact:
                    reasons.append(
                        f"artifacts[{index}].sourceRemap must be omitted "
                        "for failed artifacts"
                    )
            dispatch_variants = {
                str(record["variant"])
                for _plan_index, record in _report_dispatch_artifacts_for_record(
                    artifact,
                    project if isinstance(project, Mapping) else None,
                )
                if _is_non_empty_string(record.get("variant"))
            }
            if "variant" in artifact:
                if not _is_non_empty_string(variant):
                    reasons.append(f"artifacts[{index}].variant must be a string")
                elif dispatch_variants and variant not in dispatch_variants:
                    reasons.append(
                        f"artifacts[{index}].variant must be listed in "
                        "project.dispatchArtifactPlan for this source and target"
                    )
                elif (
                    has_summary
                    and project_variants_valid
                    and not dispatch_variants
                    and (variant not in declared_variants)
                ):
                    reasons.append(
                        f"artifacts[{index}].variant must be listed in project.variants"
                    )
            elif dispatch_variants:
                reasons.append(
                    f"artifacts[{index}].variant must be recorded for a planned "
                    "dispatch artifact"
                )
            elif has_summary and project_variants_valid and project_variants:
                reasons.append(
                    f"artifacts[{index}].variant must be recorded "
                    "when project.variants is non-empty"
                )
            if "stage" in artifact:
                stage = artifact.get("stage")
                normalized_target = (
                    _normalized_targets([target])[0]
                    if _is_non_empty_string(target)
                    else None
                )
                if not _is_non_empty_string(stage):
                    reasons.append(f"artifacts[{index}].stage must be a string")
                elif normalized_target != "webgl":
                    reasons.append(
                        f"artifacts[{index}].stage is only supported for webgl artifacts"
                    )
                elif stage not in WEBGL_PROJECT_GLSLANG_STAGE_BY_LABEL:
                    reasons.append(
                        _allowed_value_reason(
                            f"artifacts[{index}].stage",
                            frozenset(WEBGL_PROJECT_GLSLANG_STAGE_BY_LABEL),
                            stage,
                        )
                    )
            if "requiredCapabilities" in artifact:
                reasons.extend(
                    _string_list_contract_reasons(
                        f"artifacts[{index}].requiredCapabilities",
                        artifact.get("requiredCapabilities"),
                    )
                )
            reasons.extend(
                _artifact_bfloat16_lowering_contract_reasons(index, artifact)
            )
            if isinstance(project, Mapping):
                reasons.extend(
                    _artifact_defines_contract_reasons(
                        index,
                        artifact,
                        project,
                        required=has_summary,
                    )
                )
            reasons.extend(
                _artifact_define_processing_contract_reasons(
                    index,
                    artifact,
                    required=has_summary,
                )
            )
            if isinstance(project, Mapping):
                reasons.extend(
                    _artifact_include_path_processing_contract_reasons(
                        index,
                        artifact,
                        project,
                        required=has_summary,
                    )
                )
            reasons.extend(
                _artifact_include_dependency_processing_contract_reasons(
                    index,
                    artifact,
                    required=has_summary,
                )
            )
            reasons.extend(
                _artifact_template_materialization_contract_reasons(
                    index,
                    artifact,
                )
            )
            identity = _artifact_identity(artifact)
            if identity is not None:
                previous_index = artifact_identities.get(identity)
                if previous_index is None:
                    artifact_identities[identity] = index
                else:
                    reasons.append(
                        f"artifacts[{index}] duplicates artifacts[{previous_index}] "
                        "identity"
                    )
            reasons.extend(
                _source_hash_contract_reasons(
                    index,
                    artifact,
                    required=has_summary,
                    require_closed_fields=has_summary,
                )
            )
            reasons.extend(
                _artifact_unit_source_hash_contract_reasons(
                    index,
                    artifact,
                    declared_units_by_path,
                )
            )
            reasons.extend(
                _artifact_source_size_contract_reasons(
                    index,
                    artifact,
                    required=has_summary,
                )
            )
            reasons.extend(
                _artifact_unit_source_size_contract_reasons(
                    index,
                    artifact,
                    declared_units_by_path,
                )
            )
            reasons.extend(
                _generated_hash_contract_reasons(
                    index,
                    artifact,
                    required=has_summary and status == "translated",
                    require_closed_fields=has_summary,
                )
            )
            reasons.extend(
                _generated_size_contract_reasons(
                    index,
                    artifact,
                    required=has_summary and status == "translated",
                )
            )
            reasons.extend(
                _provenance_contract_reasons(
                    index,
                    artifact,
                    required=has_summary,
                    require_closed_fields=has_summary,
                )
            )
            reasons.extend(
                _source_map_contract_reasons(
                    index,
                    artifact,
                    required=has_summary and status == "translated",
                    declared_targets=(
                        declared_targets
                        if has_summary and project_targets_valid
                        else None
                    ),
                    require_canonical=has_summary,
                )
            )
            reasons.extend(
                _source_remap_contract_reasons(
                    index,
                    artifact,
                    required=has_summary and status == "translated",
                    require_closed_fields=has_summary,
                    declared_targets=(
                        declared_targets
                        if has_summary and project_targets_valid
                        else None
                    ),
                    require_canonical=has_summary,
                )
            )
        if (
            has_summary
            and isinstance(project, Mapping)
            and (
                bool(artifacts)
                or _artifact_matrix_requires_artifact_records(artifact_matrix)
            )
        ):
            reasons.extend(
                _artifact_matrix_contract_reasons(
                    project,
                    units,
                    artifacts,
                    root_path=root_path,
                    project_output_path=project_output_path,
                )
            )

    diagnostics = report.get("diagnostics", [])
    if has_summary and "diagnostics" not in report:
        reasons.append("diagnostics must be a list")
    if not isinstance(diagnostics, list):
        reasons.append("diagnostics must be a list")
    else:
        for index, diagnostic in enumerate(diagnostics):
            if not isinstance(diagnostic, Mapping):
                reasons.append(f"diagnostics[{index}] must be an object")
                continue
            if has_summary:
                reasons.extend(
                    _unsupported_mapping_field_reasons(
                        f"diagnostics[{index}]",
                        diagnostic,
                        REPORT_DIAGNOSTIC_FIELDS,
                    )
                )
            severity = diagnostic.get("severity")
            if severity not in {"note", "warning", "error"}:
                reasons.append(
                    f"diagnostics[{index}].severity must be note, warning, or error"
                )
            for field_name in ("code", "message"):
                if not _is_non_empty_string(diagnostic.get(field_name)):
                    reasons.append(
                        f"diagnostics[{index}].{field_name} must be a string"
                    )
            reasons.extend(
                _diagnostic_location_contract_reasons(
                    f"diagnostics[{index}].location",
                    diagnostic.get("location"),
                    require_closed_fields=has_summary,
                )
            )
            if "originalLocation" in diagnostic:
                reasons.extend(
                    _diagnostic_location_contract_reasons(
                        f"diagnostics[{index}].originalLocation",
                        diagnostic.get("originalLocation"),
                        require_closed_fields=has_summary,
                    )
                )
            if "target" in diagnostic:
                reasons.extend(
                    _target_name_contract_reasons(
                        f"diagnostics[{index}].target",
                        diagnostic.get("target"),
                        declared_targets=(
                            declared_targets
                            if has_summary and project_targets_valid
                            else None
                        ),
                        require_canonical=has_summary,
                    )
                )
            if "sourceBackend" in diagnostic:
                reasons.extend(
                    _source_backend_contract_reasons(
                        f"diagnostics[{index}].sourceBackend",
                        diagnostic.get("sourceBackend"),
                        require_registered=has_summary,
                        allow_backend_context=True,
                    )
                )
            if "variant" in diagnostic:
                variant = diagnostic.get("variant")
                if not _is_non_empty_string(variant):
                    reasons.append(f"diagnostics[{index}].variant must be a string")
                elif (
                    has_summary
                    and project_variants_valid
                    and project_variants
                    and variant not in declared_variants
                ):
                    reasons.append(
                        f"diagnostics[{index}].variant must be listed in "
                        "project.variants"
                    )
            if "checkKind" in diagnostic:
                check_kind = diagnostic.get("checkKind")
                if check_kind not in PROJECT_REPORT_DIAGNOSTIC_CHECK_KINDS:
                    allowed = ", ".join(sorted(PROJECT_REPORT_DIAGNOSTIC_CHECK_KINDS))
                    reasons.append(
                        f"diagnostics[{index}].checkKind must be one of {allowed}"
                    )
            missing_capabilities = diagnostic.get("missingCapabilities", [])
            if not isinstance(missing_capabilities, list) or any(
                not _is_non_empty_string(capability)
                for capability in missing_capabilities
            ):
                reasons.append(
                    f"diagnostics[{index}].missingCapabilities must be a list of strings"
                )
            if "details" in diagnostic:
                reasons.extend(
                    _diagnostic_details_contract_reasons(
                        f"diagnostics[{index}].details",
                        diagnostic.get("details"),
                    )
                )
        if has_summary and isinstance(units, list) and isinstance(project, Mapping):
            reasons.extend(
                _current_project_config_diagnostic_contract_reasons(
                    diagnostics,
                    root_path=root_path,
                    project=project,
                )
            )
            reasons.extend(
                _current_include_scan_diagnostic_contract_reasons(
                    units,
                    diagnostics,
                    root_path=root_path,
                    project=project,
                )
            )

    reasons.extend(
        _validation_contract_reasons(
            report,
            root_path=root_path,
            require_validation=has_summary,
        )
    )
    require_external_corpus = (
        has_summary
        and isinstance(project, Mapping)
        and project.get("externalCorpusManifest") is not None
    )
    external_corpus_root_path = (
        root_path
        if root_path is not None and root_path.is_absolute() and root_path.is_dir()
        else None
    )
    external_corpus_units_by_path = _declared_units_by_path(
        units, require_full_metadata=has_summary
    )
    reasons.extend(
        _external_corpus_contract_reasons(
            report,
            artifacts,
            require_external_corpus=require_external_corpus,
            require_closed_fields=has_summary,
            root_path=external_corpus_root_path,
            declared_units_by_path=external_corpus_units_by_path,
        )
    )
    if (has_summary or "diagnosticCounts" in report) and isinstance(diagnostics, list):
        reasons.extend(
            _diagnostic_counts_contract_reasons(
                "diagnosticCounts", report.get("diagnosticCounts"), diagnostics
            )
        )
    reasons.extend(
        _summary_contract_reasons(
            report, project, units, skipped, artifacts, diagnostics
        )
    )
    reasons.extend(_migration_contract_reasons(report, require_migration=has_summary))

    return [_invalid_report_diagnostic(path, reasons)] if reasons else []


def _run_toolchain_smoke(
    artifacts: Sequence[Mapping[str, Any]], root: Path
) -> list[dict[str, Any]]:
    runs = []
    for artifact in artifacts:
        if artifact.get("status") != "translated":
            continue
        target = str(artifact.get("target"))
        tools = TOOLCHAIN_BY_BACKEND.get(target, ())
        if not tools:
            continue
        artifact_path = Path(str(artifact["path"]))
        if not artifact_path.is_absolute():
            artifact_path = root / artifact_path
        artifact_path = artifact_path.resolve()
        if not _is_relative_to(artifact_path, root):
            continue
        if not artifact_path.is_file():
            continue
        with tempfile.TemporaryDirectory(prefix="crosstl-toolchain-") as temp_dir:
            smoke_commands = _toolchain_smoke_commands(
                target,
                tools,
                artifact_path,
                artifact=artifact,
                temp_dir=Path(temp_dir),
            )
            for command, check_kind in smoke_commands:
                if not command or not shutil.which(command[0]):
                    continue
                try:
                    stdin = (
                        _toolchain_smoke_stdin(target, command, artifact_path)
                        if "--stdin" in command
                        else None
                    )
                    completed = subprocess.run(
                        command,
                        cwd=str(root),
                        input=stdin,
                        capture_output=True,
                        text=True,
                        check=False,
                        timeout=TOOLCHAIN_SMOKE_TIMEOUT_SECONDS,
                    )
                    returncode = completed.returncode
                    stdout = _toolchain_output_text(completed.stdout)
                    stderr = _toolchain_output_text(completed.stderr)
                except subprocess.TimeoutExpired as exc:
                    returncode = TOOLCHAIN_TIMEOUT_RETURNCODE
                    stdout = _toolchain_output_text(getattr(exc, "stdout", None))
                    stderr = _toolchain_output_text(getattr(exc, "stderr", None))
                    timeout_message = (
                        "Validation toolchain timed out after "
                        f"{TOOLCHAIN_SMOKE_TIMEOUT_SECONDS} seconds."
                    )
                    stderr = f"{stderr.rstrip()}\n{timeout_message}".strip()
                run = {
                    "source": str(artifact.get("source", "")),
                    "target": target,
                    "path": str(artifact["path"]),
                    "command": command,
                    "checkKind": check_kind,
                    "returncode": returncode,
                    "status": "ok" if returncode == 0 else "failed",
                    "stdout": _toolchain_output_excerpt(stdout),
                    "stderr": _toolchain_output_excerpt(stderr),
                }
                if _is_non_empty_string(artifact.get("sourceBackend")):
                    run["sourceBackend"] = artifact["sourceBackend"]
                if _is_non_empty_string(artifact.get("stage")):
                    run["stage"] = artifact["stage"]
                if artifact.get("variant") is not None:
                    run["variant"] = artifact["variant"]
                if isinstance(artifact.get("entryPoint"), Mapping):
                    run["entryPoint"] = dict(artifact["entryPoint"])
                runs.append(run)
                if returncode != 0:
                    break
    return runs


def _toolchain_smoke_commands(
    target: str,
    tools: Sequence[str],
    artifact_path: Path,
    *,
    artifact: Mapping[str, Any] | None = None,
    temp_dir: Path | None = None,
) -> list[tuple[list[str], str]]:
    if target == "directx":
        return [
            (command, "artifact")
            for command in _directx_dxc_smoke_commands(
                tools[0], artifact_path, artifact=artifact
            )
        ]
    if target in {"opengl", "webgl"}:
        source_stage = _glslang_source_stage(artifact)
        stages = (
            (source_stage,) if source_stage else _glslang_guarded_stages(artifact_path)
        )
        if stages:
            return [
                (
                    _glslang_validation_command(
                        target,
                        tools[0],
                        stage,
                        artifact_path,
                        artifact=artifact,
                    ),
                    "artifact",
                )
                for stage in stages
            ]
    if target == "vulkan" and artifact_path.suffix.lower() == ".spvasm":
        return _vulkan_spirv_assembly_smoke_commands(
            tools,
            artifact_path,
            temp_dir=temp_dir,
        )
    smoke_command = _toolchain_smoke_command(
        target,
        tools,
        artifact_path,
        artifact=artifact,
    )
    return [] if smoke_command is None else [smoke_command]


def _toolchain_smoke_command(
    target: str,
    tools: Sequence[str],
    artifact_path: Path,
    *,
    artifact: Mapping[str, Any] | None = None,
) -> tuple[list[str], str] | None:
    if target == "directx":
        return (
            _directx_dxc_smoke_command(tools[0], artifact_path, artifact=artifact),
            "artifact",
        )
    if target in {"opengl", "webgl"}:
        return (
            _glslang_validation_command(
                target,
                tools[0],
                _glslang_stage(artifact_path, artifact),
                artifact_path,
                artifact=artifact,
            ),
            "artifact",
        )
    if target == "vulkan":
        if artifact_path.suffix.lower() == ".spvasm" and len(tools) > 1:
            return [tools[1], str(artifact_path), "-o", os.devnull], "artifact"
        return [tools[0], str(artifact_path)], "artifact"
    if target == "wgsl":
        return [tools[0], "--input-kind", "wgsl", str(artifact_path)], "artifact"
    availability_command = TOOLCHAIN_AVAILABILITY_COMMANDS.get(target)
    if availability_command is None:
        return None
    return list(availability_command), "tool-availability"


def _glslang_validation_command(
    target: str,
    tool: str,
    stage: str,
    artifact_path: Path,
    *,
    artifact: Mapping[str, Any] | None = None,
) -> list[str]:
    command = [tool, "--stdin", "-S", stage]
    if target != "opengl" or not _opengl_artifact_uses_specialization_constants(
        artifact_path, artifact
    ):
        return command
    return [
        *command,
        "--target-env",
        "opengl",
        "--target-env",
        "spirv1.3",
        "--auto-map-locations",
        "-o",
        os.devnull,
    ]


def _opengl_artifact_uses_specialization_constants(
    artifact_path: Path, artifact: Mapping[str, Any] | None = None
) -> bool:
    if artifact is not None:
        specialization_constants = artifact.get("specializationConstants")
        if isinstance(specialization_constants, list) and specialization_constants:
            return True
    try:
        source = artifact_path.read_text(encoding="utf-8", errors="replace")
    except OSError:
        return False
    return GLSLANG_SPECIALIZATION_CONSTANT_RE.search(source) is not None


def _vulkan_spirv_assembly_smoke_commands(
    tools: Sequence[str], artifact_path: Path, *, temp_dir: Path | None = None
) -> list[tuple[list[str], str]]:
    if len(tools) < 2:
        return []
    validator = tools[0]
    assembler = tools[1]
    assembler_command = [assembler, str(artifact_path), "-o", os.devnull]
    if not shutil.which(assembler) or not shutil.which(validator):
        return [(assembler_command, "artifact")]
    if temp_dir is None:
        temp_dir = Path(tempfile.gettempdir())
    output_path = temp_dir / f"{artifact_path.stem}.spv"
    return [
        ([assembler, str(artifact_path), "-o", str(output_path)], "artifact"),
        ([validator, str(output_path)], "artifact"),
    ]


def _toolchain_smoke_stdin(target: str, command: Sequence[str], artifact_path: Path):
    source = artifact_path.read_text(encoding="utf-8", errors="replace")
    if target not in {"opengl", "webgl"}:
        return source
    macro = _glslang_guard_macro_for_command(command)
    if macro is None or not _glslang_source_uses_guard(source, macro):
        return source
    return _filter_glslang_guarded_stage_source(source, macro)


def _glslang_guard_macro_for_command(command: Sequence[str]) -> str | None:
    try:
        stage = command[command.index("-S") + 1]
    except (ValueError, IndexError):
        return None
    return GLSLANG_GUARD_MACRO_BY_STAGE.get(stage)


def _glslang_source_uses_guard(source: str, macro: str) -> bool:
    return any(
        match.group(1).upper() == macro
        for match in GLSLANG_STAGE_GUARD_RE.finditer(source)
    )


def _filter_glslang_guarded_stage_source(source: str, macro: str) -> str:
    output = []
    stage_guard_stack = []
    for line in source.splitlines(keepends=True):
        guard_match = GLSLANG_STAGE_GUARD_LINE_RE.match(line)
        if guard_match:
            stage_guard_stack.append(guard_match.group(1).upper() == macro)
            continue
        if stage_guard_stack and GLSLANG_PREPROCESSOR_ELSE_RE.match(line):
            stage_guard_stack[-1] = not stage_guard_stack[-1]
            continue
        if stage_guard_stack and GLSLANG_PREPROCESSOR_ENDIF_RE.match(line):
            stage_guard_stack.pop()
            continue
        if all(stage_guard_stack):
            output.append(line)
    return "".join(output)


def _directx_dxc_smoke_command(
    tool: str,
    artifact_path: Path,
    *,
    artifact: Mapping[str, Any] | None = None,
) -> list[str]:
    return _directx_dxc_smoke_commands(tool, artifact_path, artifact=artifact)[0]


def _directx_dxc_smoke_commands(
    tool: str,
    artifact_path: Path,
    *,
    artifact: Mapping[str, Any] | None = None,
) -> list[list[str]]:
    try:
        source = artifact_path.read_text(encoding="utf-8", errors="replace")
    except OSError:
        source = ""
    compiler_arguments = dxc_compiler_arguments_for_source(source)
    entry_profiles = _directx_dxc_entry_profiles(artifact_path, artifact=artifact)
    if entry_profiles is None:
        return [
            [
                tool,
                "-T",
                dxc_profile_for_source("lib_6_3", source),
                *compiler_arguments,
                str(artifact_path),
                "-Fo",
                os.devnull,
            ]
        ]

    return [
        _directx_dxc_entry_smoke_command(
            tool,
            artifact_path,
            entry,
            profile,
            compiler_arguments=compiler_arguments,
        )
        for entry, profile in entry_profiles
    ]


def _directx_dxc_entry_smoke_command(
    tool: str,
    artifact_path: Path,
    entry: str,
    profile: str,
    *,
    compiler_arguments: Sequence[str] = (),
) -> list[str]:
    return [
        tool,
        "-T",
        profile,
        *compiler_arguments,
        "-E",
        entry,
        str(artifact_path),
        "-Fo",
        os.devnull,
    ]


def _directx_dxc_entry_profile(artifact_path: Path) -> tuple[str, str] | None:
    entry_profiles = _directx_dxc_entry_profiles(artifact_path)
    if entry_profiles is None:
        return None
    return entry_profiles[0]


def _directx_dxc_entry_profiles(
    artifact_path: Path,
    *,
    artifact: Mapping[str, Any] | None = None,
) -> tuple[tuple[str, str], ...] | None:
    try:
        source = artifact_path.read_text(encoding="utf-8", errors="replace")
    except OSError:
        source = ""

    lowered = source.lower()
    if any(
        f'[shader("{attribute}")]' in lowered
        for attribute in DIRECTX_DXC_LIBRARY_ATTRIBUTES
    ):
        return None

    artifact_entry_profiles = _directx_dxc_entry_profiles_from_artifact(
        artifact, source=source
    )
    if artifact_entry_profiles is None:
        return None
    if artifact_entry_profiles:
        return artifact_entry_profiles

    if source:
        source_entry_profiles = _directx_dxc_entry_profiles_from_source(source)
        if source_entry_profiles is None:
            return None
        if source_entry_profiles:
            return source_entry_profiles

    return (DIRECTX_DXC_DEFAULT_ENTRY_PROFILE,)


def _directx_dxc_entry_profiles_from_artifact(
    artifact: Mapping[str, Any] | None,
    *,
    source: str,
) -> tuple[tuple[str, str], ...] | None:
    if not isinstance(artifact, Mapping):
        return ()

    candidates = []
    for position, entry_point in enumerate(
        _directx_dxc_artifact_entry_points(artifact)
    ):
        name = entry_point.get("name")
        if not _is_non_empty_string(name):
            continue
        profile = _directx_dxc_profile_for_entry_record(entry_point)
        if profile is None:
            return None
        if not _is_non_empty_string(profile):
            continue
        candidates.append(
            (
                position,
                str(name),
                _directx_dxc_profile_for_source(str(profile), source),
                _directx_dxc_entry_record_uses_generic_profile(entry_point),
            )
        )

    return _directx_dxc_preferred_entry_profiles(candidates)


def _directx_dxc_artifact_entry_points(
    artifact: Mapping[str, Any],
) -> list[Mapping[str, Any]]:
    entry_points: list[Mapping[str, Any]] = []

    for entry_point in _record_sequence(artifact.get("entryPoints")):
        if isinstance(entry_point, Mapping):
            entry_points.append(entry_point)

    for entry_profile in _record_sequence(artifact.get("entryProfiles")):
        if not isinstance(entry_profile, Mapping):
            continue
        entry = entry_profile.get("entry", entry_profile.get("name"))
        if not _is_non_empty_string(entry):
            continue
        entry_points.append(
            {
                "name": entry,
                "profile": entry_profile.get("profile"),
                "stage": entry_profile.get("stage"),
            }
        )

    host_interface = artifact.get("hostInterface")
    if isinstance(host_interface, Mapping):
        for entry_point in _record_sequence(host_interface.get("entryPoints")):
            if isinstance(entry_point, Mapping):
                entry_points.append(entry_point)

    return entry_points


def _directx_dxc_profile_for_entry_record(
    entry_point: Mapping[str, Any],
) -> str | None:
    profile = entry_point.get("profile", entry_point.get("shaderModel"))
    if _is_non_empty_string(profile):
        return str(profile)

    stage = entry_point.get("stage")
    if _is_non_empty_string(stage):
        return _directx_dxc_profile_for_stage(str(stage))

    name = entry_point.get("name")
    if _is_non_empty_string(name):
        generic_profile = DIRECTX_DXC_PROFILE_BY_ENTRY.get(str(name))
        if generic_profile is not None:
            return generic_profile
    return ""


def _directx_dxc_entry_record_uses_generic_profile(
    entry_point: Mapping[str, Any],
) -> bool:
    if _is_non_empty_string(
        entry_point.get("profile", entry_point.get("shaderModel"))
    ) or _is_non_empty_string(entry_point.get("stage")):
        return False

    name = entry_point.get("name")
    return _is_non_empty_string(name) and str(name) in DIRECTX_DXC_PROFILE_BY_ENTRY


def _directx_dxc_profile_for_stage(stage: str) -> str | None:
    normalized = stage.strip().lower().replace("-", "_")
    if normalized in DIRECTX_DXC_LIBRARY_STAGES:
        return None
    return DIRECTX_DXC_STAGE_PROFILES.get(normalized, "")


def _directx_dxc_entry_profiles_from_source(
    source: str,
) -> tuple[tuple[str, str], ...] | None:
    struct_semantics = _directx_hlsl_struct_semantics(source)
    candidates = []
    for match in DIRECTX_HLSL_FUNCTION_RE.finditer(source):
        name = match.group("name")
        stage, uses_generic_profile = _directx_hlsl_function_stage_candidate(
            match, struct_semantics
        )
        if stage is None:
            continue
        profile = _directx_dxc_profile_for_stage(stage)
        if profile is None:
            return None
        if not profile:
            continue
        candidates.append(
            (
                match.start(),
                name,
                _directx_dxc_profile_for_source(profile, source),
                uses_generic_profile,
            )
        )

    return _directx_dxc_preferred_entry_profiles(candidates)


def _directx_dxc_preferred_entry_profiles(
    candidates: Sequence[tuple[int, str, str, bool]],
) -> tuple[tuple[str, str], ...]:
    if not candidates:
        return ()

    concrete_stages = {
        profile.split("_", 1)[0]
        for _position, _entry, profile, is_generic in candidates
        if not is_generic
    }
    selected = [
        (position, entry, profile)
        for position, entry, profile, is_generic in candidates
        if not is_generic or profile.split("_", 1)[0] not in concrete_stages
    ]

    deduped = []
    seen_entries: set[tuple[str, str]] = set()
    for position, entry, profile in sorted(selected):
        key = (entry, profile)
        if key in seen_entries:
            continue
        seen_entries.add(key)
        deduped.append((entry, profile))
    return tuple(deduped)


def _directx_hlsl_struct_semantics(source: str) -> dict[str, tuple[str, ...]]:
    semantics_by_struct: dict[str, tuple[str, ...]] = {}
    for match in DIRECTX_HLSL_STRUCT_RE.finditer(source):
        semantics_by_struct[match.group("name")] = tuple(
            semantic_match.group("semantic")
            for semantic_match in DIRECTX_HLSL_SEMANTIC_RE.finditer(match.group("body"))
        )
    return semantics_by_struct


def _directx_hlsl_function_stage_candidate(
    match: re.Match[str],
    struct_semantics: Mapping[str, Sequence[str]],
) -> tuple[str | None, bool]:
    attributes = match.group("attributes") or ""
    shader_match = DIRECTX_HLSL_SHADER_ATTR_RE.search(attributes)
    if shader_match:
        attribute = shader_match.group(1).strip().lower()
        if attribute in DIRECTX_DXC_LIBRARY_ATTRIBUTES:
            return _directx_dxc_library_stage(attribute), False
        return DIRECTX_DXC_STAGE_BY_SHADER_ATTRIBUTE.get(attribute), False

    if DIRECTX_HLSL_NUMTHREADS_RE.search(attributes):
        return "compute", False

    name = match.group("name")
    generic_stage = DIRECTX_DXC_STAGE_BY_ENTRY.get(name)
    if generic_stage is not None:
        return generic_stage, True

    semantic_stage = _directx_hlsl_return_semantic_stage(match.group("return_semantic"))
    if semantic_stage is not None:
        return semantic_stage, False

    return_type = _directx_hlsl_return_type_name(match.group("return_type") or "")
    return _directx_hlsl_struct_stage(struct_semantics.get(return_type, ())), False


def _directx_dxc_library_stage(attribute: str) -> str:
    return {
        "raygeneration": "ray_generation",
        "intersection": "ray_intersection",
        "anyhit": "ray_any_hit",
        "closesthit": "ray_closest_hit",
        "miss": "ray_miss",
        "callable": "ray_callable",
    }.get(attribute, f"ray_{attribute}")


def _directx_hlsl_return_type_name(return_type: str) -> str:
    qualifiers = {
        "const",
        "precise",
        "static",
        "row_major",
        "column_major",
        "inline",
    }
    tokens = [
        token
        for token in re.findall(r"[A-Za-z_]\w*", return_type)
        if token not in qualifiers
    ]
    return tokens[-1] if tokens else ""


def _directx_hlsl_return_semantic_stage(semantic: str | None) -> str | None:
    if not _is_non_empty_string(semantic):
        return None
    normalized = str(semantic).upper()
    if normalized.startswith(("SV_TARGET", "SV_DEPTH", "SV_COVERAGE")):
        return "fragment"
    if normalized == "SV_STENCILREF":
        return "fragment"
    if normalized == "SV_POSITION":
        return "vertex"
    return None


def _directx_hlsl_struct_stage(semantics: Sequence[str]) -> str | None:
    stages = [_directx_hlsl_return_semantic_stage(semantic) for semantic in semantics]
    if "fragment" in stages:
        return "fragment"
    if "vertex" in stages:
        return "vertex"
    return None


def _directx_dxc_profile_for_source(profile: str, source: str) -> str:
    stage = profile.split("_", 1)[0]
    minimum_profiles = []
    if re.search(r"\bSV_ShadingRate\b", source, re.IGNORECASE):
        minimum_profiles.append(DIRECTX_DXC_VRS_MIN_PROFILE_BY_STAGE.get(stage))
    if DIRECTX_HLSL_EXACT_WAVE_SIZE_RE.search(source):
        minimum_profiles.append(
            DIRECTX_DXC_EXACT_WAVE_SIZE_MIN_PROFILE_BY_STAGE.get(stage)
        )
    required = [value for value in minimum_profiles if value is not None]
    if required:
        minimum = max(required, key=_directx_dxc_profile_version)
        if _directx_dxc_profile_version(profile) < _directx_dxc_profile_version(
            minimum
        ):
            profile = minimum
    return dxc_profile_for_source(profile, source)


def _directx_dxc_profile_version(profile: str) -> tuple[int, int]:
    match = re.match(r"^[a-z]+_(\d+)_(\d+)$", profile)
    if match is None:
        return (0, 0)
    return int(match.group(1)), int(match.group(2))


GLSLANG_STAGE_BY_SUFFIX = {
    ".vert": "vert",
    ".vs": "vert",
    ".vsh": "vert",
    ".vertex": "vert",
    ".frag": "frag",
    ".fs": "frag",
    ".fsh": "frag",
    ".fragment": "frag",
    ".geom": "geom",
    ".gs": "geom",
    ".gsh": "geom",
    ".geometry": "geom",
    ".tesc": "tesc",
    ".tcs": "tesc",
    ".tese": "tese",
    ".tes": "tese",
    ".comp": "comp",
    ".cs": "comp",
    ".csh": "comp",
    ".compute": "comp",
    ".mesh": "mesh",
    ".task": "task",
    ".rgen": "rgen",
    ".rint": "rint",
    ".rahit": "rahit",
    ".rchit": "rchit",
    ".rmiss": "rmiss",
    ".rcall": "rcall",
}
GLSLANG_STAGE_FILENAME_SUFFIXES = tuple(
    (f"_{suffix[1:]}", stage) for suffix, stage in GLSLANG_STAGE_BY_SUFFIX.items()
)
GLSLANG_STAGE_BY_GENERATED_COMMENT = {
    "vertex": "vert",
    "fragment": "frag",
    "compute": "comp",
    "geometry": "geom",
    "tessellation_control": "tesc",
    "tessellation_evaluation": "tese",
    "mesh": "mesh",
    "task": "task",
    "ray_generation": "rgen",
    "ray_intersection": "rint",
    "ray_any_hit": "rahit",
    "ray_closest_hit": "rchit",
    "ray_miss": "rmiss",
    "ray_callable": "rcall",
}
GLSLANG_STAGE_BY_GUARD_MACRO = {
    "GL_VERTEX_SHADER": "vert",
    "GL_FRAGMENT_SHADER": "frag",
    "GL_COMPUTE_SHADER": "comp",
    "GL_GEOMETRY_SHADER": "geom",
    "GL_TESS_CONTROL_SHADER": "tesc",
    "GL_TESS_EVALUATION_SHADER": "tese",
    "GL_MESH_SHADER_EXT": "mesh",
    "GL_TASK_SHADER_EXT": "task",
    "GL_RAYGEN_SHADER_EXT": "rgen",
    "GL_INTERSECTION_SHADER_EXT": "rint",
    "GL_ANY_HIT_SHADER_EXT": "rahit",
    "GL_CLOSEST_HIT_SHADER_EXT": "rchit",
    "GL_MISS_SHADER_EXT": "rmiss",
    "GL_CALLABLE_SHADER_EXT": "rcall",
}
GLSLANG_GUARD_MACRO_BY_STAGE = {
    stage: macro for macro, stage in GLSLANG_STAGE_BY_GUARD_MACRO.items()
}
GLSLANG_GENERATED_STAGE_COMMENT_RE = re.compile(
    r"^\s*//\s*([A-Za-z_ -]+)\s+Shader\b",
    re.IGNORECASE | re.MULTILINE,
)
GLSLANG_STAGE_GUARD_RE = re.compile(
    r"^\s*#\s*(?:if|ifdef)\s+" r"(GL_[A-Z0-9_]+(?:_SHADER|_SHADER_EXT))\b",
    re.IGNORECASE | re.MULTILINE,
)
GLSLANG_SPECIALIZATION_CONSTANT_RE = re.compile(
    r"\blayout\s*\(\s*constant_id\s*=", re.IGNORECASE
)
GLSLANG_STAGE_GUARD_LINE_RE = re.compile(
    r"^\s*#\s*(?:if|ifdef)\s+(GL_[A-Z0-9_]+(?:_SHADER|_SHADER_EXT))\b",
    re.IGNORECASE,
)
GLSLANG_PREPROCESSOR_ELSE_RE = re.compile(r"^\s*#\s*else\b", re.IGNORECASE)
GLSLANG_PREPROCESSOR_ENDIF_RE = re.compile(r"^\s*#\s*endif\b", re.IGNORECASE)
GLSLANG_GLOBAL_STAGE_IO_RE = re.compile(
    r"^\s*"
    r"(?:layout\s*\([^;\n]*\)\s*)?"
    r"(?:(?:flat|smooth|noperspective|centroid|sample|patch|invariant|precise)\s+)*"
    r"(in|out)\s+\w",
    re.MULTILINE,
)


def _glslang_stage(
    artifact_path: Path, artifact: Mapping[str, Any] | None = None
) -> str:
    source_stage = _glslang_source_stage(artifact)
    if source_stage:
        return source_stage

    suffix_stage = _glslang_stage_from_path(artifact_path)
    if suffix_stage:
        return suffix_stage

    try:
        source = artifact_path.read_text(encoding="utf-8", errors="replace").lower()
    except OSError:
        return "comp"

    generated_stage = _glslang_stage_from_generated_source(source)
    if generated_stage:
        return generated_stage

    if "local_size_" in source or "gl_globalinvocationid" in source:
        return "comp"
    if "gl_position" in source or "vertex shader" in source:
        return "vert"
    if (
        "gl_fragcoord" in source
        or "gl_fragcolor" in source
        or "fragment shader" in source
    ):
        return "frag"
    stage_io_directions = _glslang_global_stage_io_directions(source)
    if "in" in stage_io_directions:
        return "vert"
    if "out" in stage_io_directions:
        return "frag"
    return "comp"


def _glslang_stage_from_generated_source(source: str) -> str | None:
    for match in GLSLANG_GENERATED_STAGE_COMMENT_RE.finditer(source):
        stage_name = match.group(1).strip().lower().replace("-", "_").replace(" ", "_")
        stage = GLSLANG_STAGE_BY_GENERATED_COMMENT.get(stage_name)
        if stage:
            return stage

    for match in GLSLANG_STAGE_GUARD_RE.finditer(source):
        stage = GLSLANG_STAGE_BY_GUARD_MACRO.get(match.group(1).upper())
        if stage:
            return stage

    return None


def _glslang_guarded_stages(artifact_path: Path) -> tuple[str, ...]:
    try:
        source = artifact_path.read_text(encoding="utf-8", errors="replace")
    except OSError:
        return ()

    stages = []
    seen = set()
    for match in GLSLANG_STAGE_GUARD_RE.finditer(source):
        stage = GLSLANG_STAGE_BY_GUARD_MACRO.get(match.group(1).upper())
        if stage is not None and stage not in seen:
            stages.append(stage)
            seen.add(stage)
    return tuple(stages)


def _glslang_global_stage_io_directions(source: str) -> set[str]:
    return {match.group(1) for match in GLSLANG_GLOBAL_STAGE_IO_RE.finditer(source)}


def _glslang_source_stage(artifact: Mapping[str, Any] | None) -> str | None:
    if artifact is None:
        return None
    source_backend = artifact.get("sourceBackend")
    if not _is_opengl_source_backend(source_backend):
        return None
    source = artifact.get("source")
    if not _is_non_empty_string(source):
        return None
    return _glslang_stage_from_path(str(source))


def _is_opengl_source_backend(value: Any) -> bool:
    if not _is_non_empty_string(value):
        return False
    return str(value).strip().lower() in {"opengl", "glsl", "ogl"}


def _glslang_stage_from_path(path: str | os.PathLike[str]) -> str | None:
    filename = PurePosixPath(str(path).replace("\\", "/")).name
    stem, suffix = os.path.splitext(filename)
    stage = GLSLANG_STAGE_BY_SUFFIX.get(suffix.lower())
    if stage:
        return stage
    if suffix.lower() != ".glsl":
        return None

    _, stem_suffix = os.path.splitext(stem)
    stage = GLSLANG_STAGE_BY_SUFFIX.get(stem_suffix.lower())
    if stage:
        return stage

    normalized_stem = stem.lower()
    for stage_suffix, stage in GLSLANG_STAGE_FILENAME_SUFFIXES:
        if normalized_stem.endswith(stage_suffix):
            return stage
    return None
